@app.post("/usage/credit")
async def usage_credit(request: Request):
    """Credit purchased minutes to a member.

    Intended for payment provider webhooks or admin tooling.

    Security:
      - Requires header "X-Admin-Token" matching env var USAGE_ADMIN_TOKEN.

    Body (JSON):
      {
        "member_id": "abc123",
        "minutes": 60
      }
    """
    try:
        raw = await request.json()
        _perf_stage("usage.credit.parse_json")
    except Exception:
        raw = {}

    token = (request.headers.get("x-admin-token") or request.headers.get("X-Admin-Token") or "").strip()
    if not USAGE_ADMIN_TOKEN or token != USAGE_ADMIN_TOKEN:
        raise HTTPException(status_code=403, detail="Forbidden")

    member_id = str(raw.get("member_id") or raw.get("memberId") or "").strip()
    minutes = raw.get("minutes") or raw.get("add_minutes") or raw.get("purchased_minutes") or 0

    try:
        minutes_i = int(minutes)
    except Exception:
        minutes_i = 0

    if not member_id or minutes_i <= 0:
        raise HTTPException(status_code=400, detail="member_id and minutes (> 0) are required")

    brand = _stripe_paygo_brand(raw.get("brand") or raw.get("brandId") or raw.get("brand_id") or "Elaralo")
    email = _stripe_paygo_email_norm(raw.get("email") or raw.get("customer_email") or "")
    identity_key = _usage_identity_key_for_brand(brand=brand, member_id=member_id, email=email, request=request)
    result = await run_in_threadpool(_usage_credit_minutes_sync, identity_key, minutes_i)
    return result



@app.post("/usage/status")
async def usage_status(request: Request):
    """Return current minute balance WITHOUT charging additional time.

    This endpoint is used to enable a seamless PayGo top-up UX (no page refresh):
      - When minutes are exhausted and the user completes checkout in a new tab,
        the frontend can poll this endpoint until minutes become available.

    Input JSON (same shape as /chat):
      {
        "session_id": "...",
        "session_state": { ... }
      }

    Output:
      {
        "ok": true,
        "minutes_used": 12,
        "minutes_allowed": 60,
        "minutes_remaining": 48,
        "minutes_exhausted": false,
        "identity_key": "member::<id>"
      }
    """
    try:
        raw = await request.json()
    except Exception:
        raw = {}

    session_id = str(raw.get("session_id") or raw.get("sessionId") or "").strip()
    session_state = raw.get("session_state") or raw.get("sessionState") or {}
    if not isinstance(session_state, dict):
        session_state = {}

    try:
        _member_rebranding_upsert_from_session_state(session_state)
    except Exception:
        pass

    member_id = _extract_member_id(session_state)
    plan_name_raw = _extract_plan_name(session_state)
    rebranding_key_raw = _extract_rebranding_key(session_state)
    rebranding_parsed = _parse_rebranding_key(rebranding_key_raw) if rebranding_key_raw else {}

    plan_map = _session_get_str(session_state, "elaralo_plan_map", "elaraloPlanMap") or rebranding_parsed.get("elaralo_plan_map", "")
    free_minutes_raw = _session_get_str(session_state, "free_minutes", "freeMinutes") or rebranding_parsed.get("free_minutes", "")
    cycle_days_raw = _session_get_str(session_state, "cycle_days", "cycleDays") or rebranding_parsed.get("cycle_days", "")

    free_minutes = _safe_int(free_minutes_raw)
    cycle_days = _safe_int(cycle_days_raw)

    is_anon = bool(member_id) and str(member_id).strip().lower().startswith("anon:")
    persistent_intimate_consent = False
    if member_id and not is_anon and _session_state_is_context_auto_mode_ai_connect(session_state):
        persistent_intimate_consent = await run_in_threadpool(_member_has_intimate_consent_sync, member_id)
        if persistent_intimate_consent:
            session_state["adult_verified"] = True
            session_state["explicit_consented"] = True
            session_state["explicit_consent_persisted"] = True
            if session_state.get("pending_consent") == "intimate":
                session_state["pending_consent"] = None
    # Product rule: no paid plan means Trial for visitors and logged-in members.
    # Do not require a missing/empty plan to be treated as a paid plan with 0 minutes.
    is_trial = (not bool(member_id)) or is_anon or _plan_is_absent_or_trial(plan_name_raw)
    brand_for_usage = _usage_brand_from_session_state(session_state, rebranding_parsed)
    email_for_usage = _session_get_str(session_state, "email", "customerEmail", "customer_email")
    identity_key = _usage_identity_key_for_brand(
        brand=brand_for_usage,
        member_id=member_id,
        email=email_for_usage,
        session_id=session_id,
        request=request,
    )

    # v9.2.45/v9.2.47: visitor AND logged-in Trial users get brand-specific
    # free minutes when Wix/selector payload does not explicitly provide freeMinutes.
    if free_minutes is not None:
        minutes_allowed_override: Optional[int] = free_minutes
    elif is_trial:
        minutes_allowed_override = int(_trial_minutes_for_brand(brand_for_usage))
    else:
        minutes_allowed_override = None
    cycle_days_override: Optional[int] = cycle_days if cycle_days is not None else None

    plan_name_for_limits = plan_map or plan_name_raw or ("Trial" if is_trial else "")

    usage_ok, usage_info = await run_in_threadpool(
        _usage_peek_sync,
        identity_key,
        is_trial=is_trial,
        plan_name=plan_name_for_limits,
        minutes_allowed_override=minutes_allowed_override,
        cycle_days_override=cycle_days_override,
    )

    remaining_seconds = float(usage_info.get("remaining_seconds") or 0.0)
    minutes_remaining = int(usage_info.get("minutes_remaining") or _usage_minutes_remaining_display(remaining_seconds) or 0)
    return {
        "ok": bool(usage_ok),
        "minutes_used": int(usage_info.get("minutes_used") or 0),
        "minutes_allowed": int(usage_info.get("minutes_allowed") or 0),
        "minutes_total": int(usage_info.get("minutes_total") or usage_info.get("minutes_allowed") or 0),
        "minutes_remaining": minutes_remaining,
        "minutes_exhausted": remaining_seconds <= 0.0,
        "identity_key": str(usage_info.get("identity_key") or identity_key),
        "used_seconds": float(usage_info.get("used_seconds") or 0.0),
        "remaining_seconds": remaining_seconds,
        "total_seconds": float(usage_info.get("total_seconds") or 0.0),
    }


@app.get("/admin/usage/debug")
async def admin_usage_debug(request: Request):
    """Restricted admin debug endpoint for persisted usage/minutes state.

    Security:
      - Requires header "X-Admin-Token" matching env var USAGE_ADMIN_TOKEN.

    Query params:
      - member_id / memberId (optional): if provided, returns a detailed view for that member.
      - limit (optional): if member_id is omitted, returns the most recently updated rows (default 25, max 200).
    """
    token = (request.headers.get("x-admin-token") or request.headers.get("X-Admin-Token") or "").strip()
    if not USAGE_ADMIN_TOKEN or token != USAGE_ADMIN_TOKEN:
        raise HTTPException(status_code=403, detail="Forbidden")

    member_id = (request.query_params.get("member_id") or request.query_params.get("memberId") or "").strip()
    limit_raw = (request.query_params.get("limit") or "").strip()
    try:
        limit_i = int(limit_raw) if limit_raw else 25
    except Exception:
        limit_i = 25
    limit_i = max(1, min(limit_i, 200))

    now = time.time()
    result = await run_in_threadpool(_usage_admin_debug_sync, member_id, limit_i, now)
    return result


