def _stripe_paygo_clean_text(value: Any) -> str:
    try:
        s = str(value if value is not None else "").strip()
    except Exception:
        return ""
    if s.lower() in {"", "none", "null", "undefined"}:
        return ""
    return s


def _stripe_paygo_brand(value: Any) -> str:
    raw = _stripe_paygo_clean_text(value)
    if not raw:
        return "Elaralo"
    key = re.sub(r"[^a-z0-9]+", "", raw.lower())
    if key == "dulcemoon":
        return "DulceMoon"
    if key == "elaralo":
        return "Elaralo"
    # Preserve custom white-label spelling, but remove dangerous whitespace.
    return raw[:80]


def _stripe_paygo_brand_key(brand: Any) -> str:
    b = _stripe_paygo_brand(brand)
    return re.sub(r"[^a-z0-9]+", "", b.lower()) or "elaralo"


def _stripe_paygo_is_anon_member_id(member_id: Any) -> bool:
    mid = _stripe_paygo_clean_text(member_id)
    return bool(mid) and mid.lower().startswith("anon:")


def _stripe_paygo_is_real_member_id(member_id: Any) -> bool:
    mid = _stripe_paygo_clean_text(member_id)
    return bool(mid) and not _stripe_paygo_is_anon_member_id(mid)


def _stripe_paygo_email_norm(email: Any) -> str:
    s = _stripe_paygo_clean_text(email).lower()
    return s if ("@" in s and "." in s.split("@")[-1]) else ""


def _stripe_paygo_hash(value: str, n: int = 16) -> str:
    return hashlib.sha256((value or "").encode("utf-8", errors="ignore")).hexdigest()[:n]


def _usage_identity_key_for_brand(
    *,
    brand: Any,
    member_id: Any = "",
    email: Any = "",
    session_id: Any = "",
    request: Optional[Request] = None,
) -> str:
    """Return the canonical brand-scoped usage key.

    Brand scoping prevents a PayGo credit or subscription allowance on one brand
    from increasing the available minutes on another brand for the same Wix member.
    """
    b = _stripe_paygo_brand(brand)
    mid = _stripe_paygo_clean_text(member_id)
    if mid:
        if _stripe_paygo_is_anon_member_id(mid):
            return f"brand_visitor::{b}::{mid}"
        return f"brand_member::{b}::{mid}"
    em = _stripe_paygo_email_norm(email)
    if em:
        return f"brand_email::{b}::{_stripe_paygo_hash(em, 24)}"
    sid = _stripe_paygo_clean_text(session_id)
    if sid:
        return f"brand_session::{b}::{_stripe_paygo_hash(sid, 24)}"
    ip = ""
    if request is not None:
        try:
            ip = _get_client_ip(request)
        except Exception:
            ip = ""
    return f"brand_ip::{b}::{ip or 'unknown'}"


def _usage_brand_from_session_state(session_state: Dict[str, Any], rebranding_parsed: Optional[Dict[str, Any]] = None) -> str:
    if not isinstance(session_state, dict):
        session_state = {}
    parsed = rebranding_parsed if isinstance(rebranding_parsed, dict) else {}
    raw = (
        _stripe_paygo_clean_text(session_state.get("brand"))
        or _stripe_paygo_clean_text(session_state.get("companyName"))
        or _stripe_paygo_clean_text(session_state.get("company_name"))
        or _stripe_paygo_clean_text(session_state.get("rebranding"))
        or _stripe_paygo_clean_text(parsed.get("rebranding"))
        or _stripe_paygo_clean_text(parsed.get("brand"))
        or "Elaralo"
    )
    return _stripe_paygo_brand(raw)


def _stripe_paygo_units(raw: Any) -> int:
    try:
        units = int(raw)
    except Exception:
        units = 1
    min_units = max(1, int(STRIPE_PAYGO_MIN_UNITS or 1))
    max_units = max(min_units, int(STRIPE_PAYGO_MAX_UNITS or 12))
    return max(min_units, min(max_units, units))


def _stripe_paygo_unit_minutes(brand: Any) -> int:
    key = _stripe_paygo_brand_key(brand)
    if key == "dulcemoon":
        return max(1, int(STRIPE_PAYGO_MINUTES_DULCEMOON or 30))
    return max(1, int(STRIPE_PAYGO_MINUTES_ELARALO or 30))


def _stripe_paygo_unit_amount_cents(brand: Any) -> int:
    key = _stripe_paygo_brand_key(brand)
    if key == "dulcemoon":
        return max(50, int(STRIPE_PAYGO_AMOUNT_CENTS_DULCEMOON or 699))
    return max(50, int(STRIPE_PAYGO_AMOUNT_CENTS_ELARALO or 499))


def _stripe_paygo_product_name(brand: Any) -> str:
    key = _stripe_paygo_brand_key(brand)
    if key == "dulcemoon":
        return STRIPE_PAYGO_PRODUCT_NAME_DULCEMOON or "DulceMoon Connect Voice Minutes"
    return STRIPE_PAYGO_PRODUCT_NAME_ELARALO or "Elaralo Connect Voice Minutes"


def _stripe_paygo_return_origin(request: Request, raw: Dict[str, Any]) -> str:
    """Resolve the Checkout return target.

    Prefer a full return URL supplied by Connect. This matters for Wix-hosted
    brands such as DulceMoon: if hosted Checkout is ever used as an explicit
    fallback, Stripe should return to the DulceMoon page, not to the bare Azure
    Static Apps origin where Connect defaults to Elaralo.
    """
    explicit_url = _stripe_paygo_clean_text(
        raw.get("return_url") or raw.get("returnUrl") or raw.get("success_url") or raw.get("successUrl")
    )
    if explicit_url.startswith("https://") or explicit_url.startswith("http://"):
        return explicit_url

    parent_url = _stripe_paygo_clean_text(raw.get("parent_url") or raw.get("parentUrl") or raw.get("wix_url") or raw.get("wixUrl"))
    if parent_url.startswith("https://") or parent_url.startswith("http://"):
        return parent_url

    explicit = _stripe_paygo_clean_text(raw.get("return_origin") or raw.get("returnOrigin") or raw.get("origin"))
    if explicit.startswith("https://") or explicit.startswith("http://"):
        return explicit.rstrip("/") + "/"
    if STRIPE_PAYGO_PUBLIC_BASE_URL:
        return STRIPE_PAYGO_PUBLIC_BASE_URL.rstrip("/") + "/"
    origin = _stripe_paygo_clean_text(request.headers.get("origin"))
    if origin:
        return origin.rstrip("/") + "/"
    referer = _stripe_paygo_clean_text(request.headers.get("referer") or request.headers.get("referrer"))
    if referer:
        try:
            p = urlparse(referer)
            if p.scheme and p.netloc:
                return f"{p.scheme}://{p.netloc}/"
        except Exception:
            pass
    try:
        return str(request.base_url).rstrip("/") + "/"
    except Exception:
        return ""

def _stripe_paygo_bool(value: Any, default: bool = False) -> bool:
    if value is None:
        return default
    return str(value).strip().lower() in {"1", "true", "yes", "y", "on"}

def _stripe_paygo_append_checkout_params(base_url: str, status: str) -> str:
    base = _stripe_paygo_clean_text(base_url)
    if not base:
        base = "https://example.com/"
    sep = "&" if "?" in base else "?"
    return f"{base}{sep}stripe_paygo={status}&checkout_session_id={{CHECKOUT_SESSION_ID}}"

def _extract_plan_name(session_state: Dict[str, Any]) -> str:
    plan = (
        session_state.get("planName")
        or session_state.get("plan_name")
        or session_state.get("plan")
        or ""
    )
    return str(plan).strip() if plan is not None else ""


def _normalize_rebranding_key_value(raw: Any) -> str:
    try:
        s = str(raw if raw is not None else "").strip()
    except Exception:
        return ""
    if not s:
        return ""

    folded = (
        s.replace("“", '"')
        .replace("”", '"')
        .replace("‘", "'")
        .replace("’", "'")
        .strip()
    )
    lower = folded.lower()
    if lower in ("null", "undefined"):
        return ""
    if folded in ('""', "''"):
        return ""
    if len(folded) >= 2 and folded[0] == folded[-1] and folded[0] in ('"', "'"):
        inner = folded[1:-1].strip()
        inner_lower = inner.lower()
        if not inner or inner in ('""', "''") or inner_lower in ("null", "undefined"):
            return ""
    return folded


def _extract_rebranding_key(session_state: Dict[str, Any]) -> str:
    """Extract the Wix-provided RebrandingKey (preferred) or legacy rebranding string."""
    ss = session_state if isinstance(session_state, dict) else {}
    explicit_key_fields = ("rebrandingKey", "rebranding_key", "RebrandingKey")
    if any(key in ss for key in explicit_key_fields):
        for key in explicit_key_fields:
            if key in ss:
                return _normalize_rebranding_key_value(ss.get(key))
        return ""
    return _normalize_rebranding_key_value(ss.get("rebranding"))

def _strip_rebranding_key_label(part: str) -> str:
    """Accept either raw values or labeled values like 'PayGoMinutes: 60'."""
    s = _normalize_rebranding_key_value(part)
    if not s:
        return ""
    m = re.match(r"^[A-Za-z0-9_ ()+-]+\s*[:=]\s*(.+)$", s)
    return _normalize_rebranding_key_value(m.group(1).strip() if m else s)

def _parse_rebranding_key(raw: str) -> Dict[str, str]:
    """Parse a '|' separated RebrandingKey.

    Expected order:
      Rebranding|UpgradeLink|PayGoLink|PayGoPrice|PayGoMinutes|Plan|ElaraloPlanMap|FreeMinutes|CycleDays
    """
    v = _normalize_rebranding_key_value(raw)
    if not v:
        return {}

    # Legacy support: no delimiter -> only brand name
    if "|" not in v:
        brand = _normalize_rebranding_key_value(_strip_rebranding_key_label(v))
        if not brand:
            return {}
        return {
            "rebranding": brand,
            "upgrade_link": "",
            "pay_go_link": "",
            "pay_go_price": "",
            "pay_go_minutes": "",
            "plan": "",
            "elaralo_plan_map": "",
            "free_minutes": "",
            "cycle_days": "",
        }

    parts = [_normalize_rebranding_key_value(_strip_rebranding_key_label(p)) for p in v.split("|")]
    parts += [""] * (9 - len(parts))

    (
        rebranding,
        upgrade_link,
        pay_go_link,
        pay_go_price,
        pay_go_minutes,
        plan,
        elaralo_plan_map,
        free_minutes,
        cycle_days,
    ) = parts[:9]

    return {
        "rebranding": str(rebranding or "").strip(),
        "upgrade_link": str(upgrade_link or "").strip(),
        "pay_go_link": str(pay_go_link or "").strip(),
        "pay_go_price": str(pay_go_price or "").strip(),
        "pay_go_minutes": str(pay_go_minutes or "").strip(),
        "plan": str(plan or "").strip(),
        "elaralo_plan_map": str(elaralo_plan_map or "").strip(),
        "free_minutes": str(free_minutes or "").strip(),
        "cycle_days": str(cycle_days or "").strip(),
    }


_MEMBER_REBRANDING_LOCK = threading.RLock()


def _member_rebranding_int_or_none(val: Any) -> Optional[int]:
    if val is None:
        return None
    try:
        s = str(val).strip()
    except Exception:
        return None
    if not s:
        return None
    try:
        return int(s)
    except Exception:
        pass
    m = re.search(r"-?\d+", s)
    if not m:
        return None
    try:
        return int(m.group(0))
    except Exception:
        return None


def _member_rebranding_ensure_schema(conn) -> None:
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS member_rebranding (
          member_id TEXT PRIMARY KEY,
          rebranding_key TEXT,
          pay_go_minutes INTEGER,
          free_minutes INTEGER,
          cycle_days INTEGER,
          plan TEXT,
          plan_map TEXT,
          updated_at INTEGER
        );
        """
    )
    existing_cols: Set[str] = set()
    try:
        rows = conn.execute("PRAGMA table_info(member_rebranding)").fetchall()
    except Exception:
        rows = []
    for row in rows:
        name = ""
        try:
            name = str(row["name"]).strip() if isinstance(row, sqlite3.Row) else str(row[1]).strip()
        except Exception:
            name = ""
        if name:
            existing_cols.add(name)
    for col_name, col_sql in [
        ("rebranding_key", "rebranding_key TEXT"),
        ("pay_go_minutes", "pay_go_minutes INTEGER"),
        ("free_minutes", "free_minutes INTEGER"),
        ("cycle_days", "cycle_days INTEGER"),
        ("plan", "plan TEXT"),
        ("plan_map", "plan_map TEXT"),
        ("updated_at", "updated_at INTEGER"),
    ]:
        if col_name in existing_cols:
            continue
        try:
            conn.execute(f"ALTER TABLE member_rebranding ADD COLUMN {col_sql}")
        except Exception:
            pass


def _member_rebranding_upsert_from_session_state(session_state: Optional[Dict[str, Any]]) -> None:
    ss = session_state if isinstance(session_state, dict) else {}
    member_id = str(ss.get("memberId") or ss.get("member_id") or ss.get("member") or "").strip()
    if not member_id:
        return
    if member_id.lower().startswith("anon:"):
        return

    def _getstr(*keys: str) -> str:
        for key in keys:
            try:
                val = ss.get(key)
            except Exception:
                val = None
            if val is None:
                continue
            txt = str(val).strip()
            if txt:
                return txt
        return ""

    rebranding_key_raw = _extract_rebranding_key(ss)
    rebranding_parsed = _parse_rebranding_key(rebranding_key_raw) if rebranding_key_raw else {}

    pay_go_minutes_raw = _getstr("pay_go_minutes", "payGoMinutes") or str(rebranding_parsed.get("pay_go_minutes") or "").strip()
    free_minutes_raw = _getstr("free_minutes", "freeMinutes") or str(rebranding_parsed.get("free_minutes") or "").strip()
    cycle_days_raw = _getstr("cycle_days", "cycleDays") or str(rebranding_parsed.get("cycle_days") or "").strip()
    plan_external = (
        _getstr("rebranding_plan", "rebrandingPlan", "planExternal", "plan_external")
        or str(rebranding_parsed.get("plan") or "").strip()
    )
    plan_map = _getstr("elaralo_plan_map", "elaraloPlanMap") or str(rebranding_parsed.get("elaralo_plan_map") or "").strip()

    if not any([rebranding_key_raw, pay_go_minutes_raw, free_minutes_raw, cycle_days_raw, plan_external, plan_map]):
        return

    pay_go_minutes = _member_rebranding_int_or_none(pay_go_minutes_raw)
    free_minutes = _member_rebranding_int_or_none(free_minutes_raw)
    cycle_days = _member_rebranding_int_or_none(cycle_days_raw)
    now_ts = int(time.time())

    with _MEMBER_REBRANDING_LOCK:
        conn = _econnect_conn()
        try:
            _member_rebranding_ensure_schema(conn)
            conn.execute(
                """
                INSERT INTO member_rebranding (
                  member_id, rebranding_key, pay_go_minutes, free_minutes, cycle_days, plan, plan_map, updated_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(member_id) DO UPDATE SET
                  rebranding_key = excluded.rebranding_key,
                  pay_go_minutes = excluded.pay_go_minutes,
                  free_minutes = excluded.free_minutes,
                  cycle_days = excluded.cycle_days,
                  plan = excluded.plan,
                  plan_map = excluded.plan_map,
                  updated_at = excluded.updated_at
                """,
                (
                    member_id,
                    rebranding_key_raw,
                    pay_go_minutes,
                    free_minutes,
                    cycle_days,
                    plan_external,
                    plan_map,
                    now_ts,
                ),
            )
            conn.commit()
        finally:
            try:
                conn.close()
            except Exception:
                pass


def _member_rebranding_get_paygo_config(member_id: str) -> Dict[str, Any]:
    mid = str(member_id or "").strip()
    out: Dict[str, Any] = {"minutes": None, "price_num": None, "rebranding_key": ""}
    if not mid or mid.lower().startswith("anon:"):
        return out

    with _MEMBER_REBRANDING_LOCK:
        conn = _econnect_conn()
        try:
            _member_rebranding_ensure_schema(conn)
            row = conn.execute(
                "SELECT rebranding_key, pay_go_minutes, free_minutes, cycle_days, plan, plan_map, updated_at FROM member_rebranding WHERE member_id = ? LIMIT 1",
                (mid,),
            ).fetchone()
        finally:
            try:
                conn.close()
            except Exception:
                pass

    if not row:
        return out

    try:
        rk = _normalize_rebranding_key_value(row["rebranding_key"])
    except Exception:
        try:
            rk = str(row[0] or "").strip()
        except Exception:
            rk = ""
    out["rebranding_key"] = rk

    mins = None
    try:
        mins = _member_rebranding_int_or_none(row["pay_go_minutes"])
    except Exception:
        try:
            mins = _member_rebranding_int_or_none(row[1])
        except Exception:
            mins = None

    rebranding_parsed = _parse_rebranding_key(rk) if rk else {}
    if mins is None:
        mins = _member_rebranding_int_or_none(rebranding_parsed.get("pay_go_minutes"))
    out["minutes"] = mins

    try:
        out["price_num"] = _parse_price_to_float(str(rebranding_parsed.get("pay_go_price") or ""))
    except Exception:
        out["price_num"] = None

    return out


def _payg_paylink_minutes_lookup(paylink_id: str) -> Optional[int]:
    pid = str(paylink_id or "").strip()
    if not pid:
        return None
    try:
        minutes = int(_PAYG_PAYLINK_MINUTES_MAP.get(pid) or 0)
    except Exception:
        minutes = 0
    return minutes if minutes > 0 else None


def _resolve_paygo_credit_minutes_for_member(member_id: str, paylink_id: str) -> Tuple[int, str, Optional[float]]:
    mapped = _payg_paylink_minutes_lookup(paylink_id)
    if mapped is not None and mapped > 0:
        return mapped, "paylink_minutes_map", _parse_price_to_float(PAYG_PRICE)

    cfg = _member_rebranding_get_paygo_config(member_id)
    cfg_minutes = _member_rebranding_int_or_none(cfg.get("minutes"))
    cfg_price = cfg.get("price_num")
    if cfg_minutes is not None and cfg_minutes > 0:
        return cfg_minutes, "member_rebranding", cfg_price if cfg_price is not None else _parse_price_to_float(PAYG_PRICE)

    fallback = int(PAYG_WEBHOOK_FALLBACK_MINUTES or 0)
    if fallback > 0:
        return fallback, "payg_webhook_fallback", _parse_price_to_float(PAYG_PRICE)

    legacy = int(PAYG_INCREMENT_MINUTES or 0)
    if legacy > 0:
        return legacy, "payg_increment_minutes", _parse_price_to_float(PAYG_PRICE)

    return 0, "unresolved", _parse_price_to_float(PAYG_PRICE)


