@app.post("/stream/beestreamed/embed_url")
async def beestreamed_embed_url(req: BeeStreamedEmbedUrlRequest):
    """Return an embeddable URL that *cannot* pop out of the iframe.

    This is useful when the frontend already has an eventRef (or a BeeStreamed viewer URL)
    and only needs the safe wrapper URL for the iframe container.
    """
    event_ref = (req.eventRef or "").strip()
    stream_url = (req.streamUrl or "").strip()

    if not event_ref and stream_url:
        event_ref = _extract_beestreamed_event_ref_from_url(stream_url)

    if not event_ref:
        raise HTTPException(status_code=400, detail="eventRef (or a streamUrl containing it) is required")

    return {
        "ok": True,
        "eventRef": event_ref,
        "embedUrl": f"/stream/beestreamed/embed/{event_ref}",
    }
@app.post("/stream/beestreamed/stop_embed")
async def beestreamed_stop_embed(req: BeeStreamedStopEmbedRequest):
    """Stop a BeeStreamed stream session.

    - Only the configured host may actually stop/end the stream.
    - Viewers may call this endpoint (e.g., when closing the iframe) but it won't stop the stream.
    """
    mapping = _lookup_companion_mapping(req.brand, req.avatar)
    if not mapping:
        raise HTTPException(status_code=404, detail="No mapping for that brand/avatar")

    resolved_brand = mapping.get("brand") or req.brand
    resolved_avatar = mapping.get("avatar") or req.avatar

    host_id = (mapping.get("host_member_id") or "").strip()
    member_id = (req.memberId or "").strip()
    is_host = bool(host_id) and bool(member_id) and (host_id.lower() == member_id.lower())

    # Prefer explicit eventRef from the client; fall back to DB.
    event_ref = (req.eventRef or "").strip() or (_read_event_ref_from_db(resolved_brand, resolved_avatar) or "").strip()

    if not is_host:
        return {
            "ok": True,
            "status": "not_host",
            "isHost": False,
            "canStop": False,
            "sessionActive": bool(_is_session_active(resolved_brand, resolved_avatar)),
            "eventRef": event_ref,
            "message": "",
        }

    if not event_ref:
        # If the host tries to stop without an eventRef, mark the session inactive anyway.
        _set_session_active(resolved_brand, resolved_avatar, active=False)

        _set_session_kind_room_best_effort(resolved_brand, resolved_avatar, kind="", room="")
        _set_livekit_fields_best_effort(resolved_brand, resolved_avatar, record_egress_id=None, hls_egress_id=None, hls_url=None)
        return {
            "ok": True,
            "status": "no_event_ref",
            "isHost": True,
            "canStop": True,
            "sessionActive": False,
            "eventRef": "",
            "message": "No eventRef to stop.",
        }


    # Idempotence: remember whether the session was actually active before stopping, so we don't
    # spam duplicate system lines if stop is called multiple times.
    was_active = bool(_is_session_active(resolved_brand, resolved_avatar))

    stop_res = _beestreamed_stop_webrtc_sync(event_ref)
    if not stop_res.get("ok"):
        raise HTTPException(status_code=502, detail=f"BeeStreamed stop failed: {stop_res}")

    _set_session_active(resolved_brand, resolved_avatar, active=False, event_ref=event_ref)


    _set_session_kind_room_best_effort(resolved_brand, resolved_avatar, kind="", room="")

    # Best-effort: notify any connected shared-live-chat clients.
    if was_active:
        try:
            # 1) Force clients to exit live-chat mode cleanly.
            await _livechat_broadcast(
                event_ref,
                {"type": "session_ended", "eventRef": event_ref, "ts": time.time()},
            )

            # 2) Also emit a visible system line into the chat history/UI.
            sys_msg: Dict[str, Any] = {
                "type": "chat",
                "eventRef": event_ref,
                "text": "Host ended the live stream.",
                "clientMsgId": str(uuid.uuid4()),
                "ts": time.time(),
                "senderId": "",
                "senderRole": "system",
                "name": "System",
            }
            _livechat_push_history(event_ref, sys_msg)
            await run_in_threadpool(_livechat_db_insert_sync, event_ref, sys_msg)
            await _livechat_broadcast(event_ref, sys_msg)
        except Exception:
            pass

    return {
        "ok": True,
        "status": "stopped",
        "isHost": True,
        "canStop": True,
        "sessionActive": False,
        "eventRef": event_ref,
        "message": "",
    }


# =============================================================================
# Jitsi Conference (one-on-one) session control
#
# The front-end embeds Jitsi Meet (External API) when session_active=1 AND
# session_kind == "conference". Viewers never call /start (host-only).
# =============================================================================

class JitsiConferenceStartRequest(BaseModel):
  brand: str
  avatar: str
  memberId: str = ""
  displayName: str = ""


class JitsiConferenceStopRequest(BaseModel):
  brand: str
  avatar: str
  memberId: str = ""


@app.post("/conference/jitsi/start")
async def jitsi_conference_start(req: JitsiConferenceStartRequest):
  resolved_brand = (req.brand or "").strip()
  resolved_avatar = (req.avatar or "").strip()
  if not resolved_brand or not resolved_avatar:
    raise HTTPException(status_code=400, detail="brand and avatar are required.")

  mapping = _lookup_companion_mapping(resolved_brand, resolved_avatar)
  if not mapping:
    raise HTTPException(status_code=404, detail="Unknown brand/avatar mapping.")

  host_member_id = str(mapping.get("host_member_id") or "").strip()
  caller_member_id = str(req.memberId or "").strip()

  if not host_member_id or caller_member_id != host_member_id:
    raise HTTPException(status_code=403, detail="Only the host can start the conference.")

  # Stable, per-companion room name (shared across sessions)
  room = _sanitize_room_token(f"{resolved_brand}-{resolved_avatar}")

  # Persist state for multi-worker viewers
  _set_session_kind_room_best_effort(resolved_brand, resolved_avatar, kind="conference", room=room)
  _set_session_active(resolved_brand, resolved_avatar, True, event_ref=None)

  return {"ok": True, "sessionActive": True, "sessionKind": "conference", "sessionRoom": room}


@app.post("/conference/jitsi/stop")
async def jitsi_conference_stop(req: JitsiConferenceStopRequest):
  resolved_brand = (req.brand or "").strip()
  resolved_avatar = (req.avatar or "").strip()
  if not resolved_brand or not resolved_avatar:
    raise HTTPException(status_code=400, detail="brand and avatar are required.")

  mapping = _lookup_companion_mapping(resolved_brand, resolved_avatar)
  if not mapping:
    raise HTTPException(status_code=404, detail="Unknown brand/avatar mapping.")

  host_member_id = str(mapping.get("host_member_id") or "").strip()
  caller_member_id = str(req.memberId or "").strip()

  if not host_member_id or caller_member_id != host_member_id:
    raise HTTPException(status_code=403, detail="Only the host can stop the conference.")

  _set_session_active(resolved_brand, resolved_avatar, False, event_ref=None)
  # Clear kind/room so next Play click re-prompts host
  _set_session_kind_room_best_effort(resolved_brand, resolved_avatar, kind="", room="")

  return {"ok": True, "sessionActive": False, "sessionKind": "", "sessionRoom": ""}

def _safe_int(val: Any) -> Optional[int]:
    """Parse an int from strings like '60', ' 60 ', or 'PayGoMinutes: 60'. Returns None if missing/invalid."""
    try:
        if val is None:
            return None
        s = str(val).strip()
        if not s:
            return None
        m = re.search(r"-?\d+", s)
        if not m:
            return None
        return int(m.group(0))
    except Exception:
        return None

def _session_get_str(session_state: Dict[str, Any], *keys: str) -> str:
    for k in keys:
        try:
            v = session_state.get(k)
        except Exception:
            v = None
        if v is None:
            continue
        s = str(v).strip()
        if s:
            return s
    return ""

def _normalize_plan_name_for_limits(plan_name: str) -> str:
    p = (plan_name or "").strip()
    if not p:
        return ""
    p = re.sub(r"\s*\([^)]*\)\s*$", "", p).strip()
    p = re.sub(r"\s+membership\s*$", "", p, flags=re.I).strip()
    # Normalize "Test - X" / "Test X" plans to X for quota purposes.
    p = re.sub(r"^test\s*(?:-\s*)?", "", p, flags=re.I).strip()
    key = re.sub(r"[\s_\-]+", " ", p.lower()).strip()
    # Current DulceMoon public plans mapped to Elaralo entitlements.
    aliases = {
        "discover": "discover",
        "explore": "explore",
        "encounter": "encounter",
        # Current public mode labels normalized to legacy/internal quota buckets.
        "intro": "friend",
        "mate": "romantic",
        "mature": "intimate (18+)",
        # Legacy/internal labels.
        "friend": "friend",
        "romantic": "romantic",
        "intimate": "intimate (18+)",
        "intimate 18+": "intimate (18+)",
        "pay as you go": "pay as you go",
    }
    return aliases.get(key, p)

def _included_minutes_for_plan(plan_name: str) -> int:
    p = _normalize_plan_name_for_limits(plan_name).lower()

    if p == "discover":
        return INCLUDED_MINUTES_DISCOVER
    if p == "explore":
        return INCLUDED_MINUTES_EXPLORE
    if p == "encounter":
        return INCLUDED_MINUTES_ENCOUNTER
    if p == "friend":
        return INCLUDED_MINUTES_FRIEND
    if p == "romantic":
        return INCLUDED_MINUTES_ROMANTIC
    if p == "intimate (18+)":
        return INCLUDED_MINUTES_INTIMATE
    if p == "pay as you go":
        return INCLUDED_MINUTES_PAYG
    # Unknown / not provided -> 0 included minutes
    return 0

def _get_client_ip(request: Request) -> str:
    # Azure front-ends commonly set x-forwarded-for with a comma-separated chain.
    xff = (request.headers.get("x-forwarded-for") or "").strip()
    if xff:
        return xff.split(",")[0].strip()
    rip = (request.headers.get("x-real-ip") or "").strip()
    if rip:
        return rip
    cip = (request.headers.get("x-client-ip") or "").strip()
    if cip:
        return cip
    try:
        return str(getattr(request.client, "host", "") or "").strip()
    except Exception:
        return ""

def _load_usage_store() -> Dict[str, Any]:
    try:
        if not os.path.isfile(_USAGE_STORE_PATH):
            return {}
        with open(_USAGE_STORE_PATH, "r", encoding="utf-8") as f:
            data = json.load(f)
        return data if isinstance(data, dict) else {}
    except Exception:
        return {}

def _save_usage_store(store: Dict[str, Any]) -> None:
    try:
        folder = os.path.dirname(_USAGE_STORE_PATH) or "."
        os.makedirs(folder, exist_ok=True)
        tmp = _USAGE_STORE_PATH + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(store, f)
        os.replace(tmp, _USAGE_STORE_PATH)
    except Exception:
        # Fail-open: do not crash the API
        return

def _usage_paywall_message(
    is_trial: bool,
    plan_name: str,
    minutes_allowed: int,
    *,
    upgrade_url: str = "",
    payg_pay_url: str = "",
    payg_increment_minutes: Optional[int] = None,
    payg_price_text: str = "",
) -> str:
    """Generate the user-facing message when minutes are exhausted.

    v9.2.39: Do not expose legacy PayGo/Upgrade URLs in chat.  Connect now has
    persistent in-frame controls for Add Minutes and Upgrade, so the assistant
    should point the viewer to those buttons instead of rendering raw pay links.
    """
    lines: List[str] = []

    if is_trial:
        lines.append(f"Your Free Trial time has ended ({minutes_allowed} minutes).")
    else:
        nice_plan = (plan_name or "").strip()
        if nice_plan:
            lines.append(f"You have no minutes remaining for your plan ({nice_plan}).")
        else:
            lines.append("You have no minutes remaining on your current plan.")

    lines.append("Please select the Add Minutes button or the Upgrade button to purchase more time.")
    lines.append("Once you have more minutes, you can continue our conversation here.")
    return " ".join([ln.strip() for ln in lines if ln.strip()])
def _usage_status_message(
    *,
    is_trial: bool,
    plan_name: str,
    minutes_used: int,
    minutes_allowed: int,
    minutes_remaining: int,
    cycle_days: int,
    upgrade_url: str = "",
    payg_pay_url: str = "",
    payg_increment_minutes: Optional[int] = None,
    payg_price_text: str = "",
) -> str:
    """Generate a short, deterministic answer about remaining minutes.

    v9.2.39: When exhausted, reference the in-frame Add Minutes / Upgrade
    buttons instead of returning raw legacy PayGo/Upgrade URLs.
    """
    lines: List[str] = []

    m_used = max(0, int(minutes_used or 0))
    m_allowed = max(0, int(minutes_allowed or 0))
    m_rem = max(0, int(minutes_remaining or 0))

    if is_trial:
        lines.append(f"You have {m_rem} minutes remaining in your Free Trial.")
    else:
        nice_plan = (plan_name or "").strip()
        if nice_plan:
            lines.append(f"You have {m_rem} minutes remaining on your plan ({nice_plan}).")
        else:
            lines.append(f"You have {m_rem} minutes remaining on your plan.")

    # Include a small breakdown for clarity.
    if m_allowed > 0 or m_used > 0:
        # minutes_allowed can represent the plan-included minutes, while minutes_remaining
        # already reflects any top-ups. Compute a total budget so we never show
        # confusing outputs like "Used: 93 of 30 minutes."
        m_total = max(m_used + m_rem, m_allowed)
        lines.append(f"Used: {m_used} of {m_total} minutes.")

    if (not is_trial) and int(cycle_days or 0) > 0:
        lines.append(f"Your usage cycle resets every {int(cycle_days)} days.")

    if m_rem <= 0:
        lines.append("Please select the Add Minutes button or the Upgrade button to purchase more time.")

    return " ".join([ln.strip() for ln in lines if ln.strip()])

def _usage_charge_and_check_sync(identity_key: str, *, is_trial: bool, plan_name: str, minutes_allowed_override: Optional[int] = None, cycle_days_override: Optional[int] = None) -> Tuple[bool, Dict[str, Any]]:
    """Charge usage time and determine whether the identity still has minutes.

    Returns:
      (ok, info)
        ok: True if allowed to continue, False if minutes exhausted.
        info: includes minutes_used / minutes_allowed / minutes_remaining for optional UI/debug.
    """
    now = time.time()
    try:
        with _USAGE_LOCK:
            store = _load_usage_store()
            rec = store.get(identity_key)
            if not isinstance(rec, dict):
                rec = {}

            # Initialize record
            used_seconds = float(rec.get("used_seconds") or 0.0)
            purchased_seconds = float(rec.get("purchased_seconds") or 0.0)
            last_seen = rec.get("last_seen")
            restart_grace = bool(rec.get("restart_grace"))
            cycle_start = float(rec.get("cycle_start") or now)

            # Member cycle reset (trial does not reset)
            cycle_days = int(cycle_days_override) if cycle_days_override is not None else int(USAGE_CYCLE_DAYS or 0)
            if not is_trial and cycle_days and cycle_days > 0:
                cycle_len = float(cycle_days) * 86400.0
                if (now - cycle_start) >= cycle_len:
                    used_seconds = 0.0
                    cycle_start = now

            # Charge time since last chat call (capped)
            delta = 0.0
            if last_seen is not None:
                try:
                    delta = float(now - float(last_seen))
                except Exception:
                    delta = 0.0

            if delta < 0:
                delta = 0.0

            # If we just credited minutes after exhaustion, do not bill the gap between credit and the next turn.
            if restart_grace:
                delta = 0.0

            # Don't charge long idle gaps (prevents "went AFK" from burning minutes)
            if USAGE_IDLE_GRACE_SECONDS and delta > float(USAGE_IDLE_GRACE_SECONDS):
                delta = 0.0

            # Cap per-request billable time
            max_bill = float(USAGE_MAX_BILLABLE_SECONDS_PER_REQUEST) if USAGE_MAX_BILLABLE_SECONDS_PER_REQUEST > 0 else 0.0
            if max_bill and delta > max_bill:
                delta = max_bill

            used_seconds += delta

            # Compute allowed seconds
            if minutes_allowed_override is not None:
                try:
                    minutes_allowed = max(0, int(minutes_allowed_override))
                except Exception:
                    minutes_allowed = 0
            else:
                minutes_allowed = int(TRIAL_MINUTES) if is_trial else int(_included_minutes_for_plan(plan_name))
            allowed_seconds = max(0.0, (float(minutes_allowed) * 60.0) + float(purchased_seconds or 0.0))

            # Hard stop: do not allow overage. Clamp used_seconds to allowed_seconds.
            if used_seconds > allowed_seconds:
                used_seconds = allowed_seconds

            # Persist record
            rec_out = {
                "used_seconds": used_seconds,
                "purchased_seconds": purchased_seconds,
                "last_seen": now,
                "cycle_start": cycle_start,
                "plan_name": plan_name,
                "is_trial": bool(is_trial),
            }
            store[identity_key] = rec_out
            _save_usage_store(store)

        remaining_seconds = max(0.0, allowed_seconds - used_seconds)
        ok = remaining_seconds > 0.0

        return ok, {
            "minutes_used": int(used_seconds // 60),
            "minutes_allowed": int(minutes_allowed),
            "minutes_remaining": int(remaining_seconds // 60),
            "identity_key": identity_key,
        }
    except Exception:
        # Fail-open
        return True, {"minutes_used": 0, "minutes_allowed": 0, "minutes_remaining": 0, "identity_key": identity_key}


def _usage_peek_sync(
    identity_key: str,
    *,
    is_trial: bool,
    plan_name: str,
    minutes_allowed_override: Optional[int] = None,
    cycle_days_override: Optional[int] = None,
) -> Tuple[bool, Dict[str, Any]]:
    """Read usage state WITHOUT charging time.

    This function must NOT:
      - update last_seen
      - increment used_seconds

    It is safe to use for UI polling after a PayGo checkout, so users are unblocked
    automatically once minutes are credited.
    """
    now = time.time()
    try:
        with _USAGE_LOCK:
            store = _load_usage_store()
            rec = store.get(identity_key)
            if not isinstance(rec, dict):
                rec = {}

            used_seconds = float(rec.get("used_seconds") or 0.0)
            purchased_seconds = float(rec.get("purchased_seconds") or 0.0)
            cycle_start = float(rec.get("cycle_start") or now)

        # Member cycle reset (trial does not reset)
        cycle_days = int(cycle_days_override) if cycle_days_override is not None else int(USAGE_CYCLE_DAYS or 0)
        if not is_trial and cycle_days and cycle_days > 0:
            cycle_len = float(cycle_days) * 86400.0
            if (now - cycle_start) >= cycle_len:
                used_seconds = 0.0
                cycle_start = now  # for computation only (we do not persist here)

        # Compute allowed seconds
        if minutes_allowed_override is not None:
            try:
                minutes_allowed = max(0, int(minutes_allowed_override))
            except Exception:
                minutes_allowed = 0
        else:
            minutes_allowed = int(TRIAL_MINUTES) if is_trial else int(_included_minutes_for_plan(plan_name))

        allowed_seconds = max(0.0, (float(minutes_allowed) * 60.0) + float(purchased_seconds or 0.0))

        # Clamp used_seconds to allowed_seconds (no overage)
        if used_seconds > allowed_seconds:
            used_seconds = allowed_seconds

        remaining_seconds = max(0.0, allowed_seconds - used_seconds)
        ok = remaining_seconds > 0.0
        return ok, {
            "minutes_used": int(used_seconds // 60),
            "minutes_allowed": int(minutes_allowed),
            "minutes_remaining": int(remaining_seconds // 60),
            "identity_key": identity_key,
        }
    except Exception:
        # Fail-open
        return True, {"minutes_used": 0, "minutes_allowed": 0, "minutes_remaining": 0, "identity_key": identity_key}



def _usage_credit_minutes_sync(identity_key: str, minutes: int) -> Dict[str, Any]:
    """Add purchased minutes to an identity record (used by payment webhooks/admin tooling)."""
    now = time.time()
    try:
        minutes_i = int(minutes)
        if minutes_i <= 0:
            return {"ok": False, "error": "minutes must be > 0", "identity_key": identity_key}

        with _USAGE_LOCK:
            store = _load_usage_store()
            rec = store.get(identity_key)
            if not isinstance(rec, dict):
                rec = {}

            # Snapshot current usage BEFORE credit so we can apply pause/resume semantics.
            purchased_seconds_before = float(rec.get("purchased_seconds") or 0.0)
            used_seconds_before = float(rec.get("used_seconds") or 0.0)

            # Determine whether this identity was exhausted before the credit.
            is_trial_rec = bool(rec.get("is_trial"))
            plan_for_limits = str(rec.get("plan_name") or "").strip()
            minutes_allowed_before = int(_trial_minutes_for_brand(_usage_brand_from_identity_key(identity_key))) if is_trial_rec else int(_included_minutes_for_plan(plan_for_limits))
            allowed_seconds_before = max(0.0, (float(minutes_allowed_before) * 60.0) + float(purchased_seconds_before))
            exhausted_before = used_seconds_before >= (allowed_seconds_before - 1e-6)

            purchased_seconds = purchased_seconds_before + (float(minutes_i) * 60.0)

            rec["purchased_seconds"] = purchased_seconds
            rec["used_seconds"] = used_seconds_before
            rec.setdefault("cycle_start", float(rec.get("cycle_start") or now))

            # IMPORTANT:
            # When the user was exhausted and then purchases minutes, we restart the billing clock at the
            # time the payment is verified (credit time). This prevents checkout time from being billed.
            if exhausted_before:
                rec["last_seen"] = float(now)
                rec["restart_grace"] = True
            else:
                rec.setdefault("last_seen", float(rec.get("last_seen") or now))

            rec["last_credit_at"] = int(now)
            rec["plan_name"] = rec.get("plan_name") or "Pay as You Go"

            store[identity_key] = rec
            _save_usage_store(store)

        return {
            "ok": True,
            "identity_key": identity_key,
            "minutes_added": minutes_i,
            "purchased_minutes_total": int(purchased_seconds // 60),
        }
    except Exception:
        return {"ok": False, "identity_key": identity_key}


def _normalize_mode(raw: str) -> str:
    t = (raw or "").strip().lower()
    t = re.sub(r"[\s_\-]+", " ", t).strip()
    # Public mode labels are Intro/Mate/Mature.
    # Internal routing remains friend/romantic/intimate to preserve content folders,
    # model routing, consent gates, and provider behavior.
    if t in {"mature", "mature 18+", "intimate", "intimate 18+", "explicit", "18+", "adult"}:
        return "intimate"
    if t in {"mate", "romance", "romantic"}:
        return "romantic"
    if t in {"intro", "friend", "friendly"}:
        return "friend"
    return "friend"




def _public_mode_label(mode: Any) -> str:
    """Customer-facing mode label.

    Internal mode keys remain friend/romantic/intimate for routing, content
    folders, provider selection, and consent gates.  User-facing text must use
    Intro/Mate/Mature.
    """
    m = _normalize_mode(str(mode or "friend"))
    if m == "intimate":
        return "Mature"
    if m == "romantic":
        return "Mate"
    return "Intro"


def _sanitize_public_mode_labels_text(text: Any) -> str:
    """Replace legacy/internal mode labels in customer-facing text.

    This is intentionally narrow: it rewrites mode-label phrases only, not
    ordinary uses of words like romantic/relationship.
    """
    body = str(text or "")
    if not body:
        return body
    replacements = [
        (r"\bfriend\s+mode\b", "Intro mode"),
        (r"\bfriendly\s+mode\b", "Intro mode"),
        (r"\bromantic\s+mode\b", "Mate mode"),
        (r"\bromance\s+mode\b", "Mate mode"),
        (r"\bintimate\s*(?:\(\s*18\+\s*\))?\s+mode\b", "Mature mode"),
        (r"\bexplicit\s+mode\b", "Mature mode"),
        (r"\badult\s+mode\b", "Mature mode"),
    ]
    for pattern, repl in replacements:
        body = re.sub(pattern, repl, body, flags=re.IGNORECASE)
    return body


def _sanitize_public_mode_labels_events(events: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    out: List[Dict[str, Any]] = []
    for ev in events or []:
        if not isinstance(ev, dict):
            continue
        item = dict(ev)
        if "content" in item:
            item["content"] = _sanitize_public_mode_labels_text(item.get("content"))
        out.append(item)
    return out


def _detect_mode_switch_from_text(text: str) -> Optional[str]:
    t = (text or "").lower().strip()

    # explicit hints: allow [mode:romantic] etc
    if "mode:friend" in t or "[mode:friend]" in t or "mode:intro" in t or "[mode:intro]" in t:
        return "friend"
    if "mode:romantic" in t or "[mode:romantic]" in t or "mode:mate" in t or "[mode:mate]" in t:
        return "romantic"
    if (
        "mode:intimate" in t
        or "[mode:intimate]" in t
        or "mode:mature" in t
        or "[mode:mature]" in t
        or "mode:explicit" in t
        or "[mode:explicit]" in t
    ):
        return "intimate"

    # soft detection (more natural language coverage)
    # friend
    if any(p in t for p in [
        "switch to intro",
        "change to intro",
        "move to intro",
        "make it intro",
        "go to intro",
        "back to intro",
        "intro mode",
        "set intro",
        "set mode to intro",
        "turn on intro",
        "switch to friend",
        "change to friend",
        "move to friend",
        "make it friend",
        "go to friend",
        "back to friend",
        "friend mode",
        "set friend",
        "set mode to friend",
        "turn on friend",
    ]):
        return "friend"

    # romantic
    if any(p in t for p in [
        "switch to mate",
        "change to mate",
        "move to mate",
        "go to mate",
        "back to mate",
        "mate mode",
        "set mate",
        "set mode to mate",
        "turn on mate",
        "switch to romantic",
        "change to romantic",
        "move to romantic",
        "go to romantic",
        "back to romantic",
        "romantic mode",
        "romance mode",
        "set romantic",
        "set mode to romantic",
        "turn on romantic",
        "let's be romantic",
    ]):
        return "romantic"

    # intimate/explicit
    if any(p in t for p in [
        "switch to mature",
        "change to mature",
        "move to mature",
        "go to mature",
        "back to mature",
        "mature mode",
        "set mature",
        "set mode to mature",
        "turn on mature",
        "switch to intimate",
        "change to intimate",
        "move to intimate",
        "go to intimate",
        "back to intimate",
        "intimate mode",
        "set intimate",
        "set mode to intimate",
        "turn on intimate",
        "switch to explicit",
        "explicit mode",
        "set explicit",
        "set mode to explicit",
        "turn on explicit",
        "adult mode",
        "18+ mode",
    ]):
        return "intimate"

    return None
def _is_minutes_balance_question(text: str) -> bool:
    """
    Return True when the user is asking about their remaining chat time/minutes.
    This is intentionally broad because users phrase this many different ways.
    """
    if not text:
        return False
    t = text.strip().lower()

    # Fast exact-ish contains (covers prior phrases)
    needles = [
        "minutes remaining",
        "minutes left",
        "remaining minutes",
        "time remaining",
        "time left",
        "how many minutes",
        "how much time",
        "minutes balance",
        "balance minutes",
        "what is my balance",
        "what's my balance",
        "how many minutes remain",
        "how many minutes are remaining",
        "how many minutes for chat",
        "chat minutes",
        "minutes for chat",
        "how many minutes do i have",
        "how many minutes do i have left",
        "how many minutes do i have remaining",
        "how much time do i have left",
        "how much time do i have remaining",
        "how much time is left",
        "how many minutes are left",
        "minutes used",
        "how many minutes have i used",
        "how much have i used",
        "usage minutes",
    ]
    if any(n in t for n in needles):
        return True

    # Regex fallback: any question containing "minute(s)" + remaining/left/balance/usage
    if re.search(r"\bminute(s)?\b", t) and re.search(r"\b(remain|remaining|left|balance|used|usage)\b", t):
        return True

    # Or "time" + remaining/left/balance (but avoid generic "time" questions)
    if re.search(r"\btime\b", t) and re.search(r"\b(remain|remaining|left|balance|used|usage)\b", t):
        return True

    return False

def _looks_intimate(text: str) -> bool:
    t = (text or "").lower()
    return any(
        k in t
        for k in [
            # Mode / intent
            "mature", "explicit", "intimate", "nsfw", "adult", "18+",
            # Common explicit content terms (kept intentionally simple: substring match)
            "sex", "sexy", "nude", "naked", "porn",
            "fuck", "fucking", "cock", "dick", "penis", "pussy", "vagina",
            "blowjob", "oral", "anal", "orgasm", "cum",
        ]
    )


def _session_state_brand_key_for_mode(session_state: Dict[str, Any]) -> str:
    """Normalize the Connect brand key used for context-mode automation.

    The feature is active for both the Elaralo core brand and the DulceMoon white-label
    brand, but remains limited to AI Connect sessions.  It is intentionally not used
    for Host/Human companion flows.
    """
    state = session_state if isinstance(session_state, dict) else {}
    raw = (
        state.get("brand")
        or state.get("companyName")
        or state.get("company_name")
        or state.get("rebranding")
        or state.get("rebrandingKey")
        or state.get("rebranding_key")
        or "Elaralo"
    )
    try:
        return _compact_brand_key(_host_onboarding_safe_str(raw) or "Elaralo")
    except Exception:
        return str(raw or "").strip().lower().replace(" ", "")


def _session_state_is_context_auto_mode_ai_connect(session_state: Dict[str, Any]) -> bool:
    """Return True when context-based mode switching should be enabled.

    Scope:
      - Elaralo AI Connect
      - DulceMoon AI Connect

    Explicitly excluded:
      - Human companion rows / Host Profile Studio flows
      - Unknown brands
    """
    try:
        state = session_state if isinstance(session_state, dict) else {}
        brand_key = _session_state_brand_key_for_mode(state)
        if brand_key not in {"elaralo", "dulcemoon"}:
            return False

        companion_type = str(
            state.get("companion_type")
            or state.get("companionType")
            or state.get("type")
            or ""
        ).strip().lower()
        if companion_type and companion_type not in {"ai", "ai_companion"}:
            return False
        return True
    except Exception:
        return False


def _contextual_mode_from_messages(user_text: str, current_mode: str, messages: List[Dict[str, Any]]) -> Optional[str]:
    """Deterministic context-mode classifier for AI Connect.

    It deliberately avoids an extra LLM call.  It only changes modes when the latest
    text and very recent context contain clear signals.  Mature signals only request
    Mature mode; the normal explicit-consent gate still runs before Mature content
    can be generated.
    """
    latest = str(user_text or "").strip()
    if not latest:
        return None

    recent_parts: List[str] = []
    for item in (messages or [])[-6:]:
        try:
            if not item or not isinstance(item, dict):
                continue
            recent_parts.append(str(item.get("content") or ""))
        except Exception:
            pass

    combined = " ".join(recent_parts + [latest]).lower()
    compact = re.sub(r"[^a-z0-9+]+", " ", combined)
    current = _normalize_mode(str(current_mode or "friend"))

    intimate_patterns = [
        r"\b(mature|explicit|intimate|nsfw|18\+|adult mode)\b",
        r"\b(sex|sexual|sexy|nude|naked|porn)\b",
        r"\b(fuck|fucking|cock|dick|penis|pussy|vagina|clit)\b",
        r"\b(blowjob|oral|anal|orgasm|cum|cumming)\b",
        r"\b(touch yourself|turn me on|make me hard|make me wet)\b",
    ]
    if any(re.search(p, compact) for p in intimate_patterns):
        return "intimate"

    romantic_patterns = [
        r"\b(mate|romantic|romance|flirt|flirty|date|dating)\b",
        r"\b(kiss|kissing|cuddle|cuddling|hold me|hold your hand)\b",
        r"\b(i love you|love you|falling for you|miss you|my love|sweetheart|darling|babe|baby)\b",
        r"\b(beautiful|gorgeous|handsome|attracted to you|chemistry between us)\b",
        r"\b(relationship|boyfriend|girlfriend|partner)\b",
    ]
    if current != "intimate" and any(re.search(p, compact) for p in romantic_patterns):
        return "romantic"

    practical_patterns = [
        r"\b(help me|can you help|explain|summarize|write|draft|calculate|code|debug|recipe|plan|schedule|weather)\b",
        r"\b(minutes left|minutes remaining|work|school|homework|email|resume|business|travel|budget|question)\b",
    ]
    if current != "friend" and any(re.search(p, compact) for p in practical_patterns):
        return "friend"

    return None


_MODE_ORDER: List[str] = ["friend", "romantic", "intimate"]


def _allowed_modes_from_session_state(session_state: Dict[str, Any]) -> Optional[List[str]]:
    """Read frontend entitlement mode limits from session_state.

    The Connect UI is still the primary entitlement UI, but the backend must also
    honor the same limits because context-mode switching can be triggered by the
    conversation rather than a button click.  If no allowed-modes list is present,
    return None to preserve legacy behavior.
    """
    if not isinstance(session_state, dict):
        return None
    raw = (
        session_state.get("allowed_modes")
        or session_state.get("allowedModes")
        or session_state.get("available_modes")
        or session_state.get("availableModes")
    )
    values: List[Any]
    if raw is None or raw == "":
        return None
    if isinstance(raw, str):
        values = re.split(r"[\s,|;]+", raw.strip())
    elif isinstance(raw, (list, tuple, set)):
        values = list(raw)
    else:
        return None

    out: List[str] = []
    for item in values:
        m = _normalize_mode(str(item or ""))
        if m in _MODE_ORDER and m not in out:
            out.append(m)
    return out or None


def _mode_allowed_by_session(mode: str, allowed_modes: Optional[List[str]]) -> bool:
    m = _normalize_mode(str(mode or "friend"))
    if not allowed_modes:
        return True
    return m in allowed_modes


def _fallback_mode_for_allowed_modes(allowed_modes: Optional[List[str]], preferred: str = "romantic") -> str:
    preferred_norm = _normalize_mode(str(preferred or "romantic"))
    if allowed_modes and preferred_norm in allowed_modes:
        return preferred_norm
    if allowed_modes:
        for candidate in ("romantic", "friend"):
            if candidate in allowed_modes:
                return candidate
        return allowed_modes[0]
    if preferred_norm == "intimate":
        return "romantic"
    return preferred_norm or "friend"


def _intimate_unavailable_response_text(is_anon: bool) -> str:
    if is_anon:
        return "Mature mode is not available for visitors. Please sign in with a member account to access it. We’ll keep things in Mate mode."
    return "Mature mode is not available on your current plan. We’ll keep things in Mate mode."


def _mode_consent_db_path() -> str:
    try:
        path = _get_companion_mappings_db_path(for_write=True)
        if path:
            return path
    except Exception:
        pass
    try:
        return _ensure_econnect_db_seeded()
    except Exception:
        return ""


def _ensure_member_mode_consent_table(conn: sqlite3.Connection) -> None:
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS member_mode_consents (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            member_id TEXT NOT NULL,
            mode TEXT NOT NULL,
            brand TEXT,
            avatar TEXT,
            confirmed_epoch INTEGER NOT NULL,
            source TEXT,
            UNIQUE(member_id, mode)
        )
        """
    )
    conn.execute("CREATE INDEX IF NOT EXISTS idx_member_mode_consents_member_mode ON member_mode_consents(member_id, mode)")


def _member_intimate_consent_row_sync(member_id: Any) -> Optional[Dict[str, Any]]:
    mid = str(member_id or "").strip()
    if not mid or mid.lower().startswith("anon:"):
        return None
    db_path = _mode_consent_db_path()
    if not db_path:
        return None
    try:
        conn = sqlite3.connect(db_path, timeout=10, check_same_thread=False)
        try:
            _ensure_member_mode_consent_table(conn)
            row = conn.execute(
                """
                SELECT member_id, mode, brand, avatar, confirmed_epoch, source
                FROM member_mode_consents
                WHERE member_id = ? AND mode = 'intimate'
                LIMIT 1
                """,
                (mid,),
            ).fetchone()
            if not row or int(row[4] or 0) <= 0:
                return None
            return {
                "member_id": str(row[0] or mid),
                "mode": str(row[1] or "intimate"),
                "brand": str(row[2] or ""),
                "avatar": str(row[3] or ""),
                "confirmed_epoch": int(row[4] or 0),
                "source": str(row[5] or ""),
            }
        finally:
            conn.close()
    except Exception:
        return None


def _member_has_intimate_consent_sync(member_id: Any) -> bool:
    return bool(_member_intimate_consent_row_sync(member_id))


def _record_member_intimate_consent_sync(member_id: Any, session_state: Dict[str, Any], session_id: str = "") -> bool:
    mid = str(member_id or "").strip()
    if not mid or mid.lower().startswith("anon:"):
        return False
    db_path = _mode_consent_db_path()
    if not db_path:
        return False
    state = session_state if isinstance(session_state, dict) else {}
    brand = str(state.get("brand") or state.get("companyName") or state.get("rebranding") or "").strip()
    avatar = str(state.get("avatar") or state.get("mappingAvatar") or state.get("companionName") or state.get("companion") or "").strip()
    now = _now_ts()
    try:
        conn = sqlite3.connect(db_path, timeout=10, check_same_thread=False)
        try:
            _ensure_member_mode_consent_table(conn)
            conn.execute(
                """
                INSERT INTO member_mode_consents(member_id, mode, brand, avatar, confirmed_epoch, source)
                VALUES(?, 'intimate', ?, ?, ?, ?)
                ON CONFLICT(member_id, mode) DO UPDATE SET
                    brand=excluded.brand,
                    avatar=excluded.avatar,
                    confirmed_epoch=excluded.confirmed_epoch,
                    source=excluded.source
                """,
                (mid, brand, avatar, now, f"chat:{session_id}" if session_id else "chat"),
            )
            conn.commit()
            return True
        finally:
            conn.close()
    except Exception:
        return False


@app.get("/mode-consent/intimate/status")
@app.get("/chat/intimate-consent/status")
async def mode_consent_intimate_status(memberId: str = "", member_id: str = "", brand: str = ""):
    """Return whether this member has previously confirmed Mature consent.

    Consent is keyed by member_id only, so the same member is not prompted again
    when switching between Elaralo and DulceMoon AI Connect.  The brand parameter is
    accepted for compatibility/audit but is not part of the unique key.
    """
    mid = str(memberId or member_id or "").strip()
    if not mid or mid.lower().startswith("anon:"):
        return {"ok": True, "consented": False, "granted": False, "member_id": mid}
    row = await run_in_threadpool(_member_intimate_consent_row_sync, mid)
    granted = bool(row)
    return {
        "ok": True,
        "consented": granted,
        "granted": granted,
        "member_id": mid,
        "brand": str((row or {}).get("brand") or brand or ""),
        "avatar": str((row or {}).get("avatar") or ""),
        "granted_epoch": int((row or {}).get("confirmed_epoch") or 0),
    }


def _parse_companion_meta(raw: Any) -> Dict[str, str]:
    """Parse companion identity from a flexible key.

    Accepts either:
      - "Dulce"
      - "Dulce-Female-Hispanic-GenZ"
      - "Dulce-Female-Hispanic-GenZ|live=stream"

    Always returns at least first_name when possible.
    """
    if isinstance(raw, str):
        base = raw.split("|", 1)[0].strip()
        parts = [p.strip() for p in base.split("-") if p.strip()]
        if not parts:
            return {"first_name": "", "gender": "", "ethnicity": "", "generation": ""}

        first = parts[0]
        gender = parts[1] if len(parts) >= 2 else ""
        ethnicity = parts[2] if len(parts) >= 3 else ""
        generation = "-".join(parts[3:]) if len(parts) >= 4 else ""

        return {
            "first_name": first,
            "gender": gender,
            "ethnicity": ethnicity,
            "generation": generation,
        }

    return {"first_name": "", "gender": "", "ethnicity": "", "generation": ""}


def _ai_companion_strip_extensions(raw: str) -> str:
    s = str(raw or "").strip()
    if not s:
        return ""
    # Remove any query/hash and keep only the basename.
    s = s.split("?", 1)[0].split("#", 1)[0]
    s = os.path.basename(s)
    # Some filenames arrive with double extensions like .png.jpg
    while True:
        nxt = re.sub(r"\.(png|jpg|jpeg|webp)$", "", s, flags=re.I)
        if nxt == s:
            break
        s = nxt
    return s.strip()


def _ai_companion_strip_trailing_uuid(raw: str) -> str:
    return re.sub(
        r"-[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$",
        "",
        str(raw or "").strip(),
        flags=re.I,
    )


def _ai_companion_title_token(token: str) -> str:
    lower = str(token or "").strip().lower()
    if not lower:
        return ""
    special = {
        "usa": "USA",
        "uk": "UK",
    }
    if lower in special:
        return special[lower]
    return lower[:1].upper() + lower[1:]


def _ai_companion_humanize_token(token: str) -> str:
    parts = [p for p in str(token or "").replace("_", "-").split("-") if p.strip()]
    return " ".join(_ai_companion_title_token(p) for p in parts).strip()


def _normalize_companion_generation_label(raw: Any) -> str:
    """Normalize generation facets while staying faithful to source metadata.

    This intentionally treats textual variants that mean the same generation as one
    dropdown value (for example Gen-Z, Gen Z, and GenZ -> Generation Z). It does
    not convert Millennials into Generation Y unless the source metadata literally
    says Gen-Y/Generation Y.
    """
    s = _host_onboarding_safe_str(raw)
    if not s:
        return ""
    cleaned = re.sub(r"[_\-]+", " ", s).strip()
    cleaned = re.sub(r"\s+", " ", cleaned)
    key = re.sub(r"[^a-z0-9]+", "", cleaned.lower())
    mapping = {
        "genz": "Generation Z",
        "generationz": "Generation Z",
        "genx": "Generation X",
        "generationx": "Generation X",
        "geny": "Generation Y",
        "generationy": "Generation Y",
        "genalpha": "Generation Alpha",
        "generationalpha": "Generation Alpha",
        "babyboomer": "Baby Boomers",
        "babyboomers": "Baby Boomers",
    }
    if key in mapping:
        return mapping[key]
    # Keep source labels such as Millennials and Classic as-is apart from spacing/case.
    return " ".join(_ai_companion_title_token(part) for part in cleaned.split(" ") if part).strip()


def _normalize_companion_ethnicity_label(raw: Any) -> str:
    """Normalize ethnicity/race facet labels used in My Elaralo dropdowns."""
    s = _host_onboarding_safe_str(raw)
    if not s:
        return ""
    lc = s.strip().lower()
    if lc in {"white", "caucasian"}:
        return "Caucasian"
    if "black" in lc or "african" in lc:
        return "Black"
    if "hispanic" in lc or "latina" in lc or "latino" in lc or "latin" in lc:
        return "Hispanic"
    if "asian" in lc and "middle eastern" not in lc and "north african" not in lc:
        return "Asian"
    if "middle eastern" in lc or "north african" in lc:
        return "Middle Eastern"
    if "native american" in lc or "alaska" in lc:
        return "Native American"
    if "pacific" in lc or "hawaiian" in lc:
        return "Pacific Islander"
    if "multiracial" in lc or "mixed" in lc:
        return "Multiracial"
    cleaned = re.sub(r"[^A-Za-z0-9 ]+", " ", s).strip()
    return " ".join(_ai_companion_title_token(part) for part in cleaned.split() if part).strip()


_COMPANION_AVATAR_COLLISION_SUFFIX_RE = re.compile(r"^(?P<base>.+)-(?P<num>\d{9})$")


def _companion_avatar_strip_collision_suffix(raw: Any) -> str:
    s = _host_onboarding_safe_str(raw)
    if not s:
        return ""
    m = _COMPANION_AVATAR_COLLISION_SUFFIX_RE.match(s)
    return m.group("base").strip() if m else s


def _companion_avatar_first_name(raw: Any) -> str:
    """Return the canonical first-name avatar base used in companion_mappings.avatar."""
    s = _companion_avatar_strip_collision_suffix(raw)
    if not s:
        return ""
    # Existing AI/historical values may include metadata after the first hyphen.
    first = s.split("-", 1)[0].strip()
    # Full names use the first whitespace-delimited token.
    first = re.split(r"\s+", first, maxsplit=1)[0].strip() if first else ""
    first = re.sub(r"[^A-Za-z0-9]+", " ", first).strip()
    first = re.split(r"\s+", first, maxsplit=1)[0].strip() if first else ""
    if not first:
        return "Companion"
    if first.islower() or first.isupper():
        return first[:1].upper() + first[1:].lower()
    return first[:1].upper() + first[1:]


def _companion_avatar_display_name(raw: Any) -> str:
    """Display helper: hide the -######### collision suffix from UI labels."""
    return _companion_avatar_strip_collision_suffix(raw)


def _parse_ai_companion_card_meta(raw: Any) -> Dict[str, str]:
    """Parse an AI companion filename/key into Companion Card metadata.

    For the Elaralo brand, the canonical AI companion_key is the exact
    extensionless filename stem stored in /home/site/brand/elaralo/companion/ai/.
    Example: Adriana-Female-Hispanic-Millennials.jpeg ->
    Adriana-Female-Hispanic-Millennials.
    """
    cleaned = _ai_companion_strip_trailing_uuid(_ai_companion_strip_extensions(str(raw or "")))
    cleaned = re.sub(r"\s+", "-", cleaned).strip("- ")
    base_meta = _parse_companion_meta(cleaned)
    avatar_key = cleaned or _host_onboarding_safe_str(raw)
    first_name = _ai_companion_humanize_token(base_meta.get("first_name"))
    gender = _ai_companion_humanize_token(base_meta.get("gender"))
    ethnicity = _normalize_companion_ethnicity_label(_ai_companion_humanize_token(base_meta.get("ethnicity")))
    generation = _normalize_companion_generation_label(_ai_companion_humanize_token(base_meta.get("generation")))
    out = {
        "avatar": avatar_key,
        "companion_key": avatar_key,
        "first_name": first_name,
        "gender": gender,
        "ethnicity": ethnicity,
        "generation": generation,
        "source_name": avatar_key,
    }
    return out


# -----------------------------------------------------------------------------
# Elaralo AI Companion Linux image catalog
# -----------------------------------------------------------------------------
# Source of truth for Elaralo AI companions:
#   /home/site/brand/elaralo/companion/ai/
# The filename stem is the companion_key and the metadata source.
_ELARALO_AI_COMPANION_DIR_DEFAULT = "/home/site/brand/elaralo/companion/ai"
_ELARALO_HUMAN_COMPANION_DIR_DEFAULT = "/home/site/brand/elaralo/companion/human"
_ELARALO_COMPANION_IMAGE_EXTENSIONS = (".jpeg", ".jpg", ".png", ".webp")
_ELARALO_AI_COMPANION_CACHE: Dict[str, Any] = {"loaded_at": 0.0, "items": []}
_ELARALO_AI_COMPANION_CACHE_TTL_SECONDS = 30.0


def _is_elaralo_core_brand(brand: Any) -> bool:
    return _compact_brand_key(_host_onboarding_safe_str(brand) or "Elaralo") == "elaralo"


def _ai_companion_key_has_metadata(raw: Any) -> bool:
    stem = _ai_companion_strip_trailing_uuid(_ai_companion_strip_extensions(str(raw or "")))
    stem = re.sub(r"\s+", "-", stem).strip("- ")
    parts = [p for p in stem.split("-") if p.strip()]
    return len(parts) >= 4


def _elaralo_companion_dir_candidates(companion_type: Any) -> List[str]:
    kind = _host_onboarding_safe_str(companion_type).lower()
    if kind not in ("ai", "human"):
        kind = "ai"

    out: List[str] = []

    def add(path: Any) -> None:
        p = _host_onboarding_safe_str(path)
        if not p:
            return
        p = os.path.abspath(os.path.expanduser(p))
        if p not in out:
            out.append(p)

    if kind == "ai":
        env_names = (
            "ELARALO_AI_COMPANION_IMAGE_DIR",
            "ELARALO_AI_COMPANION_DIR",
            "AI_COMPANION_IMAGE_DIR",
            "AI_COMPANION_DIR",
        )
        default_dir = _ELARALO_AI_COMPANION_DIR_DEFAULT
    else:
        env_names = (
            "ELARALO_HUMAN_COMPANION_IMAGE_DIR",
            "ELARALO_HUMAN_COMPANION_DIR",
            "HUMAN_COMPANION_IMAGE_DIR",
            "HUMAN_COMPANION_DIR",
        )
        default_dir = _ELARALO_HUMAN_COMPANION_DIR_DEFAULT

    for env_name in env_names:
        raw = os.getenv(env_name, "") or ""
        for token in re.split(r"[|;]+", raw):
            add(token)

    root = os.getenv("ELARALO_COMPANION_ROOT", "") or os.getenv("BRAND_COMPANION_ROOT", "") or ""
    if root:
        add(os.path.join(root, kind))
        add(os.path.join(root, "elaralo", "companion", kind))

    add(default_dir)
    return out


def _elaralo_ai_companion_stem(raw: Any) -> str:
    stem = _ai_companion_strip_trailing_uuid(_ai_companion_strip_extensions(str(raw or "")))
    stem = re.sub(r"\s+", "-", stem).strip("- ")
    if not stem or not _ai_companion_key_has_metadata(stem):
        return ""
    return stem


def _brand_companion_asset_path(brand: Any, companion_type: Any, filename: Any) -> Tuple[str, str]:
    """Resolve a brand companion image path without allowing traversal."""
    if not _is_elaralo_core_brand(brand):
        return "", ""
    kind = _host_onboarding_safe_str(companion_type).lower()
    if kind in ("ai_companion", "artificial_intelligence"):
        kind = "ai"
    if kind in ("human_companion", "host"):
        kind = "human"
    if kind not in ("ai", "human"):
        return "", ""

    raw_filename = unquote(_host_onboarding_safe_str(filename))
    if not raw_filename:
        return "", ""
    if raw_filename != os.path.basename(raw_filename):
        return "", ""
    if any(x in raw_filename for x in ("..", "/", "\\")):
        return "", ""

    wanted = raw_filename.lower()
    wanted_stem = _ai_companion_strip_extensions(raw_filename).lower()
    for folder in _elaralo_companion_dir_candidates(kind):
        if not os.path.isdir(folder):
            continue
        try:
            entries = os.listdir(folder)
        except Exception:
            entries = []
        for entry in entries:
            if entry.startswith("."):
                continue
            full = os.path.join(folder, entry)
            if not os.path.isfile(full):
                continue
            low = entry.lower()
            if not low.endswith(_ELARALO_COMPANION_IMAGE_EXTENSIONS):
                continue
            if low == wanted or _ai_companion_strip_extensions(entry).lower() == wanted_stem:
                return full, entry
    return "", ""


def _elaralo_ai_companion_assets(force_refresh: bool = False) -> List[Dict[str, str]]:
    now = time.time()
    if not force_refresh:
        loaded_at = float(_ELARALO_AI_COMPANION_CACHE.get("loaded_at") or 0.0)
        cached = _ELARALO_AI_COMPANION_CACHE.get("items") or []
        if loaded_at and now - loaded_at < _ELARALO_AI_COMPANION_CACHE_TTL_SECONDS:
            return [dict(item) for item in cached if isinstance(item, dict)]

    items: List[Dict[str, str]] = []
    seen: Set[str] = set()
    for folder in _elaralo_companion_dir_candidates("ai"):
        if not os.path.isdir(folder):
            continue
        try:
            entries = sorted(os.listdir(folder), key=lambda x: x.lower())
        except Exception:
            entries = []
        for entry in entries:
            if entry.startswith("."):
                continue
            low = entry.lower()
            if not low.endswith(_ELARALO_COMPANION_IMAGE_EXTENSIONS):
                continue
            if any(token in low for token in ("logo", "placeholder", "default")):
                continue
            full = os.path.join(folder, entry)
            if not os.path.isfile(full):
                continue
            stem = _elaralo_ai_companion_stem(entry)
            if not stem:
                continue
            key = stem.lower()
            if key in seen:
                continue
            seen.add(key)
            items.append({
                "stem": stem,
                "companion_key": stem,
                "file_name": entry,
                "path": full,
                "source_dir": folder,
            })

    _ELARALO_AI_COMPANION_CACHE["loaded_at"] = now
    _ELARALO_AI_COMPANION_CACHE["items"] = [dict(item) for item in items]
    return items


def _elaralo_ai_first_token(key: Any) -> str:
    stem = _ai_companion_strip_trailing_uuid(_ai_companion_strip_extensions(str(key or "")))
    stem = re.sub(r"\s+", "-", stem).strip("- ")
    return stem.split("-", 1)[0].strip() if stem else ""


def _resolve_elaralo_ai_companion_key(brand: Any, raw_avatar: Any) -> str:
    """Resolve exact Elaralo AI companion_key from the Linux image filename catalog."""
    cleaned = _ai_companion_strip_trailing_uuid(_ai_companion_strip_extensions(str(raw_avatar or "")))
    cleaned = re.sub(r"\s+", "-", cleaned).strip("- ")
    if not cleaned or not _is_elaralo_core_brand(brand):
        return cleaned

    assets = _elaralo_ai_companion_assets()
    for item in assets:
        stem = _host_onboarding_safe_str(item.get("stem"))
        file_name = _host_onboarding_safe_str(item.get("file_name"))
        if cleaned.lower() in (stem.lower(), file_name.lower(), _ai_companion_strip_extensions(file_name).lower()):
            return stem

    if "-" not in cleaned:
        matches = [item for item in assets if _elaralo_ai_first_token(item.get("stem")).lower() == cleaned.lower()]
        if len(matches) == 1:
            return _host_onboarding_safe_str(matches[0].get("stem"))

    return cleaned


def _elaralo_ai_companion_asset_for_key(brand: Any, raw_avatar: Any, public_base_url: str = "") -> Dict[str, str]:
    if not _is_elaralo_core_brand(brand):
        return {}
    resolved_key = _resolve_elaralo_ai_companion_key(brand, raw_avatar)
    if not resolved_key:
        return {}
    target = resolved_key.lower()
    target_file = os.path.basename(str(raw_avatar or "")).lower()
    for item in _elaralo_ai_companion_assets():
        stem = _host_onboarding_safe_str(item.get("stem"))
        file_name = _host_onboarding_safe_str(item.get("file_name"))
        if target in (stem.lower(), _ai_companion_strip_extensions(file_name).lower()) or target_file == file_name.lower():
            out = dict(item)
            out["url"] = _elaralo_ai_companion_file_url(file_name, public_base_url=public_base_url)
            return out
    return {}



def _companion_public_api_base_url(request: Optional[Request] = None, fallback_base: str = "") -> str:
    """Return the public API origin used to serve Linux companion images.

    Companion image files live on the Linux App Service filesystem, so browser
    URLs for these images must point at the API host, not the Static Web App
    host.  Prefer the current request host because the catalog/summary request
    is already being made to the public API origin.  Use API-oriented env vars as
    fallbacks; intentionally do not prefer APP_BASE_URL because that is commonly
    the front-end/static-app origin.
    """
    if request is not None:
        try:
            hdr = request.headers
            host = str(hdr.get("x-forwarded-host") or hdr.get("x-original-host") or hdr.get("host") or "").split(",", 1)[0].strip()
            scheme = str(hdr.get("x-forwarded-proto") or "").split(",", 1)[0].strip().lower()
            if not scheme:
                scheme = "https" if hdr.get("x-arr-ssl") else str(urlparse(str(request.base_url or "")).scheme or "https")
            if host:
                norm = _normalize_public_base_url(f"{scheme}://{host}")
                if norm:
                    return norm
        except Exception:
            pass

    env_candidates = [
        os.getenv("ELARALO_PUBLIC_API_BASE_URL", ""),
        os.getenv("PUBLIC_API_BASE_URL", ""),
        os.getenv("API_PUBLIC_BASE_URL", ""),
        os.getenv("NEXT_PUBLIC_API_BASE_URL", ""),
        os.getenv("API_BASE_URL", ""),
        os.getenv("CONTENT_PUBLIC_BASE_URL", ""),
        os.getenv("WEBSITE_HOSTNAME", ""),
        fallback_base,
    ]
    for cand in env_candidates:
        try:
            norm = _normalize_public_base_url(cand)
        except Exception:
            norm = str(cand or "").strip().rstrip("/")
        if norm:
            return norm
    return ""


def _elaralo_ai_companion_file_url(file_name_or_stem: Any, public_base_url: str = "") -> str:
    name = os.path.basename(_host_onboarding_safe_str(file_name_or_stem))
    if not name:
        return ""
    if not name.lower().endswith(_ELARALO_COMPANION_IMAGE_EXTENSIONS):
        path, resolved_name = _brand_companion_asset_path("Elaralo", "ai", name)
        _ = path
        name = resolved_name or name
    encoded_name = quote(name, safe="")
    path = f"/brand/elaralo/companion/ai/{encoded_name}"
    base = _host_onboarding_safe_str(public_base_url)
    if not base:
        try:
            base = _companion_public_api_base_url(fallback_base=public_base_url)
        except Exception:
            base = _host_onboarding_safe_str(public_base_url)
    if base:
        try:
            base = _normalize_public_base_url(base)
        except Exception:
            base = str(base or "").strip().rstrip("/")
    return f"{base}{path}" if base else path


def _lookup_companion_mapping_for_ai_media(brand: Any, avatar_key: Any) -> Dict[str, Any]:
    """Lookup provider mapping for an Elaralo AI filename key.

    Elaralo AI image companion_key is the full filename stem. Provider rows in
    companion_mappings are keyed by the SQL avatar identity, which is normally
    the first name and may include a -######### collision suffix. This lookup is
    intentionally type-isolated: an AI filename must never fall back to a Human
    mapping row simply because the host has the same first name.
    """
    brand_name = _host_onboarding_safe_str(brand) or "Elaralo"
    avatar_s = _host_onboarding_safe_str(avatar_key)

    direct = _lookup_companion_mapping_typed(brand_name, avatar_s, "AI")
    if isinstance(direct, dict):
        out = dict(direct)
        out["companion_key"] = avatar_s
        out["mapping_avatar"] = _host_onboarding_safe_str(direct.get("avatar"))
        return out

    if _is_elaralo_core_brand(brand_name):
        resolved = _resolve_elaralo_ai_companion_key(brand_name, avatar_s) or avatar_s
        first = _elaralo_ai_first_token(resolved)
        if first:
            fallback = (
                _lookup_companion_mapping_typed(brand_name, first, "AI")
                or _lookup_companion_mapping_by_avatar_base_typed(brand_name, first, "AI")
            )
            if isinstance(fallback, dict):
                out = dict(fallback)
                out["avatar"] = resolved
                out["companion_key"] = resolved
                out["mapping_avatar"] = _host_onboarding_safe_str(fallback.get("avatar"))
                return out

    return {}


def _ai_headshot_url_from_mapping_or_file(brand: Any, avatar_key: Any, mapping: Dict[str, Any], public_base_url: str = "") -> str:
    if _is_elaralo_core_brand(brand):
        asset = _elaralo_ai_companion_asset_for_key(brand, avatar_key, public_base_url=public_base_url)
        static_url = _host_onboarding_safe_str(asset.get("url"))
        if static_url:
            return static_url
    return _host_onboarding_safe_str((mapping or {}).get("headshot_url") or (mapping or {}).get("headshotUrl"))


def _ai_companion_public_payload(brand: str, raw_avatar: str, public_base_url: str = "") -> Dict[str, Any]:
    brand_name = _host_onboarding_safe_str(brand) or "Elaralo"
    resolved_avatar = _resolve_elaralo_ai_companion_key(brand_name, raw_avatar) if _is_elaralo_core_brand(brand_name) else _host_onboarding_safe_str(raw_avatar)
    meta = _parse_ai_companion_card_meta(resolved_avatar)
    avatar_key = _host_onboarding_safe_str(meta.get("avatar"))
    if not avatar_key:
        raise HTTPException(status_code=400, detail="avatar or headshot filename is required for an AI companion card")

    mapping = _lookup_companion_mapping_for_ai_media(brand_name, avatar_key) if _is_elaralo_core_brand(brand_name) else (_lookup_companion_mapping(brand_name, avatar_key) or {})
    static_asset = _elaralo_ai_companion_asset_for_key(brand_name, avatar_key, public_base_url=public_base_url)
    if _is_elaralo_core_brand(brand_name) and not static_asset and not _ai_companion_key_has_metadata(avatar_key):
        raise HTTPException(
            status_code=404,
            detail={
                "error": "Elaralo AI companion image filename not found",
                "avatar": raw_avatar,
                "expected_source_dir": _ELARALO_AI_COMPANION_DIR_DEFAULT,
                "rule": "AI companion_key must match the extensionless hyphenated image filename stem.",
            },
        )

    display_name = _host_onboarding_safe_str(meta.get("first_name")) or avatar_key
    gender = _host_onboarding_safe_str(meta.get("gender"))
    ethnicity = _host_onboarding_safe_str(meta.get("ethnicity"))
    generation = _host_onboarding_safe_str(meta.get("generation"))
    headshot_url = _ai_headshot_url_from_mapping_or_file(brand_name, avatar_key, mapping, public_base_url=public_base_url)
    headshot_file_name = _host_onboarding_safe_str(static_asset.get("file_name") or meta.get("source_name") or avatar_key)
    headshot_asset = {
        "asset_id": "",
        "slot_key": "headshot_front",
        "file_name": headshot_file_name,
        "url": headshot_url,
        "content_type": mimetypes.guess_type(headshot_file_name)[0] or ("image/*" if headshot_url else ""),
        "validation_status": "accepted" if headshot_url else "",
    }
    quick_reference = {
        "public_name": display_name,
        "gender": gender,
        "ethnicity": ethnicity,
        "generation": generation,
    }
    available_fields = [
        key for key, value in [
            ("public_name", display_name),
            ("gender", gender),
            ("ethnicity", ethnicity),
            ("generation", generation),
        ] if _host_onboarding_safe_str(value)
    ]
    public_profile = {
        "summary_mode": "ai_companion_card",
        "companion_type": _host_onboarding_safe_str((mapping or {}).get("companion_type")) or "AI",
        "brand": brand_name,
        "avatar": avatar_key,
        "companion_key": avatar_key,
        "mapping_avatar": _host_onboarding_safe_str((mapping or {}).get("mapping_avatar")),
        "public_display_name": display_name,
        "stage_name": display_name,
        "gender": gender,
        "ethnicity": ethnicity,
        "generation": generation,
        "quick_reference_summary": quick_reference,
        "available_fields": available_fields,
        "headshot_asset": headshot_asset,
        "gallery_assets": [],
    }
    public_page = {
        "headline": display_name,
        "headshot_asset": headshot_asset,
        "gallery_assets": [],
        "education_entries": [],
        "education_text": "",
        "card_type": "ai_companion",
    }
    return {
        "public_profile": public_profile,
        "public_page": public_page,
    }


def _build_persona_system_prompt(session_state: dict, *, mode: str, intimate_allowed: bool) -> str:
    comp = _parse_companion_meta(_extract_companion_raw(session_state))
    name = comp.get("first_name") or _avatar_from_session_state(session_state) or "Elara"

    lines = [
        f"You are {name}, an AI companion who is warm, attentive, and emotionally intelligent.",
        "You speak naturally and conversationally.",
        "You prioritize consent, safety, and emotional connection.",
    ]

    if mode == "romantic":
        lines.append("You may be affectionate and flirty while remaining respectful.")

    if mode == "intimate" and intimate_allowed:
        lines.append(
            "The user has consented to Mature conversation. "
            "You may engage in adult, sensual discussion, but avoid graphic or pornographic detail. "
            "Focus on intimacy, emotion, and connection."
        )

    return " ".join(lines)


def _to_openai_messages(
    messages: List[Dict[str, str]],
    session_state: dict,
    *,
    mode: str,
    intimate_allowed: bool,
    debug: bool
) -> List[Dict[str, Any]]:
    sys = _build_persona_system_prompt(session_state, mode=mode, intimate_allowed=intimate_allowed)
    _dbg(debug, "SYSTEM PROMPT:", sys)

    out: List[Dict[str, Any]] = [{"role": "system", "content": sys}]
    for m in messages:
        role = str(m.get("role") or "").strip()
        if role not in ("user", "assistant"):
            continue

        content_raw: Any = m.get("content", "")
        if role == "user" and isinstance(content_raw, str):
            content_out = _user_message_content_for_llm(content_raw)
        else:
            content_out = content_raw if content_raw is not None else ""

        out.append({"role": role, "content": content_out})
    return out


# ---------------------------------------------------------------------
# LLM latency optimizations
#   (1) Reuse OpenAI/xAI clients + underlying HTTP connection pooling.
#   (2) Optional server-side streaming for xAI (assemble full text).
#   (3) Prompt compaction (handled later in /chat flow).
#   (4) Cache onboarding/system blocks (handled later).
#   (5) Separate priming endpoint /llm/warm (implemented later).
# ---------------------------------------------------------------------

_LLM_CLIENT_LOCK = threading.RLock()
_OPENAI_CLIENT = None
_XAI_CLIENT = None
_OPENAI_SUMMARY_CLIENTS: Dict[str, Any] = {}
_SHARED_HTTP_CLIENT = None


def _get_shared_http_client():
    """Best-effort shared httpx client for connection pooling.

    Works with OpenAI Python SDK v1.x (DefaultHttpxClient). If unavailable,
    we fall back to SDK defaults (still correct, just less optimal).
    """
    global _SHARED_HTTP_CLIENT
    if _SHARED_HTTP_CLIENT is not None:
        return _SHARED_HTTP_CLIENT

    try:
        from openai import DefaultHttpxClient

        # Use SDK defaults; the main win is a shared keep-alive pool.
        _SHARED_HTTP_CLIENT = DefaultHttpxClient()
        return _SHARED_HTTP_CLIENT
    except Exception:
        _SHARED_HTTP_CLIENT = None
        return None


def _make_openai_client(*, api_key: str, base_url: Optional[str] = None, timeout: Optional[float] = None):
    from openai import OpenAI

    kwargs: Dict[str, Any] = {"api_key": api_key}
    if base_url:
        kwargs["base_url"] = base_url
    if timeout is not None:
        kwargs["timeout"] = float(timeout)

    http_client = _get_shared_http_client()
    if http_client is not None:
        kwargs["http_client"] = http_client

    return OpenAI(**kwargs)


def _resolve_openai_api_key() -> str:
    """Resolve the OpenAI key from env first, then from settings if present.

    Some deployed layouts expose OPENAI_API_KEY only via environment variables,
    while others also mirror it onto the imported settings object. STT/TTS/LLM
    paths should all use one shared resolver so they behave consistently.
    """
    raw = os.getenv("OPENAI_API_KEY")
    if raw:
        raw = str(raw).strip()
    if not raw:
        try:
            raw = str(getattr(settings, "OPENAI_API_KEY", "") or "").strip()
        except Exception:
            raw = ""
    return str(raw or "").strip()


def _get_openai_client():
    global _OPENAI_CLIENT

    api_key = _resolve_openai_api_key()
    if not api_key:
        raise RuntimeError("OPENAI_API_KEY is not set")

    with _LLM_CLIENT_LOCK:
        if _OPENAI_CLIENT is None:
            _OPENAI_CLIENT = _make_openai_client(api_key=api_key)
        return _OPENAI_CLIENT


def _get_openai_summary_client(timeout_s: float):
    """Summary client with a specific timeout, still reusing the shared HTTP pool."""
    api_key = _resolve_openai_api_key()
    if not api_key:
        raise RuntimeError("OPENAI_API_KEY is not set")

    # Bucket by rounded timeout so we don't create many clients.
    key = f"{float(timeout_s):.3f}"
    with _LLM_CLIENT_LOCK:
        c = _OPENAI_SUMMARY_CLIENTS.get(key)
        if c is None:
            c = _make_openai_client(api_key=api_key, timeout=float(timeout_s))
            _OPENAI_SUMMARY_CLIENTS[key] = c
        return c


def _get_xai_client():
    global _XAI_CLIENT

    api_key = (os.getenv("XAI_API_KEY", "") or os.getenv("XAI_API_TOKEN", "") or "").strip()
    if not api_key:
        raise RuntimeError("XAI_API_KEY is not set")

    with _LLM_CLIENT_LOCK:
        if _XAI_CLIENT is None:
            _XAI_CLIENT = _make_openai_client(api_key=api_key, base_url=_xai_base_url())
        return _XAI_CLIENT


def _extract_text_from_chat_completion(resp: Any) -> str:
    try:
        return (resp.choices[0].message.content or "").strip()
    except Exception:
        try:
            return (resp["choices"][0]["message"]["content"] or "").strip()
        except Exception:
            return ""


def _extract_text_from_stream_chunk(chunk: Any) -> str:
    """Extract incremental text from a streaming chunk across SDK variants."""
    try:
        choice0 = chunk.choices[0]
        delta = getattr(choice0, "delta", None)
        if isinstance(delta, dict):
            return str(delta.get("content") or "")
        return str(getattr(delta, "content", "") or "")
    except Exception:
        try:
            delta = chunk.get("choices", [{}])[0].get("delta", {})
            return str(delta.get("content") or "")
        except Exception:
            return ""


def _chat_completion_text(
    client: Any,
    *,
    model: str,
    messages: List[Dict[str, Any]],
    temperature: float,
    max_tokens: Optional[int] = None,
    stream: bool = False,
) -> str:
    """Return the full assistant text. If stream=True, assemble tokens from chunks."""
    params: Dict[str, Any] = {
        "model": model,
        "messages": messages,
        "temperature": float(temperature),
    }
    if max_tokens is not None:
        params["max_tokens"] = int(max_tokens)

    if not stream:
        resp = client.chat.completions.create(**params)
        return _extract_text_from_chat_completion(resp)

    # Best-effort streaming: if the provider/SDK rejects stream, fall back to non-stream.
    try:
        params["stream"] = True
        chunks = client.chat.completions.create(**params)
        parts: List[str] = []
        for ch in chunks:
            t = _extract_text_from_stream_chunk(ch)
            if t:
                parts.append(t)
        return ("".join(parts) or "").strip()
    except TypeError:
        resp = client.chat.completions.create(**{k: v for k, v in params.items() if k != "stream"})
        return _extract_text_from_chat_completion(resp)
    except Exception:
        resp = client.chat.completions.create(**{k: v for k, v in params.items() if k != "stream"})
        return _extract_text_from_chat_completion(resp)


def _call_gpt4o(messages: List[Dict[str, Any]]) -> str:
    client = _get_openai_client()
    return _chat_completion_text(
        client,
        model=os.getenv("OPENAI_MODEL", "gpt-4o"),
        messages=messages,
        temperature=float(os.getenv("OPENAI_TEMPERATURE", "0.8") or "0.8"),
        stream=False,
    )


def _call_gpt4o_with_options(
    messages: List[Dict[str, Any]],
    *,
    temperature: Optional[float] = None,
    max_tokens: Optional[int] = None,
) -> str:
    """OpenAI chat call with explicit runtime overrides.

    This keeps the simple _call_gpt4o() helper intact while allowing targeted
    call sites (for example Host Session Insights) to use conservative sampling
    and response-length controls without passing unsupported kwargs into the
    legacy wrapper.
    """
    client = _get_openai_client()
    resolved_temp = float(temperature) if temperature is not None else float(os.getenv("OPENAI_TEMPERATURE", "0.8") or "0.8")
    return _chat_completion_text(
        client,
        model=os.getenv("OPENAI_MODEL", "gpt-4o"),
        messages=messages,
        temperature=resolved_temp,
        max_tokens=max_tokens,
        stream=False,
    )





# ----------------------------
# Multi-provider LLM routing
#   - Intro/Mate -> OpenAI
#   - Mature -> xAI
# ----------------------------

def _xai_base_url() -> str:
    """Return a normalized base_url for xAI OpenAI-compatible endpoint."""
    raw = (os.getenv("XAI_BASE_URL", "") or os.getenv("XAI_API_BASE", "") or "https://api.x.ai/v1").strip()
    if not raw:
        return "https://api.x.ai/v1"
    url = raw.rstrip("/")
    # Accept either "https://api.x.ai" or "https://api.x.ai/v1"
    if url.endswith("/v1"):
        return url
    # If someone sets just https://api.x.ai, append /v1
    if url.endswith("api.x.ai"):
        return url + "/v1"
    return url


def _call_xai_chat(messages: List[Dict[str, Any]]) -> str:
    """Call xAI (OpenAI-compatible) chat completions endpoint."""
    client = _get_xai_client()

    stream_env = (os.getenv("XAI_STREAM", "1") or "1").strip().lower()
    use_stream = stream_env not in ("0", "false", "no", "off")

    return _chat_completion_text(
        client,
        model=(os.getenv("XAI_MODEL", "") or "grok-4").strip(),
        messages=messages,
        temperature=float(os.getenv("XAI_TEMPERATURE", os.getenv("OPENAI_TEMPERATURE", "0.8")) or "0.8"),
        stream=use_stream,
    )


def _extract_in_session_summaries(session_state: Dict[str, Any]) -> List[str]:
    """Extract any in-session summaries provided by the frontend/state machine.

    This function is intentionally permissive about key names to support gradual rollout.
    """
    if not isinstance(session_state, dict):
        return []

    keys = [
        "conversation_summaries",
        "conversationSummaries",
        "chat_summaries",
        "chatSummaries",
        "summaries",
        "summary_chunks",
        "summaryChunks",
    ]

    out: List[str] = []
    for k in keys:
        v = session_state.get(k)
        if not v:
            continue

        if isinstance(v, str):
            s = v.strip()
            if s:
                out.append(s)
            continue

        if isinstance(v, dict):
            s = v.get("summary") or v.get("text") or v.get("content")
            if isinstance(s, str) and s.strip():
                out.append(s.strip())
            continue

        if isinstance(v, list):
            for item in v:
                if isinstance(item, str):
                    s = item.strip()
                    if s:
                        out.append(s)
                elif isinstance(item, dict):
                    s = item.get("summary") or item.get("text") or item.get("content")
                    if isinstance(s, str) and s.strip():
                        out.append(s.strip())

    # De-dupe while preserving order (most recent items are typically appended last)
    seen: Set[str] = set()
    deduped: List[str] = []
    for s in out:
        if s in seen:
            continue
        seen.add(s)
        deduped.append(s)

    max_items = int(os.getenv("IN_SESSION_SUMMARY_MAX_ITEMS", "8") or "8")
    if max_items > 0 and len(deduped) > max_items:
        deduped = deduped[-max_items:]
    return deduped


def _sanitize_summary_for_safe_mode(text: str) -> str:
    """Sanitize a summary for Intro/Mate (OpenAI) context.

    If the summary appears intimate/explicit, replace it with a high-level, non-explicit note.
    """
    t = (text or "").strip()
    if not t:
        return ""
    if _looks_intimate(t):
        return (
            "Earlier conversation included a Mature segment with consent. "
            "Details are intentionally omitted in Intro/Mate mode."
        )

    max_chars = int(os.getenv("SAFE_MODE_SUMMARY_MAX_CHARS", "2500") or "2500")
    if max_chars > 0 and len(t) > max_chars:
        t = t[:max_chars] + " …"
    return t


_PLATFORM_CONTENT_URL_RE = re.compile(r'https?://[^\s"\'<>]+?/content/[^\s"\'<>]+', re.IGNORECASE)
_PLATFORM_ATTACHMENT_BLOCK_RE = re.compile(
    r'(?:^|\n)\s*Attachment:\s*[^\n]*\n\s*(?:https?://[^\s"\'<>]+?/content/[^\s"\'<>]+|/content/[^\s"\'<>]+)',
    re.IGNORECASE,
)
_PLATFORM_DELIVERY_LINE_RE = re.compile(
    r'(?im)^\s*Delivering\s+(?:Photo|Video|content|scheduled\s+content)[^\n]*$'
)
_PLATFORM_FILENAME_IN_TEXT_RE = re.compile(
    r'(?im)(?:^|\n)\s*(?:Attachment|File(?:\s+name)?)\s*:\s*([^\n]+)$'
)
_PLATFORM_INLINE_FILENAME_RE = re.compile(
    r'(?i)\bFile(?:\s+name)?\s*:\s*([^\n]+)'
)
_PLATFORM_GENERIC_PLACEHOLDER_RE = re.compile(
    r'(?i)^\s*Scheduled content was delivered by the platform\.?\s*$'
)
_PLATFORM_PLACEHOLDER_WITH_FILENAME_RE = re.compile(
    r'(?i)^\s*Scheduled content was delivered by the platform\s*:\s*([^\n]+?)\s*\.?\s*$'
)


def _platform_content_placeholder(file_name: str = "") -> str:
    name = str(file_name or "").strip()
    return f"Scheduled content was delivered by the platform: {name}." if name else "Scheduled content was delivered by the platform."


def _normalize_platform_filename_candidate(value: str) -> str:
    candidate = str(value or "").strip().strip("\"'")
    if not candidate:
        return ""
    candidate = re.split(r'\s+https?://', candidate, maxsplit=1)[0].strip()
    candidate = candidate.rstrip(".,;:!?").strip()
    return candidate


def _platform_content_filename_from_text(text: str) -> str:
    raw = str(text or "")
    if not raw:
        return ""

    placeholder_match = _PLATFORM_PLACEHOLDER_WITH_FILENAME_RE.match(raw.strip())
    if placeholder_match:
        candidate = _normalize_platform_filename_candidate(placeholder_match.group(1) or "")
        if candidate:
            return candidate

    for match in _PLATFORM_FILENAME_IN_TEXT_RE.finditer(raw):
        candidate = _normalize_platform_filename_candidate(match.group(1) or "")
        if candidate:
            return candidate

    inline_match = _PLATFORM_INLINE_FILENAME_RE.search(raw)
    if inline_match:
        candidate = _normalize_platform_filename_candidate(inline_match.group(1) or "")
        if candidate:
            return candidate

    return ""


def _sanitize_platform_content_text(text: str) -> Tuple[str, bool]:
    """Remove platform-scheduled attachment details from LLM-visible text."""
    raw = str(text or "")
    if not raw:
        return "", False

    t = raw.replace("\r\n", "\n").replace("\r", "\n")
    original = t

    t = _PLATFORM_ATTACHMENT_BLOCK_RE.sub("\n", t)
    t = _PLATFORM_CONTENT_URL_RE.sub("[platform content link removed]", t)
    t = _PLATFORM_DELIVERY_LINE_RE.sub("", t)
    t = re.sub(r'(?im)^\s*\[platform content link removed\]\s*$', "", t)
    t = re.sub(r'\n{3,}', "\n\n", t).strip()

    return t, (t != original.strip())


def _platform_content_message_is_generic(text: str) -> bool:
    return bool(_PLATFORM_GENERIC_PLACEHOLDER_RE.match(str(text or "").strip()))


def _extract_platform_content_filenames(messages: List[Dict[str, str]]) -> List[str]:
    out: List[str] = []
    seen: Set[str] = set()
    for item in messages or []:
        if str(item.get("role") or "").strip().lower() != "assistant":
            continue
        name = _platform_content_filename_from_text(str(item.get("content") or ""))
        if not name:
            continue
        key = name.lower()
        if key in seen:
            continue
        seen.add(key)
        out.append(name)
    return out


def _repair_generated_summary_for_platform_content(summary: str, platform_filenames: List[str]) -> str:
    text = str(summary or "").strip()
    if not text:
        return text
    if not _platform_content_message_is_generic(text):
        return text
    if not platform_filenames:
        return text
    unique_files = [str(x or "").strip() for x in platform_filenames if str(x or "").strip()]
    if not unique_files:
        return text
    if len(unique_files) == 1:
        return _platform_content_placeholder(unique_files[0])
    return "Scheduled content was delivered by the platform: " + ", ".join(unique_files) + "."


def _coerce_platform_content_filename_list(value: Any) -> List[str]:
    out: List[str] = []
    seen: Set[str] = set()

    def _push(item: Any) -> None:
        candidate = _normalize_platform_filename_candidate(str(item or ""))
        if not candidate:
            return
        key = candidate.lower()
        if key in seen:
            return
        seen.add(key)
        out.append(candidate)

    if value is None:
        return out

    if isinstance(value, dict):
        for key in ("files", "file_names", "fileNames", "names", "items"):
            if key in value:
                return _coerce_platform_content_filename_list(value.get(key))
        return out

    if isinstance(value, (list, tuple, set)):
        for item in value:
            _push(item)
        return out

    if isinstance(value, str):
        raw = value.strip()
        if not raw:
            return out
        if raw.startswith("[") and raw.endswith("]"):
            try:
                parsed = json.loads(raw)
            except Exception:
                parsed = None
            if isinstance(parsed, list):
                for item in parsed:
                    _push(item)
                return out
        _push(raw)
        return out

    _push(value)
    return out


def _merge_platform_content_filename_lists(*values: Any) -> List[str]:
    out: List[str] = []
    seen: Set[str] = set()
    for value in values:
        for name in _coerce_platform_content_filename_list(value):
            key = name.lower()
            if key in seen:
                continue
            seen.add(key)
            out.append(name)
    return out


def _summary_mentions_platform_content_filename(summary: str, file_name: str) -> bool:
    body = str(summary or "").lower()
    target = _normalize_platform_filename_candidate(file_name).lower()
    return bool(target) and (target in body)


def _append_platform_content_note_to_summary(summary: str, platform_filenames: List[str]) -> str:
    text = str(summary or "").strip()
    unique_files = _merge_platform_content_filename_lists(platform_filenames)
    if not unique_files:
        return text

    missing_files = [name for name in unique_files if not _summary_mentions_platform_content_filename(text, name)]
    if not missing_files:
        return text

    note = f"Delivered content this session: {', '.join(missing_files)}."
    if not text:
        return note
    return f"{text}\n\n{note}".strip()


_USER_ATTACHMENT_BLOCK_RE = re.compile(
    r'(?is)(?:^|\n)\s*Attachment:\s*([^\n]*)\n\s*(https?://[^\s"\'<>]+)'
)
_IMAGE_ATTACHMENT_EXTS = {
    '.png', '.jpg', '.jpeg', '.gif', '.webp', '.bmp', '.tif', '.tiff', '.avif', '.heic', '.heif'
}


def _attachment_file_ext(value: str) -> str:
    raw = str(value or '').strip()
    if not raw:
        return ''
    try:
        parsed = urlparse(raw)
        path = parsed.path or raw
    except Exception:
        path = raw.split('?', 1)[0].split('#', 1)[0]
    base = str(path or '').rsplit('/', 1)[-1]
    if '.' not in base:
        return ''
    return '.' + base.rsplit('.', 1)[-1].lower()


def _attachment_looks_like_image(name: str, url: str) -> bool:
    for candidate in (name, url):
        ext = _attachment_file_ext(candidate)
        if ext and ext in _IMAGE_ATTACHMENT_EXTS:
            return True
    return False


def _extract_user_attachments_from_text(content: str) -> Tuple[str, List[Dict[str, str]]]:
    raw = str(content or '')
    if not raw:
        return '', []

    attachments: List[Dict[str, str]] = []

    def _repl(match) -> str:
        name = str(match.group(1) or '').strip()
        url = str(match.group(2) or '').strip()
        if url:
            attachments.append({'name': name, 'url': url})
        return '\n'

    cleaned = _USER_ATTACHMENT_BLOCK_RE.sub(_repl, raw.replace('\r\n', '\n').replace('\r', '\n'))
    cleaned = re.sub(r'\n{3,}', '\n\n', cleaned).strip()
    return cleaned, attachments


def _user_message_content_for_llm(content: str) -> Any:
    """Convert serialized user attachment text into multimodal message parts when possible.

    Frontend messages are serialized like:
      Sent an attachment.

      Attachment: photo.jpg
      https://.../photo.jpg?...

    For image attachments, we transform that into Chat Completions content parts so the
    model can actually inspect the image instead of only seeing a URL as plain text.
    """
    original = str(content or '').strip()
    cleaned_text, attachments = _extract_user_attachments_from_text(original)
    if not attachments:
        return original

    image_parts: List[Dict[str, Any]] = []
    non_image_notes: List[str] = []

    for att in attachments:
        name = str(att.get('name') or '').strip()
        url = str(att.get('url') or '').strip()
        if not url:
            continue
        if _attachment_looks_like_image(name, url):
            image_parts.append({'type': 'image_url', 'image_url': {'url': url}})
        else:
            label = name or (urlparse(url).path.rsplit('/', 1)[-1] if url else '') or 'attachment'
            non_image_notes.append(f'Attachment provided: {label}.')

    if not image_parts:
        return original

    text_chunks: List[str] = []
    if cleaned_text:
        text_chunks.append(cleaned_text)
    if non_image_notes:
        text_chunks.append('\n'.join(non_image_notes))

    merged_text = '\n\n'.join([chunk for chunk in text_chunks if chunk]).strip() or 'Please analyze the attached image.'
    parts: List[Dict[str, Any]] = [{'type': 'text', 'text': merged_text}]
    parts.extend(image_parts)
    return parts


def _sanitize_message_content_for_llm(role: str, content: str) -> str:
    role_norm = str(role or "").strip().lower()
    raw = str(content or "").strip()

    if role_norm == "assistant":
        if _platform_content_message_is_generic(raw):
            return ""
        placeholder_name = _platform_content_filename_from_text(raw)
        if placeholder_name and _PLATFORM_PLACEHOLDER_WITH_FILENAME_RE.match(raw):
            return _platform_content_placeholder(placeholder_name)

    cleaned, removed = _sanitize_platform_content_text(content)
    if removed and role_norm == "assistant":
        lowered = str(content or "").lower()
        if (
            "attachment:" in lowered
            or "/content/" in lowered
            or "delivering photo" in lowered
            or "delivering video" in lowered
            or "delivering scheduled content" in lowered
        ) and not cleaned:
            file_name = _platform_content_filename_from_text(content)
            return _platform_content_placeholder(file_name) if file_name else ""
    return cleaned or raw


def _sanitize_history_for_platform_content(messages: List[Dict[str, str]]) -> List[Dict[str, str]]:
    out: List[Dict[str, str]] = []
    for m in messages or []:
        role = str(m.get("role") or "").strip()
        if role not in ("user", "assistant"):
            continue
        content = _sanitize_message_content_for_llm(role, str(m.get("content") or ""))
        if not content and role == "assistant":
            continue
        out.append({"role": role, "content": content})
    return out


def _sanitize_summary_for_platform_content(text: str) -> str:
    raw = str(text or "").strip()
    if not raw:
        return ""
    if _platform_content_message_is_generic(raw):
        return ""
    file_name = _platform_content_filename_from_text(raw)
    if file_name and _PLATFORM_PLACEHOLDER_WITH_FILENAME_RE.match(raw):
        return _platform_content_placeholder(file_name)
    cleaned, removed = _sanitize_platform_content_text(raw)
    if removed and not cleaned:
        return _platform_content_placeholder(file_name) if file_name else ""
    return cleaned or raw


def _sanitize_assistant_reply_for_platform_content(text: str) -> str:
    cleaned, removed = _sanitize_platform_content_text(text)
    if not removed:
        return str(text or "").strip()
    cleaned = cleaned.strip()
    if not cleaned or len(cleaned) < 24 or cleaned.endswith(":"):
        return "I can only share photos or videos when the platform delivers scheduled content that actually exists in the active library."
    return cleaned


def _llm_message_content_has_image_input(content: Any) -> bool:
    if not isinstance(content, list):
        return False
    for part in content:
        if not isinstance(part, dict):
            continue
        part_type = str(part.get("type") or "").strip().lower()
        if part_type != "image_url":
            continue
        image_obj = part.get("image_url")
        if isinstance(image_obj, dict):
            if str(image_obj.get("url") or "").strip():
                return True
        else:
            return True
    return False


def _llm_messages_have_user_image_input(messages: List[Dict[str, Any]]) -> bool:
    for m in messages or []:
        if str(m.get("role") or "").strip().lower() != "user":
            continue
        try:
            if _llm_message_content_has_image_input(m.get("content")):
                return True
        except Exception:
            continue
    return False


def _sanitize_assistant_reply_for_image_policy(text: str, *, had_image_input: bool) -> str:
    raw = str(text or "").strip()
    if not raw or not had_image_input:
        return raw

    rewrite_patterns = [
        r"^\s*i(?:\s*am|'m)?\s+(?:not\s+able|unable)\s+to\s+identify\s+or\s+provide\s+information\s+about\s+individuals?\s+in\s+photos?\.\s*",
        r"^\s*i\s+can(?:not|'t|’t)\s+identify\s+or\s+provide\s+information\s+about\s+individuals?\s+in\s+photos?\.\s*",
        r"^\s*i(?:\s*am|'m)?\s+(?:not\s+able|unable)\s+to\s+provide\s+information\s+about\s+individuals?\s+in\s+photos?\.\s*",
        r"^\s*i\s+can(?:not|'t|’t)\s+provide\s+information\s+about\s+individuals?\s+in\s+photos?\.\s*",
        r"^\s*i(?:\s*am|'m)?\s+(?:not\s+able|unable)\s+to\s+view\s+attachments?\s+directly[,\.]?\s*",
        r"^\s*i\s+can(?:not|'t|’t)\s+view\s+attachments?\s+directly[,\.]?\s*",
    ]

    prefix = (
        "I can't identify a real person in a photo or infer private details about them, "
        "but I can describe visible, non-identifying details from the image."
    )

    for pattern in rewrite_patterns:
        m = re.match(pattern, raw, flags=re.IGNORECASE)
        if not m:
            continue
        tail = raw[m.end():].strip()
        tail = re.sub(r"^(however|but)\s*,?\s*", "", tail, flags=re.IGNORECASE)
        return (prefix + (" " + tail if tail else "")).strip()

    return raw


def _filter_history_for_safe_mode(messages: List[Dict[str, str]]) -> Tuple[List[Dict[str, str]], Optional[str]]:
    """Filter out intimate/explicit messages before sending to a safe-mode model (OpenAI).

    Returns (filtered_messages, handoff_note).
    """
    if not messages:
        return messages, None

    kept: List[Dict[str, str]] = []
    omitted = 0

    for m in messages:
        role = m.get("role")
        if role not in ("user", "assistant"):
            continue
        content = str(m.get("content") or "")
        if _looks_intimate(content):
            omitted += 1
            continue
        kept.append({"role": role, "content": content})

    if omitted <= 0:
        return messages, None

    note = (
        f"Context note: {omitted} earlier message(s) from a Mature segment were omitted because the current mode is Intro/Mate. "
        "Assume consent had been established and an intimate conversation occurred, but do not reference explicit details. "
        "Continue naturally from the remaining chat context and any provided summaries."
    )
    return kept, note


def _clamp_text(text: str, max_chars: int) -> str:
    if max_chars <= 0:
        return str(text or "")
    t = str(text or "")
    if len(t) <= max_chars:
        return t
    if max_chars <= 1:
        return "…"
    return t[: max_chars - 1] + "…"


def _compact_llm_messages(messages: List[Dict[str, Any]], *, provider_switched: bool) -> List[Dict[str, Any]]:
    """Server-side guardrail to keep prompts bounded.

    Frontend already trims history, but this prevents occasional oversized requests
    (attachments, long copy/paste, etc.) from regressing latency.

    Rules:
      - Keep the leading contiguous system block prefix intact.
      - Keep only the last N non-system messages (N smaller on provider switch).
      - Clamp individual text content length while preserving image parts.
    """
    if not messages:
        return messages

    max_body = int(os.getenv("LLM_MAX_BODY_MESSAGES", "34") or "34")
    max_body_on_switch = int(os.getenv("LLM_MAX_BODY_MESSAGES_ON_SWITCH", "22") or "22")
    max_chars = int(os.getenv("LLM_MESSAGE_MAX_CHARS", "4000") or "4000")

    n_keep = max_body_on_switch if provider_switched else max_body
    if n_keep <= 0:
        n_keep = 12

    # Split contiguous system prefix (persona + injected system blocks).
    i = 0
    while i < len(messages) and str(messages[i].get("role") or "") == "system":
        i += 1
    sys_prefix = messages[:i]
    body = messages[i:]

    def _clamp_content(content: Any) -> Any:
        if isinstance(content, str):
            return _clamp_text(content, max_chars)
        if isinstance(content, list):
            out_parts: List[Any] = []
            for part in content:
                if isinstance(part, dict):
                    p = dict(part)
                    p_type = str(p.get("type") or "").strip().lower()
                    if p_type in ("text", "input_text") and isinstance(p.get("text"), str):
                        p["text"] = _clamp_text(str(p.get("text") or ""), max_chars)
                    out_parts.append(p)
                else:
                    out_parts.append(part)
            return out_parts
        return content

    # Clamp content.
    def clamp_msg(m: Dict[str, Any]) -> Dict[str, Any]:
        role = str(m.get("role") or "")
        return {"role": role, "content": _clamp_content(m.get("content"))}

    sys_prefix = [clamp_msg(m) for m in sys_prefix]
    body = [clamp_msg(m) for m in body]

    if len(body) > n_keep:
        body = body[-n_keep:]

    return sys_prefix + body

def _call_gpt4o_summary(messages: List[Dict[str, str]]) -> str:
    """Summarization call with conservative limits for reliability."""
    timeout_s = float(os.getenv("SAVE_SUMMARY_OPENAI_TIMEOUT_S", "25") or "25")
    client = _get_openai_summary_client(timeout_s)

    return _chat_completion_text(
        client,
        model=os.getenv("OPENAI_MODEL", "gpt-4o"),
        messages=messages,
        temperature=float(os.getenv("SAVE_SUMMARY_TEMPERATURE", "0.2") or "0.2"),
        max_tokens=int(os.getenv("SAVE_SUMMARY_MAX_TOKENS", "350") or "350"),
        stream=False,
    )


