@app.post("/host/session-insights/ask")
async def host_session_insights_ask(req: HostSessionInsightsAskRequest):
    host_id = _require_host_member(req.brand, req.avatar, req.memberId)

    question = (req.question or "").strip()
    if not question:
        raise HTTPException(status_code=400, detail="question is required")

    target_member = (req.targetMemberId or "").strip()
    companion_label = (req.avatar or "").strip() or "your AI Companion"

    # Gather context.
    if target_member:
        summaries = await run_in_threadpool(
            _host_insights_list_summaries_sync,
            req.brand,
            req.avatar,
            target_member,
            max(10, min(int(req.limit or 60), 120)),
        )
        context = {
            "scope": "single_member",
            "target_member_id": target_member,
            "summaries": summaries,
        }
    else:
        users = await run_in_threadpool(
            _host_insights_list_users_sync,
            req.brand,
            req.avatar,
            max(10, min(int(req.limit or 80), 200)),
        )
        # Provide a light-weight overview (last summary per member) to keep tokens down.
        context = {
            "scope": "all_members_overview",
            "members": users,
        }

    system = (
        f"You are {companion_label}, the AI Companion. You are helping the HOST review historical session summaries. "
        "You will be given a JSON object containing saved session summaries. "
        "Answer the host's question using ONLY the provided summaries. "
        "Use only the customer-facing mode labels Intro, Mate, and Mature. "
        "Never use Friend mode, Romantic mode, Romance mode, Intimate mode, Explicit mode, or Adult mode in host-facing answers. "
        "If the summaries do not contain enough information, say so clearly. "
        "If asked to list members/visitors, produce a clean bullet list. "
        "Do not fabricate names, details, or events that are not in the summaries."
    )

    user_msg = {
        "question": question,
        "data": context,
    }

    try:
        answer = await run_in_threadpool(
            _call_gpt4o_with_options,
            [
                {"role": "system", "content": system},
                {"role": "user", "content": json.dumps(user_msg, ensure_ascii=False)},
            ],
            temperature=0.2,
            max_tokens=700,
        )
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Failed to answer: {type(e).__name__}: {e}")

    return {"ok": True, "hostMemberId": host_id, "answer": _sanitize_public_mode_labels_text(answer)} 



@app.post("/chat/relay/poll")
async def chat_relay_poll(req: ChatRelayPollRequest):
    _perf_stage("relay.poll.start")
    sid = (req.session_id or "").strip()
    if not sid:
        raise HTTPException(status_code=400, detail="session_id is required")

    rec = _ai_override_get_session(sid) or {}
    if not isinstance(rec, dict):
        return {"ok": True, "session_id": sid, "events": [], "next_since_seq": int(req.since_seq or 0), "override_active": False}

    # Soft identity check: only enforce when both sides present.
    try:
        caller_member = _extract_member_id(req.session_state or {}) or ""
        stored_member = str(rec.get("member_id") or "").strip()
        if stored_member and caller_member and stored_member != caller_member:
            raise HTTPException(status_code=403, detail="Session access denied")
    except HTTPException:
        raise
    except Exception:
        pass

    polled = _ai_override_poll(
        sid,
        since_seq=int(req.since_seq or 0),
        audience="user",
        mark_host_read=False,
    )

    # Member only needs out-of-band messages:
    #   - host replies
    #   - system notices (override on/off, paywalls, etc.)
    events = polled.get("events") or []
    filtered: List[Dict[str, Any]] = []
    for ev in events:
        if not isinstance(ev, dict):
            continue
        sender = str(ev.get("sender") or "").strip()
        kind = str(ev.get("kind") or "").strip()
        if sender in ("host", "system"):
            filtered.append(ev)
            continue
        if kind in ("override_on", "override_off", "paywall", "minutes_exhausted"):
            filtered.append(ev)

    polled["events"] = filtered
    polled["ok"] = True
    polled["session_id"] = sid
    return polled


# ============================
# v7.21 - Minutes consistency hardening (SQLite-backed state)
# ============================
# Goal:
#  - Persist minute budgeting and cycle state per member_id (including non-member ids)
#  - Prevent regressions where "remaining > total" or totals drift due to repeated parsing
#  - Apply free_minutes from rebrandingKey ONLY once per cycle per member (or when plan upgrades)
#  - PayGo purchases ALWAYS increase total time (purchased seconds) and are tracked with update_reason

import os
import time
import sqlite3
import tempfile
import threading
from typing import Optional, Dict, Any, Tuple

_USAGE_DB_LOCK = threading.Lock()
_USAGE_DB_READY = False

# Legacy standalone usage_minutes.sqlite3 (migration source only)
_LEGACY_USAGE_DB_PATH = (os.getenv("USAGE_SQLITE_PATH") or os.getenv("USAGE_DB_PATH") or "").strip()
if not _LEGACY_USAGE_DB_PATH:
    _base = "/home/site" if os.path.isdir("/home/site") else "/home"
    # Accept both spellings to be resilient to historical typos
    cand1 = os.path.join(_base, "usage_minutes.sqlite3")
    cand2 = os.path.join(_base, "usage_minutes.sqllite3")
    if os.path.exists(cand1):
        _LEGACY_USAGE_DB_PATH = cand1
    elif os.path.exists(cand2):
        _LEGACY_USAGE_DB_PATH = cand2
    else:
        _LEGACY_USAGE_DB_PATH = cand1

def _usage_db_path() -> str:
    """Returns the unified SQLite path for usage state (econnect.sqlite3).

    The usage/minutes subsystem no longer writes to a standalone usage_minutes.sqlite3.
    _LEGACY_USAGE_DB_PATH is retained only as a migration source.
    """
    return _ensure_econnect_db_seeded()


def _normalize_usage_member_id(identity_key: str) -> str:
    """Normalize an identity key into the member_id value stored in SQLite.

    Notes:
    - Legacy identity keys may look like: "member::<uuid>".
    - Non-member identities may include values like "Anon:<...>" or "ip::<addr>".
    - We intentionally keep non-member prefixes (e.g., "Anon:") so identities remain stable.
    """
    k = str(identity_key or "").strip()
    if not k:
        return ""
    low = k.lower()
    if low.startswith("member::"):
        return k.split("::", 1)[1].strip()
    return k




# ---------------- Scheduled content delivery (media milestones) ----------------

_CONTENT_DB_LOCK = threading.Lock()
_CONTENT_DB_READY = False
_CONTENT_WINDOW_SECONDS = 24 * 60 * 60
_CONTENT_TRIGGER_START_MINUTE = 9
_CONTENT_TRIGGER_STEP_MINUTES = 10
_CONTENT_FRIEND_FIRST_TURN_TRIGGER_MINUTE = 1
_CONTENT_FRIEND_FIRST_TURN_COOLDOWN_SECONDS = 24 * 60 * 60
_CONTENT_FRIEND_FIRST_TURN_DELIVERED_VIA = "friend_first_turn_daily"


def _safe_slug(s: str) -> str:
    s = str(s or "").strip().lower()
    if not s:
        return ""
    # allow a-z, 0-9, underscore, dash. Everything else becomes '-'
    s = re.sub(r"[^a-z0-9_-]+", "-", s)
    s = re.sub(r"^-+", "", s)
    s = re.sub(r"-+$", "", s)
    return s or ""


def _content_brand_slug(session_state: Dict[str, Any]) -> str:
    # Prefer explicit slugs if present.
    for k in (
        "brandKey",
        "brand_key",
        "rebrandingSlug",
        "rebranding_slug",
        "companySlug",
        "company_slug",
    ):
        v = session_state.get(k)
        if v:
            slug = _safe_slug(v)
            if slug:
                return slug

    # Next, parse rebrandingKey (frontend format: BrandName|...)
    rk = _extract_rebranding_key(session_state)
    if rk:
        first = _normalize_rebranding_key_value(str(rk).split("|", 1)[0])
        slug = _safe_slug(first)
        if slug:
            return slug

    # Fallback to normalized brand identity. When an explicit empty RebrandingKey is present,
    # _brand_from_session_state returns "", which keeps us on the core/placeholder path instead
    # of resurrecting a stale legacy brand field.
    return _safe_slug(_brand_from_session_state(session_state) or "") or "brand"


def _content_folder_for_mode(mode: str) -> str:
    m = str(mode or "").strip().lower()
    if "intimate" in m:
        return "intimate"
    if "romantic" in m:
        return "romantic"
    return "friend"


def _content_resolve_folder(brand_slug: str, mode: str) -> str:
    """Resolve the on-disk content folder for a given mode.

    We accept `brand_slug` for future brand-specific overrides, but today all brands
    share the same disk layout: /home/site/brand/<brand>/content/mode/<mode>/.
    """

    _ = brand_slug  # reserved for future per-brand routing
    return _content_folder_for_mode(mode)


def _content_db_connect() -> sqlite3.Connection:
    # Content state is stored in the unified econnect.sqlite3
    return _econnect_conn()


def _content_table_exists(conn: sqlite3.Connection, table_name: str) -> bool:
    try:
        row = conn.execute(
            "SELECT 1 FROM sqlite_master WHERE type='table' AND name=? LIMIT 1",
            (str(table_name or "").strip(),),
        ).fetchone()
        return row is not None
    except Exception:
        return False


def _content_table_columns(conn: sqlite3.Connection, table_name: str) -> Set[str]:
    if not _content_table_exists(conn, table_name):
        return set()
    try:
        rows = conn.execute(f"PRAGMA table_info({table_name})").fetchall()
    except Exception:
        return set()
    cols: Set[str] = set()
    for row in rows:
        name = None
        try:
            if isinstance(row, sqlite3.Row):
                name = row["name"]
            elif len(row) > 1:
                name = row[1]
        except Exception:
            name = None
        if name:
            cols.add(str(name).strip())
    return cols


def _content_ensure_column(conn: sqlite3.Connection, table_name: str, column_name: str, column_sql: str) -> None:
    cols = _content_table_columns(conn, table_name)
    if str(column_name or "").strip() in cols:
        return
    conn.execute(f"ALTER TABLE {table_name} ADD COLUMN {column_sql}")


def _content_ensure_state_schema(conn: sqlite3.Connection) -> None:
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS user_content_state (
          member_id TEXT NOT NULL,
          content_folder TEXT NOT NULL,
          window_start_epoch REAL,
          window_cycle_id TEXT,
          window_base_used_seconds REAL,
          window_sent_count INTEGER DEFAULT 0,
          window_complete INTEGER DEFAULT 0,
          last_sequence TEXT,
          last_stage TEXT,
          last_trigger_minute INTEGER,
          pending_token TEXT,
          pending_trigger_minute INTEGER,
          pending_file_name TEXT,
          pending_sequence TEXT,
          pending_stage TEXT,
          pending_kind TEXT,
          pending_created_epoch REAL,
          updated_epoch REAL,
          PRIMARY KEY (member_id, content_folder)
        );
        """
    )
    for name, coldef in [
        ("window_start_epoch", "window_start_epoch REAL"),
        ("window_cycle_id", "window_cycle_id TEXT"),
        ("window_base_used_seconds", "window_base_used_seconds REAL"),
        ("window_sent_count", "window_sent_count INTEGER DEFAULT 0"),
        ("window_complete", "window_complete INTEGER DEFAULT 0"),
        ("last_sequence", "last_sequence TEXT"),
        ("last_stage", "last_stage TEXT"),
        ("last_trigger_minute", "last_trigger_minute INTEGER"),
        ("pending_token", "pending_token TEXT"),
        ("pending_trigger_minute", "pending_trigger_minute INTEGER"),
        ("pending_file_name", "pending_file_name TEXT"),
        ("pending_sequence", "pending_sequence TEXT"),
        ("pending_stage", "pending_stage TEXT"),
        ("pending_kind", "pending_kind TEXT"),
        ("pending_created_epoch", "pending_created_epoch REAL"),
        ("updated_epoch", "updated_epoch REAL"),
    ]:
        _content_ensure_column(conn, "user_content_state", name, coldef)


def _content_ensure_history_schema(conn: sqlite3.Connection) -> None:
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS user_content_history (
          user_content_history_id INTEGER PRIMARY KEY AUTOINCREMENT,
          create_datetime datetime DEFAULT CURRENT_TIMESTAMP,
          user_type VARCHAR(25),
          member_id TEXT NOT NULL,
          content_folder TEXT NOT NULL,
          content_name TEXT,
          content_sequence TEXT,
          token TEXT,
          trigger_minute INTEGER,
          content_type TEXT,
          content_stage TEXT,
          content_url TEXT,
          delivered_via TEXT
        );
        """
    )
    for name, coldef in [
        ("create_datetime", "create_datetime TEXT"),
        ("user_type", "user_type VARCHAR(25)"),
        ("member_id", "member_id TEXT"),
        ("content_folder", "content_folder TEXT"),
        ("content_name", "content_name TEXT"),
        ("content_sequence", "content_sequence TEXT"),
        ("token", "token TEXT"),
        ("trigger_minute", "trigger_minute INTEGER"),
        ("content_type", "content_type TEXT"),
        ("content_stage", "content_stage TEXT"),
        ("content_url", "content_url TEXT"),
        ("delivered_via", "delivered_via TEXT"),
    ]:
        _content_ensure_column(conn, "user_content_history", name, coldef)

    conn.execute(
        """
        CREATE UNIQUE INDEX IF NOT EXISTS idx_user_content_history_token
        ON user_content_history(token)
        WHERE token IS NOT NULL AND TRIM(token) <> '';
        """
    )
    conn.execute(
        """
        CREATE INDEX IF NOT EXISTS idx_user_content_history_member
        ON user_content_history(member_id, content_folder, create_datetime);
        """
    )
    conn.execute(
        """
        CREATE INDEX IF NOT EXISTS idx_user_content_history_member_sequence
        ON user_content_history(member_id, content_folder, content_sequence);
        """
    )


def _content_ensure_claims_schema(conn: sqlite3.Connection) -> None:
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS user_content_claims (
          token TEXT PRIMARY KEY,
          member_id TEXT NOT NULL,
          content_folder TEXT NOT NULL,
          cycle_id TEXT NOT NULL,
          trigger_minute INTEGER NOT NULL,
          content_sequence TEXT,
          content_name TEXT,
          content_kind TEXT,
          content_stage TEXT,
          content_url TEXT,
          claim_state TEXT NOT NULL,
          claimed_via TEXT,
          session_id TEXT,
          created_epoch REAL,
          updated_epoch REAL,
          delivered_epoch REAL,
          UNIQUE(member_id, content_folder, cycle_id, trigger_minute)
        );
        """
    )
    for name, coldef in [
        ("member_id", "member_id TEXT"),
        ("content_folder", "content_folder TEXT"),
        ("cycle_id", "cycle_id TEXT"),
        ("trigger_minute", "trigger_minute INTEGER"),
        ("content_sequence", "content_sequence TEXT"),
        ("content_name", "content_name TEXT"),
        ("content_kind", "content_kind TEXT"),
        ("content_stage", "content_stage TEXT"),
        ("content_url", "content_url TEXT"),
        ("claim_state", "claim_state TEXT"),
        ("claimed_via", "claimed_via TEXT"),
        ("session_id", "session_id TEXT"),
        ("created_epoch", "created_epoch REAL"),
        ("updated_epoch", "updated_epoch REAL"),
        ("delivered_epoch", "delivered_epoch REAL"),
    ]:
        _content_ensure_column(conn, "user_content_claims", name, coldef)

    conn.execute(
        """
        CREATE INDEX IF NOT EXISTS idx_user_content_claims_member_cycle
        ON user_content_claims(member_id, content_folder, cycle_id, trigger_minute);
        """
    )
    conn.execute(
        """
        CREATE INDEX IF NOT EXISTS idx_user_content_claims_state
        ON user_content_claims(member_id, content_folder, cycle_id, claim_state, trigger_minute);
        """
    )


def _content_folder_allowed_for_member(member_key: str, folder: str, intimate_allowed: bool = False) -> bool:
    folder_slug = _safe_slug(folder)
    if folder_slug != "intimate":
        return True
    if _is_anon_member_id(member_key):
        return False
    return bool(intimate_allowed)


def _content_history_needs_rebuild(conn: sqlite3.Connection) -> bool:
    if not _content_table_exists(conn, "user_content_history"):
        return False
    try:
        row = conn.execute(
            "SELECT sql FROM sqlite_master WHERE type='table' AND name='user_content_history' LIMIT 1"
        ).fetchone()
        table_sql = str((row[0] if row else "") or "").lower()
    except Exception:
        table_sql = ""

    if table_sql and re.search(r"\bmember_id\b[^,)]*\bunique\b", table_sql):
        return True

    try:
        index_rows = conn.execute("PRAGMA index_list(user_content_history)").fetchall()
    except Exception:
        index_rows = []

    for index_row in index_rows:
        try:
            is_unique = int(index_row[2] or 0) == 1
            idx_name = str(index_row[1] or "").strip()
        except Exception:
            is_unique = False
            idx_name = ""
        if not is_unique or not idx_name:
            continue
        try:
            cols = [str(c[2] or "").strip().lower() for c in conn.execute(f"PRAGMA index_info({idx_name})").fetchall()]
        except Exception:
            cols = []
        if cols == ["member_id"]:
            return True
    return False


def _content_history_insert_with_create_datetime(
    conn: sqlite3.Connection,
    token: str,
    member_id: str,
    content_folder: str,
    trigger_minute: int,
    content_sequence: Any,
    content_name: str,
    content_type: str,
    content_stage: str,
    content_url: str,
    delivered_via: str,
    create_datetime: Optional[str] = None,
    user_type: Optional[str] = None,
) -> None:
    cols = _content_table_columns(conn, "user_content_history")
    if not cols:
        return

    try:
        trigger_minute_i = int(trigger_minute or 0)
    except Exception:
        trigger_minute_i = 0

    values: Dict[str, Any] = {
        "token": str(token or "").strip(),
        "member_id": str(member_id or "").strip(),
        "content_folder": str(content_folder or "").strip(),
        "trigger_minute": trigger_minute_i,
        "content_sequence": str(content_sequence or "").strip(),
        "content_name": str(content_name or "").strip(),
        "content_type": str(content_type or "").strip(),
        "content_stage": str(content_stage or "").strip(),
        "content_url": _content_normalize_url(
            _content_normalize_url(
                str(content_url or "").strip(),
                brand_slug=_content_infer_brand_slug_from_member_key(member_id),
                folder=str(content_folder or "").strip(),
                file_name=str(content_name or "").strip(),
            ),
            brand_slug=_content_infer_brand_slug_from_member_key(member_id),
            folder=str(content_folder or "").strip(),
            file_name=str(content_name or "").strip(),
        ),
        "delivered_via": str(delivered_via or "").strip(),
        "create_datetime": str(create_datetime or "").strip() or datetime.utcnow().strftime("%Y-%m-%d %H:%M:%S"),
        "user_type": str(user_type or "").strip() or None,
    }
    ordered = [name for name in [
        "token",
        "member_id",
        "content_folder",
        "trigger_minute",
        "content_sequence",
        "content_name",
        "content_type",
        "content_stage",
        "content_url",
        "delivered_via",
        "create_datetime",
        "user_type",
    ] if name in cols]
    if not ordered:
        return
    placeholders = ", ".join(["?"] * len(ordered))
    sql = f"INSERT OR IGNORE INTO user_content_history ({', '.join(ordered)}) VALUES ({placeholders})"
    conn.execute(sql, tuple(values[name] for name in ordered))


def _content_history_has_token(conn: sqlite3.Connection, token: str) -> bool:
    tok = str(token or "").strip()
    cols = _content_table_columns(conn, "user_content_history")
    if not tok or "token" not in cols:
        return False
    row = conn.execute(
        "SELECT 1 FROM user_content_history WHERE token=? LIMIT 1",
        (tok,),
    ).fetchone()
    return row is not None


def _content_epoch_to_datetime(epoch_value: Any) -> str:
    try:
        epoch_f = float(epoch_value or 0.0)
    except Exception:
        epoch_f = 0.0
    if epoch_f <= 0:
        return datetime.utcnow().strftime("%Y-%m-%d %H:%M:%S")
    return datetime.utcfromtimestamp(epoch_f).strftime("%Y-%m-%d %H:%M:%S")


def _content_history_backfill_from_claim(conn: sqlite3.Connection, claim: Dict[str, Any]) -> bool:
    if not claim or not _content_claim_is_delivered(claim):
        return False

    member_id = str(claim.get("member_id") or "").strip()
    content_folder = str(claim.get("content_folder") or "").strip()
    if _safe_slug(content_folder) == "intimate" and _is_anon_member_id(member_id):
        return False

    token = str(claim.get("token") or "").strip()
    if token and _content_history_has_token(conn, token):
        return False

    claim_state = str(claim.get("claim_state") or "").strip().lower()
    claimed_via = str(claim.get("claimed_via") or "").strip()
    delivered_via = claimed_via
    if not delivered_via:
        if claim_state == "delivered_host":
            delivered_via = "host_pending"
        elif claim_state == "delivered_history":
            delivered_via = "history_backfill"
        else:
            delivered_via = "auto"

    _content_history_insert_with_create_datetime(
        conn,
        token=token,
        member_id=member_id,
        content_folder=content_folder,
        trigger_minute=int(claim.get("trigger_minute") or 0),
        content_sequence=claim.get("content_sequence"),
        content_name=str(claim.get("content_name") or "").strip(),
        content_type=str(claim.get("content_kind") or "").strip(),
        content_stage=str(claim.get("content_stage") or "").strip(),
        content_url=str(claim.get("content_url") or "").strip(),
        delivered_via=delivered_via,
        create_datetime=_content_epoch_to_datetime(
            claim.get("delivered_epoch") or claim.get("updated_epoch") or claim.get("created_epoch")
        ),
        user_type="member",
    )
    return bool(token and _content_history_has_token(conn, token))


def _content_backfill_history_from_claims(
    conn: sqlite3.Connection,
    member_id: str = "",
    content_folder: str = "",
) -> int:
    if not _content_table_exists(conn, "user_content_claims"):
        return 0

    where = ["LOWER(COALESCE(claim_state, '')) IN ('delivered_user', 'delivered_host', 'delivered_history')"]
    params: List[Any] = []
    if str(member_id or "").strip():
        where.append("member_id = ?")
        params.append(str(member_id or "").strip())
    if str(content_folder or "").strip():
        where.append("content_folder = ?")
        params.append(str(content_folder or "").strip())

    sql = f"""
        SELECT *
        FROM user_content_claims
        WHERE {' AND '.join(where)}
        ORDER BY COALESCE(delivered_epoch, updated_epoch, created_epoch), trigger_minute, token
    """
    inserted = 0
    for row in conn.execute(sql, tuple(params)).fetchall():
        claim = dict(row)
        token = str(claim.get("token") or "").strip()
        if token and _content_history_has_token(conn, token):
            continue
        if _content_history_backfill_from_claim(conn, claim):
            inserted += 1
    return inserted


def _content_rebuild_history_schema(conn: sqlite3.Connection) -> bool:
    if not _content_table_exists(conn, "user_content_history"):
        _content_ensure_history_schema(conn)
        return False

    old_rows = conn.execute(
        "SELECT * FROM user_content_history ORDER BY COALESCE(create_datetime, ''), rowid"
    ).fetchall()

    conn.execute("DROP TABLE user_content_history")
    _content_ensure_history_schema(conn)

    for row in old_rows:
        payload = dict(row)
        _content_history_insert_with_create_datetime(
            conn,
            token=str(payload.get("token") or "").strip(),
            member_id=str(payload.get("member_id") or "").strip(),
            content_folder=str(payload.get("content_folder") or "").strip(),
            trigger_minute=int(payload.get("trigger_minute") or 0),
            content_sequence=payload.get("content_sequence"),
            content_name=str(payload.get("content_name") or "").strip(),
            content_type=str(payload.get("content_type") or "").strip(),
            content_stage=str(payload.get("content_stage") or "").strip(),
            content_url=str(payload.get("content_url") or "").strip(),
            delivered_via=str(payload.get("delivered_via") or "").strip(),
            create_datetime=str(payload.get("create_datetime") or "").strip(),
            user_type=str(payload.get("user_type") or "").strip() or None,
        )
    return True


def _content_purge_anon_intimate_rows(conn: sqlite3.Connection) -> None:
    for table in ("user_content_history", "user_content_claims", "user_content_state"):
        cols = _content_table_columns(conn, table)
        if not {"member_id", "content_folder"}.issubset(cols):
            continue
        conn.execute(
            f"DELETE FROM {table} WHERE lower(content_folder)=? AND instr(lower(member_id), 'anon:') > 0",
            ("intimate",),
        )


def _content_repair_history_schema_and_backfill(conn: sqlite3.Connection) -> None:
    if _content_history_needs_rebuild(conn):
        _content_rebuild_history_schema(conn)
    _content_purge_anon_intimate_rows(conn)
    _content_backfill_history_from_claims(conn)


def _content_db_ensure_schema(conn: sqlite3.Connection) -> None:
    global _CONTENT_DB_READY
    if _CONTENT_DB_READY:
        return
    with _CONTENT_DB_LOCK:
        if _CONTENT_DB_READY:
            return
        _content_ensure_state_schema(conn)
        _content_ensure_history_schema(conn)
        _content_ensure_claims_schema(conn)
        _content_repair_history_schema_and_backfill(conn)
        conn.commit()
        _CONTENT_DB_READY = True


def _content_history_insert(
    conn: sqlite3.Connection,
    token: str,
    member_id: str,
    content_folder: str,
    trigger_minute: int,
    content_sequence: Any,
    content_name: str,
    content_type: str,
    content_stage: str,
    content_url: str,
    delivered_via: str,
) -> None:
    _content_history_insert_with_create_datetime(
        conn,
        token=token,
        member_id=member_id,
        content_folder=content_folder,
        trigger_minute=trigger_minute,
        content_sequence=content_sequence,
        content_name=content_name,
        content_type=content_type,
        content_stage=content_stage,
        content_url=content_url,
        delivered_via=delivered_via,
    )


def _content_parse_filename(name: str) -> Dict[str, str]:
    """Parse branded content filenames.

    Canonical format:
        <SEQ>-<DESCRIPTION>-<TYPE>-<STAGE>.<ext>

    Business rules rely on:
      - DESCRIPTION = 2nd hyphen-delimited field
      - TYPE = 3rd hyphen-delimited field (Photo/Video)

    Some assets may have double extensions (e.g. .png.jpg). We strip everything after the first dot.
    """
    if not name:
        return {}

    # Robustly strip extensions (handles double extensions like .png.jpg)
    stem = name.split(".")[0]
    parts = [p.strip() for p in stem.split("-") if p.strip()]
    if len(parts) < 3:
        return {}

    seq = parts[0]

    # Canonical fields
    description = parts[1] if len(parts) >= 2 else ""
    type_field3 = parts[2] if len(parts) >= 3 else ""

    # Backwards-compatible inference (more robust if extra hyphens ever appear)
    stage = parts[-1] if len(parts) >= 4 else ""
    type_from_end = parts[-2] if len(parts) >= 4 else type_field3

    # Title shown to host / metadata; preserve old behavior (join middle parts)
    title = "-".join(parts[1:-2]).replace("_", " ").strip() if len(parts) >= 4 else description

    kind = "unknown"
    ct = (type_from_end or type_field3 or "").lower()
    if ct in ("photo", "image", "pic", "jpeg", "jpg", "png"):
        kind = "image"
    elif ct in ("video", "mp4", "mov", "webm", "m4v"):
        kind = "video"

    return {
        "sequence": seq,
        "description": (description or title or stem).strip(),
        "title": (title or description or stem).strip(),
        "kind": kind,
        "stage": stage.strip(),
        # Human-facing type string (prefer 3rd hyphen field)
        "content_type": (type_field3 or type_from_end).strip(),
    }

def _content_cycle_scope(cycle_id: Any, fallback_epoch: Any = None) -> str:
    raw = cycle_id if cycle_id not in (None, "") else fallback_epoch
    try:
        return str(int(float(raw)))
    except Exception:
        s = str(raw or "").strip()
        if not s:
            return ""
        try:
            return str(int(float(s)))
        except Exception:
            return s


def _content_due_scheduled_minutes(*, used_seconds: float, include_host_early: bool) -> List[int]:
    try:
        used_minutes = int(float(used_seconds or 0.0) // 60)
    except Exception:
        used_minutes = 0
    if include_host_early:
        if used_minutes < 8:
            return []
        due_count = 1 + (used_minutes - 8) // _CONTENT_TRIGGER_STEP_MINUTES
    else:
        if used_minutes < 9:
            return []
        due_count = 1 + (used_minutes - 9) // _CONTENT_TRIGGER_STEP_MINUTES
    return [_CONTENT_TRIGGER_START_MINUTE + (_CONTENT_TRIGGER_STEP_MINUTES * i) for i in range(max(0, due_count))]


def _content_pick_first_file(brand_slug: str, folder: str, prefer_kind: str = "") -> Optional[str]:
    files = _content_list_files(brand_slug, folder)
    if not files:
        return None

    desired_kind = str(prefer_kind or "").strip().lower()
    if desired_kind:
        for fn in files:
            info = _content_parse_filename(fn)
            kind = str((info or {}).get("kind") or "").strip().lower()
            if kind == desired_kind:
                return fn

    return files[0]


def _content_history_has_recent_delivery(
    conn: sqlite3.Connection,
    *,
    member_id: str,
    content_folder: str,
    delivered_via: str,
    since_epoch: float,
) -> bool:
    cols = _content_table_columns(conn, "user_content_history")
    if not cols or "member_id" not in cols or "content_folder" not in cols:
        return False

    where = ["member_id = ?", "content_folder = ?"]
    params: List[Any] = [
        str(member_id or "").strip(),
        str(content_folder or "").strip(),
    ]

    if "delivered_via" in cols and str(delivered_via or "").strip():
        where.append("delivered_via = ?")
        params.append(str(delivered_via or "").strip())

    if float(since_epoch or 0.0) > 0 and "create_datetime" in cols:
        where.append("create_datetime >= datetime(?, 'unixepoch')")
        params.append(float(since_epoch or 0.0))

    row = conn.execute(
        f"SELECT 1 FROM user_content_history WHERE {' AND '.join(where)} LIMIT 1",
        tuple(params),
    ).fetchone()
    return row is not None


def _content_deliver_friend_first_turn_once_per_24h(
    *,
    session_id: str,
    brand_slug: str,
    member_key: str,
    base_url: str,
    now_epoch: Optional[float] = None,
) -> Optional[Dict[str, Any]]:
    brand = str(brand_slug or "").strip()
    member = str(member_key or "").strip()
    if not brand or not member:
        return None

    now = float(now_epoch or time.time())
    since_epoch = max(0.0, now - _CONTENT_FRIEND_FIRST_TURN_COOLDOWN_SECONDS)

    conn: Optional[sqlite3.Connection] = None
    try:
        conn = _content_db_connect()
        _content_db_ensure_schema(conn)
        conn.execute("BEGIN IMMEDIATE")

        if _content_history_has_recent_delivery(
            conn,
            member_id=member,
            content_folder="friend",
            delivered_via="",
            since_epoch=since_epoch,
        ):
            conn.commit()
            return None

        file_name = _content_pick_first_file(brand, "friend", prefer_kind="image")
        if not file_name:
            conn.commit()
            return None

        prepared = _content_prepare_delivery_payload(
            brand_slug=brand,
            folder="friend",
            file_name=file_name,
            base_url=str(base_url or ""),
            trigger_minute=_CONTENT_FRIEND_FIRST_TURN_TRIGGER_MINUTE,
        )

        cycle_id = f"friend_first_turn_daily:{int(now)}"
        token = _content_delivery_token(
            member,
            "friend",
            cycle_id,
            _CONTENT_FRIEND_FIRST_TURN_TRIGGER_MINUTE,
            prepared["sequence"],
            file_name,
        )

        _content_claim_upsert(
            conn,
            token=token,
            member_id=member,
            content_folder="friend",
            cycle_id=cycle_id,
            trigger_minute=_CONTENT_FRIEND_FIRST_TURN_TRIGGER_MINUTE,
            content_sequence=prepared["sequence"],
            content_name=file_name,
            content_kind=prepared["content_kind"],
            content_stage=prepared["content_stage"],
            content_url=prepared["content_url"],
            claim_state="delivered_user",
            claimed_via=_CONTENT_FRIEND_FIRST_TURN_DELIVERED_VIA,
            session_id=session_id,
            now_epoch=now,
            delivered_epoch=now,
        )

        _content_history_insert(
            conn,
            token,
            member,
            "friend",
            _CONTENT_FRIEND_FIRST_TURN_TRIGGER_MINUTE,
            prepared["sequence"],
            file_name,
            prepared["content_kind"] or "image",
            prepared["content_stage"],
            prepared["content_url"],
            _CONTENT_FRIEND_FIRST_TURN_DELIVERED_VIA,
        )

        _content_state_upsert(
            conn,
            member,
            "friend",
            {"updated_epoch": now},
        )
        conn.commit()

        return {
            "token": token,
            "triggerMinute": _CONTENT_FRIEND_FIRST_TURN_TRIGGER_MINUTE,
            "trigger_minute": _CONTENT_FRIEND_FIRST_TURN_TRIGGER_MINUTE,
            "folder": "friend",
            **prepared["content"],
        }
    except Exception:
        if conn is not None:
            try:
                conn.rollback()
            except Exception:
                pass
        return None
    finally:
        if conn is not None:
            try:
                conn.close()
            except Exception:
                pass


def _content_delivery_token(
    member_id: str,
    content_folder: str,
    cycle_id: str,
    trigger_minute: int,
    content_sequence: Any,
    content_name: str,
) -> str:
    raw = "|".join(
        [
            str(member_id or "").strip(),
            str(content_folder or "").strip(),
            str(cycle_id or "").strip(),
            str(int(trigger_minute or 0)),
            str(content_sequence or "").strip(),
            str(content_name or "").strip(),
        ]
    )
    return hashlib.sha256(raw.encode("utf-8")).hexdigest()


def _content_claim_get(
    conn: sqlite3.Connection,
    member_id: str,
    content_folder: str,
    cycle_id: str,
    trigger_minute: int,
) -> Dict[str, Any]:
    if not _content_table_exists(conn, "user_content_claims"):
        return {}
    row = conn.execute(
        """
        SELECT *
        FROM user_content_claims
        WHERE member_id=? AND content_folder=? AND cycle_id=? AND trigger_minute=?
        LIMIT 1
        """,
        (
            str(member_id or "").strip(),
            str(content_folder or "").strip(),
            str(cycle_id or "").strip(),
            int(trigger_minute or 0),
        ),
    ).fetchone()
    return dict(row) if row else {}


def _content_claim_has_any(
    conn: sqlite3.Connection,
    member_id: str,
    content_folder: str,
    cycle_id: str,
) -> bool:
    if not _content_table_exists(conn, "user_content_claims"):
        return False
    row = conn.execute(
        """
        SELECT 1
        FROM user_content_claims
        WHERE member_id=? AND content_folder=? AND cycle_id=?
        LIMIT 1
        """,
        (
            str(member_id or "").strip(),
            str(content_folder or "").strip(),
            str(cycle_id or "").strip(),
        ),
    ).fetchone()
    return row is not None


def _content_claim_is_delivered(claim: Dict[str, Any]) -> bool:
    state = str((claim or {}).get("claim_state") or "").strip().lower()
    return state in {"delivered_user", "delivered_host", "delivered_history"}


def _content_history_row_for_trigger(
    conn: sqlite3.Connection,
    member_id: str,
    content_folder: str,
    scheduled_minute: int,
    window_start_epoch: float,
    tol: int = 1,
) -> Dict[str, Any]:
    cols = _content_table_columns(conn, "user_content_history")
    if not cols or "member_id" not in cols or "content_folder" not in cols:
        return {}

    where = ["member_id = ?", "content_folder = ?"]
    params: List[Any] = [
        str(member_id or "").strip(),
        str(content_folder or "").strip(),
    ]

    if "trigger_minute" in cols:
        lo = int(scheduled_minute) - int(tol)
        hi = int(scheduled_minute) + int(tol)
        where.append("trigger_minute BETWEEN ? AND ?")
        params.extend([lo, hi])

    if float(window_start_epoch or 0.0) > 0 and "create_datetime" in cols:
        where.append("create_datetime >= datetime(?, 'unixepoch')")
        params.append(float(window_start_epoch or 0.0))

    order_col = "id" if "id" in cols else "rowid"
    sql = f"SELECT * FROM user_content_history WHERE {' AND '.join(where)} ORDER BY {order_col} DESC LIMIT 1"
    try:
        row = conn.execute(sql, tuple(params)).fetchone()
        return dict(row) if row else {}
    except Exception:
        return {}


def _content_claim_get_or_backfill(
    conn: sqlite3.Connection,
    *,
    member_id: str,
    content_folder: str,
    cycle_id: str,
    trigger_minute: int,
    window_start_epoch: float,
) -> Dict[str, Any]:
    if not _content_table_exists(conn, "user_content_claims"):
        _content_ensure_claims_schema(conn)

    claim = _content_claim_get(conn, member_id, content_folder, cycle_id, trigger_minute)
    if claim:
        return claim

    hist = _content_history_row_for_trigger(
        conn,
        member_id=member_id,
        content_folder=content_folder,
        scheduled_minute=trigger_minute,
        window_start_epoch=window_start_epoch,
        tol=1,
    )
    if not hist:
        return {}

    hist_name = str(hist.get("content_name") or "").strip()
    delivered_via = str(hist.get("delivered_via") or "").strip().lower()
    claim_state = "delivered_host" if delivered_via == "host_pending" else "delivered_user"
    token = str(hist.get("token") or "").strip()
    if not token:
        token = _content_delivery_token(
            member_id,
            content_folder,
            cycle_id,
            int(trigger_minute or 0),
            hist.get("content_sequence"),
            hist_name,
        )

    hist_url = _content_normalize_url(
        str(hist.get("content_url") or "").strip(),
        brand_slug=_content_infer_brand_slug_from_member_key(member_id),
        folder=str(content_folder or "").strip(),
        file_name=hist_name,
    )

    now_epoch = time.time()
    conn.execute(
        """
        INSERT OR IGNORE INTO user_content_claims
        (token, member_id, content_folder, cycle_id, trigger_minute, content_sequence, content_name, content_kind, content_stage, content_url, claim_state, claimed_via, session_id, created_epoch, updated_epoch, delivered_epoch)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """,
        (
            token,
            str(member_id or "").strip(),
            str(content_folder or "").strip(),
            str(cycle_id or "").strip(),
            int(trigger_minute or 0),
            str(hist.get("content_sequence") or "").strip(),
            hist_name,
            str(hist.get("content_type") or "").strip(),
            str(hist.get("content_stage") or "").strip(),
            hist_url,
            claim_state,
            delivered_via or "history_backfill",
            "",
            now_epoch,
            now_epoch,
            now_epoch,
        ),
    )
    claim = _content_claim_get(conn, member_id, content_folder, cycle_id, trigger_minute)
    if claim:
        return claim
    return {
        "token": token,
        "member_id": member_id,
        "content_folder": content_folder,
        "cycle_id": cycle_id,
        "trigger_minute": int(trigger_minute or 0),
        "content_sequence": str(hist.get("content_sequence") or "").strip(),
        "content_name": hist_name,
        "content_kind": str(hist.get("content_type") or "").strip(),
        "content_stage": str(hist.get("content_stage") or "").strip(),
        "content_url": hist_url,
        "claim_state": claim_state,
        "claimed_via": delivered_via or "history_backfill",
        "session_id": "",
        "created_epoch": now_epoch,
        "updated_epoch": now_epoch,
        "delivered_epoch": now_epoch,
    }


def _content_trigger_delivery_status(
    conn: sqlite3.Connection,
    *,
    member_id: str,
    content_folder: str,
    cycle_id: str,
    trigger_minute: int,
    window_start_epoch: float,
) -> Dict[str, Any]:
    claim = _content_claim_get_or_backfill(
        conn,
        member_id=member_id,
        content_folder=content_folder,
        cycle_id=cycle_id,
        trigger_minute=int(trigger_minute or 0),
        window_start_epoch=window_start_epoch,
    )
    history = _content_history_row_for_trigger(
        conn,
        member_id=member_id,
        content_folder=content_folder,
        scheduled_minute=int(trigger_minute or 0),
        window_start_epoch=window_start_epoch,
        tol=1,
    )
    claim_state = str((claim or {}).get("claim_state") or "").strip().lower()
    file_name = str((claim or {}).get("content_name") or "").strip()

    if (not history) and claim and claim_state in {"delivered_user", "delivered_host", "delivered_history"}:
        _content_history_backfill_from_claim(conn, claim)
        history = _content_history_row_for_trigger(
            conn,
            member_id=member_id,
            content_folder=content_folder,
            scheduled_minute=int(trigger_minute or 0),
            window_start_epoch=window_start_epoch,
            tol=1,
        )

    if history:
        status = "delivered"
    elif claim_state == "pending_host" and file_name:
        status = "pending_host"
    elif claim and claim_state in {"delivered_user", "delivered_host", "delivered_history"}:
        status = "claim_only_delivered"
    else:
        status = "undelivered"

    return {
        "trigger_minute": int(trigger_minute or 0),
        "claim": claim,
        "history": history,
        "status": status,
    }


def _content_collect_due_backlog(
    conn: sqlite3.Connection,
    *,
    member_id: str,
    content_folder: str,
    cycle_id: str,
    window_start_epoch: float,
    used_seconds: float,
    include_host_early: bool,
) -> List[Dict[str, Any]]:
    due_scheduled_minutes = _content_due_scheduled_minutes(
        used_seconds=float(used_seconds or 0.0),
        include_host_early=bool(include_host_early),
    )
    if not due_scheduled_minutes:
        return []

    backlog: List[Dict[str, Any]] = []
    for sm in due_scheduled_minutes:
        trigger_minute = int(sm)
        release_gate_minute = max(0, trigger_minute - 1) if include_host_early else trigger_minute
        if float(used_seconds or 0.0) < release_gate_minute * 60:
            continue
        status = _content_trigger_delivery_status(
            conn,
            member_id=member_id,
            content_folder=content_folder,
            cycle_id=cycle_id,
            trigger_minute=trigger_minute,
            window_start_epoch=window_start_epoch,
        )
        if str(status.get("status") or "") == "delivered":
            continue
        status["release_gate_minute"] = release_gate_minute
        backlog.append(status)
    return backlog


def _content_delivery_items(payload: Optional[Dict[str, Any]]) -> List[Dict[str, Any]]:
    if not isinstance(payload, dict):
        return []
    for key in ("content_batch", "contentBatch", "items"):
        raw = payload.get(key)
        if isinstance(raw, list):
            return [dict(item) for item in raw if isinstance(item, dict)]
    return [payload]


def _content_compose_delivery_result(items: List[Dict[str, Any]]) -> Optional[Dict[str, Any]]:
    if not items:
        return None
    primary = dict(items[0])
    if len(items) > 1:
        primary["content_batch"] = list(items)
        primary["contentBatch"] = list(items)
        primary["items"] = list(items)
        primary["contentCount"] = len(items)
    return primary


def _content_merge_delivery_payloads(*payloads: Optional[Dict[str, Any]]) -> Optional[Dict[str, Any]]:
    merged: List[Dict[str, Any]] = []
    seen: Set[str] = set()
    for payload in payloads:
        for item in _content_delivery_items(payload):
            item_dict = dict(item)
            token = str(item_dict.get("token") or "").strip()
            key = token or "|".join(
                [
                    str(item_dict.get("folder") or item_dict.get("content_folder") or "").strip(),
                    str(item_dict.get("fileName") or item_dict.get("filename") or "").strip(),
                    str(item_dict.get("triggerMinute") or item_dict.get("trigger_minute") or "").strip(),
                ]
            )
            if key in seen:
                continue
            seen.add(key)
            merged.append(item_dict)
    return _content_compose_delivery_result(merged)

def _content_claim_upsert(
    conn: sqlite3.Connection,
    *,
    token: str,
    member_id: str,
    content_folder: str,
    cycle_id: str,
    trigger_minute: int,
    content_sequence: Any,
    content_name: str,
    content_kind: str,
    content_stage: str,
    content_url: str,
    claim_state: str,
    claimed_via: str,
    session_id: str,
    now_epoch: float,
    delivered_epoch: Optional[float] = None,
) -> Dict[str, Any]:
    if not _content_table_exists(conn, "user_content_claims"):
        _content_ensure_claims_schema(conn)
    conn.execute(
        """
        INSERT INTO user_content_claims
        (token, member_id, content_folder, cycle_id, trigger_minute, content_sequence, content_name, content_kind, content_stage, content_url, claim_state, claimed_via, session_id, created_epoch, updated_epoch, delivered_epoch)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        ON CONFLICT(member_id, content_folder, cycle_id, trigger_minute) DO UPDATE SET
          token=excluded.token,
          content_sequence=excluded.content_sequence,
          content_name=excluded.content_name,
          content_kind=excluded.content_kind,
          content_stage=excluded.content_stage,
          content_url=excluded.content_url,
          claim_state=excluded.claim_state,
          claimed_via=excluded.claimed_via,
          session_id=excluded.session_id,
          updated_epoch=excluded.updated_epoch,
          delivered_epoch=COALESCE(excluded.delivered_epoch, user_content_claims.delivered_epoch)
        """,
        (
            str(token or "").strip(),
            str(member_id or "").strip(),
            str(content_folder or "").strip(),
            str(cycle_id or "").strip(),
            int(trigger_minute or 0),
            str(content_sequence or "").strip(),
            str(content_name or "").strip(),
            str(content_kind or "").strip(),
            str(content_stage or "").strip(),
            str(content_url or "").strip(),
            str(claim_state or "").strip(),
            str(claimed_via or "").strip(),
            str(session_id or "").strip(),
            float(now_epoch or time.time()),
            float(now_epoch or time.time()),
            float(delivered_epoch) if delivered_epoch is not None else None,
        ),
    )
    return _content_claim_get(conn, member_id, content_folder, cycle_id, trigger_minute)


def _content_prepare_delivery_payload(
    brand_slug: str,
    folder: str,
    file_name: str,
    base_url: str,
    trigger_minute: int,
) -> Dict[str, Any]:
    info = _content_parse_filename(file_name)
    content_kind = str(info.get("kind") or "").strip().lower() or "image"
    content_stage = str(info.get("stage") or "").strip()
    content_title = str(info.get("title") or "").strip()
    content_description = str(info.get("description") or content_title or "").strip()
    content_type_label = str(info.get("content_type") or "").strip()

    try:
        sequence = int(info.get("sequence") or 0)
    except Exception:
        sequence = 0

    if not content_type_label:
        if content_kind == "video":
            content_type_label = "Video"
        elif content_kind == "image":
            content_type_label = "Photo"

    content_url = _content_build_url(brand_slug=brand_slug, folder=folder, file_name=file_name, base_url=str(base_url or ""))
    content: Dict[str, Any] = {
        "sequence": sequence,
        "filename": file_name,
        "fileName": file_name,
        "type": content_kind,
        "kind": content_kind,
        "stage": content_stage,
        "title": content_title,
        "url": content_url,
        "triggerMinute": int(trigger_minute or 0),
    }

    try:
        if content_description and file_name:
            content["message"] = f"Delivering {content_type_label or 'content'}: {content_description}. File: {file_name}"
        elif content_description:
            content["message"] = f"Delivering {content_type_label or 'content'}: {content_description}."
        elif file_name:
            content["message"] = f"Delivering {content_type_label or 'content'}. File: {file_name}"
        else:
            content["message"] = f"Delivering {content_type_label or 'content'}."
        mime, _enc = mimetypes.guess_type(file_name)
        if not mime:
            mime = "video/mp4" if content_kind == "video" else "image/jpeg" if content_kind == "image" else "application/octet-stream"
        content["attachment"] = {
            "url": content_url,
            "name": file_name,
            "contentType": mime,
            "size": 0,
            "container": "brand_content",
            "blobName": f"{folder}/{file_name}",
        }
    except Exception:
        mime, _enc = mimetypes.guess_type(file_name)
        if not mime:
            mime = "application/octet-stream"
        content["message"] = "Delivering scheduled content."
        content["attachment"] = {
            "url": content_url,
            "name": file_name,
            "contentType": mime,
            "size": 0,
            "container": "brand_content",
            "blobName": f"{folder}/{file_name}",
        }

    return {
        "sequence": sequence,
        "content_kind": content_kind,
        "content_stage": content_stage,
        "content_title": content_title,
        "content_description": content_description,
        "content_type_label": content_type_label,
        "content_url": content_url,
        "content": content,
    }


def _content_clear_pending_fields(now_epoch: float) -> Dict[str, Any]:
    return {
        "pending_token": None,
        "pending_trigger_minute": None,
        "pending_file_name": None,
        "pending_sequence": None,
        "pending_stage": None,
        "pending_kind": None,
        "pending_created_epoch": None,
        "updated_epoch": now_epoch,
    }



def _content_history_max_sequence(
    conn: sqlite3.Connection,
    member_id: str,
    content_folder: str,
    window_start_epoch: float,
) -> int:
    cols = _content_table_columns(conn, "user_content_history")
    if not cols or "content_sequence" not in cols or "member_id" not in cols or "content_folder" not in cols:
        return 0
    where = ["member_id = ?", "content_folder = ?"]
    params: List[Any] = [
        str(member_id or "").strip(),
        str(content_folder or "").strip(),
    ]
    if float(window_start_epoch or 0.0) > 0 and "create_datetime" in cols:
        where.append("create_datetime >= datetime(?, 'unixepoch')")
        params.append(float(window_start_epoch or 0.0))
    try:
        row = conn.execute(
            f"""
            SELECT COALESCE(MAX(CAST(content_sequence AS INTEGER)), 0)
            FROM user_content_history
            WHERE {' AND '.join(where)}
            """,
            tuple(params),
        ).fetchone()
        return int(row[0] or 0)
    except Exception:
        return 0


def _content_history_has_any_delivery(
    conn: sqlite3.Connection,
    member_id: str,
    content_folder: str,
    window_start_epoch: float,
) -> bool:
    cols = _content_table_columns(conn, "user_content_history")
    if not cols or "member_id" not in cols or "content_folder" not in cols:
        return False
    where = ["member_id = ?", "content_folder = ?"]
    params: List[Any] = [
        str(member_id or "").strip(),
        str(content_folder or "").strip(),
    ]
    if float(window_start_epoch or 0.0) > 0 and "create_datetime" in cols:
        where.append("create_datetime >= datetime(?, 'unixepoch')")
        params.append(float(window_start_epoch or 0.0))
    row = conn.execute(
        f"""
        SELECT 1
        FROM user_content_history
        WHERE {' AND '.join(where)}
        LIMIT 1
        """,
        tuple(params),
    ).fetchone()
    return row is not None


def _content_root_candidates() -> List[str]:
    roots: List[str] = []
    env_roots = [
        os.getenv("CONTENT_BRAND_ROOT", ""),
        os.getenv("BRAND_CONTENT_ROOT", ""),
    ]
    defaults = [
        "/home/site/brand",
        "/home/site",
        "/home/site/wwwroot/brand",
        "/home/site/wwwroot",
        "/home/brand",
        "/home",
    ]
    for raw in env_roots + defaults:
        path = str(raw or "").strip()
        if not path:
            continue
        if path not in roots:
            roots.append(path)
    return roots


def _content_slug_equivalent(actual_name: str, requested_slug: str) -> bool:
    actual = str(actual_name or "").strip()
    requested = str(requested_slug or "").strip()
    if not actual or not requested:
        return False
    if actual == requested:
        return True
    if actual.lower() == requested.lower():
        return True
    if _safe_slug(actual) == requested:
        return True
    actual_compact = re.sub(r"[^a-z0-9]+", "", _safe_slug(actual))
    requested_compact = re.sub(r"[^a-z0-9]+", "", requested.lower())
    if actual_compact and requested_compact and actual_compact == requested_compact:
        return True
    if actual_compact == f"brand{requested_compact}":
        return True
    return False


def _content_brand_dir_candidates(brand_slug: str) -> List[str]:
    slug = _safe_slug(brand_slug)
    dirs: List[str] = []
    seen: Set[str] = set()
    for root in _content_root_candidates():
        if not os.path.isdir(root):
            continue
        exact = os.path.join(root, slug)
        if os.path.isdir(exact):
            real = os.path.realpath(exact)
            if real not in seen:
                seen.add(real)
                dirs.append(exact)
        try:
            entries = os.listdir(root)
        except Exception:
            entries = []
        for entry in entries:
            full = os.path.join(root, entry)
            if not os.path.isdir(full):
                continue
            if not _content_slug_equivalent(entry, slug):
                continue
            real = os.path.realpath(full)
            if real in seen:
                continue
            seen.add(real)
            dirs.append(full)
    return dirs


def _content_mode_dir_candidates(brand_dir: str, folder: str) -> List[str]:
    folder_slug = _safe_slug(folder)
    candidates = [
        os.path.join(brand_dir, "content", "mode", folder_slug),
        os.path.join(brand_dir, "content", folder_slug),
        os.path.join(brand_dir, folder_slug),
        os.path.join(brand_dir, "Content", "mode", folder_slug),
        os.path.join(brand_dir, "Content", folder_slug),
    ]
    out: List[str] = []
    seen: Set[str] = set()
    for cand in candidates:
        real = os.path.realpath(cand)
        if real in seen:
            continue
        seen.add(real)
        out.append(cand)
    return out


def _content_resolve_mode_dir(brand_slug: str, folder: str) -> str:
    for brand_dir in _content_brand_dir_candidates(brand_slug):
        for cand in _content_mode_dir_candidates(brand_dir, folder):
            if os.path.isdir(cand):
                return cand
    return ""


def _content_resolve_existing_filename(base_dir: str, filename: str) -> str:
    if not base_dir or not filename:
        return ""
    direct = os.path.join(base_dir, filename)
    if os.path.isfile(direct):
        return filename
    want = str(filename or "").strip().lower()
    try:
        entries = os.listdir(base_dir)
    except Exception:
        entries = []
    for entry in entries:
        if str(entry or "").lower() == want and os.path.isfile(os.path.join(base_dir, entry)):
            return entry
    return ""


def _content_is_legacy_brand_placeholder(brand_slug: str) -> bool:
    slug = _safe_slug(brand_slug)
    return slug in {"", "brand", "mode", "content"}


def _content_infer_brand_slug_from_member_key(member_id: str) -> str:
    raw = str(member_id or "").strip()
    if not raw:
        return ""
    if "::" in raw:
        prefix = str(raw.split("::", 1)[0] or "").strip()
        slug = _safe_slug(prefix)
        if slug and not _content_is_legacy_brand_placeholder(slug):
            return slug
    return ""


def _normalize_public_base_url(raw: str) -> str:
    s = str(raw or "").strip()
    if not s:
        return ""
    if "://" not in s:
        s = "https://" + s.lstrip("/")
    try:
        u = urlparse(s)
    except Exception:
        return ""
    scheme = (u.scheme or "https").strip().lower() or "https"
    netloc = str(u.netloc or "").strip()
    if not netloc:
        return ""
    if netloc.endswith('.scm.azurewebsites.net'):
        netloc = netloc[:-len('.scm.azurewebsites.net')] + '.azurewebsites.net'
    netloc = netloc.replace('.scm.', '.')
    return f"{scheme}://{netloc}".rstrip('/')


def _content_public_base_url(request: Optional[Request] = None, fallback_base: str = "") -> str:
    env_candidates = [
        os.getenv("CONTENT_PUBLIC_BASE_URL", ""),
        os.getenv("PUBLIC_API_BASE_URL", ""),
        os.getenv("API_PUBLIC_BASE_URL", ""),
        os.getenv("APP_BASE_URL", ""),
        os.getenv("PUBLIC_BASE_URL", ""),
        os.getenv("API_BASE_URL", ""),
    ]
    for cand in env_candidates:
        norm = _normalize_public_base_url(cand)
        if norm:
            return norm
    if request is not None:
        try:
            hdr = request.headers
            host = str(hdr.get("x-forwarded-host") or hdr.get("x-original-host") or hdr.get("host") or "").split(",", 1)[0].strip()
            scheme = str(hdr.get("x-forwarded-proto") or "").split(",", 1)[0].strip().lower()
            if not scheme:
                scheme = "https" if hdr.get("x-arr-ssl") else str(urlparse(str(request.base_url or "")).scheme or "https")
            if host:
                norm = _normalize_public_base_url(f"{scheme}://{host}")
                if norm:
                    return norm
        except Exception:
            pass
    norm = _normalize_public_base_url(fallback_base)
    if norm:
        return norm
    website_host = _normalize_public_base_url(os.getenv("WEBSITE_HOSTNAME", ""))
    if website_host:
        return website_host
    return ""


def _content_build_url(brand_slug: str, folder: str, file_name: str, base_url: str = "", request: Optional[Request] = None) -> str:
    slug = _safe_slug(brand_slug) or "elaralo"
    folder_slug = _safe_slug(folder)
    encoded_name = quote(str(file_name or "").strip(), safe="")
    path = f"/content/{slug}/{folder_slug}/{encoded_name}"
    public_base = _content_public_base_url(request=request, fallback_base=base_url)
    return f"{public_base}{path}" if public_base else path


def _content_normalize_url(url: str, *, brand_slug: str, folder: str, file_name: str, base_url: str = "") -> str:
    canonical = _content_build_url(brand_slug=brand_slug, folder=folder, file_name=file_name, base_url=base_url)
    raw = str(url or "").strip()
    if not raw:
        return canonical
    try:
        parsed = urlparse(raw)
        path = str(parsed.path or "")
        parts = [p for p in path.split('/') if p]
        needs_rebuild = False
        if '.scm.' in str(parsed.netloc or '').lower():
            needs_rebuild = True
        if len(parts) < 4 or parts[0].lower() != 'content':
            needs_rebuild = True
        else:
            url_brand = _safe_slug(parts[1])
            url_mode = _safe_slug(parts[2])
            url_file = unquote(parts[3])
            if _content_is_legacy_brand_placeholder(url_brand):
                needs_rebuild = True
            if url_mode != _safe_slug(folder):
                needs_rebuild = True
            if url_file != str(file_name or '').strip():
                needs_rebuild = True
        return canonical if needs_rebuild else raw
    except Exception:
        return canonical


def _content_resolve_unique_file_across_brands(folder: str, filename: str) -> Tuple[str, str]:
    folder_slug = _safe_slug(folder)
    requested = str(filename or '').strip()
    if not folder_slug or not requested:
        return "", ""
    matches: List[Tuple[str, str]] = []
    seen: Set[str] = set()
    for root in _content_root_candidates():
        if not os.path.isdir(root):
            continue
        try:
            entries = os.listdir(root)
        except Exception:
            entries = []
        for entry in entries:
            full = os.path.join(root, entry)
            if not os.path.isdir(full):
                continue
            for cand in _content_mode_dir_candidates(full, folder_slug):
                if not os.path.isdir(cand):
                    continue
                resolved = _content_resolve_existing_filename(cand, requested)
                if not resolved:
                    continue
                real = os.path.realpath(os.path.join(cand, resolved))
                if real in seen:
                    continue
                seen.add(real)
                matches.append((cand, resolved))
    if len(matches) == 1:
        return matches[0]
    return "", ""


def _content_repair_persisted_urls_sync() -> None:
    """Best-effort repair of persisted scheduled-content URLs."""
    conn: Optional[sqlite3.Connection] = None
    try:
        conn = _content_db_connect()
        _content_db_ensure_schema(conn)
        for table in ("user_content_history", "user_content_claims"):
            if not _content_table_exists(conn, table):
                continue
            cols = set(_content_table_columns(conn, table))
            if not {"member_id", "content_folder", "content_name", "content_url"}.issubset(cols):
                continue
            rows = conn.execute(f'SELECT rowid, member_id, content_folder, content_name, content_url FROM {table}').fetchall()
            for row in rows:
                rowid = int(row[0])
                member_id = str(row[1] or "").strip()
                content_folder = str(row[2] or "").strip()
                content_name = str(row[3] or "").strip()
                content_url = str(row[4] or "").strip()
                fixed = _content_normalize_url(
                    content_url,
                    brand_slug=_content_infer_brand_slug_from_member_key(member_id),
                    folder=content_folder,
                    file_name=content_name,
                )
                if fixed and fixed != content_url:
                    conn.execute(f'UPDATE {table} SET content_url=? WHERE rowid=?', (fixed, rowid))
        conn.commit()
    except Exception as e:
        try:
            if conn is not None:
                conn.rollback()
        except Exception:
            pass
        print(f"[content] WARNING: failed repairing persisted content URLs: {e!r}")
    finally:
        try:
            if conn is not None:
                conn.close()
        except Exception:
            pass


def _content_list_files(brand_slug: str, folder: str) -> List[str]:
    base = _content_resolve_mode_dir(brand_slug, folder)
    if not base:
        return []
    try:
        entries = os.listdir(base)
    except Exception:
        return []
    files: List[str] = []
    for fn in entries:
        if fn.startswith("."):
            continue
        full = os.path.join(base, fn)
        if os.path.isfile(full):
            files.append(fn)
    # Sort by leading numeric prefix if present.
    def _seq_key(fn: str) -> int:
        try:
            prefix = fn.split("-", 1)[0]
            return int(prefix)
        except Exception:
            return 10**18
    files.sort(key=_seq_key)
    return files


def _content_pick_next_file(brand_slug: str, folder: str, last_sequence: Optional[str]) -> Optional[str]:
    files = _content_list_files(brand_slug, folder)
    if not files:
        return None

    last_n = -1
    if last_sequence:
        try:
            last_n = int(str(last_sequence).strip())
        except Exception:
            last_n = -1

    # Pick the first file whose numeric prefix is greater than last_sequence.
    for fn in files:
        try:
            n = int(fn.split("-", 1)[0])
        except Exception:
            continue
        if n > last_n:
            return fn

    # Wrap-around fallback: start from the beginning.
    return files[0]


def _content_state_get(conn: sqlite3.Connection, member_id: str, folder: str) -> Dict[str, Any]:
    row = conn.execute(
        "SELECT * FROM user_content_state WHERE member_id=? AND content_folder=?",
        (member_id, folder),
    ).fetchone()
    return dict(row) if row else {}


def _content_state_upsert(conn: sqlite3.Connection, member_id: str, folder: str, updates: Dict[str, Any]) -> None:
    # SQLite UPSERT
    cols = ["member_id", "content_folder"] + list(updates.keys())
    vals = [member_id, folder] + list(updates.values())
    placeholders = ",".join(["?"] * len(cols))
    assignments = ",".join([f"{c}=excluded.{c}" for c in updates.keys()])
    conn.execute(
        f"INSERT INTO user_content_state ({','.join(cols)}) VALUES ({placeholders}) "
        f"ON CONFLICT(member_id, content_folder) DO UPDATE SET {assignments}",
        vals,
    )


def _content_roll_window_if_needed(
    conn: sqlite3.Connection,
    *,
    member_id: str,
    folder: str,
    now_epoch: float,
    cycle_id: str,
    cycle_used_seconds: float,
    autocommit: bool = True,
) -> Dict[str, Any]:
    state = _content_state_get(conn, member_id, folder)

    window_start = float(state.get("window_start_epoch") or 0) or None
    window_cycle_id = str(state.get("window_cycle_id") or "")
    base_used = float(state.get("window_base_used_seconds") or 0)

    expired = False
    if window_start is not None:
        if now_epoch - window_start >= _CONTENT_WINDOW_SECONDS:
            expired = True
    if window_cycle_id and window_cycle_id != str(cycle_id or ""):
        expired = True

    # Start a new window if missing or expired.
    if window_start is None or expired:
        _content_state_upsert(
            conn,
            member_id,
            folder,
            {
                "window_start_epoch": now_epoch,
                "window_cycle_id": str(cycle_id or ""),
                "window_base_used_seconds": 0.0,
                "window_sent_count": 0,
                "window_complete": 0,
                "last_sequence": None,
                "last_stage": None,
                "last_trigger_minute": None,
                **_content_clear_pending_fields(now_epoch),
            },
        )
        if autocommit:
            conn.commit()
        state = _content_state_get(conn, member_id, folder)

    # Coerce base fields.
    if not state.get("window_cycle_id"):
        state["window_cycle_id"] = str(cycle_id or "")
    if state.get("window_base_used_seconds") is None:
        state["window_base_used_seconds"] = float(cycle_used_seconds or 0)

    return state



def _content_next_trigger_minute(state: Dict[str, Any]) -> Optional[int]:
    if int(state.get("window_complete") or 0) == 1:
        return None

    sent = int(state.get("window_sent_count") or 0)
    last_trig = state.get("last_trigger_minute")

    if sent <= 0 or last_trig is None:
        return _CONTENT_TRIGGER_START_MINUTE
    try:
        return int(last_trig) + _CONTENT_TRIGGER_STEP_MINUTES
    except Exception:
        return _CONTENT_TRIGGER_START_MINUTE


def _content_window_used_seconds(state: Dict[str, Any], cycle_used_seconds: float) -> float:
    """Compute scheduler used seconds.

    Content delivery triggers are based on *cumulative usage seconds within the current usage cycle*
    (9 minutes, then every +10 minutes). This must work even if the scheduler first runs late
    (e.g., the first invocation happens at paywall).

    We therefore use cycle_used_seconds directly and ignore window_base_used_seconds.
    """
    used = float(cycle_used_seconds or 0.0)
    if used < 0:
        used = 0.0
    return used


def _ai_override_has_token_event(session_id: str, token: str, kind: str) -> bool:
    if not token:
        return False
    with _AI_OVERRIDE_LOCK:
        rec = _AI_OVERRIDE_SESSIONS.get(session_id)
        if not rec:
            return False
        for ev in rec.get("events", []) or []:
            if ev.get("kind") != kind:
                continue
            payload = ev.get("payload")
            if isinstance(payload, dict) and str(payload.get("token") or "") == token:
                return True
        return False


def _content_queue_pending_for_host_from_base_url(
    *,
    session_id: str,
    member_id: str,
    brand_slug: str,
    folder: str,
    cycle_id: str,
    cycle_used_seconds: float,
    now_epoch: float,
    base_url: str,
) -> Optional[Dict[str, Any]]:
    class _ContentRequestShim:
        def __init__(self, base_url: str) -> None:
            self.base_url = str(base_url or "")
    return _content_queue_pending_for_host(
        request=_ContentRequestShim(base_url),
        session_id=session_id,
        member_id=member_id,
        brand_slug=brand_slug,
        folder=folder,
        cycle_id=cycle_id,
        cycle_used_seconds=cycle_used_seconds,
        now_epoch=now_epoch,
    )


def _content_queue_pending_for_host(
    *,
    request: Request,
    session_id: str,
    member_id: str,
    brand_slug: str,
    folder: str,
    cycle_id: str,
    cycle_used_seconds: float,
    now_epoch: float,
) -> Optional[Dict[str, Any]]:
    """Queue all due content milestones for the host when override is active.

    If earlier milestones were missed, the next scheduler pass queues the full backlog in
    trigger-minute order so the host can push them sequentially.
    """

    conn = _content_db_connect()
    member_key = f"{brand_slug}::{member_id}" if brand_slug else member_id
    folder_slug = _safe_slug(folder)
    if folder_slug == "friend":
        return None
    if folder_slug == "intimate" and _is_anon_member_id(member_key):
        return None
    now = float(now_epoch or time.time())
    try:
        _content_db_ensure_schema(conn)
        conn.execute("BEGIN IMMEDIATE")

        state = _content_roll_window_if_needed(
            conn,
            member_id=member_key,
            folder=folder,
            now_epoch=now,
            cycle_id=cycle_id,
            cycle_used_seconds=cycle_used_seconds,
            autocommit=False,
        )

        cycle_scope = _content_cycle_scope(cycle_id, state.get("window_start_epoch"))
        window_start_epoch = float(state.get("window_start_epoch") or 0.0)
        try:
            cycle_start_epoch = float(cycle_id or 0)
        except Exception:
            cycle_start_epoch = 0.0
        if cycle_start_epoch > 0:
            window_start_epoch = cycle_start_epoch

        history_any = _content_history_has_any_delivery(
            conn,
            member_id=member_key,
            content_folder=folder,
            window_start_epoch=window_start_epoch,
        )
        claims_any = _content_claim_has_any(conn, member_key, folder, cycle_scope)

        stale_state = (not history_any) and (not claims_any) and (
            int(state.get("window_complete") or 0) == 1
            or int(state.get("window_sent_count") or 0) > 0
            or bool(str(state.get("last_sequence") or "").strip())
            or bool(str(state.get("last_trigger_minute") or "").strip())
            or bool(str(state.get("pending_token") or "").strip())
        )
        if stale_state:
            _content_state_upsert(
                conn,
                member_key,
                folder,
                {
                    "window_sent_count": 0,
                    "window_complete": 0,
                    "last_sequence": None,
                    "last_stage": None,
                    "last_trigger_minute": None,
                    **_content_clear_pending_fields(now),
                },
            )
            state = _content_state_get(conn, member_key, folder) or {}

        if int(state.get("window_complete") or 0) == 1:
            conn.commit()
            return None

        used_in_window = _content_window_used_seconds(state, cycle_used_seconds)
        backlog = _content_collect_due_backlog(
            conn,
            member_id=member_key,
            content_folder=folder,
            cycle_id=cycle_scope,
            window_start_epoch=window_start_epoch,
            used_seconds=used_in_window,
            include_host_early=True,
        )
        if not backlog:
            conn.commit()
            return None

        last_seq_cursor = _content_history_max_sequence(conn, member_key, folder, window_start_epoch)
        batch_payloads: List[Dict[str, Any]] = []
        latest_state_update: Dict[str, Any] = {}

        for entry in backlog:
            trigger_minute = int(entry.get("trigger_minute") or 0)
            claim = entry.get("claim") if isinstance(entry.get("claim"), dict) else {}
            claim_state = str((claim or {}).get("claim_state") or "").strip().lower()
            existing_file_name = str((claim or {}).get("content_name") or "").strip()
            token = str((claim or {}).get("token") or "").strip()

            if claim_state == "pending_host" and existing_file_name:
                file_name = existing_file_name
                prepared = _content_prepare_delivery_payload(
                    brand_slug=brand_slug,
                    folder=folder,
                    file_name=file_name,
                    base_url=str(request.base_url),
                    trigger_minute=trigger_minute,
                )
                existing_seq = str((claim or {}).get("content_sequence") or prepared.get("sequence") or "").strip()
                if existing_seq:
                    last_seq_cursor = existing_seq
            else:
                file_name = _content_pick_next_file(brand_slug, folder, last_seq_cursor)
                if not file_name:
                    break
                prepared = _content_prepare_delivery_payload(
                    brand_slug=brand_slug,
                    folder=folder,
                    file_name=file_name,
                    base_url=str(request.base_url),
                    trigger_minute=trigger_minute,
                )
                if not token:
                    token = _content_delivery_token(
                        member_key,
                        folder,
                        cycle_scope,
                        trigger_minute,
                        prepared["sequence"],
                        file_name,
                    )
                claim = _content_claim_upsert(
                    conn,
                    token=token,
                    member_id=member_key,
                    content_folder=folder,
                    cycle_id=cycle_scope,
                    trigger_minute=trigger_minute,
                    content_sequence=prepared["sequence"],
                    content_name=file_name,
                    content_kind=prepared["content_kind"],
                    content_stage=prepared["content_stage"],
                    content_url=prepared["content_url"],
                    claim_state="pending_host",
                    claimed_via="host_pending",
                    session_id=session_id,
                    now_epoch=now,
                    delivered_epoch=None,
                )
                last_seq_cursor = str(prepared["sequence"])

            latest_state_update = {
                "pending_token": token,
                "pending_trigger_minute": trigger_minute,
                "pending_file_name": file_name,
                "pending_sequence": str(prepared["sequence"]),
                "pending_stage": str(prepared["content_stage"] or ""),
                "pending_kind": str(prepared["content_kind"] or "image"),
                "pending_created_epoch": now,
                "updated_epoch": now,
            }

            content = prepared["content"]
            payload = {
                "token": token,
                "content": content,
                "trigger_minute": trigger_minute,
                "member_id": member_id,
                "content_folder": folder,
                "brand_slug": brand_slug,
                "content_sequence": str(prepared["sequence"]),
                "content_stage": str(prepared["content_stage"] or ""),
                "content_kind": str(prepared["content_kind"] or "image"),
                "content_name": file_name,
                "cycle_id": cycle_scope,
                "window_start_epoch": window_start_epoch,
            }
            batch_payloads.append(payload)

        if not batch_payloads:
            conn.commit()
            return None

        if latest_state_update:
            _content_state_upsert(conn, member_key, folder, latest_state_update)
        conn.commit()

        for payload in batch_payloads:
            token = str(payload.get("token") or "").strip()
            if token and _ai_override_has_token_event(session_id, token, "content_pending"):
                continue
            try:
                _ai_override_append_event(
                    session_id,
                    role="system",
                    content="",
                    sender="system",
                    audience="host",
                    kind="content_pending",
                    payload=payload,
                )
            except Exception:
                pass

        return batch_payloads[0]
    except Exception:
        try:
            conn.rollback()
        except Exception:
            pass
        return None
    finally:
        try:
            conn.close()
        except Exception:
            pass

def _content_deliver_to_user_if_due(
    session_id: str,
    brand_slug: str,
    member_key: str,
    folder: str,
    cycle_id: str,
    cycle_used_seconds: int,
    base_url: str,
    now_epoch: Optional[float] = None,
    force_user_delivery: bool = False,
) -> Optional[Dict[str, Any]]:
    """Deliver all due scheduled content when due.

    Restored self-healing rule:
      - if earlier milestones were missed, the next eligible delivery pass flushes the full backlog
        in trigger-minute order instead of delivering only one item.
      - claims that say delivered but have no matching history row are treated as not yet fulfilled.
    """

    conn: Optional[sqlite3.Connection] = None
    folder_slug = _safe_slug(folder)
    if folder_slug == "friend":
        return None
    if folder_slug == "intimate" and _is_anon_member_id(member_key):
        return None
    now = float(now_epoch or time.time())
    try:
        conn = _content_db_connect()
        _content_db_ensure_schema(conn)
        conn.execute("BEGIN IMMEDIATE")

        state = _content_roll_window_if_needed(
            conn,
            member_id=member_key,
            folder=folder,
            now_epoch=now,
            cycle_id=str(cycle_id or ""),
            cycle_used_seconds=float(cycle_used_seconds or 0.0),
            autocommit=False,
        ) or {}

        try:
            cycle_start_epoch = float(cycle_id or 0)
        except Exception:
            cycle_start_epoch = 0.0

        window_start_epoch = float(state.get("window_start_epoch") or 0.0)
        if cycle_start_epoch > 0:
            window_start_epoch = cycle_start_epoch
        cycle_scope = _content_cycle_scope(cycle_id, window_start_epoch)

        history_any = _content_history_has_any_delivery(
            conn,
            member_id=member_key,
            content_folder=folder,
            window_start_epoch=window_start_epoch,
        )
        claims_any = _content_claim_has_any(conn, member_key, folder, cycle_scope)

        stale_state = (not history_any) and (not claims_any) and (
            int(state.get("window_complete") or 0) == 1
            or int(state.get("window_sent_count") or 0) > 0
            or bool(str(state.get("last_sequence") or "").strip())
            or bool(str(state.get("last_trigger_minute") or "").strip())
            or bool(str(state.get("pending_token") or "").strip())
        )
        if stale_state:
            _content_state_upsert(
                conn,
                member_key,
                folder,
                {
                    "window_sent_count": 0,
                    "window_complete": 0,
                    "last_sequence": None,
                    "last_stage": None,
                    "last_trigger_minute": None,
                    **_content_clear_pending_fields(now),
                },
            )
            state = _content_state_get(conn, member_key, folder) or {}

        if int(state.get("window_complete") or 0) == 1:
            conn.commit()
            return None

        deliver_to_host_first = False
        if not force_user_delivery:
            try:
                deliver_to_host_first = bool(_ai_override_is_active(session_id))
            except Exception:
                deliver_to_host_first = False

        used_in_window = _content_window_used_seconds(state, float(cycle_used_seconds or 0.0))
        backlog = _content_collect_due_backlog(
            conn,
            member_id=member_key,
            content_folder=folder,
            cycle_id=cycle_scope,
            window_start_epoch=window_start_epoch,
            used_seconds=used_in_window,
            include_host_early=bool(force_user_delivery or deliver_to_host_first),
        )
        if not backlog:
            conn.commit()
            return None

        # When host override is active, queue the entire backlog for the host 1 minute early.
        if deliver_to_host_first and not force_user_delivery:
            conn.commit()
            member_id_for_host = str(member_key or "")
            brand_prefix = f"{brand_slug}::" if brand_slug else ""
            if brand_prefix and member_id_for_host.startswith(brand_prefix):
                member_id_for_host = member_id_for_host[len(brand_prefix):]
            return _content_queue_pending_for_host_from_base_url(
                session_id=session_id,
                member_id=member_id_for_host,
                brand_slug=brand_slug,
                folder=folder,
                cycle_id=cycle_id,
                cycle_used_seconds=float(cycle_used_seconds or 0.0),
                now_epoch=now,
                base_url=str(base_url or ""),
            )

        last_seq_cursor = _content_history_max_sequence(conn, member_key, folder, window_start_epoch)
        delivered_items: List[Dict[str, Any]] = []

        for entry in backlog:
            trigger_minute = int(entry.get("trigger_minute") or 0)
            claim = entry.get("claim") if isinstance(entry.get("claim"), dict) else {}
            claim_state = str((claim or {}).get("claim_state") or "").strip().lower()
            existing_file_name = str((claim or {}).get("content_name") or "").strip()
            token = str((claim or {}).get("token") or "").strip()

            if claim_state == "pending_host" and existing_file_name:
                file_name = existing_file_name
                prepared = _content_prepare_delivery_payload(
                    brand_slug=brand_slug,
                    folder=folder,
                    file_name=file_name,
                    base_url=str(base_url or ""),
                    trigger_minute=trigger_minute,
                )
                existing_seq = str((claim or {}).get("content_sequence") or prepared.get("sequence") or "").strip()
                if existing_seq:
                    last_seq_cursor = existing_seq
            else:
                file_name = _content_pick_next_file(brand_slug, folder, last_seq_cursor)
                if not file_name:
                    break
                prepared = _content_prepare_delivery_payload(
                    brand_slug=brand_slug,
                    folder=folder,
                    file_name=file_name,
                    base_url=str(base_url or ""),
                    trigger_minute=trigger_minute,
                )
                last_seq_cursor = str(prepared["sequence"])

            if not token:
                token = _content_delivery_token(
                    member_key,
                    folder,
                    cycle_scope,
                    trigger_minute,
                    prepared["sequence"],
                    file_name,
                )

            _content_claim_upsert(
                conn,
                token=token,
                member_id=member_key,
                content_folder=folder,
                cycle_id=cycle_scope,
                trigger_minute=trigger_minute,
                content_sequence=prepared["sequence"],
                content_name=file_name,
                content_kind=prepared["content_kind"],
                content_stage=prepared["content_stage"],
                content_url=prepared["content_url"],
                claim_state="delivered_user",
                claimed_via="auto",
                session_id=session_id,
                now_epoch=now,
                delivered_epoch=now,
            )

            _content_history_insert(
                conn,
                token,
                member_key,
                folder,
                trigger_minute,
                prepared["sequence"],
                file_name,
                prepared["content_kind"] or "image",
                prepared["content_stage"],
                prepared["content_url"],
                "auto",
            )

            delivered_items.append({
                "token": token,
                "triggerMinute": trigger_minute,
                "trigger_minute": trigger_minute,
                "folder": folder,
                **prepared["content"],
            })

        if not delivered_items:
            conn.commit()
            return None

        last_item = delivered_items[-1]
        last_stage = str(last_item.get("stage") or "")
        _content_state_upsert(
            conn,
            member_key,
            folder,
            {
                "last_sequence": str(last_item.get("sequence") or ""),
                "last_stage": last_stage,
                "last_trigger_minute": int(last_item.get("triggerMinute") or last_item.get("trigger_minute") or 0),
                "window_sent_count": int(state.get("window_sent_count") or 0) + len(delivered_items),
                "window_complete": 1 if folder == "friend" or last_stage.strip().lower() == "end" else 0,
                **_content_clear_pending_fields(now),
            },
        )
        conn.commit()

        return _content_compose_delivery_result(delivered_items)

    except Exception:
        if conn is not None:
            try:
                conn.rollback()
            except Exception:
                pass
        return None
    finally:
        if conn is not None:
            try:
                conn.close()
            except Exception:
                pass

def _content_mark_host_received(payload: Dict[str, Any]) -> None:
    """Mark a host-pending content item as delivered (business rule: delivered once host receives)."""

    if not isinstance(payload, dict):
        return
    token = str(payload.get("token") or "").strip()
    if not token:
        return

    member_id = str(payload.get("member_id") or "").strip()
    brand_slug = str(payload.get("brand_slug") or "").strip()
    member_key = f"{brand_slug}::{member_id}" if brand_slug else member_id
    folder = str(payload.get("content_folder") or "").strip() or "friend"
    trig = payload.get("trigger_minute")
    try:
        trig_i = int(trig)
    except Exception:
        trig_i = None

    content_obj = payload.get("content") if isinstance(payload.get("content"), dict) else {}
    file_name = str(content_obj.get("fileName") or payload.get("content_name") or "").strip()
    seq = str(payload.get("content_sequence") or "").strip()
    stage = str(payload.get("content_stage") or "").strip()
    kind = str(payload.get("content_kind") or "").strip()
    url = str(content_obj.get("url") or "").strip()
    url = _content_normalize_url(
        url,
        brand_slug=brand_slug or _content_infer_brand_slug_from_member_key(member_key),
        folder=folder,
        file_name=file_name,
    )
    cycle_id = _content_cycle_scope(payload.get("cycle_id"), payload.get("window_start_epoch"))
    if not cycle_id:
        cycle_id = _content_cycle_scope(None, None)

    if not member_id or trig_i is None:
        return

    now_epoch = time.time()

    conn = _content_db_connect()
    try:
        _content_db_ensure_schema(conn)
        conn.execute("BEGIN IMMEDIATE")

        claim = _content_claim_get(conn, member_key, folder, cycle_id, trig_i)
        if not claim:
            # Fallback: locate by token if legacy callers omitted cycle_id.
            row = conn.execute(
                """
                SELECT *
                FROM user_content_claims
                WHERE token = ?
                LIMIT 1
                """,
                (token,),
            ).fetchone()
            claim = dict(row) if row else {}

        if claim and _content_claim_is_delivered(claim):
            if str(claim.get("token") or "").strip() == str(token or "").strip():
                row = conn.execute(
                    "SELECT pending_token FROM user_content_state WHERE member_id=? AND content_folder=?",
                    (member_key, folder),
                ).fetchone()
                if row and str(row["pending_token"] or "") == token:
                    conn.execute(
                        """
                        UPDATE user_content_state
                        SET pending_token=NULL,
                            pending_trigger_minute=NULL,
                            pending_file_name=NULL,
                            pending_sequence=NULL,
                            pending_stage=NULL,
                            pending_kind=NULL,
                            pending_created_epoch=NULL,
                            updated_epoch=?
                        WHERE member_id=? AND content_folder=? AND pending_token=?
                        """,
                        (now_epoch, member_key, folder, token),
                    )
            conn.commit()
            return

        if claim:
            cycle_id = str(claim.get("cycle_id") or "").strip() or cycle_id
            if not file_name:
                file_name = str(claim.get("content_name") or "").strip()
            if not seq:
                seq = str(claim.get("content_sequence") or "").strip()
            if not stage:
                stage = str(claim.get("content_stage") or "").strip()
            if not kind:
                kind = str(claim.get("content_kind") or "").strip()
            if not url:
                url = str(claim.get("content_url") or "").strip()

        _content_claim_upsert(
            conn,
            token=token,
            member_id=member_key,
            content_folder=folder,
            cycle_id=cycle_id,
            trigger_minute=trig_i,
            content_sequence=seq,
            content_name=file_name,
            content_kind=kind,
            content_stage=stage,
            content_url=url,
            claim_state="delivered_host",
            claimed_via="host_pending",
            session_id=str(payload.get("session_id") or "").strip(),
            now_epoch=now_epoch,
            delivered_epoch=now_epoch,
        )

        _content_history_insert(
            conn,
            token,
            member_key,
            folder,
            trig_i,
            seq,
            file_name,
            kind,
            stage,
            url,
            "host_pending",
        )

        row = conn.execute(
            "SELECT window_sent_count, pending_token, window_complete FROM user_content_state WHERE member_id=? AND content_folder=?",
            (member_key, folder),
        ).fetchone()
        if row and str(row["pending_token"] or "") == token:
            sent_count = int(row["window_sent_count"] or 0) + 1
            complete = 0
            if folder == "friend":
                complete = 1
            elif str(stage or "").strip().lower() == "end":
                complete = 1

            conn.execute(
                """
                UPDATE user_content_state
                SET pending_token=NULL,
                    pending_trigger_minute=NULL,
                    pending_file_name=NULL,
                    pending_sequence=NULL,
                    pending_stage=NULL,
                    pending_kind=NULL,
                    pending_created_epoch=NULL,
                    last_sequence=?,
                    last_stage=?,
                    last_trigger_minute=?,
                    window_sent_count=?,
                    window_complete=?,
                    updated_epoch=?
                WHERE member_id=? AND content_folder=? AND pending_token=?
                """,
                (
                    seq,
                    stage,
                    trig_i,
                    sent_count,
                    complete,
                    now_epoch,
                    member_key,
                    folder,
                    token,
                ),
            )

        conn.commit()
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _usage_db_connect() -> sqlite3.Connection:
    path = _usage_db_path()
    conn = sqlite3.connect(path, timeout=30, check_same_thread=False)
    conn.row_factory = sqlite3.Row
    try:
        conn.execute("PRAGMA journal_mode=WAL;")
    except Exception:
        pass
    try:
        conn.execute("PRAGMA synchronous=NORMAL;")
    except Exception:
        pass
    try:
        conn.execute("PRAGMA busy_timeout=5000;")
    except Exception:
        pass
    return conn


def _usage_db_ensure_schema(conn: sqlite3.Connection) -> None:
    global _USAGE_DB_READY
    if _USAGE_DB_READY:
        return
    with _USAGE_DB_LOCK:
        if _USAGE_DB_READY:
            return
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS member_usage_minutes (
              member_id TEXT PRIMARY KEY,
              create_datetime datetime DEFAULT CURRENT_TIMESTAMP,
              update_datetime datetime DEFAULT CURRENT_TIMESTAMP,
              cycle_start_epoch REAL,
              cycle_days INTEGER,
              plan_name TEXT,
              plan_signature TEXT,
              free_minutes_total INTEGER,
              purchased_seconds REAL DEFAULT 0,
              used_seconds REAL DEFAULT 0,
              last_seen_epoch REAL,
              restart_grace INTEGER DEFAULT 0,
              update_reason TEXT
            );
            """
        )
        conn.execute("CREATE INDEX IF NOT EXISTS idx_member_usage_minutes_cycle ON member_usage_minutes(cycle_start_epoch);")
        conn.execute("CREATE INDEX IF NOT EXISTS idx_member_usage_minutes_plan ON member_usage_minutes(plan_name);")
        # One-time migration: legacy usage_minutes.sqlite3 -> econnect.sqlite3
        # We only import rows that do NOT already exist in econnect, to avoid
        # overwriting newer server-side state.
        try:
            dest_path = _ensure_econnect_db_seeded()
            legacy_path = (_LEGACY_USAGE_DB_PATH or "").strip()
            if (
                legacy_path
                and os.path.exists(legacy_path)
                and os.path.abspath(legacy_path) != os.path.abspath(dest_path)
            ):
                lconn = sqlite3.connect(legacy_path)
                lconn.row_factory = sqlite3.Row
                try:
                    lcur = lconn.cursor()
                    lcur.execute(
                        "SELECT 1 FROM sqlite_master WHERE type='table' AND name='member_usage_minutes' LIMIT 1;"
                    )
                    if lcur.fetchone() is not None:
                        legacy_rows = lconn.execute("SELECT * FROM member_usage_minutes;").fetchall() or []
                        for r in legacy_rows:
                            try:
                                member_id = r["member_id"]
                                # Skip if already present
                                if conn.execute(
                                    "SELECT 1 FROM member_usage_minutes WHERE member_id = ? LIMIT 1;",
                                    (member_id,),
                                ).fetchone() is not None:
                                    continue

                                conn.execute(
                                    """
                                    INSERT INTO member_usage_minutes (
                                      member_id, create_datetime, update_datetime,
                                      cycle_start_epoch, cycle_days,
                                      plan_name, plan_signature,
                                      free_minutes_total,
                                      purchased_seconds, used_seconds,
                                      last_seen_epoch, restart_grace,
                                      update_reason
                                    ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?);
                                    """,
                                    (
                                        member_id,
                                        r["create_datetime"] if "create_datetime" in r.keys() else None,
                                        r["update_datetime"] if "update_datetime" in r.keys() else None,
                                        r["cycle_start_epoch"] if "cycle_start_epoch" in r.keys() else None,
                                        r["cycle_days"] if "cycle_days" in r.keys() else None,
                                        r["plan_name"] if "plan_name" in r.keys() else None,
                                        r["plan_signature"] if "plan_signature" in r.keys() else None,
                                        r["free_minutes_total"] if "free_minutes_total" in r.keys() else None,
                                        r["purchased_seconds"] if "purchased_seconds" in r.keys() else 0,
                                        r["used_seconds"] if "used_seconds" in r.keys() else 0,
                                        r["last_seen_epoch"] if "last_seen_epoch" in r.keys() else None,
                                        r["restart_grace"] if "restart_grace" in r.keys() else 0,
                                        r["update_reason"] if "update_reason" in r.keys() else None,
                                    ),
                                )
                            except Exception:
                                continue
                finally:
                    try:
                        lconn.close()
                    except Exception:
                        pass
        except Exception:
            # Never fail API startup due to migration.
            pass
        conn.commit()
        _USAGE_DB_READY = True


def _usage_db_get_row(conn: sqlite3.Connection, member_id: str) -> Optional[sqlite3.Row]:
    cur = conn.execute("SELECT * FROM member_usage_minutes WHERE member_id = ?;", (member_id,))
    return cur.fetchone()


def _usage_db_set_update_reason(conn: sqlite3.Connection, member_id: str, reason: str) -> None:
    conn.execute(
        """
        UPDATE member_usage_minutes
           SET update_reason = ?,
               update_datetime = CURRENT_TIMESTAMP
         WHERE member_id = ?;
        """,
        (reason, member_id),
    )


def _usage_db_upsert_init(
    conn: sqlite3.Connection,
    member_id: str,
    now: float,
    cycle_days: int,
    plan_name: str,
    plan_signature: str,
    free_minutes_total: int,
    used_seconds: float = 0.0,
    purchased_seconds: float = 0.0,
    last_seen_epoch: Optional[float] = None,
    restart_grace: int = 0,
    update_reason: str = "init",
) -> None:
    conn.execute(
        """
        INSERT INTO member_usage_minutes
        (member_id, cycle_start_epoch, cycle_days, plan_name, plan_signature, free_minutes_total,
         used_seconds, purchased_seconds, last_seen_epoch, restart_grace, update_reason)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        ON CONFLICT(member_id) DO UPDATE SET
          cycle_start_epoch=excluded.cycle_start_epoch,
          cycle_days=excluded.cycle_days,
          plan_name=excluded.plan_name,
          plan_signature=excluded.plan_signature,
          free_minutes_total=excluded.free_minutes_total,
          used_seconds=excluded.used_seconds,
          purchased_seconds=excluded.purchased_seconds,
          last_seen_epoch=COALESCE(member_usage_minutes.last_seen_epoch, excluded.last_seen_epoch),
          restart_grace=excluded.restart_grace,
          update_reason=excluded.update_reason,
          update_datetime=CURRENT_TIMESTAMP;
        """,
        (
            member_id,
            float(now),
            int(cycle_days),
            plan_name,
            plan_signature,
            int(free_minutes_total),
            float(used_seconds),
            float(purchased_seconds),
            float(last_seen_epoch) if last_seen_epoch is not None else None,
            int(restart_grace),
            update_reason,
        ),
    )


def _usage_db_maybe_migrate_from_json(conn: sqlite3.Connection, member_id: str) -> bool:
    """
    One-time best-effort migration from the legacy /home/elaralo_usage.json store.
    We only migrate if:
      - row doesn't exist yet, AND
      - the json store contains a record for either:
          a) member::<member_id>
          b) member_id as-is
    """
    try:
        # legacy store is used by earlier builds
        store = _load_usage_store()  
        if not isinstance(store, dict):
            return False
    except Exception:
        return False

    legacy_keys = []
    if member_id:
        legacy_keys.append(f"member::{member_id}")
        legacy_keys.append(member_id)

    rec = None
    for k in legacy_keys:
        v = store.get(k)
        if isinstance(v, dict):
            rec = v
            break
    if not isinstance(rec, dict):
        return False

    try:
        cycle_start = float(rec.get("cycle_start") or 0.0) or time.time()
        cycle_days = int(rec.get("cycle_days") or USAGE_CYCLE_DAYS)  
        plan_name = str(rec.get("plan_name") or "").strip()
        free_minutes_total = int(rec.get("minutes_allowed") or 0) if rec.get("minutes_allowed") is not None else 0
        used_seconds = float(rec.get("used_seconds") or 0.0)
        purchased_seconds = float(rec.get("purchased_seconds") or 0.0)
        last_seen = rec.get("last_seen")
        last_seen_epoch = float(last_seen) if last_seen is not None else None
        restart_grace = int(rec.get("restart_grace") or 0)
        plan_signature = str(rec.get("plan_signature") or "").strip() or f"{plan_name}|{free_minutes_total}|{cycle_days}"
    except Exception:
        return False

    _usage_db_upsert_init(
        conn,
        member_id=member_id,
        now=cycle_start,
        cycle_days=cycle_days,
        plan_name=plan_name,
        plan_signature=plan_signature,
        free_minutes_total=free_minutes_total,
        used_seconds=used_seconds,
        purchased_seconds=purchased_seconds,
        last_seen_epoch=last_seen_epoch,
        restart_grace=restart_grace,
        update_reason="migrated_from_json",
    )
    return True


def _usage_db_ensure_member_row(
    conn: sqlite3.Connection,
    identity_key: str,
    is_trial: bool,
    plan_name: str,
    minutes_allowed_override: Optional[int],
    cycle_days_override: Optional[int],
    now: float,
    allow_create: bool = True,
) -> sqlite3.Row:
    """
    Ensures a DB row exists and performs any eligibility updates that are allowed to change totals:
      - cycle reset (once per cycle)
      - plan upgrade/change (when signature changes)

    IMPORTANT: We do NOT change totals just because the payload is re-sent;
               totals are only updated on init, cycle reset, plan change, or paygo credit.
    """
    member_id = _normalize_usage_member_id(identity_key)
    if not member_id:
        # Should never happen, but avoid NULL keys.
        member_id = f"unknown::{hash(identity_key)}"

    requested_cycle_days = int(cycle_days_override) if cycle_days_override is not None else int(USAGE_CYCLE_DAYS)  
    if requested_cycle_days < 0:
        requested_cycle_days = int(USAGE_CYCLE_DAYS)  

    if minutes_allowed_override is not None:
        requested_free_minutes = int(minutes_allowed_override)
    else:
        if is_trial:
            requested_free_minutes = int(TRIAL_MINUTES)  
        else:
            requested_free_minutes = int(_included_minutes_for_plan(plan_name))  

    # Clamp free minutes to a sane floor.
    if requested_free_minutes < 0:
        requested_free_minutes = 0

    # Plan signature: anything that should cause a "plan change" update.
    # We include:
    #  - trial flag
    #  - plan name
    #  - free minutes (from rebrandingKey override or plan map)
    #  - cycle length
    requested_sig = f"{int(bool(is_trial))}|{plan_name}|{requested_free_minutes}|{requested_cycle_days}"

    row = _usage_db_get_row(conn, member_id)

    if row is None and allow_create:
        # Best-effort migration from the legacy JSON store.
        try:
            _usage_db_maybe_migrate_from_json(conn, member_id)
        except Exception:
            pass
        row = _usage_db_get_row(conn, member_id)

    if row is None and allow_create:
        _usage_db_upsert_init(
            conn,
            member_id=member_id,
            now=now,
            cycle_days=requested_cycle_days,
            plan_name=plan_name,
            plan_signature=requested_sig,
            free_minutes_total=requested_free_minutes,
            used_seconds=0.0,
            purchased_seconds=0.0,
            last_seen_epoch=None,
            restart_grace=0,
            update_reason="init",
        )
        row = _usage_db_get_row(conn, member_id)

    if row is None:
        raise RuntimeError("Unable to initialize usage row")

        # Cycle reset: applies for any account with cycle_days > 0.
    try:
        cycle_start = float(row["cycle_start_epoch"] or 0.0) or float(now)
    except Exception:
        cycle_start = float(now)

    try:
        stored_cycle_days = int(row["cycle_days"] or 0) or requested_cycle_days
    except Exception:
        stored_cycle_days = requested_cycle_days

    # Normalize stored cycle days if missing
    if stored_cycle_days <= 0:
        stored_cycle_days = requested_cycle_days

    # Refresh plan metadata if the upstream signature changed (upgrade / plan change).
    stored_sig = str(row["plan_signature"] or "").strip()

    # Perform cycle reset before plan change so the next cycle starts clean.
    if stored_cycle_days > 0:
        cycle_len = float(stored_cycle_days) * 86400.0
        if (float(now) - float(cycle_start)) >= cycle_len:
            # Carryover rules:
            #   - Paid plans: carry over ALL unused minutes (included + purchased).
            #   - Free Trial: carry over ONLY unused purchased minutes; unused free minutes do NOT carry over.
            try:
                old_free_min = int(row["free_minutes_total"] or 0)
            except Exception:
                old_free_min = 0
            try:
                old_purchased_s = float(row["purchased_seconds"] or 0.0)
            except Exception:
                old_purchased_s = 0.0
            try:
                old_used_s = float(row["used_seconds"] or 0.0)
            except Exception:
                old_used_s = 0.0

            old_free_s = max(0.0, float(old_free_min) * 60.0)

            if bool(is_trial):
                # Assume free minutes are consumed first, then purchased minutes.
                purchased_used_s = max(0.0, float(old_used_s) - float(old_free_s))
                if purchased_used_s > float(old_purchased_s):
                    purchased_used_s = float(old_purchased_s)
                carryover_seconds = max(0.0, float(old_purchased_s) - float(purchased_used_s))
                cycle_reason = "cycle_reset_trial_free_rollover_zero"
            else:
                old_total_s = max(0.0, float(old_free_s) + float(old_purchased_s))
                carryover_seconds = max(0.0, float(old_total_s) - float(old_used_s))
                cycle_reason = "cycle_reset"

            conn.execute(
                """
                UPDATE member_usage_minutes
                   SET cycle_start_epoch = ?,
                       cycle_days = ?,
                       plan_name = ?,
                       plan_signature = ?,
                       free_minutes_total = ?,
                       used_seconds = 0,
                       purchased_seconds = ?,
                       restart_grace = 0,
                       update_reason = ?,
                       update_datetime = CURRENT_TIMESTAMP
                 WHERE member_id = ?;
                """,
                (
                    float(now),
                    int(requested_cycle_days),
                    plan_name,
                    requested_sig,
                    int(requested_free_minutes),
                    float(carryover_seconds),
                    cycle_reason,
                    member_id,
                ),
            )
            row = _usage_db_get_row(conn, member_id)
            stored_sig = requested_sig

    # Plan upgrade/change mid-cycle: update free minutes (does not reset used or purchases).
    # This is the only other way the "total available minutes" can change automatically.
    if stored_sig != requested_sig:
        conn.execute(
            """
            UPDATE member_usage_minutes
               SET cycle_days = ?,
                   plan_name = ?,
                   plan_signature = ?,
                   free_minutes_total = ?,
                   update_reason = ?,
                   update_datetime = CURRENT_TIMESTAMP
             WHERE member_id = ?;
            """,
            (
                int(requested_cycle_days),
                plan_name,
                requested_sig,
                int(requested_free_minutes),
                "plan_change_or_upgrade",
                member_id,
            ),
        )
        row = _usage_db_get_row(conn, member_id)

    if row is None:
        raise RuntimeError("Usage row missing after updates")
    return row


def _usage_minutes_remaining_display(remaining_seconds: float) -> int:
    remaining = max(0.0, float(remaining_seconds or 0.0))
    if remaining <= 0.0:
        return 0
    return max(1, int(math.ceil(remaining / 60.0)))


def _usage_info_from_row(row: sqlite3.Row) -> Dict[str, Any]:
    free_minutes_total = int(row["free_minutes_total"] or 0)
    purchased_seconds = float(row["purchased_seconds"] or 0.0)
    used_seconds = float(row["used_seconds"] or 0.0)

    total_seconds = max(0.0, float(free_minutes_total) * 60.0 + purchased_seconds)
    used_seconds = min(total_seconds, max(0.0, used_seconds))
    remaining_seconds = max(0.0, total_seconds - used_seconds)

    minutes_included = max(0, int(free_minutes_total))
    minutes_purchased = max(0, int(purchased_seconds // 60))
    minutes_total = max(minutes_included + minutes_purchased, int((used_seconds + remaining_seconds) // 60))

    return {
        "member_id": str(row["member_id"]),
        "cycle_start_epoch": row["cycle_start_epoch"],
        "cycle_days": int(row["cycle_days"] or 0),
        "plan_name": str(row["plan_name"] or ""),
        "minutes_included": minutes_included,
        "minutes_purchased": minutes_purchased,
        # Keep legacy field name used by frontend: minutes_allowed == TOTAL budget in minutes.
        "minutes_allowed": max(0, int(total_seconds // 60)),
        "minutes_total": minutes_total,
        "minutes_used": max(0, int(used_seconds // 60)),
        "minutes_remaining": _usage_minutes_remaining_display(remaining_seconds),
        # Seconds-level fields (used by scheduled content delivery + debugging).
        "used_seconds": used_seconds,
        "remaining_seconds": remaining_seconds,
        "total_seconds": total_seconds,
        "purchased_seconds": purchased_seconds,
        # Aliases used by older scheduler code paths.
        "cycle_used_seconds": used_seconds,
        "cycle_remaining_seconds": remaining_seconds,
        "cycle_total_seconds": total_seconds,
        "minutes_exhausted": remaining_seconds <= 0.0,
        "update_reason": str(row["update_reason"] or ""),
    }


def _usage_admin_debug_sync(member_id: str, limit: int, now: float) -> Dict[str, Any]:
    """Sync helper for /admin/usage/debug (runs in threadpool).

    If member_id is provided, returns a detailed record including raw DB row fields and computed totals.
    If member_id is empty, returns the most recently updated rows (limited) for triage.
    """
    conn = _usage_db_connect()
    _usage_db_ensure_schema(conn)

    member_id_norm = _normalize_usage_member_id(member_id) if member_id else ""
    if member_id_norm:
        row = _usage_db_get_row(conn, member_id_norm)
        if row is None:
            return {"ok": False, "error": "not_found", "member_id": member_id_norm, "db_path": _usage_db_path()}

        raw_row = {k: row[k] for k in row.keys()}
        info = _usage_info_from_row(row)

        try:
            cycle_start = float(row["cycle_start_epoch"] or 0.0)
        except Exception:
            cycle_start = 0.0
        try:
            cycle_days = int(row["cycle_days"] or 0)
        except Exception:
            cycle_days = 0

        cycle_end = cycle_start + float(cycle_days) * 86400.0 if cycle_start and cycle_days > 0 else None
        reset_in_seconds = max(0.0, float(cycle_end - now)) if cycle_end else None

        # Provide seconds-level totals for debugging (minutes are floored in _usage_info_from_row).
        free_minutes_total = int(row["free_minutes_total"] or 0)
        purchased_seconds = float(row["purchased_seconds"] or 0.0)
        used_seconds = float(row["used_seconds"] or 0.0)
        total_seconds = max(0.0, float(free_minutes_total) * 60.0 + purchased_seconds)
        used_seconds_c = min(total_seconds, max(0.0, used_seconds))
        remaining_seconds = max(0.0, total_seconds - used_seconds_c)

        return {
            "ok": True,
            "db_path": _usage_db_path(),
            "now_epoch": now,
            "member_id": member_id_norm,
            "raw_row": raw_row,
            "computed": {
                **info,
                "plan_signature": str(row["plan_signature"] or ""),
                "free_minutes_total": free_minutes_total,
                "purchased_seconds": purchased_seconds,
                "used_seconds": used_seconds,
                "total_seconds": total_seconds,
                "remaining_seconds": remaining_seconds,
                "cycle_end_epoch": cycle_end,
                "reset_in_seconds": reset_in_seconds,
            },
        }

    # No member_id -> list recent rows
    try:
        lim = int(limit)
    except Exception:
        lim = 25
    lim = max(1, min(lim, 200))

    rows = conn.execute(
        "SELECT * FROM member_usage_minutes ORDER BY update_datetime DESC, create_datetime DESC LIMIT ?;",
        (lim,),
    ).fetchall()

    items: List[Dict[str, Any]] = []
    for r in rows:
        try:
            info = _usage_info_from_row(r)
        except Exception:
            info = {}
        try:
            raw_row = {k: r[k] for k in r.keys()}
        except Exception:
            raw_row = {}
        items.append(
            {
                "member_id": str(r["member_id"]),
                "update_datetime": str(r["update_datetime"] or ""),
                "update_reason": str(r["update_reason"] or ""),
                "plan_name": str(r["plan_name"] or ""),
                "plan_signature": str(r["plan_signature"] or ""),
                "minutes_allowed": info.get("minutes_allowed"),
                "minutes_used": info.get("minutes_used"),
                "minutes_remaining": info.get("minutes_remaining"),
                "raw_row": raw_row,
            }
        )

    return {"ok": True, "db_path": _usage_db_path(), "now_epoch": now, "count": len(items), "rows": items}


# --- Override legacy usage functions to use SQLite table state ---

def _usage_credit_minutes_sync(identity_key: str, add_minutes: int) -> Dict[str, Any]:
    """
    Credits purchased minutes (PayGo) to the DB-backed usage state.

    Important behaviors:
      - This ALWAYS increases purchased_seconds (no caps).
      - It sets restart_grace so we don't bill the gap between purchase and next chat turn.
      - It logs update_reason='paygo_credit'.
    """
    member_id = _normalize_usage_member_id(identity_key)
    if not member_id:
        member_id = str(identity_key or "").strip()

    try:
        add_minutes_i = int(add_minutes)
    except Exception:
        add_minutes_i = 0

    if add_minutes_i <= 0:
        return {"ok": False, "error": "add_minutes must be > 0"}

    now = time.time()
    add_seconds = float(add_minutes_i) * 60.0

    with _USAGE_LOCK:  
        conn = _usage_db_connect()
        try:
            _usage_db_ensure_schema(conn)
            conn.execute("BEGIN IMMEDIATE;")

            # Ensure row exists (plan metadata may be unknown here; we keep existing if present).
            row = _usage_db_get_row(conn, member_id)
            if row is None:
                _usage_db_upsert_init(
                    conn,
                    member_id=member_id,
                    now=now,
                    cycle_days=int(USAGE_CYCLE_DAYS),  
                    plan_name="",
                    plan_signature=f"0||0|{int(USAGE_CYCLE_DAYS)}",  
                    free_minutes_total=0,
                    used_seconds=0.0,
                    purchased_seconds=0.0,
                    last_seen_epoch=None,
                    restart_grace=0,
                    update_reason="init_for_paygo_credit",
                )
                row = _usage_db_get_row(conn, member_id)

            purchased_seconds = float(row["purchased_seconds"] or 0.0) if row is not None else 0.0
            new_purchased = max(0.0, purchased_seconds + add_seconds)

            conn.execute(
                """
                UPDATE member_usage_minutes
                   SET purchased_seconds = ?,
                       restart_grace = 1,
                       update_reason = ?,
                       update_datetime = CURRENT_TIMESTAMP
                 WHERE member_id = ?;
                """,
                (float(new_purchased), "paygo_credit", member_id),
            )
            conn.commit()

            row2 = _usage_db_get_row(conn, member_id)
            if row2 is None:
                return {"ok": True, "member_id": member_id, "added_minutes": add_minutes_i}
            info = _usage_info_from_row(row2)
            info.update({"ok": True, "added_minutes": add_minutes_i})
            return info
        finally:
            try:
                conn.close()
            except Exception:
                pass


def _usage_charge_and_check_sync(
    identity_key: str,
    *,
    is_trial: bool,
    plan_name: str,
    minutes_allowed_override: Optional[int],
    cycle_days_override: Optional[int],
) -> Tuple[bool, Dict[str, Any]]:
    """
    DB-backed usage charging.

    We charge time based on wall-clock delta between turns, with an idle grace period,
    and a max-billable cap per request. Totals (free minutes + purchases) are persisted
    per member_id and only change on:
      - init
      - cycle reset
      - plan upgrade/change
      - paygo credit
    """
    now = time.time()

    # Normalize legacy identity keys (member::<id>) to member_id for the DB.
    member_id = _normalize_usage_member_id(identity_key)
    if not member_id:
        member_id = str(identity_key or "").strip()

    with _USAGE_LOCK:  
        conn = _usage_db_connect()
        try:
            _usage_db_ensure_schema(conn)
            conn.execute("BEGIN IMMEDIATE;")

            row = _usage_db_ensure_member_row(
                conn,
                identity_key=identity_key,
                is_trial=bool(is_trial),
                plan_name=str(plan_name or "").strip(),
                minutes_allowed_override=minutes_allowed_override,
                cycle_days_override=cycle_days_override,
                now=now,
                allow_create=True,
            )

            free_minutes_total = int(row["free_minutes_total"] or 0)
            purchased_seconds = float(row["purchased_seconds"] or 0.0)
            used_seconds = float(row["used_seconds"] or 0.0)

            allowed_seconds = max(0.0, float(free_minutes_total) * 60.0 + purchased_seconds)
            used_seconds = min(allowed_seconds, max(0.0, used_seconds))

            last_seen = row["last_seen_epoch"]
            restart_grace = int(row["restart_grace"] or 0)

            delta = 0.0
            if restart_grace:
                # Do not bill the gap after a PayGo credit.
                conn.execute(
                    """
                    UPDATE member_usage_minutes
                       SET restart_grace = 0,
                           update_datetime = CURRENT_TIMESTAMP
                     WHERE member_id = ?;
                    """,
                    (member_id,),
                )
                delta = 0.0
            else:
                if last_seen is None:
                    delta = 0.0
                else:
                    try:
                        delta = float(now) - float(last_seen)
                    except Exception:
                        delta = 0.0

                # Idle grace: if the user was away for a while, don't bill the gap.
                try:
                    if delta > float(USAGE_IDLE_GRACE_SECONDS):  
                        delta = 0.0
                except Exception:
                    pass

                # Cap per request for safety.
                try:
                    cap = float(USAGE_MAX_BILLABLE_SECONDS_PER_REQUEST)  
                    if delta > cap:
                        delta = cap
                except Exception:
                    pass

                if delta < 0:
                    delta = 0.0

            new_used = min(allowed_seconds, used_seconds + float(delta))

            conn.execute(
                """
                UPDATE member_usage_minutes
                   SET used_seconds = ?,
                       last_seen_epoch = ?,
                       update_datetime = CURRENT_TIMESTAMP
                 WHERE member_id = ?;
                """,
                (float(new_used), float(now), member_id),
            )
            conn.commit()

            row2 = _usage_db_get_row(conn, member_id)
            if row2 is None:
                remaining_seconds = max(0.0, allowed_seconds - new_used)
                ok = remaining_seconds > 0.0
                return ok, {"minutes_used": int(new_used // 60), "minutes_allowed": int(allowed_seconds // 60), "minutes_remaining": _usage_minutes_remaining_display(remaining_seconds), "used_seconds": float(new_used), "remaining_seconds": float(remaining_seconds), "total_seconds": float(allowed_seconds)}
            info = _usage_info_from_row(row2)

            ok = float(info.get("remaining_seconds") or 0.0) > 0.0
            # Maintain legacy key name expected elsewhere in the app.
            info["identity_key"] = member_id
            return ok, info
        finally:
            try:
                conn.close()
            except Exception:
                pass


def _usage_peek_sync(
    identity_key: str,
    *,
    is_trial: bool,
    plan_name: str,
    minutes_allowed_override: Optional[int],
    cycle_days_override: Optional[int],
) -> Tuple[bool, Dict[str, Any]]:
    """
    Returns current minute balance WITHOUT charging additional time.
    Still performs eligible maintenance that may affect totals:
      - init (if missing)
      - cycle reset
      - plan upgrade/change
    """
    now = time.time()

    member_id = _normalize_usage_member_id(identity_key)
    if not member_id:
        member_id = str(identity_key or "").strip()

    with _USAGE_LOCK:  
        conn = _usage_db_connect()
        try:
            _usage_db_ensure_schema(conn)
            conn.execute("BEGIN IMMEDIATE;")

            row = _usage_db_ensure_member_row(
                conn,
                identity_key=identity_key,
                is_trial=bool(is_trial),
                plan_name=str(plan_name or "").strip(),
                minutes_allowed_override=minutes_allowed_override,
                cycle_days_override=cycle_days_override,
                now=now,
                allow_create=True,
            )

            conn.commit()

            row2 = _usage_db_get_row(conn, member_id)
            if row2 is None:
                return True, {"minutes_used": 0, "minutes_allowed": 0, "minutes_remaining": 0, "identity_key": member_id}

            info = _usage_info_from_row(row2)
            ok = float(info.get("remaining_seconds") or 0.0) > 0.0
            info["identity_key"] = member_id
            return ok, info
        finally:
            try:
                conn.close()
            except Exception:
                pass


