def _host_onboarding_income_estimate_from_title(title: Any) -> str:
    t = _host_onboarding_safe_str(title).lower()
    if not t:
        return ""
    rules = [
        (["chief executive", "ceo", "president", "founder", "co-founder", "owner"], "$180,000-$450,000+"),
        (["chief", "vp", "vice president", "senior vice president", "svp"], "$140,000-$280,000"),
        (["director", "head of"], "$100,000-$220,000"),
        (["manager", "producer", "lead", "supervisor"], "$70,000-$150,000"),
        (["coordinator", "specialist", "analyst", "consultant"], "$55,000-$120,000"),
        (["assistant", "associate", "representative"], "$40,000-$85,000"),
        (["teacher", "nurse", "designer", "creator", "artist"], "$50,000-$130,000"),
        (["student", "intern"], "$0-$35,000"),
    ]
    for needles, band in rules:
        if any(n in t for n in needles):
            return band
    return "$60,000-$140,000"


def _host_onboarding_ensure_schema(conn: sqlite3.Connection) -> None:
    conn.execute(
        f"""
        CREATE TABLE IF NOT EXISTS {_HOST_ONBOARDING_SESSIONS_TABLE} (
            session_id TEXT PRIMARY KEY,
            member_id TEXT NOT NULL,
            brand TEXT,
            avatar TEXT,
            host_display_name TEXT,
            logged_in INTEGER NOT NULL DEFAULT 0,
            workflow_state TEXT NOT NULL DEFAULT 'not_started',
            publish_status TEXT NOT NULL DEFAULT 'draft',
            limited_publish_allowed INTEGER NOT NULL DEFAULT 0,
            full_publish_ready INTEGER NOT NULL DEFAULT 0,
            approved_version_id TEXT,
            basics_json TEXT NOT NULL DEFAULT '{{}}',
            derived_json TEXT NOT NULL DEFAULT '{{}}',
            review_json TEXT NOT NULL DEFAULT '{{}}',
            completion_json TEXT NOT NULL DEFAULT '{{}}',
            three_d_opt_in INTEGER NOT NULL DEFAULT 0,
            created_epoch REAL NOT NULL,
            updated_epoch REAL NOT NULL
        )
        """
    )
    conn.execute(
        f"CREATE INDEX IF NOT EXISTS idx_{_HOST_ONBOARDING_SESSIONS_TABLE}_member ON {_HOST_ONBOARDING_SESSIONS_TABLE}(member_id, updated_epoch DESC)"
    )
    conn.execute(
        f"""
        CREATE TABLE IF NOT EXISTS {_HOST_ONBOARDING_ASSETS_TABLE} (
            asset_id TEXT PRIMARY KEY,
            session_id TEXT NOT NULL,
            slot_key TEXT NOT NULL,
            required_flag INTEGER NOT NULL DEFAULT 0,
            url TEXT NOT NULL,
            file_name TEXT,
            content_type TEXT,
            size_bytes INTEGER NOT NULL DEFAULT 0,
            width_px INTEGER NOT NULL DEFAULT 0,
            height_px INTEGER NOT NULL DEFAULT 0,
            duration_seconds REAL NOT NULL DEFAULT 0,
            validation_status TEXT NOT NULL DEFAULT 'pending',
            validation_errors_json TEXT NOT NULL DEFAULT '[]',
            created_epoch REAL NOT NULL,
            updated_epoch REAL NOT NULL,
            UNIQUE(session_id, slot_key)
        )
        """
    )
    try:
        cols = {str(row[1] or "").strip().lower() for row in conn.execute(f"PRAGMA table_info({_HOST_ONBOARDING_ASSETS_TABLE})").fetchall()}
        if "duration_seconds" not in cols:
            conn.execute(f"ALTER TABLE {_HOST_ONBOARDING_ASSETS_TABLE} ADD COLUMN duration_seconds REAL NOT NULL DEFAULT 0")
    except Exception:
        pass
    conn.execute(
        f"""
        CREATE TABLE IF NOT EXISTS {_HOST_ONBOARDING_VERSIONS_TABLE} (
            version_id TEXT PRIMARY KEY,
            session_id TEXT NOT NULL,
            member_id TEXT NOT NULL,
            version_no INTEGER NOT NULL,
            publish_scope TEXT NOT NULL,
            profile_json TEXT NOT NULL,
            created_epoch REAL NOT NULL,
            approved_epoch REAL NOT NULL
        )
        """
    )
    conn.execute(
        f"CREATE INDEX IF NOT EXISTS idx_{_HOST_ONBOARDING_VERSIONS_TABLE}_session ON {_HOST_ONBOARDING_VERSIONS_TABLE}(session_id, version_no DESC)"
    )
    conn.execute(
        f"""
        CREATE TABLE IF NOT EXISTS {_HOST_ONBOARDING_AUDIT_TABLE} (
            audit_id TEXT PRIMARY KEY,
            session_id TEXT NOT NULL,
            member_id TEXT NOT NULL,
            event_type TEXT NOT NULL,
            payload_json TEXT NOT NULL,
            created_epoch REAL NOT NULL
        )
        """
    )


def _host_onboarding_audit(conn: sqlite3.Connection, session_id: str, member_id: str, event_type: str, payload: Any) -> None:
    try:
        conn.execute(
            f"INSERT INTO {_HOST_ONBOARDING_AUDIT_TABLE} (audit_id, session_id, member_id, event_type, payload_json, created_epoch) VALUES (?, ?, ?, ?, ?, ?)",
            (uuid.uuid4().hex, session_id, member_id, event_type, _host_onboarding_json_dumps(payload), _host_onboarding_now()),
        )
    except Exception:
        pass


def _host_onboarding_required_slot(slot_key: str) -> bool:
    return _host_onboarding_safe_str(slot_key) in set(_HOST_ONBOARDING_REQUIRED_SLOTS)


def _host_onboarding_validate_asset(
    slot_key: str,
    content_type: str,
    file_name: str,
    size_bytes: int,
    width_px: int = 0,
    height_px: int = 0,
    duration_seconds: float = 0.0,
) -> Tuple[str, List[str]]:
    errors: List[str] = []
    slot = _host_onboarding_safe_str(slot_key)
    ct = _host_onboarding_safe_str(content_type).lower()
    fn = _host_onboarding_safe_str(file_name)
    if slot not in _HOST_ONBOARDING_ALLOWED_SLOTS:
        errors.append("Unknown onboarding asset slot.")
        return ("needs_review", errors)

    if slot == _HOST_ONBOARDING_VOICE_SLOT:
        if ct not in _HOST_ONBOARDING_ALLOWED_AUDIO_TYPES:
            errors.append("Only audio files supported by the browser recorder/uploader are accepted for the minimum 30-second voice capture.")
        if int(size_bytes or 0) <= 0:
            errors.append("Uploaded voice capture is empty.")
        if int(size_bytes or 0) > int(_HOST_ONBOARDING_MAX_AUDIO_BYTES):
            errors.append("Uploaded voice capture exceeds the 15 MB limit.")
        if float(duration_seconds or 0.0) <= 0.0:
            errors.append("Voice capture duration could not be determined. Please record in the app or upload a standard audio file with readable duration metadata.")
        elif float(duration_seconds or 0.0) < float(_HOST_ONBOARDING_VOICE_MIN_SECONDS) - 0.5:
            errors.append(f"Voice capture must be at least {int(_HOST_ONBOARDING_VOICE_MIN_SECONDS)} seconds long.")
        if fn and len(fn) > 240:
            errors.append("Original file name is too long.")
        return ("accepted" if not errors else "needs_review"), errors

    if ct not in _HOST_ONBOARDING_ALLOWED_IMAGE_TYPES:
        errors.append("Only JPG, PNG, WebP, or HEIC images are supported in this onboarding step.")
    if int(size_bytes or 0) <= 0:
        errors.append("Uploaded photo is empty.")
    if int(size_bytes or 0) > int(_HOST_ONBOARDING_MAX_ASSET_BYTES):
        errors.append("Uploaded photo exceeds the 15 MB limit.")
    if width_px and height_px:
        if min(int(width_px), int(height_px)) < 600:
            errors.append("Photo resolution is too low. Minimum recommended size is 600px on the shortest side.")
    if fn and len(fn) > 240:
        errors.append("Original file name is too long.")
    return ("accepted" if not errors else "needs_review"), errors


def _host_onboarding_try_read_image_size(data: bytes) -> Tuple[int, int]:
    try:
        from PIL import Image  # type: ignore
        img = Image.open(io.BytesIO(data))
        return int(img.size[0] or 0), int(img.size[1] or 0)
    except Exception:
        return 0, 0


def _host_onboarding_session_row_to_dict(row: sqlite3.Row, assets: Optional[List[Dict[str, Any]]] = None) -> Dict[str, Any]:
    obj = dict(row) if row is not None else {}
    basics = _host_onboarding_json_loads(obj.get("basics_json"), {})
    derived = _host_onboarding_json_loads(obj.get("derived_json"), {})
    review = _host_onboarding_json_loads(obj.get("review_json"), {})
    completion = _host_onboarding_json_loads(obj.get("completion_json"), {})
    compiled_assets = assets if assets is not None else []
    return {
        "session_id": _host_onboarding_safe_str(obj.get("session_id")),
        "member_id": _host_onboarding_safe_str(obj.get("member_id")),
        "brand": _host_onboarding_safe_str(obj.get("brand")),
        "avatar": _host_onboarding_safe_str(obj.get("avatar")),
        "host_display_name": _host_onboarding_safe_str(obj.get("host_display_name")),
        "logged_in": bool(int(obj.get("logged_in") or 0) == 1),
        "workflow_state": _host_onboarding_safe_str(obj.get("workflow_state")) or "not_started",
        "publish_status": _host_onboarding_safe_str(obj.get("publish_status")) or "draft",
        "limited_publish_allowed": bool(int(obj.get("limited_publish_allowed") or 0) == 1),
        "full_publish_ready": bool(int(obj.get("full_publish_ready") or 0) == 1),
        "approved_version_id": _host_onboarding_safe_str(obj.get("approved_version_id")),
        "three_d_opt_in": bool(int(obj.get("three_d_opt_in") or 0) == 1),
        "basics": basics if isinstance(basics, dict) else {},
        "derived": derived if isinstance(derived, dict) else {},
        "review": review if isinstance(review, dict) else {},
        "completion": completion if isinstance(completion, dict) else {},
        "assets": compiled_assets,
        "created_epoch": float(obj.get("created_epoch") or 0.0),
        "updated_epoch": float(obj.get("updated_epoch") or 0.0),
    }


def _host_onboarding_asset_rows(conn: sqlite3.Connection, session_id: str) -> List[Dict[str, Any]]:
    rows = conn.execute(
        f"SELECT * FROM {_HOST_ONBOARDING_ASSETS_TABLE} WHERE session_id = ? ORDER BY created_epoch ASC, slot_key ASC",
        (session_id,),
    ).fetchall()
    out: List[Dict[str, Any]] = []
    for row in rows:
        obj = dict(row)
        out.append(
            {
                "asset_id": _host_onboarding_safe_str(obj.get("asset_id")),
                "session_id": _host_onboarding_safe_str(obj.get("session_id")),
                "slot_key": _host_onboarding_safe_str(obj.get("slot_key")),
                "required": bool(int(obj.get("required_flag") or 0) == 1),
                "url": _host_onboarding_safe_str(obj.get("url")),
                "file_name": _host_onboarding_safe_str(obj.get("file_name")),
                "content_type": _host_onboarding_safe_str(obj.get("content_type")),
                "size_bytes": int(obj.get("size_bytes") or 0),
                "width_px": int(obj.get("width_px") or 0),
                "height_px": int(obj.get("height_px") or 0),
                "duration_seconds": float(obj.get("duration_seconds") or 0.0),
                "validation_status": _host_onboarding_safe_str(obj.get("validation_status")) or "pending",
                "validation_errors": _host_onboarding_json_loads(obj.get("validation_errors_json"), []),
            }
        )
    return out


def _host_onboarding_get_session_by_id(conn: sqlite3.Connection, session_id: str) -> Optional[Dict[str, Any]]:
    row = conn.execute(
        f"SELECT * FROM {_HOST_ONBOARDING_SESSIONS_TABLE} WHERE session_id = ?",
        (session_id,),
    ).fetchone()
    if row is None:
        return None
    return _host_onboarding_session_row_to_dict(row, _host_onboarding_asset_rows(conn, session_id))


def _host_onboarding_find_active_session(conn: sqlite3.Connection, member_id: str, brand: str, avatar: str) -> Optional[Dict[str, Any]]:
    filters = ["member_id = ?"]
    params: List[Any] = [member_id]
    if brand:
        filters.append("COALESCE(brand, '') = ?")
        params.append(brand)
    if avatar:
        filters.append("COALESCE(avatar, '') = ?")
        params.append(avatar)
    row = conn.execute(
        f"SELECT * FROM {_HOST_ONBOARDING_SESSIONS_TABLE} WHERE {' AND '.join(filters)} ORDER BY updated_epoch DESC LIMIT 1",
        tuple(params),
    ).fetchone()
    if row is None:
        return None
    return _host_onboarding_session_row_to_dict(row, _host_onboarding_asset_rows(conn, _host_onboarding_safe_str(row['session_id'])))


def _host_onboarding_find_latest_session_for_member_brand(conn: sqlite3.Connection, member_id: str, brand: str) -> Optional[Dict[str, Any]]:
    mid = _host_onboarding_normalize_member_id(member_id)
    if not mid:
        return None
    params: List[Any] = [mid]
    filters = ["member_id = ?"]
    if _host_onboarding_safe_str(brand):
        filters.append("COALESCE(brand, '') = ?")
        params.append(_host_onboarding_safe_str(brand))
    row = conn.execute(
        f"SELECT * FROM {_HOST_ONBOARDING_SESSIONS_TABLE} WHERE {' AND '.join(filters)} ORDER BY updated_epoch DESC LIMIT 1",
        tuple(params),
    ).fetchone()
    if row is None:
        return None
    return _host_onboarding_session_row_to_dict(row, _host_onboarding_asset_rows(conn, _host_onboarding_safe_str(row['session_id'])))


def _host_onboarding_find_latest_approved_session(conn: sqlite3.Connection, member_id: str, brand: str = "", avatar: str = "") -> Optional[Dict[str, Any]]:
    """Return the latest approved/full Host Profile Studio session for a member.

    This is used when a host reopens Profile Studio after approval. Older code
    created a blank draft in that case; this helper lets startup seed the editor
    from the approved profile instead.
    """
    mid = _host_onboarding_normalize_member_id(member_id)
    if not mid:
        return None
    base_filters = ["member_id = ?", "lower(COALESCE(publish_status, '')) IN ('approved', 'full', 'limited')"]
    base_params: List[Any] = [mid]
    brand_norm = _host_onboarding_safe_str(brand)
    avatar_norm = _host_onboarding_safe_str(avatar)

    attempts: List[Tuple[List[str], List[Any]]] = []
    if brand_norm and avatar_norm:
        attempts.append((base_filters + ["COALESCE(brand, '') = ?", "COALESCE(avatar, '') = ?"], base_params + [brand_norm, avatar_norm]))
    if brand_norm:
        attempts.append((base_filters + ["COALESCE(brand, '') = ?"], base_params + [brand_norm]))
    attempts.append((base_filters, base_params))

    seen_sql: Set[str] = set()
    for filters, params in attempts:
        sql_where = " AND ".join(filters)
        if sql_where in seen_sql:
            continue
        seen_sql.add(sql_where)
        row = conn.execute(
            f"SELECT * FROM {_HOST_ONBOARDING_SESSIONS_TABLE} WHERE {sql_where} ORDER BY approved_version_id IS NULL ASC, updated_epoch DESC LIMIT 1",
            tuple(params),
        ).fetchone()
        if row is not None:
            return _host_onboarding_session_row_to_dict(row, _host_onboarding_asset_rows(conn, _host_onboarding_safe_str(row['session_id'])))
    return None


def _host_onboarding_session_has_profile_content(session: Optional[Dict[str, Any]]) -> bool:
    if not isinstance(session, dict):
        return False
    for key in ("basics", "derived", "review", "completion"):
        value = session.get(key)
        if isinstance(value, dict) and any(_host_onboarding_safe_str(v) or isinstance(v, (dict, list)) and len(v) > 0 for v in value.values()):
            return True
    return bool(session.get("assets"))


def _host_onboarding_clone_assets_to_session(conn: sqlite3.Connection, source_session_id: str, target_session_id: str) -> None:
    source = _host_onboarding_safe_str(source_session_id)
    target = _host_onboarding_safe_str(target_session_id)
    if not source or not target or source == target:
        return
    rows = conn.execute(
        f"SELECT * FROM {_HOST_ONBOARDING_ASSETS_TABLE} WHERE session_id = ? ORDER BY created_epoch ASC, slot_key ASC",
        (source,),
    ).fetchall()
    now = _host_onboarding_now()
    for row in rows:
        obj = dict(row)
        slot_key = _host_onboarding_safe_str(obj.get("slot_key"))
        if not slot_key:
            continue
        exists = conn.execute(
            f"SELECT asset_id FROM {_HOST_ONBOARDING_ASSETS_TABLE} WHERE session_id = ? AND slot_key = ? LIMIT 1",
            (target, slot_key),
        ).fetchone()
        if exists is not None:
            continue
        conn.execute(
            f"""
            INSERT INTO {_HOST_ONBOARDING_ASSETS_TABLE}
                (asset_id, session_id, slot_key, required_flag, url, file_name, content_type, size_bytes,
                 width_px, height_px, duration_seconds, validation_status, validation_errors_json, created_epoch, updated_epoch)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                uuid.uuid4().hex,
                target,
                slot_key,
                int(obj.get("required_flag") or 0),
                _host_onboarding_safe_str(obj.get("url")),
                _host_onboarding_safe_str(obj.get("file_name")),
                _host_onboarding_safe_str(obj.get("content_type")),
                int(obj.get("size_bytes") or 0),
                int(obj.get("width_px") or 0),
                int(obj.get("height_px") or 0),
                float(obj.get("duration_seconds") or 0.0),
                _host_onboarding_safe_str(obj.get("validation_status")) or "pending",
                _host_onboarding_safe_str(obj.get("validation_errors_json")) or "[]",
                now,
                now,
            ),
        )


def _host_onboarding_seed_draft_from_approved_session(
    conn: sqlite3.Connection,
    *,
    target_session_id: str,
    member_id: str,
    brand: str,
    avatar: str,
    host_display_name: str,
    logged_in: bool,
    approved_session: Dict[str, Any],
) -> Dict[str, Any]:
    seeded = _host_onboarding_upsert_session(
        conn,
        session_id=target_session_id,
        member_id=member_id,
        brand=brand or _host_onboarding_safe_str(approved_session.get("brand")),
        avatar=avatar or _host_onboarding_safe_str(approved_session.get("avatar")),
        host_display_name=host_display_name or _host_onboarding_safe_str(approved_session.get("host_display_name")),
        logged_in=logged_in,
        workflow_state="awaiting_final_approval",
        publish_status="draft",
        basics=dict(approved_session.get("basics") or {}),
        derived=dict(approved_session.get("derived") or {}),
        review=dict(approved_session.get("review") or {}),
        completion=dict(approved_session.get("completion") or {}),
        three_d_opt_in=bool(approved_session.get("three_d_opt_in") is True),
        approved_version_id=_host_onboarding_safe_str(approved_session.get("approved_version_id")),
    )
    _host_onboarding_clone_assets_to_session(
        conn,
        _host_onboarding_safe_str(approved_session.get("session_id")),
        _host_onboarding_safe_str(seeded.get("session_id")),
    )
    seeded = _host_onboarding_get_session_by_id(conn, _host_onboarding_safe_str(seeded.get("session_id"))) or seeded
    readiness = _host_onboarding_compute_readiness(seeded)
    seeded = _host_onboarding_upsert_session(
        conn,
        session_id=_host_onboarding_safe_str(seeded.get("session_id")),
        member_id=member_id,
        brand=_host_onboarding_safe_str(seeded.get("brand")),
        avatar=_host_onboarding_safe_str(seeded.get("avatar")),
        host_display_name=_host_onboarding_safe_str(seeded.get("host_display_name")),
        logged_in=bool(seeded.get("logged_in") is True),
        limited_publish_allowed=bool(readiness.get("limited_publish_allowed") is True),
        full_publish_ready=bool(readiness.get("full_publish_ready") is True),
    )
    return seeded


def _host_onboarding_enrich_session_with_mapping_phonetic_on_conn(conn: sqlite3.Connection, session: Dict[str, Any]) -> Dict[str, Any]:
    """Surface the manually curated mapping phonetic in Profile Studio.

    This only fills the optional completion field when the session does not
    already contain an explicit phonetic value. It never derives a value from the
    first name.
    """
    if not isinstance(session, dict):
        return session
    completion = dict(session.get("completion") or {})
    if _host_onboarding_extract_explicit_phonetic(completion):
        return session
    member_id = _host_onboarding_normalize_member_id(session.get("member_id"))
    brand = _host_onboarding_safe_str(session.get("brand")) or "Elaralo"
    avatar = _host_onboarding_safe_str(session.get("avatar"))
    if not member_id:
        return session
    try:
        conn.row_factory = sqlite3.Row
        row = None
        if avatar:
            row = conn.execute(
                """
                SELECT phonetic
                  FROM companion_mappings
                 WHERE lower(COALESCE(brand, '')) = lower(?)
                   AND lower(COALESCE(avatar, '')) = lower(?)
                   AND lower(COALESCE(companion_type, '')) = 'human'
                 LIMIT 1
                """,
                (brand, avatar),
            ).fetchone()
        if row is None:
            row = conn.execute(
                """
                SELECT phonetic
                  FROM companion_mappings
                 WHERE lower(COALESCE(brand, '')) = lower(?)
                   AND COALESCE(host_member_id, '') = ?
                   AND lower(COALESCE(companion_type, '')) = 'human'
                 ORDER BY rowid DESC
                 LIMIT 1
                """,
                (brand, member_id),
            ).fetchone()
        phonetic = _host_onboarding_optional_phonetic(row["phonetic"] if row is not None else "")
        if phonetic:
            completion["phonetic_pronunciation"] = phonetic
            completion["phonetic_pronunciation_of_first_name"] = phonetic
            session = {**session, "completion": completion}
    except Exception:
        pass
    return session


def _host_onboarding_upsert_session(
    conn: sqlite3.Connection,
    *,
    session_id: str,
    member_id: str,
    brand: str,
    avatar: str,
    host_display_name: str,
    logged_in: bool,
    workflow_state: Optional[str] = None,
    publish_status: Optional[str] = None,
    basics: Optional[Dict[str, Any]] = None,
    derived: Optional[Dict[str, Any]] = None,
    review: Optional[Dict[str, Any]] = None,
    completion: Optional[Dict[str, Any]] = None,
    three_d_opt_in: Optional[bool] = None,
    limited_publish_allowed: Optional[bool] = None,
    full_publish_ready: Optional[bool] = None,
    approved_version_id: Optional[str] = None,
) -> Dict[str, Any]:
    existing_row = conn.execute(
        f"SELECT * FROM {_HOST_ONBOARDING_SESSIONS_TABLE} WHERE session_id = ?",
        (session_id,),
    ).fetchone()
    now = _host_onboarding_now()
    existing = _host_onboarding_session_row_to_dict(existing_row, _host_onboarding_asset_rows(conn, session_id)) if existing_row is not None else None
    basics_json = basics if basics is not None else (existing or {}).get("basics") or {}
    derived_json = derived if derived is not None else (existing or {}).get("derived") or {}
    review_json = review if review is not None else (existing or {}).get("review") or {}
    completion_json = completion if completion is not None else (existing or {}).get("completion") or {}
    state_value = _host_onboarding_safe_str(workflow_state) or ((existing or {}).get("workflow_state") or "not_started")
    publish_value = _host_onboarding_safe_str(publish_status) or ((existing or {}).get("publish_status") or "draft")
    three_d_value = int(bool(three_d_opt_in if three_d_opt_in is not None else ((existing or {}).get("three_d_opt_in") is True)))
    limited_value = int(bool(limited_publish_allowed if limited_publish_allowed is not None else ((existing or {}).get("limited_publish_allowed") is True)))
    full_value = int(bool(full_publish_ready if full_publish_ready is not None else ((existing or {}).get("full_publish_ready") is True)))
    approved_value = _host_onboarding_safe_str(approved_version_id) or _host_onboarding_safe_str((existing or {}).get("approved_version_id"))
    created_epoch = float((existing or {}).get("created_epoch") or now)
    conn.execute(
        f"""
        INSERT INTO {_HOST_ONBOARDING_SESSIONS_TABLE}
        (session_id, member_id, brand, avatar, host_display_name, logged_in, workflow_state, publish_status,
         limited_publish_allowed, full_publish_ready, approved_version_id, basics_json, derived_json, review_json,
         completion_json, three_d_opt_in, created_epoch, updated_epoch)
        VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        ON CONFLICT(session_id) DO UPDATE SET
            member_id=excluded.member_id,
            brand=excluded.brand,
            avatar=excluded.avatar,
            host_display_name=excluded.host_display_name,
            logged_in=excluded.logged_in,
            workflow_state=excluded.workflow_state,
            publish_status=excluded.publish_status,
            limited_publish_allowed=excluded.limited_publish_allowed,
            full_publish_ready=excluded.full_publish_ready,
            approved_version_id=excluded.approved_version_id,
            basics_json=excluded.basics_json,
            derived_json=excluded.derived_json,
            review_json=excluded.review_json,
            completion_json=excluded.completion_json,
            three_d_opt_in=excluded.three_d_opt_in,
            updated_epoch=excluded.updated_epoch
        """,
        (
            session_id,
            member_id,
            brand,
            avatar,
            host_display_name,
            int(bool(logged_in)),
            state_value,
            publish_value,
            limited_value,
            full_value,
            approved_value,
            _host_onboarding_json_dumps(basics_json),
            _host_onboarding_json_dumps(derived_json),
            _host_onboarding_json_dumps(review_json),
            _host_onboarding_json_dumps(completion_json),
            three_d_value,
            created_epoch,
            now,
        ),
    )
    row = conn.execute(
        f"SELECT * FROM {_HOST_ONBOARDING_SESSIONS_TABLE} WHERE session_id = ?",
        (session_id,),
    ).fetchone()
    return _host_onboarding_session_row_to_dict(row, _host_onboarding_asset_rows(conn, session_id))


def _host_onboarding_assert_member_access(session: Dict[str, Any], member_id: str) -> None:
    owner = _host_onboarding_safe_str((session or {}).get("member_id"))
    if not owner or owner != _host_onboarding_safe_str(member_id):
        raise HTTPException(status_code=403, detail="Host onboarding session access denied")


def _host_onboarding_required_slots_present(assets: List[Dict[str, Any]]) -> Tuple[bool, List[str]]:
    accepted = {str(a.get("slot_key") or "").strip() for a in (assets or []) if str(a.get("validation_status") or "") in ("accepted", "needs_review") and str(a.get("url") or "").strip()}
    missing = [slot for slot in _HOST_ONBOARDING_REQUIRED_SLOTS if slot not in accepted]
    return len(missing) == 0, missing


def _host_onboarding_voice_capture_asset_ok(assets: List[Dict[str, Any]]) -> Tuple[bool, Optional[Dict[str, Any]], List[str]]:
    """Return whether the host has a publishable voice sample.

    This is intentionally stricter than the required photo-slot check:
      - voice_capture_30s must exist
      - the uploaded asset must have a browser/API-loadable URL
      - validation_status must be accepted
      - duration_seconds must be at least HOST_ONBOARDING_VOICE_MIN_SECONDS

    The voice sample is required for BOTH limited and full Human Companion profile
    approval because it is exported into the Connect companion mapping/profile.
    """
    best_asset: Optional[Dict[str, Any]] = None
    blockers: List[str] = []
    for raw in list(assets or []):
        if not isinstance(raw, dict):
            continue
        if _host_onboarding_safe_str(raw.get("slot_key")) != _HOST_ONBOARDING_VOICE_SLOT:
            continue
        asset = dict(raw)
        best_asset = asset
        url = _host_onboarding_safe_str(asset.get("url"))
        status = _host_onboarding_safe_str(asset.get("validation_status")).lower()
        try:
            duration = float(asset.get("duration_seconds") or 0.0)
        except Exception:
            duration = 0.0
        validation_errors = asset.get("validation_errors") or asset.get("validation_errors_json") or []
        if isinstance(validation_errors, str):
            parsed_errors = _host_onboarding_json_loads(validation_errors, [])
            validation_errors = parsed_errors if isinstance(parsed_errors, list) else [validation_errors]
        if not url:
            blockers.append("Voice capture file is missing.")
        if status != "accepted":
            blockers.append("Voice capture must be accepted by validation.")
        if duration < float(_HOST_ONBOARDING_VOICE_MIN_SECONDS):
            blockers.append(f"Voice capture must be at least {int(_HOST_ONBOARDING_VOICE_MIN_SECONDS)} seconds long.")
        for err in list(validation_errors or []):
            msg = _host_onboarding_safe_str(err)
            if msg and msg not in blockers:
                blockers.append(msg)
        if url and status == "accepted" and duration >= float(_HOST_ONBOARDING_VOICE_MIN_SECONDS):
            return True, asset, []

    if best_asset is None:
        blockers.append(f"Voice capture (minimum {int(_HOST_ONBOARDING_VOICE_MIN_SECONDS)} seconds) is required.")
    # De-dupe while preserving order.
    deduped: List[str] = []
    for msg in blockers:
        msg_s = _host_onboarding_safe_str(msg)
        if msg_s and msg_s not in deduped:
            deduped.append(msg_s)
    return False, best_asset, deduped


def _host_onboarding_build_astro_profile(sign: str) -> Dict[str, Any]:
    info = _HOST_ONBOARDING_ZODIAC_NOTES.get(_host_onboarding_safe_str(sign), {})
    strengths = list(info.get("strengths") or [])
    challenges = list(info.get("challenges") or [])
    personality = _host_onboarding_safe_str(info.get("personality"))
    if not sign:
        return {"sign": "", "strengths": [], "challenges": [], "narrative": ""}
    narrative = f"{sign} profile draft: {personality}".strip()
    return {
        "sign": sign,
        "strengths": strengths,
        "challenges": challenges,
        "narrative": narrative,
    }


def _host_onboarding_build_quick_reference(basics: Dict[str, Any], nationalities: List[str], age_years: Optional[int], zodiac_sign: str) -> Dict[str, Any]:
    birth_city = _host_onboarding_safe_str(basics.get("birth_city"))
    birth_state = _host_onboarding_safe_str(basics.get("birth_state_region"))
    birth_country = _host_onboarding_safe_str(basics.get("birth_country"))
    birthplace_parts = [x for x in [birth_city, birth_state, birth_country] if x]
    race_primary = _host_onboarding_safe_str(basics.get("race_primary"))
    ethnicity_detail = _host_onboarding_safe_str(basics.get("ethnicity_detail"))
    public_name = _host_onboarding_safe_str(basics.get("stage_name")) or _host_onboarding_safe_str(basics.get("public_display_name"))
    return {
        "public_name": public_name,
        "age": age_years,
        "zodiac_sign": zodiac_sign,
        "birth_location": ", ".join(birthplace_parts),
        "nationalities": nationalities,
        "race": race_primary,
        "ethnicity": ethnicity_detail,
    }


def _host_onboarding_build_family_heritage_draft(basics: Dict[str, Any], nationalities: List[str]) -> str:
    ethnicity_detail = _host_onboarding_safe_str(basics.get("ethnicity_detail"))
    race_primary = _host_onboarding_safe_str(basics.get("race_primary"))
    birth_country = _host_onboarding_safe_str(basics.get("birth_country"))
    parts: List[str] = []
    if ethnicity_detail:
        parts.append(f"The host identifies their ethnicity as {ethnicity_detail}.")
    if race_primary:
        parts.append(f"The host identifies their race as {race_primary}.")
    if nationalities:
        if len(nationalities) == 1:
            parts.append(f"The current nationality suggestion is {nationalities[0]} and remains host-reviewable.")
        else:
            parts.append("The current nationality suggestions are " + ", ".join(nationalities) + ", and remain host-reviewable.")
    if birth_country:
        parts.append(f"Birth country is recorded as {birth_country}.")
    return " ".join(parts).strip()


def _host_onboarding_build_personality_draft(zodiac_sign: str) -> str:
    info = _HOST_ONBOARDING_ZODIAC_NOTES.get(_host_onboarding_safe_str(zodiac_sign), {})
    personality = _host_onboarding_safe_str(info.get("personality"))
    if not zodiac_sign:
        return ""
    return f"Draft personality framing based on {zodiac_sign}: {personality} This draft is for host review and editing before approval.".strip()


_HOST_ONBOARDING_PHYSICAL_DESCRIPTION_PLACEHOLDER = "Physical description is intentionally left for host review and completion in this MVP."


_HOST_ONBOARDING_ASSET_SLOT_LABELS = {
    "headshot_front": "Headshot (front)",
    "full_body_front": "Full body (front)",
    "three_quarter_body": "Three-quarter body",
    "angle_left_45": "45-degree left",
    "angle_right_45": "45-degree right",
    "left_profile": "Left profile",
    "right_profile": "Right profile",
    "smiling_headshot": "Smiling headshot",
    "neutral_headshot": "Neutral-expression headshot",
    "extra_angle": "Extra angle",
    _HOST_ONBOARDING_VOICE_SLOT: "Voice capture (30 seconds)",
}
_HOST_ONBOARDING_ASSET_SLOT_ORDER = {
    slot: idx for idx, slot in enumerate(_HOST_ONBOARDING_ASSET_SLOT_LABELS.keys())
}


def _host_onboarding_slot_label(slot_key: Any) -> str:
    slot = _host_onboarding_safe_str(slot_key)
    return _HOST_ONBOARDING_ASSET_SLOT_LABELS.get(slot, slot.replace("_", " ").strip().title())


def _host_onboarding_normalize_education_entries(raw: Any) -> List[Dict[str, str]]:
    items: List[Any]
    if raw is None:
        items = []
    elif isinstance(raw, list):
        items = list(raw)
    else:
        items = [raw]

    out: List[Dict[str, str]] = []
    for item in items:
        if item is None:
            continue
        entry = {
            "degree": "",
            "field_of_study": "",
            "institution": "",
            "graduation_year": "",
            "notes": "",
        }
        if isinstance(item, str):
            text = _host_onboarding_safe_str(item)
            if not text:
                continue
            entry["notes"] = text
        elif isinstance(item, dict):
            entry["degree"] = _host_onboarding_safe_str(item.get("degree"))
            entry["field_of_study"] = _host_onboarding_safe_str(item.get("field_of_study") or item.get("field") or item.get("major"))
            entry["institution"] = _host_onboarding_safe_str(item.get("institution") or item.get("school") or item.get("university"))
            entry["graduation_year"] = _host_onboarding_safe_str(item.get("graduation_year") or item.get("year"))
            entry["notes"] = _host_onboarding_safe_str(
                item.get("notes")
                or item.get("focus")
                or item.get("academic_focus")
                or item.get("areas_of_focus")
                or item.get("summary")
                or item.get("education")
                or item.get("text")
            )
        else:
            continue
        if not any(entry.values()):
            continue
        out.append(entry)
    return out


def _host_onboarding_format_education_entry(entry: Dict[str, Any]) -> str:
    degree = _host_onboarding_safe_str((entry or {}).get("degree"))
    field = _host_onboarding_safe_str((entry or {}).get("field_of_study"))
    institution = _host_onboarding_safe_str((entry or {}).get("institution"))
    graduation_year = _host_onboarding_safe_str((entry or {}).get("graduation_year"))
    notes = _host_onboarding_safe_str((entry or {}).get("notes"))

    lead = degree
    if degree and field:
        lead = f"{degree} in {field}"
    elif field and not degree:
        lead = field

    parts: List[str] = []
    if lead:
        parts.append(lead)
    if institution:
        parts.append(institution)
    if graduation_year:
        parts.append(f"Class of {graduation_year}")
    text = " — ".join([p for p in parts if p])
    if notes:
        text = f"{text}. {notes}".strip() if text else notes
    return text.strip()


def _host_onboarding_format_education_entries_text(entries: Any) -> str:
    normalized = _host_onboarding_normalize_education_entries(entries)
    lines = [line for line in [_host_onboarding_format_education_entry(entry) for entry in normalized] if line]
    return "\n".join(lines).strip()



def _host_onboarding_has_meaningful_education(value: Any) -> bool:
    if _host_onboarding_normalize_education_entries(value):
        return True
    return bool(_host_onboarding_safe_str(value))


def _host_onboarding_public_asset_payload(asset: Dict[str, Any]) -> Dict[str, Any]:
    a = dict(asset or {})
    slot_key = _host_onboarding_safe_str(a.get("slot_key"))
    return {
        "asset_id": _host_onboarding_safe_str(a.get("asset_id")),
        "slot_key": slot_key,
        "slot_label": _host_onboarding_slot_label(slot_key),
        "sort_order": int(_HOST_ONBOARDING_ASSET_SLOT_ORDER.get(slot_key, 999)),
        "url": _host_onboarding_safe_str(a.get("url")),
        "file_name": _host_onboarding_safe_str(a.get("file_name")),
        "content_type": _host_onboarding_safe_str(a.get("content_type")),
        "width_px": int(a.get("width_px") or 0),
        "height_px": int(a.get("height_px") or 0),
        "duration_seconds": float(a.get("duration_seconds") or 0.0),
        "validation_status": _host_onboarding_safe_str(a.get("validation_status")),
    }


def _host_onboarding_split_public_assets(assets: Any) -> Tuple[Optional[Dict[str, Any]], List[Dict[str, Any]]]:
    normalized_assets: List[Dict[str, Any]] = []
    for asset in list(assets or []):
        if not isinstance(asset, dict):
            continue
        url = _host_onboarding_safe_str(asset.get("url"))
        slot_key = _host_onboarding_safe_str(asset.get("slot_key"))
        content_type = _host_onboarding_safe_str(asset.get("content_type")).lower()
        if not url or slot_key == _HOST_ONBOARDING_VOICE_SLOT:
            continue
        if content_type and not content_type.startswith("image/"):
            continue
        normalized_assets.append(_host_onboarding_public_asset_payload(asset))

    if not normalized_assets:
        return None, []

    headshot: Optional[Dict[str, Any]] = None
    for asset in normalized_assets:
        if _host_onboarding_safe_str(asset.get("slot_key")) == "headshot_front":
            headshot = asset
            break
    if headshot is None:
        headshot = normalized_assets[0]

    headshot_id = _host_onboarding_safe_str((headshot or {}).get("asset_id"))
    gallery = [
        asset for asset in normalized_assets
        if _host_onboarding_safe_str(asset.get("slot_key")) != "headshot_front" and _host_onboarding_safe_str(asset.get("asset_id")) != headshot_id
    ]
    gallery.sort(key=lambda asset: (int(asset.get("sort_order") or 999), _host_onboarding_safe_str(asset.get("file_name")), _host_onboarding_safe_str(asset.get("asset_id"))))
    return headshot, gallery


def _host_onboarding_meaningful_physical_description(value: Any) -> str:
    text = _host_onboarding_safe_str(value)
    if not text:
        return ""
    lowered = text.strip().lower()
    if lowered == _HOST_ONBOARDING_PHYSICAL_DESCRIPTION_PLACEHOLDER.strip().lower():
        return ""
    return text


def _host_onboarding_generation_label(birthdate: Any) -> str:
    dt = _host_onboarding_parse_birthdate(birthdate)
    year = int(dt.year) if dt else 0
    if year >= 1997:
        return "Generation Z"
    if year >= 1981:
        return "Millennials"
    if year >= 1965:
        return "Generation X"
    if year >= 1946:
        return "Baby Boomers"
    return "Classic"


def _host_onboarding_gender_label(raw: Any) -> str:
    s = _host_onboarding_safe_str(raw)
    lc = s.lower()
    if "female" in lc or "woman" in lc:
        return "Female"
    if "male" in lc or "man" in lc:
        return "Male"
    if not s:
        return "Companion"
    cleaned = re.sub(r"[^A-Za-z0-9 ]+", " ", s).strip()
    return cleaned.title() if cleaned else "Companion"


def _host_onboarding_race_label(raw: Any) -> str:
    s = _host_onboarding_safe_str(raw)
    lc = s.lower()
    if "black" in lc or "african" in lc:
        return "Black"
    if "white" in lc or "caucasian" in lc:
        return "Caucasian"
    if "asian" in lc:
        return "Asian"
    if "middle eastern" in lc or "north african" in lc:
        return "Middle Eastern"
    if "native american" in lc or "alaska" in lc:
        return "Native American"
    if "pacific" in lc or "hawaiian" in lc:
        return "Pacific Islander"
    if "multiracial" in lc or "mixed" in lc:
        return "Multiracial"
    cleaned = re.sub(r"[^A-Za-z0-9 ]+", " ", s).strip()
    return cleaned.title() if cleaned else "Companion"


def _host_onboarding_primary_public_name(basics: Dict[str, Any]) -> str:
    return _host_onboarding_safe_str(basics.get("stage_name")) or _host_onboarding_safe_str(basics.get("public_display_name")) or "Companion"


def _host_onboarding_avatar_key_from_session(session: Dict[str, Any]) -> str:
    """Return the Human Companion avatar base for companion_mappings.avatar.

    Human avatar values in companion_mappings are first-name based. Duplicate names
    for the same brand get a database-assigned -######### suffix at export/upsert
    time, where the DB can see existing rows.
    """
    basics = dict(session.get("basics") or {})
    public_name = _host_onboarding_primary_public_name(basics)
    return _companion_avatar_first_name(public_name) or "Companion"


def _host_onboarding_non_default_first_name(raw: Any) -> str:
    """Return a first-name avatar candidate, excluding app/default companion names.

    Historical Host Onboarding sessions sometimes stored the currently selected
    Connect companion (for example Elara) in session.avatar. That value is a
    selection context, not the host's Human Companion identity, and must never be
    used to target companion_mappings for a Host export/repair.
    """
    first = _companion_avatar_first_name(raw)
    if not first:
        return ""
    if first.strip().lower() in {"elara", "elaralo", "companion", "human"}:
        return ""
    return first


def _host_onboarding_human_avatar_key_from_profile(profile: Dict[str, Any], session: Optional[Dict[str, Any]] = None) -> str:
    """Resolve the Human Companion mapping avatar from Host profile data only.

    This deliberately prefers approved Host/Profile Studio naming fields and only
    uses stored connect_platform avatar values as a last resort. It does not use
    session.avatar defaults such as Elara, because those can represent the
    companion the host selected in Connect rather than the host herself.
    """
    profile = dict(profile or {})
    session_obj = dict(session or {}) if isinstance(session, dict) else {}
    public_profile = dict(profile.get("public_profile") or {})
    private_profile = dict(profile.get("private_profile") or {})
    ai_profile = dict(profile.get("ai_profile") or {})
    profile_session = dict(profile.get("session") or {})
    basics = dict(session_obj.get("basics") or {})
    completion = dict(session_obj.get("completion") or {})
    ai_connect = dict(ai_profile.get("connect_platform") or {})
    connect_platform = dict(profile.get("connect_platform") or {})

    primary_candidates = [
        public_profile.get("public_display_name"),
        public_profile.get("stage_name"),
        ai_profile.get("approved_stage_name"),
        basics.get("public_display_name"),
        basics.get("stage_name"),
        completion.get("public_display_name"),
        completion.get("stage_name"),
        profile_session.get("public_display_name"),
        profile_session.get("stage_name"),
        session_obj.get("host_display_name"),
        private_profile.get("legal_name"),
    ]
    for candidate in primary_candidates:
        first = _host_onboarding_non_default_first_name(candidate)
        if first:
            return first

    # Last resort: older approved profiles may have already exported a correct
    # human connect_platform avatar such as Sera-Female-Caucasian-Gen-Z or Sera.
    # Reject app-default selections such as Elara.
    fallback_candidates = [
        connect_platform.get("avatar"),
        ai_connect.get("avatar"),
    ]
    for candidate in fallback_candidates:
        first = _host_onboarding_non_default_first_name(candidate)
        if first:
            return first

    return ""


def _host_onboarding_gallery_description_for_slot(slot_key: Any) -> str:
    slot = _host_onboarding_safe_str(slot_key)
    mapping = {
        "full_body_front": "Full Body",
        "three_quarter_body": "Three Quarter",
        "angle_left_45": "45 Degree Left",
        "angle_right_45": "45 Degree Right",
        "left_profile": "Left Profile",
        "right_profile": "Right Profile",
        "smiling_headshot": "Smiling Headshot",
        "neutral_headshot": "Neutral Headshot",
        "extra_angle": "Extra Angle",
    }
    return mapping.get(slot, _host_onboarding_slot_label(slot)).replace("-", " ").strip()


def _host_onboarding_safe_filename_component(value: Any) -> str:
    s = _host_onboarding_safe_str(value)
    s = re.sub(r"[\/:*?\"<>|]+", " ", s).strip()
    s = re.sub(r"\s+", " ", s).strip()
    return s or "Asset"


def _host_onboarding_connect_public_filename(slot_key: Any, index: int, ext: str) -> str:
    seq = f"{max(1, int(index)):09d}"
    desc = _host_onboarding_safe_filename_component(_host_onboarding_gallery_description_for_slot(slot_key))
    ext_norm = ext if str(ext or "").startswith(".") else f".{str(ext or '').strip()}"
    ext_norm = ext_norm or ".bin"
    return f"{seq}-{desc}-Photo-Public{ext_norm}"


def _host_onboarding_connect_voice_filename(avatar_key: Any, ext: str) -> str:
    base = _host_onboarding_safe_filename_component(avatar_key).replace(" ", "-") or "Companion"
    ext_norm = ext if str(ext or "").startswith(".") else f".{str(ext or '').strip()}"
    ext_norm = ext_norm or ".bin"
    return f"{base}-Voice-Capture-Audio{ext_norm}"


def _elevenlabs_voice_create_endpoint() -> str:
    return (os.getenv("ELEVENLABS_VOICE_CREATE_URL", "https://api.elevenlabs.io/v1/voices/add") or "https://api.elevenlabs.io/v1/voices/add").strip()


def _host_onboarding_should_require_eleven_voice() -> bool:
    return str(os.getenv("ELEVENLABS_REQUIRE_VOICE_ON_PUBLISH", "0") or "0").strip().lower() in {"1", "true", "yes", "on"}


def _host_onboarding_should_attempt_eleven_voice() -> bool:
    api_key = (os.getenv("ELEVENLABS_API_KEY", "") or "").strip()
    enabled = str(os.getenv("ELEVENLABS_AUTO_CREATE_ON_PUBLISH", "1") or "1").strip().lower() in {"1", "true", "yes", "on"}
    return bool(api_key) and enabled


def _host_onboarding_eleven_voice_display_name(session: Dict[str, Any], profile: Dict[str, Any], avatar_key: str) -> str:
    public_profile = dict((profile or {}).get("public_profile") or {})
    basics = dict((session or {}).get("basics") or {})
    public_name = _host_onboarding_safe_str(public_profile.get("public_display_name") or public_profile.get("stage_name") or basics.get("stage_name") or basics.get("public_display_name"))
    if public_name:
        return public_name
    return _host_onboarding_safe_str(avatar_key).replace("-", " ") or "Elaralo Human Companion"


_ELEVENLABS_LABEL_VALUE_MAX_CHARS = 50


def _host_onboarding_eleven_label_value(value: Any, max_chars: int = _ELEVENLABS_LABEL_VALUE_MAX_CHARS) -> str:
    """Return an ElevenLabs-safe label value.

    ElevenLabs rejects voice-create requests when any label value exceeds 50
    characters. Preserve useful traceability by truncating long values and adding
    an 8-character digest suffix so IDs/names remain distinguishable.
    """
    text = re.sub(r"\s+", " ", _host_onboarding_safe_str(value)).strip()
    if not text:
        return ""
    try:
        limit = int(max_chars)
    except Exception:
        limit = _ELEVENLABS_LABEL_VALUE_MAX_CHARS
    limit = max(12, min(limit, _ELEVENLABS_LABEL_VALUE_MAX_CHARS))
    if len(text) <= limit:
        return text
    digest = hashlib.sha1(text.encode("utf-8", errors="ignore")).hexdigest()[:8]
    keep = max(1, limit - len(digest) - 1)
    prefix = text[:keep].rstrip(" -_.:/|,")
    if not prefix:
        prefix = text[:keep]
    return f"{prefix}-{digest}"[:limit]


def _host_onboarding_sanitize_eleven_voice_labels(labels: Dict[str, Any]) -> Dict[str, str]:
    out: Dict[str, str] = {}
    for raw_key, raw_value in (labels or {}).items():
        key = re.sub(r"[^A-Za-z0-9_-]+", "_", _host_onboarding_safe_str(raw_key)).strip("_")
        if not key:
            continue
        value = _host_onboarding_eleven_label_value(raw_value)
        if value:
            out[key] = value
    return out


def _host_onboarding_build_eleven_voice_labels(session: Dict[str, Any], profile: Dict[str, Any], avatar_key: str, version_id: str) -> Dict[str, str]:
    basics = dict((session or {}).get("basics") or {})
    public_profile = dict((profile or {}).get("public_profile") or {})
    labels = {
        "brand": "Elaralo",
        "avatar": _host_onboarding_safe_str(avatar_key),
        "member_id": _host_onboarding_safe_str((session or {}).get("member_id")),
        "approved_version_id": _host_onboarding_safe_str(version_id),
        "public_display_name": _host_onboarding_safe_str(public_profile.get("public_display_name") or public_profile.get("stage_name")),
        "gender": _host_onboarding_safe_str(public_profile.get("gender") or basics.get("gender_display")),
        "ethnicity": _host_onboarding_safe_str(public_profile.get("ethnicity") or basics.get("ethnicity_detail") or basics.get("ethnicity_bucket")),
        "generation": _host_onboarding_safe_str(public_profile.get("generation") or _host_onboarding_generation_label(basics.get("birthdate"))),
        "source": "host_onboarding_publish_export",
    }
    return _host_onboarding_sanitize_eleven_voice_labels(labels)


def _host_onboarding_create_eleven_voice_from_asset(asset: Dict[str, Any], voice_name: str, labels: Dict[str, str]) -> Dict[str, Any]:
    if not _host_onboarding_should_attempt_eleven_voice():
        return {
            "status": "skipped",
            "reason": "ELEVENLABS_API_KEY not configured or voice auto-create disabled",
            "voice_id": "",
            "voice_name": _host_onboarding_safe_str(voice_name),
        }

    source_url = _host_onboarding_safe_str((asset or {}).get("url"))
    if not source_url:
        raise ValueError("Voice asset URL is missing")

    file_name = _host_onboarding_safe_str((asset or {}).get("file_name")) or "voice_capture.wav"
    content_type = _host_onboarding_safe_str((asset or {}).get("content_type")) or mimetypes.guess_type(file_name)[0] or "application/octet-stream"
    data = _host_onboarding_download_bytes_sync(source_url)
    if not data:
        raise ValueError("Voice asset bytes could not be downloaded")

    import requests  # type: ignore

    endpoint = _elevenlabs_voice_create_endpoint()
    headers = {"xi-api-key": (os.getenv("ELEVENLABS_API_KEY", "") or "").strip()}
    safe_labels = _host_onboarding_sanitize_eleven_voice_labels(labels or {})
    payload = {
        "name": _host_onboarding_safe_str(voice_name) or "Elaralo Human Companion Voice",
        "description": f"Host onboarding approved voice for {_host_onboarding_safe_str(voice_name) or 'Elaralo Human Companion'}",
        "labels": json.dumps(safe_labels, ensure_ascii=False),
    }
    files = [("files", (file_name, data, content_type))]
    response = requests.post(endpoint, headers=headers, data=payload, files=files, timeout=120)
    if response.status_code >= 400:
        raise RuntimeError(f"ElevenLabs voice-create error {response.status_code}: {(response.text or '')[:500]}")
    try:
        body = response.json()
    except Exception:
        body = {}
    if not isinstance(body, dict):
        body = {}
    voice_id = _host_onboarding_safe_str(body.get("voice_id") or body.get("voiceId") or ((body.get("voice") or {}).get("voice_id") if isinstance(body.get("voice"), dict) else ""))
    if not voice_id:
        raise RuntimeError("ElevenLabs voice-create did not return voice_id")
    return {
        "status": "created",
        "voice_id": voice_id,
        "voice_name": _host_onboarding_safe_str(payload.get("name")),
        "response": body,
    }


def _host_onboarding_download_bytes_sync(url: str) -> bytes:
    target = _host_onboarding_safe_str(url)
    if not target:
        return b""
    import requests  # type: ignore
    r = requests.get(target, timeout=30)
    r.raise_for_status()
    return bytes(r.content or b"")


def _host_onboarding_export_blob_name(*parts: str) -> str:
    cleaned = [str(p or "").strip().strip("/") for p in parts if str(p or "").strip().strip("/")]
    prefix = _HOST_ONBOARDING_CONNECT_EXPORT_PREFIX.strip().strip("/")
    if prefix:
        cleaned.insert(0, prefix)
    return "/".join(cleaned)


def _host_onboarding_export_bytes_sync(blob_name: str, content_type: str, data: bytes) -> str:
    if not data:
        raise ValueError("No bytes available for export")
    return _azure_upload_bytes_and_get_sas_url(
        container_name=_UPLOADS_CONTAINER,
        blob_name=blob_name,
        content_type=content_type or "application/octet-stream",
        data=data,
    )


def _host_onboarding_export_asset_from_url(asset: Dict[str, Any], blob_name: str) -> Dict[str, Any]:
    source_url = _host_onboarding_safe_str((asset or {}).get("url"))
    if not source_url:
        raise ValueError("Asset URL is missing")
    content_type = _host_onboarding_safe_str((asset or {}).get("content_type")) or "application/octet-stream"
    file_name = _host_onboarding_safe_str((asset or {}).get("file_name")) or os.path.basename(blob_name)
    data = _host_onboarding_download_bytes_sync(source_url)
    exported_url = _host_onboarding_export_bytes_sync(blob_name, content_type, data)
    out = dict(asset or {})
    out["source_url"] = source_url
    out["url"] = exported_url
    out["file_name"] = os.path.basename(blob_name)
    out["original_file_name"] = file_name
    out["export_blob_name"] = blob_name
    out["exported_at_epoch"] = _host_onboarding_now()
    return out


def _host_onboarding_resolve_brand_id_for_brand_on_conn(conn: sqlite3.Connection, brand: str) -> Optional[int]:
    """Resolve a brand_id by querying existing companion_mappings rows.

    This intentionally does not hard-code Elaralo's numeric brand_id. The live DB
    already contains branded AI rows, so Host Onboarding inherits the brand_id
    from those canonical rows.
    """
    brand_name = _host_onboarding_safe_str(brand) or "Elaralo"
    try:
        cur = conn.cursor()
        cur.execute("PRAGMA table_info(companion_mappings)")
        cols = {str(row[1] or "").strip().lower() for row in cur.fetchall()}
        if "brand_id" not in cols:
            return None
        if "brand" in cols:
            row = cur.execute(
                """
                SELECT brand_id
                  FROM companion_mappings
                 WHERE lower(brand)=lower(?)
                   AND brand_id IS NOT NULL
                   AND trim(CAST(brand_id AS TEXT)) <> ''
                 ORDER BY rowid
                 LIMIT 1
                """,
                (brand_name,),
            ).fetchone()
            if row is not None and row[0] is not None and str(row[0]).strip() != "":
                try:
                    return int(row[0])
                except Exception:
                    return None
    except Exception:
        return None
    return None


def _host_onboarding_backfill_brand_id_for_brand_on_conn(conn: sqlite3.Connection, brand: str) -> None:
    brand_name = _host_onboarding_safe_str(brand) or "Elaralo"
    brand_id = _host_onboarding_resolve_brand_id_for_brand_on_conn(conn, brand_name)
    if brand_id is None:
        return
    try:
        conn.execute(
            """
            UPDATE companion_mappings
               SET brand_id = ?
             WHERE lower(brand)=lower(?)
               AND (brand_id IS NULL OR trim(CAST(brand_id AS TEXT)) = '')
            """,
            (brand_id, brand_name),
        )
    except Exception:
        pass


def _host_onboarding_backfill_companion_ids_on_conn(conn: sqlite3.Connection) -> None:
    """Backfill missing companion_id values from DB state, not application logic.

    Existing rows created before companion_id existed still need a one-time value.
    New rows are handled by the SQLite trigger created below.
    """
    try:
        cur = conn.cursor()
        cur.execute("PRAGMA table_info(companion_mappings)")
        cols = {str(row[1] or "").strip().lower() for row in cur.fetchall()}
        if "companion_id" not in cols:
            return
        rows = cur.execute(
            """
            SELECT rowid
              FROM companion_mappings
             WHERE companion_id IS NULL OR trim(CAST(companion_id AS TEXT)) = ''
             ORDER BY rowid
            """
        ).fetchall()
        for row in rows or []:
            rowid = row[0]
            cur.execute(
                """
                UPDATE companion_mappings
                   SET companion_id = (
                         SELECT COALESCE(MAX(CAST(companion_id AS INTEGER)), 0) + 1
                           FROM companion_mappings
                          WHERE rowid <> ?
                            AND companion_id IS NOT NULL
                            AND trim(CAST(companion_id AS TEXT)) <> ''
                            AND CAST(companion_id AS INTEGER) > 0
                       )
                 WHERE rowid = ?
                   AND (companion_id IS NULL OR trim(CAST(companion_id AS TEXT)) = '')
                """,
                (rowid, rowid),
            )
    except Exception:
        pass


def _host_onboarding_create_companion_mapping_triggers_on_conn(conn: sqlite3.Connection) -> None:
    """Create SQLite triggers for companion_mappings derived identifiers.

    SQLite only supports AUTOINCREMENT on an INTEGER PRIMARY KEY. The deployed
    table already uses its own primary key shape, so companion_id is auto-filled
    at the database layer with an INSERT trigger using max(companion_id)+1.
    """
    try:
        cur = conn.cursor()
        cur.execute(
            """
            CREATE TRIGGER IF NOT EXISTS companion_mappings_companion_id_autofill
            AFTER INSERT ON companion_mappings
            FOR EACH ROW
            WHEN NEW.companion_id IS NULL OR trim(CAST(NEW.companion_id AS TEXT)) = ''
            BEGIN
                UPDATE companion_mappings
                   SET companion_id = (
                         SELECT COALESCE(MAX(CAST(companion_id AS INTEGER)), 0) + 1
                           FROM companion_mappings
                          WHERE rowid <> NEW.rowid
                            AND companion_id IS NOT NULL
                            AND trim(CAST(companion_id AS TEXT)) <> ''
                            AND CAST(companion_id AS INTEGER) > 0
                       )
                 WHERE rowid = NEW.rowid;
            END;
            """
        )
    except Exception:
        pass
    try:
        cur = conn.cursor()
        cur.execute(
            """
            CREATE TRIGGER IF NOT EXISTS companion_mappings_brand_id_autofill
            AFTER INSERT ON companion_mappings
            FOR EACH ROW
            WHEN NEW.brand_id IS NULL OR trim(CAST(NEW.brand_id AS TEXT)) = ''
            BEGIN
                UPDATE companion_mappings
                   SET brand_id = (
                         SELECT brand_id
                           FROM companion_mappings
                          WHERE rowid <> NEW.rowid
                            AND lower(brand)=lower(NEW.brand)
                            AND brand_id IS NOT NULL
                            AND trim(CAST(brand_id AS TEXT)) <> ''
                          ORDER BY rowid
                          LIMIT 1
                       )
                 WHERE rowid = NEW.rowid;
            END;
            """
        )
    except Exception:
        pass
    try:
        # Defense-in-depth for the exact production failure class: Host
        # Onboarding/export/repair data must never be stamped onto AI rows.
        # Earlier protection only blocked *changed* host fields, which still
        # allowed a historically contaminated AI row with an existing
        # host_member_id to be reused by host-scoped repair code. These triggers
        # enforce the invariant on the NEW row image: AI rows may not carry
        # Host Onboarding ownership/version/media-clone fields at all.
        cur = conn.cursor()
        cur.execute("DROP TRIGGER IF EXISTS companion_mappings_prevent_ai_host_overwrite")
        cur.execute("DROP TRIGGER IF EXISTS companion_mappings_prevent_ai_host_insert")
        cur.execute(
            """
            CREATE TRIGGER companion_mappings_prevent_ai_host_overwrite
            BEFORE UPDATE ON companion_mappings
            FOR EACH ROW
            WHEN lower(COALESCE(OLD.companion_type, '')) = 'ai'
             AND (
                    lower(COALESCE(NEW.companion_type, '')) <> 'ai'
                 OR trim(COALESCE(NEW.host_member_id, '')) <> ''
                 OR trim(COALESCE(NEW.approved_version_id, '')) <> ''
                 OR trim(COALESCE(NEW.voice_capture_url, '')) <> ''
                 OR trim(COALESCE(NEW.public_gallery_json, '')) <> ''
                 OR trim(COALESCE(NEW.voice_clone_status, '')) <> ''
                 OR trim(COALESCE(NEW.voice_clone_error, '')) <> ''
                 )
            BEGIN
                SELECT RAISE(ABORT, 'Refusing to store Host Onboarding data on an AI companion_mappings row');
            END;
            """
        )
        cur.execute(
            """
            CREATE TRIGGER companion_mappings_prevent_ai_host_insert
            BEFORE INSERT ON companion_mappings
            FOR EACH ROW
            WHEN lower(COALESCE(NEW.companion_type, '')) = 'ai'
             AND (
                    trim(COALESCE(NEW.host_member_id, '')) <> ''
                 OR trim(COALESCE(NEW.approved_version_id, '')) <> ''
                 OR trim(COALESCE(NEW.voice_capture_url, '')) <> ''
                 OR trim(COALESCE(NEW.public_gallery_json, '')) <> ''
                 OR trim(COALESCE(NEW.voice_clone_status, '')) <> ''
                 OR trim(COALESCE(NEW.voice_clone_error, '')) <> ''
                 )
            BEGIN
                SELECT RAISE(ABORT, 'Refusing to insert Host Onboarding data on an AI companion_mappings row');
            END;
            """
        )
    except Exception as e:
        # Do not fail platform startup, but make trigger installation failures
        # visible in App Service logs.
        try:
            print(f"[mappings] ERROR creating AI row protection triggers: {e!r}")
        except Exception:
            pass


def _host_onboarding_ensure_companion_export_columns_on_conn(conn: sqlite3.Connection) -> None:
    """Ensure companion_mappings has the columns required by Host Onboarding exports.

    This is intentionally usable inside the active Host Onboarding approval transaction.
    The prior best-effort helper opened a second SQLite connection while approval already
    held a write transaction, which could prevent the Human companion mapping row from
    being created before the approved profile was committed.
    """
    cur = conn.cursor()
    try:
        cur.execute(
            """
            CREATE TABLE IF NOT EXISTS companion_mappings (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                brand TEXT,
                avatar TEXT
            )
            """
        )
    except Exception:
        # If the deployed DB already has the table with a different compatible shape,
        # continue to the ALTER checks below.
        pass

    cur.execute("PRAGMA table_info(companion_mappings)")
    cols = {str(row[1] or "").strip().lower() for row in cur.fetchall()}
    for col_name, col_type in [
        ("brand_id", "INTEGER"),
        ("companion_id", "INTEGER"),
        ("host_member_id", "TEXT"),
        ("channel_cap", "TEXT"),
        ("live", "TEXT"),
        ("companion_type", "TEXT"),
        ("phonetic", "TEXT"),
        ("headshot_url", "TEXT"),
        ("voice_capture_url", "TEXT"),
        ("public_gallery_json", "TEXT"),
        ("approved_version_id", "TEXT"),
        ("eleven_voice_id", "TEXT"),
        ("eleven_voice_name", "TEXT"),
        ("voice_clone_status", "TEXT"),
        ("voice_clone_error", "TEXT"),
        ("list_in_companion_catalog", "INTEGER"),
        ("catalog_hidden_reason", "TEXT"),
        ("catalog_visibility_updated_at", "INTEGER"),
        ("catalog_visibility_updated_by", "TEXT"),
    ]:
        if col_name not in cols:
            try:
                cur.execute(f"ALTER TABLE companion_mappings ADD COLUMN {col_name} {col_type}")
                cols.add(col_name)
            except Exception:
                pass

    _host_onboarding_create_companion_mapping_triggers_on_conn(conn)
    _host_onboarding_backfill_brand_id_for_brand_on_conn(conn, "Elaralo")
    _host_onboarding_backfill_companion_ids_on_conn(conn)
    _brand_feature_flags_ensure_table_on_conn(conn)
    _companion_catalog_visibility_install_triggers_on_conn(conn)
    # Avatar identity normalization is intentionally not run from this generic
    # schema helper. It is applied once at app startup by
    # _deployment_run_startup_migrations_sync(), then recorded in
    # app_startup_migrations so ordinary schema checks do not rewrite identity
    # values on every request.


def _host_onboarding_ensure_companion_export_columns_best_effort() -> None:
    try:
        db_path = _get_companion_mappings_db_path(for_write=True) or _ensure_econnect_db_seeded()
        if not db_path:
            return
        conn = sqlite3.connect(db_path)
        try:
            _host_onboarding_ensure_companion_export_columns_on_conn(conn)
            conn.commit()
        finally:
            conn.close()
    except Exception:
        pass


def _host_onboarding_find_existing_human_mapping_row_on_conn(
    conn: sqlite3.Connection,
    *,
    member_id: str,
    approved_version_id: str = "",
    legacy_avatar: str = "",
    expected_avatar: str = "",
) -> Optional[sqlite3.Row]:
    """Find the existing Human mapping row for a host/version.

    Safety rule: host_member_id alone is not enough to select a row. Historical
    contamination put a host_member_id on an AI row, so a candidate must also be
    explicitly Human and have the same first-name avatar base as the host profile
    being exported.
    """
    try:
        conn.row_factory = sqlite3.Row
        cur = conn.cursor()
        member_norm = _host_onboarding_normalize_member_id(member_id)
        version_norm = _host_onboarding_safe_str(approved_version_id)
        legacy_norm = _host_onboarding_safe_str(legacy_avatar)
        expected_base = _companion_avatar_first_name(expected_avatar or legacy_avatar)
        rows = cur.execute(
            """
            SELECT rowid AS _rowid, *
              FROM companion_mappings
             WHERE lower(COALESCE(brand, '')) = lower(?)
               AND lower(COALESCE(companion_type, '')) = 'human'
               AND (
                    (? <> '' AND lower(COALESCE(approved_version_id, '')) = lower(?))
                 OR (? <> '' AND lower(COALESCE(avatar, '')) = lower(?))
                 OR (? <> '' AND lower(COALESCE(host_member_id, '')) = lower(?))
               )
             ORDER BY
               CASE
                 WHEN ? <> '' AND lower(COALESCE(approved_version_id, '')) = lower(?) THEN 0
                 WHEN ? <> '' AND lower(COALESCE(avatar, '')) = lower(?) THEN 1
                 WHEN ? <> '' AND lower(COALESCE(host_member_id, '')) = lower(?) THEN 2
                 ELSE 3
               END,
               rowid
             LIMIT 20
            """,
            (
                "Elaralo",
                version_norm, version_norm,
                legacy_norm, legacy_norm,
                member_norm, member_norm,
                version_norm, version_norm,
                legacy_norm, legacy_norm,
                member_norm, member_norm,
            ),
        ).fetchall()
        if not rows:
            return None
        if not expected_base:
            return rows[0]
        expected_lc = expected_base.lower()
        for row in rows:
            row_base = _companion_avatar_first_name(row["avatar"] if "avatar" in row.keys() else "")
            if row_base.lower() == expected_lc:
                return row
        return None
    except Exception:
        return None

def _host_onboarding_unique_avatar_for_brand_on_conn(
    conn: sqlite3.Connection,
    brand: str,
    proposed_avatar: Any,
    *,
    current_rowid: Optional[int] = None,
) -> str:
    """Return first-name avatar or first-name-######### for duplicate names.

    The first row for a name/brand receives the bare first name. Later rows with
    the same first-name base receive the lowest available nine-digit suffix.
    """
    base = _companion_avatar_first_name(proposed_avatar) or "Companion"
    brand_name = _host_onboarding_safe_str(brand) or "Elaralo"
    used_exact = False
    used_nums: Set[int] = set()
    try:
        cur = conn.cursor()
        rows = cur.execute(
            """
            SELECT rowid AS _rowid, avatar
              FROM companion_mappings
             WHERE lower(COALESCE(brand, '')) = lower(?)
               AND (lower(COALESCE(avatar, '')) = lower(?) OR lower(COALESCE(avatar, '')) LIKE lower(?))
             ORDER BY rowid
            """,
            (brand_name, base, f"{base}-%"),
        ).fetchall()
        for row in rows or []:
            try:
                rowid = int(row["_rowid"] if isinstance(row, sqlite3.Row) else row[0])
            except Exception:
                rowid = 0
            if current_rowid is not None and rowid == int(current_rowid):
                continue
            avatar = _host_onboarding_safe_str(row["avatar"] if isinstance(row, sqlite3.Row) else row[1])
            if avatar.lower() == base.lower():
                used_exact = True
                continue
            m = _COMPANION_AVATAR_COLLISION_SUFFIX_RE.match(avatar)
            if m and m.group("base").lower() == base.lower():
                try:
                    used_nums.add(int(m.group("num")))
                except Exception:
                    pass
    except Exception:
        pass

    if not used_exact:
        return base
    n = 1
    while n in used_nums:
        n += 1
    return f"{base}-{n:09d}"


def _host_onboarding_normalize_companion_mapping_avatars_for_brand_on_conn(conn: sqlite3.Connection, brand: str = "Elaralo") -> None:
    """Best-effort one-time normalization for existing Elaralo mapping rows.

    Existing rows are processed in rowid order so the first instance of a name keeps
    the bare first name and later instances receive -######### suffixes. DulceMoon
    and other white-label rows are intentionally not touched by the Elaralo startup
    repair path.
    """
    brand_name = _host_onboarding_safe_str(brand) or "Elaralo"
    try:
        conn.row_factory = sqlite3.Row
        cur = conn.cursor()
        rows = cur.execute(
            """
            SELECT rowid AS _rowid, avatar
              FROM companion_mappings
             WHERE lower(COALESCE(brand, '')) = lower(?)
             ORDER BY rowid
            """,
            (brand_name,),
        ).fetchall()
        used: Dict[str, Set[int]] = {}
        has_bare: Set[str] = set()
        updates: List[Tuple[str, int]] = []
        for row in rows or []:
            rowid = int(row["_rowid"])
            old_avatar = _host_onboarding_safe_str(row["avatar"])
            base = _companion_avatar_first_name(old_avatar) or "Companion"
            base_key = base.lower()
            used.setdefault(base_key, set())
            if base_key not in has_bare:
                new_avatar = base
                has_bare.add(base_key)
            else:
                n = 1
                while n in used[base_key]:
                    n += 1
                used[base_key].add(n)
                new_avatar = f"{base}-{n:09d}"
            if new_avatar != old_avatar:
                updates.append((new_avatar, rowid))
        for new_avatar, rowid in updates:
            cur.execute("UPDATE companion_mappings SET avatar = ? WHERE rowid = ?", (new_avatar, rowid))
    except Exception:
        pass




def _bool_from_any(value: Any, default: Optional[bool] = None) -> Optional[bool]:
    if value is None:
        return default
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        if int(value) == 1:
            return True
        if int(value) == 0:
            return False
    text = _host_onboarding_safe_str(value).strip().lower()
    if not text:
        return default
    if text in ("1", "true", "yes", "y", "on", "enabled", "enable", "visible", "show", "shown", "public"):
        return True
    if text in ("0", "false", "no", "n", "off", "disabled", "disable", "hidden", "hide", "private"):
        return False
    return default


def _brand_feature_flag_key(value: Any) -> str:
    return re.sub(r"[^a-z0-9]+", "_", _host_onboarding_safe_str(value).strip().lower()).strip("_")


def _brand_feature_flags_ensure_table_on_conn(conn: sqlite3.Connection) -> None:
    try:
        conn.execute(
            """
            CREATE TABLE IF NOT EXISTS brand_feature_flags (
                brand TEXT NOT NULL,
                feature_key TEXT NOT NULL,
                enabled INTEGER NOT NULL DEFAULT 0,
                config_json TEXT,
                updated_at_epoch INTEGER,
                updated_by TEXT,
                PRIMARY KEY (brand, feature_key)
            )
            """
        )
    except Exception:
        pass


def _brand_feature_flag_db_enabled_on_conn(conn: sqlite3.Connection, brand: str, feature_key: str) -> Optional[bool]:
    try:
        _brand_feature_flags_ensure_table_on_conn(conn)
        row = conn.execute(
            """
            SELECT enabled
              FROM brand_feature_flags
             WHERE lower(COALESCE(brand, '')) = lower(?)
               AND lower(COALESCE(feature_key, '')) = lower(?)
             LIMIT 1
            """,
            (_host_onboarding_safe_str(brand), _host_onboarding_safe_str(feature_key)),
        ).fetchone()
        if row is None:
            return None
        return _bool_from_any(row[0], default=False)
    except Exception:
        return None


def _env_bool(name: str, default: Optional[bool] = None) -> Optional[bool]:
    if name not in os.environ:
        return default
    return _bool_from_any(os.getenv(name), default=default)


def _brand_feature_flag_enabled_sync(brand: Any, feature_key: Any, *, default: bool = False) -> bool:
    """Resolve a brand feature flag with default-off behavior.

    Env vars are the primary switch. A DB row may disable or enable a feature for
    a brand. If neither env nor DB is present, default is used.
    """
    brand_name = _host_onboarding_safe_str(brand) or "Elaralo"
    feature = _brand_feature_flag_key(feature_key)
    brand_env = f"{_brand_feature_flag_key(brand_name).upper()}_{feature.upper()}_ENABLED"
    global_env = f"{feature.upper()}_ENABLED"
    env_value = _env_bool(brand_env, default=None)
    if env_value is None:
        env_value = _env_bool(global_env, default=None)
    effective = bool(env_value if env_value is not None else default)
    try:
        db_path = _get_companion_mappings_db_path(for_write=False) or _ensure_econnect_db_seeded()
        if db_path:
            conn = sqlite3.connect(db_path, timeout=10, check_same_thread=False)
            try:
                db_value = _brand_feature_flag_db_enabled_on_conn(conn, brand_name, feature)
                if db_value is False:
                    return False
                if db_value is True:
                    return True
            finally:
                conn.close()
    except Exception:
        pass
    return effective


def _host_profile_studio_enabled_for_brand(brand: Any) -> bool:
    return _brand_feature_flag_enabled_sync(brand or "Elaralo", "host_profile_studio", default=False)


def _companion_catalog_visibility_value(value: Any, *, default: Optional[bool] = None) -> Optional[bool]:
    return _bool_from_any(value, default=default)


def _host_onboarding_catalog_visible_from_objs(*objs: Any) -> Optional[bool]:
    keys = (
        "list_in_companion_catalog",
        "listInCompanionCatalog",
        "catalog_visible",
        "catalogVisible",
        "show_in_companion_catalog",
        "showInCompanionCatalog",
        "public_catalog_visible",
        "publicCatalogVisible",
    )
    for obj in objs:
        if not isinstance(obj, dict):
            continue
        for key in keys:
            if key in obj:
                parsed = _companion_catalog_visibility_value(obj.get(key), default=None)
                if parsed is not None:
                    return parsed
    return None


def _companion_catalog_visibility_install_triggers_on_conn(conn: sqlite3.Connection) -> None:
    try:
        cur = conn.cursor()
        cur.execute("DROP TRIGGER IF EXISTS companion_mappings_default_catalog_visibility_insert")
        cur.execute(
            """
            CREATE TRIGGER companion_mappings_default_catalog_visibility_insert
            AFTER INSERT ON companion_mappings
            FOR EACH ROW
            WHEN NEW.list_in_companion_catalog IS NULL
            BEGIN
                UPDATE companion_mappings
                   SET list_in_companion_catalog = CASE
                          WHEN lower(COALESCE(NEW.companion_type, '')) = 'human' THEN 0
                          ELSE 1
                       END,
                       catalog_hidden_reason = CASE
                          WHEN lower(COALESCE(NEW.companion_type, '')) = 'human' THEN COALESCE(NULLIF(catalog_hidden_reason, ''), 'host_hidden_by_default')
                          ELSE catalog_hidden_reason
                       END,
                       catalog_visibility_updated_at = COALESCE(catalog_visibility_updated_at, CAST(strftime('%s','now') AS INTEGER))
                 WHERE rowid = NEW.rowid;
            END;
            """
        )
    except Exception:
        pass


def _companion_mapping_catalog_visible(mapping: Any, current_member_id: str = "") -> bool:
    try:
        obj = dict(mapping) if not isinstance(mapping, dict) else mapping
    except Exception:
        obj = {}
    ctype = _host_onboarding_safe_str(obj.get("companion_type") or obj.get("companionType")).lower()
    host_member = _host_onboarding_normalize_member_id(obj.get("host_member_id") or obj.get("hostMemberId"))
    current = _host_onboarding_normalize_member_id(current_member_id)
    explicit = _companion_catalog_visibility_value(
        obj.get("list_in_companion_catalog") if "list_in_companion_catalog" in obj else obj.get("listInCompanionCatalog"),
        default=None,
    )
    if ctype == "human":
        if current and host_member and current.lower() == host_member.lower():
            return True
        return bool(explicit is True)
    if explicit is False:
        return False
    return True


def _companion_mapping_is_hidden_for_owner(mapping: Any) -> bool:
    try:
        obj = dict(mapping) if not isinstance(mapping, dict) else mapping
    except Exception:
        obj = {}
    ctype = _host_onboarding_safe_str(obj.get("companion_type") or obj.get("companionType")).lower()
    if ctype != "human":
        return False
    explicit = _companion_catalog_visibility_value(
        obj.get("list_in_companion_catalog") if "list_in_companion_catalog" in obj else obj.get("listInCompanionCatalog"),
        default=False,
    )
    return not bool(explicit)


_STARTUP_MIGRATION_COMPANION_AVATAR_IDENTITY_V9_2_18 = "v9_2_18_companion_avatar_identity_generation_ethnicity"
_STARTUP_MIGRATION_AI_ROW_OWNERSHIP_HYGIENE_V9_2_22 = "v9_2_22_companion_ai_row_ownership_hygiene"
_STARTUP_MIGRATION_COMPANION_CATALOG_VISIBILITY_V9_2_30 = "v9_2_30_companion_catalog_visibility_defaults"


def _startup_migrations_ensure_table_on_conn(conn: sqlite3.Connection) -> None:
    """Create the one-time startup migration ledger.

    This table lives in the same econnect.sqlite3 DB as companion_mappings, so the
    deployment migration is recorded with the data it changed. If the packaged DB
    is replaced by a future deployment that lacks the marker, the migration runs
    for that new DB exactly once.
    """
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS app_startup_migrations (
            migration_id TEXT PRIMARY KEY,
            applied_at_epoch INTEGER NOT NULL,
            status TEXT NOT NULL,
            details_json TEXT
        )
        """
    )


def _startup_migration_is_applied_on_conn(conn: sqlite3.Connection, migration_id: str) -> bool:
    try:
        _startup_migrations_ensure_table_on_conn(conn)
        row = conn.execute(
            "SELECT status FROM app_startup_migrations WHERE migration_id = ? LIMIT 1",
            (_host_onboarding_safe_str(migration_id),),
        ).fetchone()
        return bool(row and _host_onboarding_safe_str(row[0]).lower() == "applied")
    except Exception:
        return False


def _startup_migration_mark_applied_on_conn(conn: sqlite3.Connection, migration_id: str, details: Dict[str, Any]) -> None:
    _startup_migrations_ensure_table_on_conn(conn)
    conn.execute(
        """
        INSERT INTO app_startup_migrations (migration_id, applied_at_epoch, status, details_json)
        VALUES (?, ?, 'applied', ?)
        ON CONFLICT(migration_id) DO UPDATE SET
            applied_at_epoch = excluded.applied_at_epoch,
            status = excluded.status,
            details_json = excluded.details_json
        """,
        (
            _host_onboarding_safe_str(migration_id),
            int(_host_onboarding_now()),
            _host_onboarding_json_dumps(details or {}),
        ),
    )


def _startup_normalize_companion_mapping_metadata_for_brand_on_conn(conn: sqlite3.Connection, brand: str = "Elaralo") -> Dict[str, Any]:
    """Normalize existing metadata columns when present.

    Current live companion_mappings does not always include generation/ethnicity
    columns. This function is defensive: if those columns are absent, it records
    zero updates and exits. If they exist in a future DB, it normalizes values to
    the same compact dropdown set used by the My Elaralo catalog.
    """
    brand_name = _host_onboarding_safe_str(brand) or "Elaralo"
    generation_updates = 0
    ethnicity_updates = 0
    try:
        conn.row_factory = sqlite3.Row
        cur = conn.cursor()
        cur.execute("PRAGMA table_info(companion_mappings)")
        cols = {str(row[1] or "").strip().lower() for row in cur.fetchall()}
        if "brand" not in cols:
            return {"generation_updates": 0, "ethnicity_updates": 0}

        rows = cur.execute(
            """
            SELECT rowid AS _rowid, *
              FROM companion_mappings
             WHERE lower(COALESCE(brand, '')) = lower(?)
             ORDER BY rowid
            """,
            (brand_name,),
        ).fetchall()

        if "generation" in cols:
            for row in rows or []:
                try:
                    old = _host_onboarding_safe_str(row["generation"])
                    new_value = _normalize_companion_generation_label(old)
                    if new_value and new_value != old:
                        cur.execute("UPDATE companion_mappings SET generation = ? WHERE rowid = ?", (new_value, int(row["_rowid"])))
                        generation_updates += 1
                except Exception:
                    continue

        if "ethnicity" in cols:
            for row in rows or []:
                try:
                    old = _host_onboarding_safe_str(row["ethnicity"])
                    new_value = _normalize_companion_ethnicity_label(old)
                    if new_value and new_value != old:
                        cur.execute("UPDATE companion_mappings SET ethnicity = ? WHERE rowid = ?", (new_value, int(row["_rowid"])))
                        ethnicity_updates += 1
                except Exception:
                    continue
    except Exception:
        pass
    return {"generation_updates": generation_updates, "ethnicity_updates": ethnicity_updates}


def _startup_run_companion_avatar_identity_migration_on_conn(conn: sqlite3.Connection, brand: str = "Elaralo") -> Dict[str, Any]:
    """Apply the Elaralo companion identity migration once for the deployment.

    Effects:
      - Existing Elaralo companion_mappings.avatar values become first-name IDs.
      - Duplicate first names within the brand receive -######### suffixes.
      - brand_id / companion_id repair and DB triggers remain in place.
      - Generation/Ethnicity columns are normalized if present.

    This is idempotent and safe to run inside a deployment startup transaction.
    The surrounding one-time ledger prevents re-running after success.
    """
    brand_name = _host_onboarding_safe_str(brand) or "Elaralo"
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    _host_onboarding_ensure_companion_export_columns_on_conn(conn)

    before_rows = cur.execute(
        """
        SELECT rowid AS _rowid, avatar
          FROM companion_mappings
         WHERE lower(COALESCE(brand, '')) = lower(?)
         ORDER BY rowid
        """,
        (brand_name,),
    ).fetchall()
    before_by_rowid = {
        int(row["_rowid"]): _host_onboarding_safe_str(row["avatar"])
        for row in before_rows or []
    }

    _host_onboarding_normalize_companion_mapping_avatars_for_brand_on_conn(conn, brand_name)
    metadata_result = _startup_normalize_companion_mapping_metadata_for_brand_on_conn(conn, brand_name)

    after_rows = cur.execute(
        """
        SELECT rowid AS _rowid, avatar
          FROM companion_mappings
         WHERE lower(COALESCE(brand, '')) = lower(?)
         ORDER BY rowid
        """,
        (brand_name,),
    ).fetchall()
    avatar_updates: List[Dict[str, Any]] = []
    for row in after_rows or []:
        rowid = int(row["_rowid"])
        old_avatar = before_by_rowid.get(rowid, "")
        new_avatar = _host_onboarding_safe_str(row["avatar"])
        if old_avatar != new_avatar:
            avatar_updates.append({"rowid": rowid, "old": old_avatar, "new": new_avatar})

    return {
        "brand": brand_name,
        "rows_scanned": len(before_by_rowid),
        "avatar_updates": avatar_updates,
        "avatar_update_count": len(avatar_updates),
        "generation_update_count": int((metadata_result or {}).get("generation_updates") or 0),
        "ethnicity_update_count": int((metadata_result or {}).get("ethnicity_updates") or 0),
    }



def _startup_run_ai_mapping_ownership_hygiene_on_conn(conn: sqlite3.Connection, brand: str = "Elaralo") -> Dict[str, Any]:
    """Clear stale Host Onboarding ownership fields from AI mapping rows.

    This is a one-time startup hygiene migration for rows that were polluted
    before the stronger AI-row triggers existed. It does not modify AI voice,
    channel_cap, live, D-ID, or avatar identity fields.
    """
    brand_name = _host_onboarding_safe_str(brand) or "Elaralo"
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    _host_onboarding_ensure_companion_export_columns_on_conn(conn)
    rows = cur.execute(
        """
        SELECT rowid AS _rowid, *
          FROM companion_mappings
         WHERE lower(COALESCE(brand, '')) = lower(?)
           AND lower(COALESCE(companion_type, '')) = 'ai'
           AND (
                trim(COALESCE(host_member_id, '')) <> ''
             OR trim(COALESCE(approved_version_id, '')) <> ''
             OR trim(COALESCE(voice_capture_url, '')) <> ''
             OR trim(COALESCE(public_gallery_json, '')) <> ''
             OR trim(COALESCE(voice_clone_status, '')) <> ''
             OR trim(COALESCE(voice_clone_error, '')) <> ''
             OR lower(COALESCE(headshot_url, '')) LIKE '%/host-onboarding/%'
             OR lower(COALESCE(headshot_url, '')) LIKE '%connect-platform/companion/headshot/%'
           )
         ORDER BY rowid
        """,
        (brand_name,),
    ).fetchall()

    cleared: List[Dict[str, Any]] = []
    for row in rows or []:
        rowid = int(row["_rowid"])
        old_headshot = _host_onboarding_safe_str(row["headshot_url"] if "headshot_url" in row.keys() else "")
        clear_headshot = (
            "/host-onboarding/" in old_headshot.lower()
            or "connect-platform/companion/headshot/" in old_headshot.lower()
        )
        cur.execute(
            """
            UPDATE companion_mappings
               SET host_member_id = NULL,
                   approved_version_id = NULL,
                   voice_capture_url = NULL,
                   public_gallery_json = NULL,
                   voice_clone_status = NULL,
                   voice_clone_error = NULL,
                   headshot_url = CASE WHEN ? THEN NULL ELSE headshot_url END
             WHERE rowid = ?
               AND lower(COALESCE(companion_type, '')) = 'ai'
            """,
            (1 if clear_headshot else 0, rowid),
        )
        cleared.append({
            "rowid": rowid,
            "avatar": _host_onboarding_safe_str(row["avatar"] if "avatar" in row.keys() else ""),
            "cleared_headshot_url": bool(clear_headshot),
        })
    return {"brand": brand_name, "ai_rows_scanned": len(rows or []), "ai_rows_cleaned": len(cleared), "cleaned_rows": cleared}


def _startup_run_companion_catalog_visibility_defaults_on_conn(conn: sqlite3.Connection) -> Dict[str, Any]:
    """Initialize catalog visibility defaults for existing rows.

    Future Human Companion rows default hidden. For existing rows, preserve the
    working DulceMoon default companion by making Dulce visible if it has no
    explicit value yet. Elaralo Human Host rows with NULL visibility are hidden.
    AI rows stay visible unless explicitly hidden.
    """
    conn.row_factory = sqlite3.Row
    cur = conn.cursor()
    _host_onboarding_ensure_companion_export_columns_on_conn(conn)
    rows = cur.execute(
        """
        SELECT rowid AS _rowid, brand, avatar, companion_type, list_in_companion_catalog
          FROM companion_mappings
         WHERE list_in_companion_catalog IS NULL
         ORDER BY rowid
        """
    ).fetchall()
    updates: List[Dict[str, Any]] = []
    now_epoch = int(_host_onboarding_now())
    for row in rows or []:
        rowid = int(row["_rowid"])
        brand = _host_onboarding_safe_str(row["brand"])
        avatar = _host_onboarding_safe_str(row["avatar"])
        ctype = _host_onboarding_safe_str(row["companion_type"]).lower()
        visible = 1
        reason = None
        if ctype == "human":
            if brand.lower() == "dulcemoon" and _companion_avatar_first_name(avatar).lower() == "dulce":
                visible = 1
            else:
                visible = 0
                reason = "host_hidden_by_default"
        cur.execute(
            """
            UPDATE companion_mappings
               SET list_in_companion_catalog = ?,
                   catalog_hidden_reason = CASE WHEN ? = 1 THEN NULL ELSE COALESCE(NULLIF(catalog_hidden_reason, ''), ?) END,
                   catalog_visibility_updated_at = COALESCE(catalog_visibility_updated_at, ?),
                   catalog_visibility_updated_by = COALESCE(NULLIF(catalog_visibility_updated_by, ''), 'startup_migration_v9_2_30')
             WHERE rowid = ?
            """,
            (visible, visible, reason or "", now_epoch, rowid),
        )
        updates.append({"rowid": rowid, "brand": brand, "avatar": avatar, "companion_type": ctype, "visible": bool(visible)})
    return {"rows_scanned": len(rows or []), "visibility_updates": len(updates), "updates": updates}

def _deployment_run_startup_migrations_sync() -> Dict[str, Any]:
    """Run deployment-time DB migrations once per DB.

    Runs the existing avatar identity migration and the v9.2.22 AI-row
    ownership hygiene migration. Each migration has its own ledger marker so a
    new safety migration can run even when an earlier one was already applied.
    """
    db_path = ""
    applied: List[Dict[str, Any]] = []
    try:
        db_path = _get_companion_mappings_db_path(for_write=True) or _ensure_econnect_db_seeded()
        if not db_path:
            return {"ok": False, "skipped": True, "reason": "no_db_path"}

        lock_path = f"{db_path}.startup-migrations.lock"
        with FileLock(lock_path, timeout=30):
            conn = sqlite3.connect(db_path, timeout=30, check_same_thread=False)
            conn.row_factory = sqlite3.Row
            try:
                try:
                    conn.execute("PRAGMA busy_timeout=5000;")
                except Exception:
                    pass
                _startup_migrations_ensure_table_on_conn(conn)
                _host_onboarding_ensure_companion_export_columns_on_conn(conn)
                conn.commit()

                migration_plan = [
                    (
                        _STARTUP_MIGRATION_COMPANION_AVATAR_IDENTITY_V9_2_18,
                        lambda c: _startup_run_companion_avatar_identity_migration_on_conn(c, "Elaralo"),
                    ),
                    (
                        _STARTUP_MIGRATION_AI_ROW_OWNERSHIP_HYGIENE_V9_2_22,
                        lambda c: _startup_run_ai_mapping_ownership_hygiene_on_conn(c, "Elaralo"),
                    ),
                    (
                        _STARTUP_MIGRATION_COMPANION_CATALOG_VISIBILITY_V9_2_30,
                        lambda c: _startup_run_companion_catalog_visibility_defaults_on_conn(c),
                    ),
                ]

                for migration_id, runner in migration_plan:
                    conn.execute("BEGIN IMMEDIATE")
                    try:
                        if _startup_migration_is_applied_on_conn(conn, migration_id):
                            conn.commit()
                            applied.append({"migration_id": migration_id, "skipped": True, "reason": "already_applied"})
                            continue
                        result = runner(conn) or {}
                        _startup_migration_mark_applied_on_conn(conn, migration_id, result)
                        conn.commit()
                        applied.append({"migration_id": migration_id, "skipped": False, **result})
                        print(f"[startup-migration] applied {migration_id}: {result}")
                    except Exception:
                        try:
                            conn.rollback()
                        except Exception:
                            pass
                        raise

                return {"ok": True, "db_path": db_path, "migrations": applied}
            finally:
                try:
                    conn.close()
                except Exception:
                    pass
    except Exception as e:
        print(f"[startup-migration] ERROR applying startup migrations to {db_path or '<unknown>'}: {e!r}")
        return {"ok": False, "db_path": db_path, "error": repr(e), "migrations": applied}

def _lookup_companion_mapping_by_avatar_base(brand: str, avatar_base: Any) -> Optional[Dict[str, Any]]:
    """Lookup a mapping by first-name base, preferring the bare first-name row."""
    b = _norm_key(brand) or "elaralo"
    base = _companion_avatar_first_name(avatar_base)
    if not base:
        return None
    exact = _lookup_companion_mapping(brand, base)
    if exact:
        return exact
    base_lc = base.lower()
    candidates: List[Tuple[int, str, Dict[str, Any]]] = []
    for (row_brand, row_avatar), mapping in list(_COMPANION_MAPPINGS.items()):
        if row_brand != b:
            continue
        avatar = _host_onboarding_safe_str((mapping or {}).get("avatar"))
        m = _COMPANION_AVATAR_COLLISION_SUFFIX_RE.match(avatar)
        if not m or m.group("base").lower() != base_lc:
            continue
        try:
            n = int(m.group("num"))
        except Exception:
            n = 999999999
        candidates.append((n, avatar.lower(), mapping))
    if not candidates:
        return None
    candidates.sort(key=lambda item: (item[0], item[1]))
    return dict(candidates[0][2])


def _companion_mapping_companion_type_lc(mapping: Any) -> str:
    if not isinstance(mapping, dict):
        try:
            mapping = dict(mapping)
        except Exception:
            mapping = {}
    return _host_onboarding_safe_str((mapping or {}).get("companion_type") or (mapping or {}).get("companionType")).lower()


def _companion_mapping_matches_requested_type(mapping: Any, requested_type: Any) -> bool:
    """Return whether a mapping row is safe to use for an explicit companion type.

    The important production invariant is isolation: an AI selection must never
    reuse a Human mapping row for the same first name, and a Human selection must
    not consume an AI mapping row. Blank legacy rows are tolerated only when they
    do not carry Host Onboarding ownership/version markers.
    """
    wanted = _host_onboarding_safe_str(requested_type).lower()
    if wanted in ("human_companion", "human-companion"):
        wanted = "human"
    elif wanted in ("ai_companion", "ai-companion"):
        wanted = "ai"
    if wanted not in ("human", "ai"):
        return bool(mapping)
    if not isinstance(mapping, dict):
        try:
            mapping = dict(mapping)
        except Exception:
            mapping = {}
    if not mapping:
        return False
    ctype = _companion_mapping_companion_type_lc(mapping)
    host_member_id = _host_onboarding_safe_str((mapping or {}).get("host_member_id") or (mapping or {}).get("hostMemberId"))
    approved_version_id = _host_onboarding_safe_str((mapping or {}).get("approved_version_id") or (mapping or {}).get("approvedVersionId"))
    if wanted == "ai":
        if ctype == "ai":
            return True
        # Historical AI rows may have a blank companion_type, but they should not
        # be Host Onboarding rows. A row with host_member_id/approved_version_id is Human-owned.
        return not ctype and not host_member_id and not approved_version_id
    if wanted == "human":
        if ctype == "ai":
            return False
        return ctype == "human" or bool(host_member_id or approved_version_id)
    return False


def _lookup_companion_mapping_typed(brand: str, avatar: Any, requested_type: Any) -> Optional[Dict[str, Any]]:
    row = _lookup_companion_mapping(brand, _host_onboarding_safe_str(avatar))
    if row and _companion_mapping_matches_requested_type(row, requested_type):
        return dict(row)
    return None


def _lookup_companion_mapping_by_avatar_base_typed(brand: str, avatar_base: Any, requested_type: Any) -> Optional[Dict[str, Any]]:
    """Lookup by first-name base while preserving AI/Human type isolation."""
    b = _norm_key(brand) or "elaralo"
    base = _companion_avatar_first_name(avatar_base)
    if not base:
        return None
    exact = _lookup_companion_mapping_typed(brand, base, requested_type)
    if exact:
        return exact
    base_lc = base.lower()
    candidates: List[Tuple[int, str, Dict[str, Any]]] = []
    for (row_brand, _row_avatar), mapping in list(_COMPANION_MAPPINGS.items()):
        if row_brand != b:
            continue
        if not _companion_mapping_matches_requested_type(mapping, requested_type):
            continue
        avatar = _host_onboarding_safe_str((mapping or {}).get("avatar"))
        m = _COMPANION_AVATAR_COLLISION_SUFFIX_RE.match(avatar)
        if not m or m.group("base").lower() != base_lc:
            continue
        try:
            n = int(m.group("num"))
        except Exception:
            n = 999999999
        candidates.append((n, avatar.lower(), mapping))
    if not candidates:
        return None
    candidates.sort(key=lambda item: (item[0], item[1]))
    return dict(candidates[0][2])


def _host_onboarding_upsert_connect_companion_mapping(
    *,
    member_id: str,
    avatar_key: str,
    headshot_url: str,
    voice_capture_url: str,
    public_gallery_assets: List[Dict[str, Any]],
    approved_version_id: str,
    eleven_voice_id: str = "",
    eleven_voice_name: str = "",
    voice_clone_status: str = "",
    voice_clone_error: str = "",
    phonetic_pronunciation: str = "",
    list_in_companion_catalog: Optional[bool] = None,
    conn: Optional[sqlite3.Connection] = None,
) -> str:
    """Create/update the Elaralo Human companion mapping exported by Host Onboarding.

    Human Companion rows are created by Host Onboarding after a limited/full approval.
    They are always Human + Stream + Video. AI mapping rows are not modified here.

    The companion_mappings.avatar value is first-name based. The first row for a
    name/brand uses the bare first name; later rows receive -######### suffixes.
    """
    proposed_avatar = _companion_avatar_first_name(avatar_key) or _host_onboarding_safe_str(avatar_key)
    member_id = _host_onboarding_normalize_member_id(member_id)
    approved_version_id_norm = _host_onboarding_safe_str(approved_version_id)
    if not proposed_avatar or not member_id:
        return _host_onboarding_safe_str(avatar_key)

    owns_conn = conn is None
    if owns_conn:
        _host_onboarding_ensure_companion_export_columns_best_effort()
        db_path = _get_companion_mappings_db_path(for_write=True)
        conn = sqlite3.connect(db_path, timeout=30, check_same_thread=False)
        conn.row_factory = sqlite3.Row
        try:
            conn.execute("PRAGMA busy_timeout=5000;")
        except Exception:
            pass

    final_avatar = proposed_avatar
    try:
        assert conn is not None
        conn.row_factory = sqlite3.Row
        _host_onboarding_ensure_companion_export_columns_on_conn(conn)
        cur = conn.cursor()

        brand_id = _host_onboarding_resolve_brand_id_for_brand_on_conn(conn, "Elaralo")
        existing = _host_onboarding_find_existing_human_mapping_row_on_conn(
            conn,
            member_id=member_id,
            approved_version_id=approved_version_id_norm,
            legacy_avatar=_host_onboarding_safe_str(avatar_key),
            expected_avatar=proposed_avatar,
        )
        # Defense in depth: Host Onboarding must never overwrite an AI mapping row.
        # If a historical/corrupt row is marked AI, create a distinct Human row
        # instead of converting the selected AI companion into the host.
        try:
            if existing is not None and _host_onboarding_safe_str(existing["companion_type"]).lower() == "ai":
                existing = None
        except Exception:
            pass
        current_rowid: Optional[int] = None
        if existing is not None:
            try:
                current_rowid = int(existing["_rowid"])
            except Exception:
                current_rowid = None

        final_avatar = _host_onboarding_unique_avatar_for_brand_on_conn(
            conn,
            "Elaralo",
            proposed_avatar,
            current_rowid=current_rowid,
        )

        if existing is None:
            if brand_id is not None:
                cur.execute(
                    "INSERT INTO companion_mappings (brand, avatar, brand_id) VALUES (?, ?, ?)",
                    ("Elaralo", final_avatar, brand_id),
                )
            else:
                cur.execute(
                    "INSERT INTO companion_mappings (brand, avatar) VALUES (?, ?)",
                    ("Elaralo", final_avatar),
                )
            current_rowid = int(cur.lastrowid)

        cur.execute(
            """
            UPDATE companion_mappings
               SET avatar = ?,
                   brand_id = CASE
                        WHEN ? IS NOT NULL AND (brand_id IS NULL OR trim(CAST(brand_id AS TEXT)) = '') THEN ?
                        ELSE brand_id
                   END,
                   host_member_id = ?,
                   channel_cap = 'Video',
                   live = 'Stream',
                   companion_type = 'Human',
                   phonetic = CASE
                        WHEN trim(?) <> '' THEN ?
                        ELSE phonetic
                   END,
                   headshot_url = ?,
                   voice_capture_url = ?,
                   public_gallery_json = ?,
                   approved_version_id = ?,
                   eleven_voice_id = COALESCE(NULLIF(?, ''), eleven_voice_id),
                   eleven_voice_name = COALESCE(NULLIF(?, ''), eleven_voice_name),
                   voice_clone_status = ?,
                   voice_clone_error = ?
             WHERE rowid = ?
            """,
            (
                final_avatar,
                brand_id,
                brand_id,
                member_id,
                _host_onboarding_optional_phonetic(phonetic_pronunciation),
                _host_onboarding_optional_phonetic(phonetic_pronunciation),
                _host_onboarding_safe_str(headshot_url),
                _host_onboarding_safe_str(voice_capture_url),
                _host_onboarding_json_dumps(public_gallery_assets or []),
                approved_version_id_norm,
                _host_onboarding_safe_str(eleven_voice_id),
                _host_onboarding_safe_str(eleven_voice_name),
                _host_onboarding_safe_str(voice_clone_status),
                _host_onboarding_safe_str(voice_clone_error),
                current_rowid,
            ),
        )
        # Human Host profiles are private by default. Preserve an existing explicit
        # listing choice unless Host/Profile Studio supplied a new value.
        visible_choice = list_in_companion_catalog
        if visible_choice is None:
            cur.execute(
                """
                UPDATE companion_mappings
                   SET list_in_companion_catalog = COALESCE(list_in_companion_catalog, 0),
                       catalog_hidden_reason = CASE
                            WHEN COALESCE(list_in_companion_catalog, 0) = 1 THEN NULL
                            ELSE COALESCE(NULLIF(catalog_hidden_reason, ''), 'host_hidden_by_default')
                       END,
                       catalog_visibility_updated_at = COALESCE(catalog_visibility_updated_at, ?),
                       catalog_visibility_updated_by = COALESCE(NULLIF(catalog_visibility_updated_by, ''), ?)
                 WHERE rowid = ?
                """,
                (int(_host_onboarding_now()), member_id, current_rowid),
            )
        else:
            visible_int = 1 if bool(visible_choice) else 0
            cur.execute(
                """
                UPDATE companion_mappings
                   SET list_in_companion_catalog = ?,
                       catalog_hidden_reason = CASE WHEN ? = 1 THEN NULL ELSE 'host_hidden_by_default' END,
                       catalog_visibility_updated_at = ?,
                       catalog_visibility_updated_by = ?
                 WHERE rowid = ?
                """,
                (visible_int, visible_int, int(_host_onboarding_now()), member_id, current_rowid),
            )

        if owns_conn:
            conn.commit()
    finally:
        if owns_conn and conn is not None:
            conn.close()
    if owns_conn:
        try:
            _load_companion_mappings_sync()
        except Exception:
            pass
    return final_avatar

def _host_onboarding_upsert_hco_row(
    *,
    member_id: str,
    avatar_key: str,
    voice_capture_url: str,
    raw_profile: Dict[str, Any],
    conn: Optional[sqlite3.Connection] = None,
) -> None:
    owns_conn = conn is None
    if owns_conn:
        db_path = _get_companion_mappings_db_path(for_write=True)
        conn = sqlite3.connect(db_path, timeout=30, check_same_thread=False)
        conn.row_factory = sqlite3.Row
        try:
            conn.execute("PRAGMA busy_timeout=5000;")
        except Exception:
            pass
    try:
        assert conn is not None
        conn.row_factory = sqlite3.Row
        try:
            _host_onboarding_ensure_schema(conn)
        except Exception:
            pass
        cur = conn.cursor()
        companion_row = cur.execute(
            "SELECT id, companion_id, phonetic FROM companion_mappings WHERE lower(brand)=lower(?) AND lower(avatar)=lower(?) LIMIT 1",
            ("Elaralo", avatar_key),
        ).fetchone()
        companion_id_raw = None
        if companion_row:
            try:
                companion_id_raw = companion_row["companion_id"]
            except Exception:
                companion_id_raw = None
            if companion_id_raw is None or _host_onboarding_safe_str(companion_id_raw) == "":
                companion_id_raw = companion_row["id"] if companion_row["id"] is not None else None
        companion_id = int(companion_id_raw) if companion_id_raw is not None and _host_onboarding_safe_str(companion_id_raw) else None
        existing_phonetic = _host_onboarding_safe_str(companion_row["phonetic"] if companion_row else "")

        public_profile = dict((raw_profile or {}).get("public_profile") or {})
        private_profile = dict((raw_profile or {}).get("private_profile") or {})
        basics = dict((raw_profile or {}).get("session") or {})
        public_name = _host_onboarding_safe_str(public_profile.get("public_display_name") or public_profile.get("stage_name") or avatar_key)
        first_name = re.split(r"\s+", public_name, 1)[0].strip() if public_name else avatar_key.split("-", 1)[0]
        legal_name = _host_onboarding_safe_str(private_profile.get("legal_name"))
        last_name = ""
        if legal_name:
            parts = re.split(r"\s+", legal_name.strip(), maxsplit=1)
            if len(parts) == 2:
                last_name = parts[1].strip()
        birthday = _host_onboarding_safe_str(private_profile.get("birthdate"))
        gender = _host_onboarding_safe_str(public_profile.get("gender"))
        ethnicity = _normalize_companion_ethnicity_label(private_profile.get("race_primary") or basics.get("race_primary") or private_profile.get("ethnicity_detail") or private_profile.get("ethnicity_bucket"))
        wix_id = f"host_onboarding::{_host_onboarding_safe_str(member_id)}::{avatar_key}"
        source_file = "host_onboarding_approved_version"
        now_epoch = int(_host_onboarding_now())
        raw_json = _host_onboarding_json_dumps(raw_profile)
        phonetic = _host_onboarding_extract_explicit_phonetic(raw_profile) or existing_phonetic

        cur.execute(
            """
            INSERT INTO human_companion_onboarding (
                wix_id, created_date, email, first_name, last_name, status, gender, birthday,
                phonetic_pronunciation_of_first_name, audio_or_video_file_upload, consent_to_voice_used, ethnicity,
                raw_json, ingested_at, source_file, companion_id
            ) VALUES (?, ?, '', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(wix_id) DO UPDATE SET
                created_date=excluded.created_date,
                first_name=excluded.first_name,
                last_name=excluded.last_name,
                status=excluded.status,
                gender=excluded.gender,
                birthday=excluded.birthday,
                phonetic_pronunciation_of_first_name=excluded.phonetic_pronunciation_of_first_name,
                audio_or_video_file_upload=excluded.audio_or_video_file_upload,
                consent_to_voice_used=excluded.consent_to_voice_used,
                ethnicity=excluded.ethnicity,
                raw_json=excluded.raw_json,
                ingested_at=excluded.ingested_at,
                source_file=excluded.source_file,
                companion_id=excluded.companion_id
            """,
            (
                wix_id,
                datetime.utcnow().isoformat(timespec="seconds") + "Z",
                first_name,
                last_name,
                "approved",
                gender,
                birthday,
                phonetic,
                _host_onboarding_safe_str(voice_capture_url),
                "yes" if _host_onboarding_safe_str(voice_capture_url) else "",
                ethnicity,
                raw_json,
                now_epoch,
                source_file,
                companion_id,
            ),
        )
        if owns_conn:
            conn.commit()
    except Exception:
        if owns_conn and conn is not None:
            try:
                conn.rollback()
            except Exception:
                pass
    finally:
        if owns_conn and conn is not None:
            conn.close()


def _host_onboarding_export_connect_profile(session: Dict[str, Any], profile: Dict[str, Any], version_id: str, db_conn: Optional[sqlite3.Connection] = None) -> Dict[str, Any]:
    assets = list(session.get("assets") or [])
    public_profile = dict(profile.get("public_profile") or {})
    public_page = dict(profile.get("public_page") or {})
    ai_profile = dict(profile.get("ai_profile") or {})
    private_profile = dict(profile.get("private_profile") or {})
    avatar_key = _host_onboarding_avatar_key_from_session(session)
    try:
        if db_conn is not None:
            existing_mapping = _host_onboarding_find_existing_human_mapping_row_on_conn(
                db_conn,
                member_id=_host_onboarding_safe_str(session.get("member_id")),
                approved_version_id=version_id,
                legacy_avatar=avatar_key,
                expected_avatar=avatar_key,
            )
            existing_rowid = int(existing_mapping["_rowid"]) if existing_mapping is not None else None
            avatar_key = _host_onboarding_unique_avatar_for_brand_on_conn(
                db_conn,
                "Elaralo",
                avatar_key,
                current_rowid=existing_rowid,
            )
    except Exception:
        avatar_key = _host_onboarding_avatar_key_from_session(session)
    headshot_asset, gallery_assets = _host_onboarding_split_public_assets(assets)
    voice_asset = next((asset for asset in assets if _host_onboarding_safe_str((asset or {}).get("slot_key")) == _HOST_ONBOARDING_VOICE_SLOT and _host_onboarding_safe_str((asset or {}).get("url"))), None)

    exported_headshot = None
    if isinstance(headshot_asset, dict) and _host_onboarding_safe_str(headshot_asset.get("url")):
        ext = _infer_upload_ext(_host_onboarding_safe_str(headshot_asset.get("content_type")), _host_onboarding_safe_str(headshot_asset.get("file_name")))
        blob_name = _host_onboarding_export_blob_name("companion", "headshot", f"{avatar_key}{ext}")
        exported_headshot = _host_onboarding_export_asset_from_url(headshot_asset, blob_name)

    exported_gallery: List[Dict[str, Any]] = []
    for idx, asset in enumerate(gallery_assets, start=1):
        ext = _infer_upload_ext(_host_onboarding_safe_str(asset.get("content_type")), _host_onboarding_safe_str(asset.get("file_name")))
        file_name = _host_onboarding_connect_public_filename(asset.get("slot_key"), idx, ext)
        blob_name = _host_onboarding_export_blob_name("public", "gallery", avatar_key, file_name)
        exported_gallery.append(_host_onboarding_export_asset_from_url(asset, blob_name))

    exported_voice = None
    if isinstance(voice_asset, dict) and _host_onboarding_safe_str(voice_asset.get("url")):
        ext = _infer_upload_ext(_host_onboarding_safe_str(voice_asset.get("content_type")), _host_onboarding_safe_str(voice_asset.get("file_name")))
        file_name = _host_onboarding_connect_voice_filename(avatar_key, ext)
        blob_name = _host_onboarding_export_blob_name("companion", "voice", file_name)
        exported_voice = _host_onboarding_export_asset_from_url(voice_asset, blob_name)

    eleven_voice = {"status": "skipped", "voice_id": "", "voice_name": "", "error": ""}
    if isinstance(exported_voice, dict) and _host_onboarding_safe_str(exported_voice.get("url")):
        try:
            eleven_voice = _host_onboarding_create_eleven_voice_from_asset(
                exported_voice,
                _host_onboarding_eleven_voice_display_name(session, profile, avatar_key),
                _host_onboarding_build_eleven_voice_labels(session, profile, avatar_key, version_id),
            )
        except Exception as exc:
            if _host_onboarding_should_require_eleven_voice():
                raise
            eleven_voice = {
                "status": "error",
                "voice_id": "",
                "voice_name": _host_onboarding_eleven_voice_display_name(session, profile, avatar_key),
                "error": f"{type(exc).__name__}: {exc}",
            }

    explicit_phonetic_pronunciation = _host_onboarding_extract_explicit_phonetic(
        dict(session or {}).get("completion") if isinstance(session, dict) else {},
        private_profile,
        public_profile,
        ai_profile,
        profile,
    )
    saved_avatar_key = _host_onboarding_upsert_connect_companion_mapping(
        member_id=_host_onboarding_safe_str(session.get("member_id")),
        avatar_key=avatar_key,
        headshot_url=_host_onboarding_safe_str((exported_headshot or {}).get("url")),
        voice_capture_url=_host_onboarding_safe_str((exported_voice or {}).get("url")),
        public_gallery_assets=exported_gallery,
        approved_version_id=version_id,
        eleven_voice_id=_host_onboarding_safe_str((eleven_voice or {}).get("voice_id")),
        eleven_voice_name=_host_onboarding_safe_str((eleven_voice or {}).get("voice_name")),
        voice_clone_status=_host_onboarding_safe_str((eleven_voice or {}).get("status")),
        voice_clone_error=_host_onboarding_safe_str((eleven_voice or {}).get("error")),
        phonetic_pronunciation=explicit_phonetic_pronunciation,
        list_in_companion_catalog=_host_onboarding_catalog_visible_from_objs(dict(session or {}).get("completion") if isinstance(session, dict) else {}),
        conn=db_conn,
    )
    if saved_avatar_key:
        avatar_key = saved_avatar_key
    _host_onboarding_upsert_hco_row(
        member_id=_host_onboarding_safe_str(session.get("member_id")),
        avatar_key=avatar_key,
        voice_capture_url=_host_onboarding_safe_str((exported_voice or {}).get("url")),
        raw_profile=profile,
        conn=db_conn,
    )

    public_profile["headshot_asset"] = exported_headshot or public_profile.get("headshot_asset")
    public_profile["gallery_assets"] = exported_gallery or public_profile.get("gallery_assets") or []
    public_page["headshot_asset"] = exported_headshot or public_page.get("headshot_asset")
    public_page["gallery_assets"] = exported_gallery or public_page.get("gallery_assets") or []
    connect_export = {
        "brand": "Elaralo",
        "avatar": avatar_key,
        "headshot_asset": exported_headshot,
        "voice_capture_asset": exported_voice,
        "public_gallery_assets": exported_gallery,
        "eleven_voice_id": _host_onboarding_safe_str((eleven_voice or {}).get("voice_id")),
        "eleven_voice_name": _host_onboarding_safe_str((eleven_voice or {}).get("voice_name")),
        "voice_clone_status": _host_onboarding_safe_str((eleven_voice or {}).get("status")),
    }
    ai_profile["connect_platform"] = connect_export
    return {
        **profile,
        "session": {
            **dict(profile.get("session") or {}),
            "brand": "Elaralo",
            "avatar": avatar_key,
        },
        "private_profile": private_profile,
        "public_profile": public_profile,
        "public_page": public_page,
        "ai_profile": ai_profile,
        "connect_platform": connect_export,
    }






def _host_onboarding_repair_connect_companion_mapping_from_approved_profile(
    *,
    member_id: str,
    brand_name: str,
    version_id: str,
    profile: Dict[str, Any],
    session: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    """Best-effort backfill for older approved Elaralo Human profiles.

    Normal path: approval writes the Human companion row in companion_mappings.
    This repair path handles profiles approved before that export was reliable, so the
    current host's Human card can appear and Connect can find the SQL mapping.
    """
    if not _is_elaralo_core_brand(brand_name):
        return {}
    resolved_member_id = _host_onboarding_normalize_member_id(member_id)
    approved_version_id = _host_onboarding_safe_str(version_id)
    if not resolved_member_id or not approved_version_id or not isinstance(profile, dict):
        return {}

    public_profile = dict(profile.get("public_profile") or {})
    public_page = dict(profile.get("public_page") or {})
    profile_session = dict(profile.get("session") or {})
    connect_platform = dict(profile.get("connect_platform") or {})
    ai_profile = dict(profile.get("ai_profile") or {})
    ai_connect = dict(ai_profile.get("connect_platform") or {})

    display_name = _host_onboarding_safe_str(
        public_profile.get("public_display_name")
        or public_profile.get("stage_name")
        or ai_profile.get("approved_stage_name")
        or (dict((session or {}).get("basics") or {}).get("public_display_name") if isinstance(session, dict) else "")
        or (dict((session or {}).get("basics") or {}).get("stage_name") if isinstance(session, dict) else "")
        or (session or {}).get("host_display_name")
        or "Human Companion"
    )
    avatar_key = _host_onboarding_human_avatar_key_from_profile(profile, session)
    if not avatar_key:
        # If we cannot derive a Host identity from approved profile fields, do not
        # repair/write companion_mappings. Falling back to profile_session.avatar
        # or session.avatar can target the currently selected AI companion.
        return {}

    headshot_asset = {}
    for candidate in [
        connect_platform.get("headshot_asset"),
        ai_connect.get("headshot_asset"),
        public_page.get("headshot_asset"),
        public_profile.get("headshot_asset"),
    ]:
        if isinstance(candidate, dict) and _host_onboarding_safe_str(candidate.get("url")):
            headshot_asset = dict(candidate)
            break
    headshot_url = _host_onboarding_safe_str((headshot_asset or {}).get("url"))

    voice_asset = None
    for candidate in [
        connect_platform.get("voice_capture_asset"),
        ai_connect.get("voice_capture_asset"),
        ai_profile.get("voice_capture_asset"),
    ]:
        if isinstance(candidate, dict) and _host_onboarding_safe_str(candidate.get("url")):
            voice_asset = dict(candidate)
            break
    voice_capture_url = _host_onboarding_safe_str((voice_asset or {}).get("url"))

    gallery_assets = connect_platform.get("public_gallery_assets") or public_page.get("gallery_assets") or public_profile.get("gallery_assets") or []
    if not isinstance(gallery_assets, list):
        gallery_assets = []

    eleven_voice_id = _host_onboarding_safe_str(connect_platform.get("eleven_voice_id") or ai_connect.get("eleven_voice_id"))
    eleven_voice_name = _host_onboarding_safe_str(connect_platform.get("eleven_voice_name") or ai_connect.get("eleven_voice_name"))
    voice_clone_status = _host_onboarding_safe_str(connect_platform.get("voice_clone_status") or ai_connect.get("voice_clone_status"))

    explicit_phonetic_pronunciation = _host_onboarding_extract_explicit_phonetic(
        profile,
        dict(session or {}).get("completion") if isinstance(session, dict) else {},
    )
    saved_avatar_key = _host_onboarding_upsert_connect_companion_mapping(
        member_id=resolved_member_id,
        avatar_key=avatar_key,
        headshot_url=headshot_url,
        voice_capture_url=voice_capture_url,
        public_gallery_assets=gallery_assets,
        approved_version_id=approved_version_id,
        eleven_voice_id=eleven_voice_id,
        eleven_voice_name=eleven_voice_name,
        voice_clone_status=voice_clone_status or "repaired_from_approved_profile",
        voice_clone_error="",
        phonetic_pronunciation=explicit_phonetic_pronunciation,
        list_in_companion_catalog=_host_onboarding_catalog_visible_from_objs(dict(session or {}).get("completion") if isinstance(session, dict) else {}, profile),
    )
    if saved_avatar_key:
        avatar_key = saved_avatar_key
    try:
        _host_onboarding_upsert_hco_row(
            member_id=resolved_member_id,
            avatar_key=avatar_key,
            voice_capture_url=voice_capture_url,
            raw_profile=profile,
        )
    except Exception:
        pass

    return _lookup_companion_mapping("Elaralo", avatar_key) or {
        "brand": "Elaralo",
        "avatar": avatar_key,
        "host_member_id": resolved_member_id,
        "companion_type": "Human",
        "channel_cap": "Video",
        "live": "Stream",
        "headshot_url": headshot_url,
        "approved_version_id": approved_version_id,
        "eleven_voice_id": eleven_voice_id,
        "voice_capture_url": voice_capture_url,
    }


def _host_onboarding_first_sentence(value: Any, max_words: int = 28) -> str:
    text = _host_onboarding_safe_str(value)
    text = re.sub(r"\s+", " ", text).strip()
    if not text:
        return ""
    first = re.split(r"(?<=[.!?])\s+", text, maxsplit=1)[0]
    words = first.split()
    if len(words) > max_words:
        first = " ".join(words[:max_words]).rstrip(",;:") + "."
    if first and not re.search(r"[.!?]$", first):
        first += "."
    return first


def _host_onboarding_ensure_sentence(value: Any) -> str:
    text = re.sub(r"\s+", " ", _host_onboarding_safe_str(value)).strip()
    if not text:
        return ""
    if not re.search(r"[.!?]$", text):
        text += "."
    return text


def _host_onboarding_first_clause_without_mid_sentence_cut(value: Any, max_words: int = 28) -> str:
    text = re.sub(r"\s+", " ", _host_onboarding_safe_str(value)).strip()
    if not text:
        return ""
    first = re.split(r"(?<=[.!?])\s+", text, maxsplit=1)[0]
    if len(first.split()) <= max_words:
        return _host_onboarding_ensure_sentence(first)
    clauses = [part.strip() for part in re.split(r"\s*(?:;|—|–|,|\bwhile\b|\bbut\b)\s*", first, flags=re.IGNORECASE) if part and part.strip()]
    chosen = ""
    for clause in clauses:
        candidate = f"{chosen}, {clause}" if chosen else clause
        if len(candidate.split()) <= max_words:
            chosen = candidate
            continue
        break
    if chosen and len(chosen.split()) >= 6:
        return _host_onboarding_ensure_sentence(chosen)
    return _host_onboarding_ensure_sentence(first)


def _host_onboarding_voice_to_first_person(value: Any, display_name: str, max_words: int = 28) -> str:
    text = _host_onboarding_first_clause_without_mid_sentence_cut(value, max_words=max_words)
    if not text:
        return ""
    name = _host_onboarding_safe_str(display_name)
    if name:
        text = re.sub(rf"\b{re.escape(name)}'s\b", "my", text, flags=re.IGNORECASE)
        text = re.sub(rf"\b{re.escape(name)}\b", "I", text, flags=re.IGNORECASE)
    replacements = [
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}'s\s+father's\s+family\b", "My father's family"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}'s\s+mother's\s+family\b", "My mother's family"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}'s\b", "my"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+is\s+known\s+for\b", "I am known for"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+combines\b", "I combine"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+embodies\b", "I embody"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+maintains\b", "I maintain"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+values\b", "I value"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+carries\b", "I carry"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+approaches\b", "I approach"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+remains\b", "I remain"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+prefers\b", "I prefer"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+enjoys\b", "I enjoy"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+likes\b", "I like"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+works\b", "I work"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+grew\s+up\b", "I grew up"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+was\b", "I was"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+has\b", "I have"),
        (r"^[A-Z][a-z]+(?:\s+[A-Z][a-z]+){0,3}\s+is\b", "I am"),
        (r"\b[Ss]he's\b", "I'm"),
        (r"\b[Hh]e's\b", "I'm"),
        (r"\b[Tt]hey're\b", "I'm"),
        (r"\b[Ss]he is\b", "I am"),
        (r"\b[Hh]e is\b", "I am"),
        (r"\b[Tt]hey are\b", "I am"),
        (r"\b[Ss]he was\b", "I was"),
        (r"\b[Hh]e was\b", "I was"),
        (r"\b[Tt]hey were\b", "I was"),
        (r"\b[Ss]he has\b", "I have"),
        (r"\b[Hh]e has\b", "I have"),
        (r"\b[Tt]hey have\b", "I have"),
        (r"\b[Ss]he\b", "I"),
        (r"\b[Hh]e\b", "I"),
        (r"\b[Tt]hey\b", "I"),
        (r"\b[Hh]er\b", "my"),
        (r"\b[Hh]is\b", "my"),
        (r"\b[Tt]heir\b", "my"),
        (r"\b[Hh]ers\b", "mine"),
        (r"\b[Tt]heirs\b", "mine"),
        (r"\bI combines\b", "I combine"),
        (r"\bI embodies\b", "I embody"),
        (r"\bI maintains\b", "I maintain"),
        (r"\bI values\b", "I value"),
        (r"\bI carries\b", "I carry"),
        (r"\bI approaches\b", "I approach"),
        (r"\bI remains\b", "I remain"),
        (r"\bI prefers\b", "I prefer"),
        (r"\bI enjoys\b", "I enjoy"),
        (r"\bI likes\b", "I like"),
        (r"\bI works\b", "I work"),
        (r"\bI's\b", "my"),
    ]
    for pattern, replacement in replacements:
        text = re.sub(pattern, replacement, text)
    return _host_onboarding_ensure_sentence(text)


def _host_onboarding_readable_list(items: List[str]) -> str:
    values = [re.sub(r"\s+", " ", _host_onboarding_safe_str(item)).strip() for item in items if _host_onboarding_safe_str(item)]
    values = [v for v in values if v]
    if not values:
        return ""
    if len(values) == 1:
        return values[0]
    if len(values) == 2:
        return f"{values[0]} and {values[1]}"
    return ", ".join(values[:-1]) + f", and {values[-1]}"


def _host_onboarding_voice_list(raw: Any, max_items: int = 6) -> List[str]:
    out: List[str] = []
    seen: Set[str] = set()
    values = raw if isinstance(raw, list) else [raw]
    for value in values:
        for part in re.split(r"[\n,;•]+", _host_onboarding_safe_str(value)):
            cleaned = re.sub(r"\s+", " ", _host_onboarding_safe_str(part)).strip()
            if not cleaned:
                continue
            key = cleaned.lower()
            if key in seen:
                continue
            seen.add(key)
            out.append(cleaned)
            if len(out) >= max_items:
                return out
    return out


def _host_onboarding_voice_format_education_entry(entry: Dict[str, Any]) -> str:
    row = dict(entry or {})
    degree = _host_onboarding_safe_str(row.get("degree") or row.get("credential") or row.get("program_name"))
    field = _host_onboarding_safe_str(row.get("field_of_study") or row.get("focus") or row.get("academic_focus"))
    institution = _host_onboarding_safe_str(row.get("institution") or row.get("school"))
    graduation_year = _host_onboarding_safe_str(row.get("graduation_year") or row.get("year"))
    if degree and field:
        phrase = f"{degree} in {field}"
    else:
        phrase = degree or field or institution
    if institution and institution.lower() not in phrase.lower():
        phrase = f"{phrase} from {institution}" if phrase else institution
    if graduation_year:
        phrase = f"{phrase}, class of {graduation_year}" if phrase else f"class of {graduation_year}"
    return re.sub(r"\s+", " ", phrase).strip()


def _host_onboarding_compose_voice_script(sentences: List[str], filler_sentences: List[str], min_words: int = 130, max_words: int = 175) -> Tuple[str, int]:
    chosen: List[str] = []
    total = 0
    normalized_sentences = [_host_onboarding_ensure_sentence(s) for s in sentences if _host_onboarding_safe_str(s)]
    for idx, sentence in enumerate(normalized_sentences):
        sentence_words = len([w for w in re.split(r"\s+", sentence) if w])
        is_essential = idx < 4
        if is_essential or total + sentence_words <= max_words:
            chosen.append(sentence)
            total += sentence_words
    for filler in [_host_onboarding_ensure_sentence(s) for s in filler_sentences if _host_onboarding_safe_str(s)]:
        if total >= min_words:
            break
        filler_words = len([w for w in re.split(r"\s+", filler) if w])
        if total + filler_words > max_words:
            continue
        chosen.append(filler)
        total += filler_words
    script = " ".join(chosen).strip()
    return script, total


def _host_onboarding_voice_capture_guidance(public_profile: Dict[str, Any], private_profile: Dict[str, Any]) -> Dict[str, Any]:
    profile = dict(public_profile or {})
    private_data = dict(private_profile or {})
    display_name = _host_onboarding_safe_str(profile.get("public_display_name") or profile.get("stage_name")) or "this host"
    zodiac = _host_onboarding_safe_str(profile.get("zodiac_sign"))
    physical = _host_onboarding_voice_to_first_person(profile.get("physical_description"), display_name, max_words=28)
    personality = _host_onboarding_voice_to_first_person(profile.get("personality"), display_name, max_words=26)
    family = _host_onboarding_voice_to_first_person(profile.get("family_heritage"), display_name, max_words=28)
    education_entries = _host_onboarding_normalize_education_entries(profile.get("education_entries") or profile.get("education"))
    education_line = _host_onboarding_readable_list([_host_onboarding_voice_format_education_entry(entry) for entry in education_entries[:2] if _host_onboarding_voice_format_education_entry(entry)])
    career = dict(profile.get("career") or {})
    current_job_title = _host_onboarding_safe_str(career.get("current_job_title"))
    current_company = _host_onboarding_safe_str(career.get("current_company"))
    career_summary = _host_onboarding_voice_to_first_person(career.get("career_summary"), display_name, max_words=24)
    interests = _host_onboarding_readable_list(_host_onboarding_voice_list([profile.get("likes"), profile.get("hobbies")], max_items=4))
    lifestyle = _host_onboarding_voice_to_first_person(profile.get("lifestyle"), display_name, max_words=24)
    background = _host_onboarding_voice_to_first_person(profile.get("background_story"), display_name, max_words=26)
    core_values = _host_onboarding_voice_list([profile.get("core_values")], max_items=6)
    motto = _host_onboarding_safe_str(profile.get("personal_motto"))
    birth_country = _host_onboarding_safe_str(private_data.get("birth_country"))
    nationality_list = private_data.get("nationalities") if isinstance(private_data.get("nationalities"), list) else []
    nationality = _host_onboarding_readable_list([_host_onboarding_safe_str(x) for x in nationality_list][:2])

    sentences: List[str] = [
        f"Hello, my name is {display_name}. Thank you for listening to my voice sample for the Connect Platform.",
    ]
    if personality:
        sentences.append(personality)
    elif zodiac:
        sentences.append(f"I bring the thoughtful and intentional energy often associated with {zodiac}.")
    if physical:
        sentences.append(physical)
    if education_line:
        sentences.append(f"My educational background includes {education_line}.")
    if current_job_title and current_company:
        sentences.append(f"Professionally, I work as {current_job_title} at {current_company}.")
    elif current_job_title:
        sentences.append(f"Professionally, I work as {current_job_title}.")
    elif career_summary:
        sentences.append(career_summary)
    if family:
        sentences.append(family)
    elif background:
        sentences.append(background)
    if nationality and birth_country:
        sentences.append(f"My background is rooted in {birth_country}, and my approved nationality profile includes {nationality}.")
    if interests:
        sentences.append(f"In my personal time, I enjoy {interests}.")
    if lifestyle:
        sentences.append(lifestyle)
    if core_values:
        sentences.append(f"My values are centered on {_host_onboarding_readable_list(core_values)}.")
    if motto:
        sentences.append(f"A phrase that represents me well is: {_host_onboarding_safe_str(motto).rstrip('.')}.")
    sentences.append("I want this sample to sound natural, confident, and consistent with the approved profile information that represents me on the platform.")
    sentences.append("Thank you for listening, and I hope this gives you a clear sense of my voice, presence, and personality.")

    filler_sentences = [
        "I am reading this at a calm, conversational pace so you can hear my pronunciation, warmth, and natural rhythm clearly.",
        "I want this recording to feel polished and expressive while still sounding authentic to the way I would naturally introduce myself and speak in a real conversation.",
    ]

    script, word_count = _host_onboarding_compose_voice_script(sentences, filler_sentences, min_words=130, max_words=175)
    estimated_seconds = int(round((word_count / 145.0) * 60.0)) if word_count else 0
    if estimated_seconds < int(_HOST_ONBOARDING_VOICE_TARGET_SECONDS):
        estimated_seconds = int(_HOST_ONBOARDING_VOICE_TARGET_SECONDS)
    return {
        "minimum_seconds": int(_HOST_ONBOARDING_VOICE_MIN_SECONDS),
        "target_seconds": int(_HOST_ONBOARDING_VOICE_TARGET_SECONDS),
        "estimated_seconds": estimated_seconds,
        "word_count": word_count,
        "script": script,
    }


def _host_onboarding_compile_profile(session: Dict[str, Any]) -> Dict[str, Any]:
    basics = dict(session.get("basics") or {})
    derived = dict(session.get("derived") or {})
    review = dict(session.get("review") or {})
    completion = dict(session.get("completion") or {})
    assets = list(session.get("assets") or [])
    nationalities = []
    for item in (review.get("nationalities") or derived.get("nationalities") or []):
        t = _host_onboarding_safe_str(item)
        if t and t not in nationalities:
            nationalities.append(t)
    public_name = _host_onboarding_safe_str(basics.get("stage_name")) or _host_onboarding_safe_str(basics.get("public_display_name"))
    legal_name = _host_onboarding_safe_str(basics.get("legal_name"))
    career_title = _host_onboarding_safe_str(completion.get("current_job_title"))
    income_estimate = _host_onboarding_safe_str(completion.get("estimated_income") or derived.get("estimated_income"))
    if not income_estimate and career_title:
        income_estimate = _host_onboarding_income_estimate_from_title(career_title)
    education_entries = _host_onboarding_normalize_education_entries(completion.get("education_entries") or completion.get("education"))
    education_text = _host_onboarding_format_education_entries_text(education_entries) or _host_onboarding_safe_str(completion.get("education"))
    phonetic_pronunciation = _host_onboarding_extract_explicit_phonetic(completion)
    headshot_asset, gallery_assets = _host_onboarding_split_public_assets(assets)
    voice_capture_asset = next((asset for asset in assets if _host_onboarding_safe_str((asset or {}).get("slot_key")) == _HOST_ONBOARDING_VOICE_SLOT and _host_onboarding_safe_str((asset or {}).get("url"))), None)
    private_identity = {
        "legal_name": legal_name,
        "birthdate": _host_onboarding_safe_str(basics.get("birthdate")),
        "birth_city": _host_onboarding_safe_str(basics.get("birth_city")),
        "birth_state_region": _host_onboarding_safe_str(basics.get("birth_state_region")),
        "birth_country": _host_onboarding_safe_str(basics.get("birth_country")),
        "nationalities": nationalities,
        "race_primary": _host_onboarding_safe_str(basics.get("race_primary")),
        "race_detail": _host_onboarding_safe_str(basics.get("race_detail")),
        "ethnicity_bucket": _host_onboarding_safe_str(basics.get("ethnicity_bucket")),
        "ethnicity_detail": _host_onboarding_safe_str(basics.get("ethnicity_detail")),
        "estimated_income": income_estimate,
        "phonetic_pronunciation": phonetic_pronunciation,
        "phonetic_pronunciation_of_first_name": phonetic_pronunciation,
    }
    public_profile = {
        "stage_name": public_name,
        "public_display_name": _host_onboarding_safe_str(basics.get("public_display_name")) or public_name,
        "gender": _host_onboarding_safe_str(basics.get("gender_display")),
        "age": review.get("age_years") or derived.get("age_years"),
        "zodiac_sign": _host_onboarding_safe_str(review.get("zodiac_sign") or derived.get("zodiac_sign")),
        "quick_reference_summary": review.get("quick_reference") or derived.get("quick_reference") or {},
        "family_heritage": _host_onboarding_safe_str(review.get("family_heritage_draft") or derived.get("family_heritage_draft")),
        "astrological_profile": review.get("astrological_profile") or derived.get("astrological_profile") or {},
        "personality": _host_onboarding_safe_str(review.get("personality_draft") or derived.get("personality_draft")),
        "physical_description": _host_onboarding_meaningful_physical_description(review.get("physical_description_draft")) or _host_onboarding_meaningful_physical_description(completion.get("physical_description")),
        "education": education_text,
        "education_entries": education_entries,
        "career": {
            "current_job_title": career_title,
            "current_company": _host_onboarding_safe_str(completion.get("current_company")),
            "career_summary": _host_onboarding_safe_str(completion.get("career_summary")),
        },
        "likes": _host_onboarding_safe_str(completion.get("likes")),
        "dislikes": _host_onboarding_safe_str(completion.get("dislikes")),
        "hobbies": _host_onboarding_safe_str(completion.get("hobbies")),
        "lifestyle": _host_onboarding_safe_str(completion.get("lifestyle")),
        "background_story": _host_onboarding_safe_str(completion.get("background_story")),
        "core_values": _host_onboarding_safe_str(completion.get("core_values")),
        "personal_motto": _host_onboarding_safe_str(completion.get("personal_motto")),
        "assets": assets,
        "headshot_asset": headshot_asset,
        "gallery_assets": gallery_assets,
    }
    public_page = {
        "headline": _host_onboarding_safe_str(public_profile.get("public_display_name")) or public_name,
        "headshot_asset": headshot_asset,
        "gallery_assets": gallery_assets,
        "education_entries": education_entries,
        "education_text": education_text,
    }
    voice_capture_guidance = _host_onboarding_voice_capture_guidance(public_profile, private_identity)
    ai_profile = {
        "approved_stage_name": public_profile.get("stage_name"),
        "host_real_name_private": legal_name,
        "public_identity": public_profile,
        "private_identity": private_identity,
        "three_d_opt_in": bool(session.get("three_d_opt_in") is True),
        "phonetic_pronunciation": phonetic_pronunciation,
        "voice_capture_asset": voice_capture_asset,
    }
    return {
        "session": {
            "session_id": _host_onboarding_safe_str(session.get("session_id")),
            "member_id": _host_onboarding_safe_str(session.get("member_id")),
            "brand": _host_onboarding_safe_str(session.get("brand")),
            "avatar": _host_onboarding_safe_str(session.get("avatar")),
            "publish_status": _host_onboarding_safe_str(session.get("publish_status")),
            "workflow_state": _host_onboarding_safe_str(session.get("workflow_state")),
        },
        "private_profile": private_identity,
        "public_profile": public_profile,
        "public_page": public_page,
        "voice_capture_guidance": voice_capture_guidance,
        "ai_profile": ai_profile,
    }


def _host_onboarding_compute_readiness(session: Dict[str, Any]) -> Dict[str, Any]:
    basics = dict(session.get("basics") or {})
    review = dict(session.get("review") or {})
    completion = dict(session.get("completion") or {})
    assets = list(session.get("assets") or [])
    basics_required = [
        basics.get("legal_name"),
        basics.get("stage_name"),
        basics.get("birthdate"),
        basics.get("birth_city"),
        basics.get("birth_state_region"),
        basics.get("birth_country"),
        basics.get("race_primary"),
        basics.get("ethnicity_bucket"),
    ]
    basics_ok = all(_host_onboarding_safe_str(v) for v in basics_required)
    photos_ok, missing_slots = _host_onboarding_required_slots_present(assets)
    voice_capture_ok, voice_capture_asset, voice_capture_blockers = _host_onboarding_voice_capture_asset_ok(assets)
    review_ok = bool(review) and bool(_host_onboarding_safe_str(review.get("zodiac_sign") or review.get("family_heritage_draft") or review.get("personality_draft")))
    skipped_sections = completion.get("skipped_sections") or {}
    if not isinstance(skipped_sections, dict):
        skipped_sections = {}

    section_labels = {
        "education": "Education",
        "career_summary": "Career summary",
        "likes": "Likes",
        "dislikes": "Dislikes",
        "hobbies": "Hobbies",
        "lifestyle": "Lifestyle",
        "background_story": "Background story",
        "core_values": "Core values",
        "personal_motto": "Personal motto",
        "physical_description": "Physical description",
        "voice_capture": "Voice capture (minimum 30 seconds)",
    }
    section_value_getters = {
        "education": lambda: _host_onboarding_format_education_entries_text(completion.get("education_entries")) or _host_onboarding_safe_str(completion.get("education")),
        "career_summary": lambda: _host_onboarding_safe_str(completion.get("career_summary")),
        "likes": lambda: _host_onboarding_safe_str(completion.get("likes")),
        "dislikes": lambda: _host_onboarding_safe_str(completion.get("dislikes")),
        "hobbies": lambda: _host_onboarding_safe_str(completion.get("hobbies")),
        "lifestyle": lambda: _host_onboarding_safe_str(completion.get("lifestyle")),
        "background_story": lambda: _host_onboarding_safe_str(completion.get("background_story")),
        "core_values": lambda: _host_onboarding_safe_str(completion.get("core_values")),
        "personal_motto": lambda: _host_onboarding_safe_str(completion.get("personal_motto")),
        "physical_description": lambda: _host_onboarding_meaningful_physical_description(review.get("physical_description_draft")) or _host_onboarding_meaningful_physical_description(completion.get("physical_description")),
        "voice_capture": lambda: voice_capture_ok,
    }
    full_publish_missing_sections: List[str] = []
    full_publish_skipped_sections: List[str] = []
    for key, getter in section_value_getters.items():
        if getter():
            continue
        label = section_labels.get(key) or key.replace("_", " ").title()
        if bool(skipped_sections.get(key) is True):
            full_publish_skipped_sections.append(label)
            full_publish_missing_sections.append(label)
            continue
        full_publish_missing_sections.append(label)

    limited_publish_missing_sections: List[str] = []
    if not basics_ok:
        limited_publish_missing_sections.append("Basics")
    if not photos_ok:
        photo_label = "Required photos"
        if missing_slots:
            photo_label += ": " + ", ".join(_host_onboarding_slot_label(slot) for slot in missing_slots)
        limited_publish_missing_sections.append(photo_label)
    if not review_ok:
        limited_publish_missing_sections.append("Derived review")
    if not voice_capture_ok:
        limited_publish_missing_sections.append(section_labels["voice_capture"])

    limited_allowed = basics_ok and photos_ok and review_ok and voice_capture_ok
    return {
        "basics_ok": basics_ok,
        "photos_ok": photos_ok,
        "missing_required_slots": missing_slots,
        "review_ok": review_ok,
        "voice_capture_ok": voice_capture_ok,
        "voice_capture_required": True,
        "voice_capture_min_seconds": int(_HOST_ONBOARDING_VOICE_MIN_SECONDS),
        "voice_capture_asset_id": _host_onboarding_safe_str((voice_capture_asset or {}).get("asset_id")),
        "voice_capture_blockers": voice_capture_blockers,
        "limited_publish_allowed": limited_allowed,
        "limited_publish_missing_sections": limited_publish_missing_sections,
        "limited_publish_blockers": voice_capture_blockers if not voice_capture_ok else [],
        "full_publish_ready": limited_allowed and not full_publish_missing_sections,
        "full_publish_missing_sections": full_publish_missing_sections,
        "full_publish_skipped_sections": full_publish_skipped_sections,
    }


