def _host_onboarding_public_payload_from_profile(profile: Dict[str, Any]) -> Dict[str, Any]:
    public_profile = dict(profile.get("public_profile") or {})
    public_page = dict(profile.get("public_page") or {})
    education_entries = _host_onboarding_normalize_education_entries(public_profile.get("education_entries") or public_page.get("education_entries") or public_profile.get("education") or public_page.get("education_text"))
    education_text = _host_onboarding_format_education_entries_text(education_entries) or _host_onboarding_safe_str(public_profile.get("education") or public_page.get("education_text"))
    headshot_asset, gallery_assets = _host_onboarding_split_public_assets(public_profile.get("assets") or public_page.get("gallery_assets") or [])
    if public_page.get("headshot_asset") and isinstance(public_page.get("headshot_asset"), dict):
        headshot_asset = _host_onboarding_public_asset_payload(public_page.get("headshot_asset") or {})
    if isinstance(public_page.get("gallery_assets"), list) and public_page.get("gallery_assets"):
        gallery_assets = [_host_onboarding_public_asset_payload(item) for item in list(public_page.get("gallery_assets") or []) if isinstance(item, dict) and _host_onboarding_safe_str(item.get("url"))]
    public_page_payload = {
        "headline": _host_onboarding_safe_str(public_page.get("headline") or public_profile.get("public_display_name") or public_profile.get("stage_name")),
        "headshot_asset": headshot_asset,
        "gallery_assets": gallery_assets,
        "education_entries": education_entries,
        "education_text": education_text,
    }
    public_profile["education_entries"] = education_entries
    public_profile["education"] = education_text
    public_profile["headshot_asset"] = headshot_asset
    public_profile["gallery_assets"] = gallery_assets
    return {"public_profile": public_profile, "public_page": public_page_payload}



def _my_elaralo_catalog_filter_match(value: Any, expected: Any) -> bool:
    want = _host_onboarding_safe_str(expected).strip().lower()
    if not want:
        return True
    have = _host_onboarding_safe_str(value).strip().lower()
    return have == want


def _my_elaralo_companion_cards_db_sync(brand: str, companion_type: str = "", generation: str = "", ethnicity: str = "", gender: str = "", member_id: str = "") -> List[Dict[str, Any]]:
    brand_name = _host_onboarding_safe_str(brand) or "Elaralo"
    rows: List[sqlite3.Row] = []
    conn = _econnect_conn()
    try:
        _host_onboarding_ensure_schema(conn)
        _host_onboarding_ensure_companion_export_columns_best_effort()
        conn.row_factory = sqlite3.Row
        cur = conn.cursor()
        rows = cur.execute(
            """
            SELECT * FROM companion_mappings
             WHERE lower(brand)=lower(?)
             ORDER BY lower(COALESCE(avatar, '')) ASC
            """,
            (brand_name,),
        ).fetchall()
        version_rows: Dict[str, sqlite3.Row] = {}
        version_ids = [str(r["approved_version_id"] or "").strip() for r in rows if str(r["approved_version_id"] or "").strip()]
        if version_ids:
            placeholders = ",".join(["?"] * len(version_ids))
            for vr in cur.execute(
                f"SELECT * FROM {_HOST_ONBOARDING_VERSIONS_TABLE} WHERE version_id IN ({placeholders})",
                tuple(version_ids),
            ).fetchall():
                version_rows[str(vr["version_id"] or "").strip()] = vr
    finally:
        try:
            conn.close()
        except Exception:
            pass

    out: List[Dict[str, Any]] = []
    want_type = _host_onboarding_safe_str(companion_type).lower()
    for row in rows:
        avatar_key = _host_onboarding_safe_str(row["avatar"])
        if not avatar_key:
            continue
        if not _companion_mapping_catalog_visible(row, current_member_id=member_id):
            continue
        mapping_type = _host_onboarding_safe_str(row["companion_type"] or ("Human" if _host_onboarding_safe_str(row["approved_version_id"]) else "AI"))
        normalized_type = mapping_type.lower() if mapping_type else ("human" if _host_onboarding_safe_str(row["approved_version_id"]) else "ai")
        if want_type and normalized_type != want_type:
            continue

        if normalized_type == "human" and _host_onboarding_safe_str(row["approved_version_id"]):
            version_row = version_rows.get(_host_onboarding_safe_str(row["approved_version_id"]))
            if version_row is None:
                continue
            try:
                profile = _host_onboarding_json_loads(version_row["profile_json"], {})
            except Exception:
                profile = {}
            if not isinstance(profile, dict):
                profile = {}
            payload = _host_onboarding_public_payload_from_profile(profile)
            public_profile = dict(payload.get("public_profile") or {})
            public_page = dict(payload.get("public_page") or {})
            quick_ref = dict(public_profile.get("quick_reference_summary") or {})
            display_name = _host_onboarding_safe_str(public_profile.get("public_display_name") or public_profile.get("stage_name") or quick_ref.get("public_name") or avatar_key)
            card = {
                "brand": brand_name,
                "avatar": avatar_key,
                "companion_type": "Human",
                "list_in_companion_catalog": bool(_companion_catalog_visibility_value(row["list_in_companion_catalog"], default=False)),
                "catalog_hidden": _companion_mapping_is_hidden_for_owner(row),
                "hidden": _companion_mapping_is_hidden_for_owner(row),
                "display_name": display_name,
                "headline": _host_onboarding_safe_str(public_page.get("headline") or display_name),
                "gender": _host_onboarding_safe_str(public_profile.get("gender") or quick_ref.get("gender")),
                "ethnicity": _normalize_companion_ethnicity_label(public_profile.get("ethnicity") or quick_ref.get("ethnicity")),
                "generation": _normalize_companion_generation_label(public_profile.get("generation") or quick_ref.get("generation")),
                "headshot_url": _host_onboarding_safe_str(((public_page.get("headshot_asset") or {}).get("url")) or row["headshot_url"]),
                "approved_version_id": _host_onboarding_safe_str(row["approved_version_id"]),
                "elevenVoiceId": _host_onboarding_safe_str(row["eleven_voice_id"]),
                "channel_cap": _host_onboarding_safe_str(row["channel_cap"]),
                "live": _host_onboarding_safe_str(row["live"]),
                "summary_public_url": f"/summary-public?versionId={_host_onboarding_safe_str(row['approved_version_id'])}",
            }
        else:
            payload = _ai_companion_public_payload(brand_name, avatar_key)
            public_profile = dict(payload.get("public_profile") or {})
            public_page = dict(payload.get("public_page") or {})
            card = {
                "brand": brand_name,
                "avatar": avatar_key,
                "companion_type": _host_onboarding_safe_str(public_profile.get("companion_type") or mapping_type or "AI"),
                "display_name": _host_onboarding_safe_str(public_profile.get("public_display_name") or avatar_key),
                "headline": _host_onboarding_safe_str(public_page.get("headline") or public_profile.get("public_display_name") or avatar_key),
                "gender": _host_onboarding_safe_str(public_profile.get("gender")),
                "ethnicity": _normalize_companion_ethnicity_label(public_profile.get("ethnicity")),
                "generation": _normalize_companion_generation_label(public_profile.get("generation")),
                "headshot_url": _host_onboarding_safe_str(((public_page.get("headshot_asset") or {}).get("url")) or row["headshot_url"]),
                "approved_version_id": "",
                "elevenVoiceId": _host_onboarding_safe_str(row["eleven_voice_id"]),
                "channel_cap": _host_onboarding_safe_str(row["channel_cap"]),
                "live": _host_onboarding_safe_str(row["live"]),
                "summary_public_url": f"/summary-public?brand={quote(brand_name)}&avatar={quote(avatar_key)}",
            }

        if not _my_elaralo_catalog_filter_match(card.get("generation"), generation):
            continue
        if not _my_elaralo_catalog_filter_match(card.get("ethnicity"), ethnicity):
            continue
        if not _my_elaralo_catalog_filter_match(card.get("gender"), gender):
            continue
        out.append(card)

    out.sort(key=lambda item: (_host_onboarding_safe_str(item.get("display_name")).lower(), _host_onboarding_safe_str(item.get("avatar")).lower()))
    return out


def _my_elaralo_card_matches_filters(
    card: Dict[str, Any],
    companion_type: str = "",
    generation: str = "",
    ethnicity: str = "",
    gender: str = "",
) -> bool:
    if not _my_elaralo_catalog_filter_match(card.get("companion_type"), companion_type):
        return False
    if not _my_elaralo_catalog_filter_match(card.get("generation"), generation):
        return False
    if not _my_elaralo_catalog_filter_match(card.get("ethnicity"), ethnicity):
        return False
    if not _my_elaralo_catalog_filter_match(card.get("gender"), gender):
        return False
    return True


def _my_elaralo_ai_file_cards(brand_name: str, public_base_url: str = "") -> List[Dict[str, Any]]:
    cards: List[Dict[str, Any]] = []
    for asset in _elaralo_ai_companion_assets():
        companion_key = _host_onboarding_safe_str(asset.get("stem"))
        file_name = _host_onboarding_safe_str(asset.get("file_name"))
        if not companion_key or not file_name:
            continue
        payload = _ai_companion_public_payload(brand_name, companion_key, public_base_url=public_base_url)
        public_profile = dict(payload.get("public_profile") or {})
        public_page = dict(payload.get("public_page") or {})
        mapping = _lookup_companion_mapping_for_ai_media(brand_name, companion_key)
        cards.append({
            "brand": brand_name,
            "avatar": companion_key,
            "companion_key": companion_key,
            "mapping_avatar": _host_onboarding_safe_str((mapping or {}).get("mapping_avatar")),
            "companion_type": "AI",
            "display_name": _host_onboarding_safe_str(public_profile.get("public_display_name") or companion_key.split("-", 1)[0]),
            "headline": _host_onboarding_safe_str(public_page.get("headline") or public_profile.get("public_display_name") or companion_key),
            "gender": _host_onboarding_safe_str(public_profile.get("gender")),
            "ethnicity": _host_onboarding_safe_str(public_profile.get("ethnicity")),
            "generation": _host_onboarding_safe_str(public_profile.get("generation")),
            "headshot_url": _host_onboarding_safe_str(((public_page.get("headshot_asset") or {}).get("url")) or _elaralo_ai_companion_file_url(file_name, public_base_url=public_base_url)),
            "headshot_file_name": file_name,
            "approved_version_id": "",
            "elevenVoiceId": _host_onboarding_safe_str((mapping or {}).get("eleven_voice_id")),
            "channel_cap": _host_onboarding_safe_str((mapping or {}).get("channel_cap")) or "Video",
            "live": _host_onboarding_safe_str((mapping or {}).get("live")) or "D-ID",
            "summary_public_url": f"/summary-public?brand={quote(brand_name)}&avatar={quote(companion_key)}",
        })
    return cards


def _my_elaralo_mapping_row_to_dict(row: Any) -> Dict[str, Any]:
    if not row:
        return {}
    if isinstance(row, dict):
        return dict(row)
    try:
        return dict(row)
    except Exception:
        return {}


def _my_elaralo_row_value(row: Any, *keys: str) -> str:
    obj = _my_elaralo_mapping_row_to_dict(row)
    if not obj:
        return ""
    keys_lc = {str(k).lower(): k for k in obj.keys()}
    for key in keys:
        actual = keys_lc.get(str(key or "").lower())
        if actual is not None:
            return _host_onboarding_safe_str(obj.get(actual))
    return ""


def _my_elaralo_public_asset_url(asset: Any) -> str:
    if isinstance(asset, dict):
        return _host_onboarding_safe_str(asset.get("url"))
    return ""


def _my_elaralo_human_profile_card_from_version(
    *,
    brand_name: str,
    member_id: str,
    version_row: Any,
    session: Optional[Dict[str, Any]],
    mapping: Optional[Dict[str, Any]],
) -> Optional[Dict[str, Any]]:
    version_id = _my_elaralo_row_value(version_row, "version_id", "versionId")
    if not version_id:
        return None
    try:
        profile = _host_onboarding_json_loads(_my_elaralo_row_value(version_row, "profile_json", "profileJson"), {})
    except Exception:
        profile = {}
    if not isinstance(profile, dict):
        profile = {}

    payload = _host_onboarding_public_payload_from_profile(profile)
    public_profile = dict(payload.get("public_profile") or {})
    public_page = dict(payload.get("public_page") or {})
    quick_ref = dict(public_profile.get("quick_reference_summary") or {})
    private_profile = dict(profile.get("private_profile") or {})
    profile_session = dict(profile.get("session") or {})
    connect_platform = dict(profile.get("connect_platform") or {})
    ai_profile = dict(profile.get("ai_profile") or {})
    ai_connect = dict(ai_profile.get("connect_platform") or {})
    basics = dict((session or {}).get("basics") or {})

    display_name = _host_onboarding_safe_str(
        public_profile.get("public_display_name")
        or public_profile.get("stage_name")
        or quick_ref.get("public_name")
        or (session or {}).get("host_display_name")
        or profile_session.get("avatar")
        or "Human Companion"
    )

    avatar_key = _host_onboarding_safe_str(
        _my_elaralo_row_value(mapping, "avatar")
        or connect_platform.get("avatar")
        or ai_connect.get("avatar")
        or profile_session.get("avatar")
        or (session or {}).get("avatar")
    )
    if not avatar_key and session:
        try:
            avatar_key = _host_onboarding_avatar_key_from_session(session)
        except Exception:
            avatar_key = ""
    if not avatar_key:
        first = re.split(r"\s+", display_name.strip(), maxsplit=1)[0] if display_name.strip() else "Human"
        avatar_key = re.sub(r"[^A-Za-z0-9]+", "-", first).strip("-") or "Human"

    headshot_asset = dict(public_page.get("headshot_asset") or public_profile.get("headshot_asset") or {})
    if not _my_elaralo_public_asset_url(headshot_asset) and session:
        try:
            session_headshot, _session_gallery = _host_onboarding_split_public_assets((session or {}).get("assets") or [])
            if session_headshot:
                headshot_asset = dict(session_headshot)
        except Exception:
            pass

    gallery_assets = public_page.get("gallery_assets") or public_profile.get("gallery_assets") or []
    if not isinstance(gallery_assets, list):
        gallery_assets = []

    headshot_url = (
        _my_elaralo_public_asset_url(headshot_asset)
        or _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "headshot_url", "headshotUrl"))
    )

    birthdate = (
        private_profile.get("birthdate")
        or basics.get("birthdate")
        or quick_ref.get("birthdate")
    )
    generation = _normalize_companion_generation_label(
        public_profile.get("generation")
        or quick_ref.get("generation")
        or _host_onboarding_generation_label(birthdate)
    )
    race_source = (
        public_profile.get("race")
        or quick_ref.get("race")
        or private_profile.get("race_primary")
        or basics.get("race_primary")
        or private_profile.get("race_detail")
        or basics.get("race_detail")
    )
    ethnicity = _normalize_companion_ethnicity_label(
        _host_onboarding_race_label(race_source) if _host_onboarding_safe_str(race_source) else (
            public_profile.get("ethnicity")
            or quick_ref.get("ethnicity")
            or private_profile.get("ethnicity_detail")
            or private_profile.get("ethnicity_bucket")
            or basics.get("ethnicity_detail")
            or basics.get("ethnicity_bucket")
        )
    )
    gender = _host_onboarding_safe_str(
        public_profile.get("gender")
        or quick_ref.get("gender")
        or basics.get("gender_display")
        or basics.get("gender_pick")
    )

    channel_cap = _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "channel_cap", "channelCap")) or "Video"
    live = _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "live")) or "Stream"
    eleven_voice_id = _host_onboarding_safe_str(
        _my_elaralo_row_value(mapping, "eleven_voice_id", "elevenVoiceId")
        or connect_platform.get("eleven_voice_id")
        or ai_connect.get("eleven_voice_id")
    )
    voice_capture_url = _host_onboarding_safe_str(
        _my_elaralo_row_value(mapping, "voice_capture_url", "voiceCaptureUrl")
        or ((connect_platform.get("voice_capture_asset") or {}).get("url") if isinstance(connect_platform.get("voice_capture_asset"), dict) else "")
        or ((ai_profile.get("voice_capture_asset") or {}).get("url") if isinstance(ai_profile.get("voice_capture_asset"), dict) else "")
    )

    approved_epoch_raw = _my_elaralo_row_value(version_row, "approved_epoch", "approvedEpoch")
    try:
        approved_epoch = float(approved_epoch_raw or 0.0)
    except Exception:
        approved_epoch = 0.0

    return {
        "id": f"human:{_host_onboarding_safe_str(member_id)}:{version_id}",
        "brand": brand_name,
        "member_id": _host_onboarding_safe_str(member_id),
        "host_member_id": _host_onboarding_safe_str(member_id),
        "avatar": avatar_key,
        "companion_key": avatar_key,
        "mapping_avatar": _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "avatar")) or avatar_key,
        "companion_type": "Human",
        "list_in_companion_catalog": bool(_companion_catalog_visibility_value(_my_elaralo_row_value(mapping, "list_in_companion_catalog", "listInCompanionCatalog"), default=False)),
        "catalog_hidden": _companion_mapping_is_hidden_for_owner(mapping or {}),
        "hidden": _companion_mapping_is_hidden_for_owner(mapping or {}),
        "display_name": display_name,
        "headline": _host_onboarding_safe_str(public_page.get("headline") or display_name),
        "gender": gender,
        "ethnicity": ethnicity,
        "generation": generation,
        "headshot_url": headshot_url,
        "headshot_asset": headshot_asset,
        "gallery_assets": gallery_assets,
        "voice_capture_url": voice_capture_url,
        "approved_version_id": version_id,
        "approved_epoch": approved_epoch,
        "elevenVoiceId": eleven_voice_id,
        "eleven_voice_id": eleven_voice_id,
        "channel_cap": channel_cap,
        "channelCap": channel_cap,
        "live": live,
        "summary_public_url": f"/summary-public?versionId={quote(version_id)}&brand={quote(brand_name)}",
        "mapping_found": bool(mapping),
    }


def _my_elaralo_member_human_cards_sync(
    brand_name: str,
    member_id: str = "",
    public_base_url: str = "",
) -> List[Dict[str, Any]]:
    _ = public_base_url
    resolved_member_id = _host_onboarding_normalize_member_id(member_id)
    if not resolved_member_id:
        return []

    conn = _econnect_conn()
    try:
        _host_onboarding_ensure_schema(conn)
        _host_onboarding_ensure_companion_export_columns_best_effort()
        conn.row_factory = sqlite3.Row
        cur = conn.cursor()

        mapping_rows: List[sqlite3.Row] = []
        try:
            mapping_rows = cur.execute(
                """
                SELECT * FROM companion_mappings
                 WHERE lower(COALESCE(brand, '')) = lower(?)
                 ORDER BY lower(COALESCE(avatar, '')) ASC
                """,
                (brand_name,),
            ).fetchall()
        except Exception:
            mapping_rows = []

        member_mapping_rows: List[Dict[str, Any]] = []
        for row in mapping_rows:
            row_obj = _my_elaralo_mapping_row_to_dict(row)
            ctype = _host_onboarding_safe_str(_my_elaralo_row_value(row_obj, "companion_type", "companionType")).lower()
            # A stale host_member_id on an AI row must not make that AI row look
            # like the logged-in host's Human Companion. Human catalog merge only
            # consumes rows explicitly typed Human.
            if ctype != "human":
                continue
            host_member = _host_onboarding_normalize_member_id(_my_elaralo_row_value(row_obj, "host_member_id", "hostMemberId"))
            if host_member.lower() != resolved_member_id.lower():
                continue
            member_mapping_rows.append(row_obj)

        mapping_by_version: Dict[str, Dict[str, Any]] = {}
        mapping_by_avatar: Dict[str, Dict[str, Any]] = {}
        for mapping in member_mapping_rows:
            approved_vid = _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "approved_version_id", "approvedVersionId"))
            avatar_key = _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "avatar"))
            if approved_vid and approved_vid.lower() not in mapping_by_version:
                mapping_by_version[approved_vid.lower()] = mapping
            if avatar_key and avatar_key.lower() not in mapping_by_avatar:
                mapping_by_avatar[avatar_key.lower()] = mapping

        version_rows: List[sqlite3.Row] = []
        try:
            version_rows = cur.execute(
                f"""
                SELECT * FROM {_HOST_ONBOARDING_VERSIONS_TABLE}
                 WHERE member_id = ?
                 ORDER BY approved_epoch DESC, created_epoch DESC
                 LIMIT 10
                """,
                (resolved_member_id,),
            ).fetchall()
        except Exception:
            version_rows = []

        # If the mapping references an approved version that was not returned by the member query
        # due to historical member-id normalization differences, fetch it explicitly.
        known_version_ids = {
            _host_onboarding_safe_str(_my_elaralo_row_value(vr, "version_id", "versionId")).lower()
            for vr in version_rows
            if _host_onboarding_safe_str(_my_elaralo_row_value(vr, "version_id", "versionId"))
        }
        missing_version_ids = [vid for vid in mapping_by_version.keys() if vid and vid not in known_version_ids]
        for vid in missing_version_ids[:10]:
            try:
                row = cur.execute(
                    f"SELECT * FROM {_HOST_ONBOARDING_VERSIONS_TABLE} WHERE lower(version_id)=lower(?) LIMIT 1",
                    (vid,),
                ).fetchone()
                if row is not None:
                    version_rows.append(row)
            except Exception:
                pass

        session_cache: Dict[str, Dict[str, Any]] = {}

        def get_session(session_id: str) -> Optional[Dict[str, Any]]:
            sid = _host_onboarding_safe_str(session_id)
            if not sid:
                return None
            if sid not in session_cache:
                try:
                    session_cache[sid] = _host_onboarding_get_session_by_id(conn, sid) or {}
                except Exception:
                    session_cache[sid] = {}
            return session_cache.get(sid) or None

        cards: List[Dict[str, Any]] = []
        seen: Set[str] = set()
        for vr in version_rows:
            version_id = _host_onboarding_safe_str(_my_elaralo_row_value(vr, "version_id", "versionId"))
            if not version_id or version_id.lower() in seen:
                continue
            session = get_session(_my_elaralo_row_value(vr, "session_id", "sessionId"))
            mapping = mapping_by_version.get(version_id.lower())
            profile_for_repair: Dict[str, Any] = {}
            if not mapping:
                try:
                    profile_for_repair = _host_onboarding_json_loads(_my_elaralo_row_value(vr, "profile_json", "profileJson"), {})
                    p_session = dict((profile_for_repair or {}).get("session") or {}) if isinstance(profile_for_repair, dict) else {}
                    avatar_key = _host_onboarding_safe_str(p_session.get("avatar") or ((session or {}).get("avatar") if session else ""))
                    if avatar_key:
                        mapping = mapping_by_avatar.get(avatar_key.lower())
                except Exception:
                    profile_for_repair = {}
                    mapping = None
            needs_mapping_repair = (
                not mapping
                or not _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "approved_version_id", "approvedVersionId"))
                or not _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "headshot_url", "headshotUrl"))
                or _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "companion_type", "companionType")).lower() != "human"
            )
            if needs_mapping_repair:
                try:
                    if not profile_for_repair:
                        profile_for_repair = _host_onboarding_json_loads(_my_elaralo_row_value(vr, "profile_json", "profileJson"), {})
                    repaired = _host_onboarding_repair_connect_companion_mapping_from_approved_profile(
                        member_id=resolved_member_id,
                        brand_name=brand_name,
                        version_id=version_id,
                        profile=profile_for_repair if isinstance(profile_for_repair, dict) else {},
                        session=session,
                    )
                    if repaired:
                        mapping = repaired
                        approved_vid = _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "approved_version_id", "approvedVersionId"))
                        avatar_key = _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "avatar"))
                        if approved_vid:
                            mapping_by_version[approved_vid.lower()] = mapping
                        if avatar_key:
                            mapping_by_avatar[avatar_key.lower()] = mapping
                except Exception:
                    pass
            card = _my_elaralo_human_profile_card_from_version(
                brand_name=brand_name,
                member_id=resolved_member_id,
                version_row=vr,
                session=session,
                mapping=mapping,
            )
            if not card:
                continue
            seen.add(version_id.lower())
            cards.append(card)

        # Last-resort fallback: a Human companion mapping with a headshot but no readable version row.
        # This keeps the card visible while the Companion Card button still uses memberId and will
        # gracefully 404 if no approved public profile exists.
        if not cards:
            for mapping in member_mapping_rows:
                avatar_key = _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "avatar"))
                headshot_url = _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "headshot_url", "headshotUrl"))
                display_name = _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "phonetic")) or (avatar_key.split("-", 1)[0] if avatar_key else "Human Companion")
                if not avatar_key and not headshot_url:
                    continue
                cards.append({
                    "id": f"human:{resolved_member_id}:{avatar_key or display_name}",
                    "brand": brand_name,
                    "member_id": resolved_member_id,
                    "host_member_id": resolved_member_id,
                    "avatar": avatar_key or display_name,
                    "companion_key": avatar_key or display_name,
                    "mapping_avatar": avatar_key or display_name,
                    "companion_type": "Human",
                    "display_name": display_name,
                    "headline": display_name,
                    "gender": "",
                    "ethnicity": "",
                    "generation": "",
                    "headshot_url": headshot_url,
                    "approved_version_id": _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "approved_version_id", "approvedVersionId")),
                    "elevenVoiceId": _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "eleven_voice_id", "elevenVoiceId")),
                    "eleven_voice_id": _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "eleven_voice_id", "elevenVoiceId")),
                    "channel_cap": _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "channel_cap", "channelCap")) or "Video",
                    "channelCap": _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "channel_cap", "channelCap")) or "Video",
                    "live": _host_onboarding_safe_str(_my_elaralo_row_value(mapping, "live")) or "Stream",
                    "summary_public_url": f"/summary-public?memberId={quote(resolved_member_id)}&brand={quote(brand_name)}",
                    "mapping_found": True,
                })
                break

        cards.sort(key=lambda item: (
            -float(item.get("approved_epoch") or 0.0),
            _host_onboarding_safe_str(item.get("display_name")).lower(),
            _host_onboarding_safe_str(item.get("avatar")).lower(),
        ))
        return cards[:1]
    finally:
        try:
            conn.close()
        except Exception:
            pass


def _my_elaralo_companion_cards_sync(
    brand: str,
    member_id: str = "",
    companion_type: str = "",
    generation: str = "",
    ethnicity: str = "",
    gender: str = "",
    public_base_url: str = "",
) -> List[Dict[str, Any]]:
    brand_name = _host_onboarding_safe_str(brand) or "Elaralo"

    if not _is_elaralo_core_brand(brand_name):
        return _my_elaralo_companion_cards_db_sync(brand_name, companion_type, generation, ethnicity, gender, member_id=member_id)

    out: List[Dict[str, Any]] = []
    seen: Set[Tuple[str, str]] = set()

    def add_card(card: Dict[str, Any]) -> None:
        if not isinstance(card, dict):
            return
        if not _my_elaralo_card_matches_filters(card, companion_type, generation, ethnicity, gender):
            return
        ctype = _host_onboarding_safe_str(card.get("companion_type") or card.get("companionType") or "AI")
        avatar_key = _host_onboarding_safe_str(card.get("avatar") or card.get("companion_key") or card.get("display_name"))
        sig = (ctype.lower(), avatar_key.lower())
        if sig in seen:
            return
        seen.add(sig)
        out.append(card)

    want_type = _host_onboarding_safe_str(companion_type).lower()

    ai_cards = _my_elaralo_ai_file_cards(brand_name, public_base_url=public_base_url)
    if want_type != "human":
        for card in ai_cards:
            add_card(card)

    if not ai_cards and want_type != "human":
        for card in _my_elaralo_companion_cards_db_sync(brand_name, "AI", "", "", "", member_id=member_id):
            add_card(card)

    if want_type != "ai":
        human_cards = _my_elaralo_member_human_cards_sync(
            brand_name,
            member_id=member_id,
            public_base_url=public_base_url,
        )
        for card in human_cards:
            add_card(card)

        # Historical fallback for non-member-scoped Elaralo rows. In normal My Elaralo use,
        # member_id is present and the member-scoped Host Onboarding/Profile Studio card above
        # is the source of truth for the Human Companion.
        if not human_cards:
            for card in _my_elaralo_companion_cards_db_sync(brand_name, "Human", "", "", "", member_id=member_id):
                add_card(card)

    out.sort(key=lambda item: (_host_onboarding_safe_str(item.get("display_name")).lower(), _host_onboarding_safe_str(item.get("avatar")).lower()))
    return out


@app.get("/my-elaralo/companions/catalog")
@app.get("/catalog/my-elaralo")
async def my_elaralo_companions_catalog(
    request: Request,
    memberId: Optional[str] = None,
    member_id: Optional[str] = None,
    brand: Optional[str] = None,
    companionType: Optional[str] = None,
    companion_type: Optional[str] = None,
    generation: Optional[str] = None,
    ethnicity: Optional[str] = None,
    gender: Optional[str] = None,
):
    resolved_member_id = _host_onboarding_normalize_member_id(memberId or member_id)
    brand_name = _host_onboarding_safe_str(brand) or "Elaralo"
    # v9.2.45: Elaralo visitors can browse/select AI companions and open
    # Connect using the brand-specific free-minute allowance.  Member-scoped
    # hidden Host owner cards still require memberId and are only included when
    # resolved_member_id is present; public/visitor catalog calls receive AI
    # cards plus any explicitly visible Human cards.
    items = _my_elaralo_companion_cards_sync(
        brand=brand_name,
        member_id=resolved_member_id,
        companion_type=_host_onboarding_safe_str(companionType or companion_type),
        generation=_host_onboarding_safe_str(generation),
        ethnicity=_host_onboarding_safe_str(ethnicity),
        gender=_host_onboarding_safe_str(gender),
        public_base_url=_companion_public_api_base_url(request=request),
    )
    return {
        "ok": True,
        "brand": brand_name,
        "member_id": resolved_member_id,
        "count": len(items),
        "items": items,
    }


@app.post("/host-onboarding/catalog-visibility")
async def host_onboarding_catalog_visibility(request: Request):
    """Update the logged-in Host's Human Companion catalog visibility.

    v9.2.43 hardening:
      - Fixes the implicit SQLite transaction issue from schema repair before BEGIN IMMEDIATE.
      - Treat this as a lightweight preference update, not a page/navigation action.
      - Persist the value into the active Host/Profile Studio session completion JSON
        so the checkbox hydrates correctly after reload.
      - Update the Human companion_mappings row when it exists.
      - If a mapping row does not exist yet, do not hard-fail the UI; the row will be
        created during the normal Host Onboarding/Profile Studio approval/export path.
    """
    try:
        raw = await request.json()
    except Exception:
        raw = {}
    if not isinstance(raw, dict):
        raw = {}

    member_id = _host_onboarding_normalize_member_id(raw.get("memberId") or raw.get("member_id"))
    brand_name = _host_onboarding_safe_str(raw.get("brand") or raw.get("brandId") or raw.get("brand_id") or "Elaralo") or "Elaralo"
    session_id = _host_onboarding_safe_str(raw.get("sessionId") or raw.get("session_id"))

    visible = _host_onboarding_catalog_visible_from_objs(raw)
    if visible is None:
        visible = _bool_from_any(raw.get("visible"), default=None)
    if visible is None:
        raise HTTPException(status_code=400, detail="visible/list_in_companion_catalog is required")
    if not member_id:
        raise HTTPException(status_code=400, detail="memberId is required")

    db_path = _get_companion_mappings_db_path(for_write=True) or _ensure_econnect_db_seeded()
    if not db_path:
        raise HTTPException(status_code=500, detail="companion mappings database is not configured")

    visible_int = 1 if bool(visible) else 0
    now_epoch = int(_host_onboarding_now())
    mapping_updated = 0
    session_updated = 0
    latest_session_id = ""

    conn = sqlite3.connect(db_path, timeout=30, check_same_thread=False)
    conn.row_factory = sqlite3.Row
    try:
        conn.execute("PRAGMA busy_timeout=5000;")
        _host_onboarding_ensure_schema(conn)
        _host_onboarding_ensure_companion_export_columns_on_conn(conn)

        # Schema/trigger repair helpers can execute DDL/DML and may leave the
        # sqlite3 connection inside an implicit transaction. Starting another
        # BEGIN IMMEDIATE at that point raises:
        #   sqlite3.OperationalError: cannot start a transaction within a transaction
        # Commit the repair work before opening the lightweight catalog visibility
        # transaction. This preserves the same write-lock behavior while avoiding
        # the 500 seen when the checkbox is toggled.
        try:
            conn.commit()
        except Exception:
            pass

        cur = conn.cursor()
        cur.execute("BEGIN IMMEDIATE")

        # First persist the preference into the active session completion JSON. This
        # prevents the UI from hydrating back to the previous value after reload.
        session_row = None
        if session_id:
            session_row = cur.execute(
                f"SELECT * FROM {_HOST_ONBOARDING_SESSIONS_TABLE} WHERE session_id = ? AND member_id = ? LIMIT 1",
                (session_id, member_id),
            ).fetchone()
        if session_row is None:
            session_row = cur.execute(
                f"""
                SELECT *
                  FROM {_HOST_ONBOARDING_SESSIONS_TABLE}
                 WHERE member_id = ?
                   AND lower(COALESCE(brand, '')) = lower(?)
                 ORDER BY updated_epoch DESC, created_epoch DESC
                 LIMIT 1
                """,
                (member_id, brand_name),
            ).fetchone()

        if session_row is not None:
            try:
                completion = _host_onboarding_json_loads(session_row["completion_json"], {})
                if not isinstance(completion, dict):
                    completion = {}
            except Exception:
                completion = {}
            completion["list_in_companion_catalog"] = bool(visible_int)
            completion["catalog_visible"] = bool(visible_int)
            completion["show_in_companion_catalog"] = bool(visible_int)
            completion["catalog_visibility_updated_at"] = now_epoch
            completion["catalog_visibility_updated_by"] = member_id
            latest_session_id = _host_onboarding_safe_str(session_row["session_id"])
            cur.execute(
                f"""
                UPDATE {_HOST_ONBOARDING_SESSIONS_TABLE}
                   SET completion_json = ?,
                       updated_epoch = ?
                 WHERE session_id = ?
                   AND member_id = ?
                """,
                (_host_onboarding_json_dumps(completion), now_epoch, latest_session_id, member_id),
            )
            session_updated = int(cur.rowcount or 0)

        # Then update the exported Human mapping when it exists. Do not allow AI rows
        # to be touched by this preference route.
        cur.execute(
            """
            UPDATE companion_mappings
               SET list_in_companion_catalog = ?,
                   catalog_hidden_reason = CASE WHEN ? = 1 THEN NULL ELSE 'host_hidden_by_default' END,
                   catalog_visibility_updated_at = ?,
                   catalog_visibility_updated_by = ?
             WHERE lower(COALESCE(brand, '')) = lower(?)
               AND lower(COALESCE(companion_type, '')) = 'human'
               AND lower(COALESCE(host_member_id, '')) = lower(?)
            """,
            (visible_int, visible_int, now_epoch, member_id, brand_name, member_id),
        )
        mapping_updated = int(cur.rowcount or 0)

        conn.commit()
    except Exception:
        try:
            conn.rollback()
        except Exception:
            pass
        raise
    finally:
        try:
            conn.close()
        except Exception:
            pass

    try:
        _load_companion_mappings_sync()
    except Exception:
        pass

    return {
        "ok": True,
        "brand": brand_name,
        "member_id": member_id,
        "session_id": latest_session_id or session_id,
        "list_in_companion_catalog": bool(visible_int),
        "catalog_visible": bool(visible_int),
        "mapping_updated": mapping_updated,
        "session_updated": session_updated,
        "updated": mapping_updated + session_updated,
        "mapping_missing": mapping_updated <= 0,
        "message": "Catalog visibility saved. Human Companion mapping will be updated after Host profile export if it does not exist yet." if mapping_updated <= 0 else "Catalog visibility saved.",
    }


@app.get("/host-onboarding/public/summary")
async def host_onboarding_public_summary(
    request: Request,
    memberId: Optional[str] = None,
    member_id: Optional[str] = None,
    versionId: Optional[str] = None,
    version_id: Optional[str] = None,
    brand: Optional[str] = None,
    brandId: Optional[str] = None,
    avatar: Optional[str] = None,
    companion: Optional[str] = None,
    companionKey: Optional[str] = None,
    companion_key: Optional[str] = None,
    headshot: Optional[str] = None,
    headshotFile: Optional[str] = None,
    headshot_file: Optional[str] = None,
):
    resolved_version_id = _host_onboarding_safe_str(versionId or version_id)
    resolved_member_id = _host_onboarding_normalize_member_id(memberId or member_id)
    resolved_brand = _host_onboarding_safe_str(brand or brandId) or "Elaralo"
    resolved_avatar = _host_onboarding_safe_str(avatar or companion or companionKey or companion_key or headshot or headshotFile or headshot_file)
    if not resolved_version_id and not resolved_member_id and not resolved_avatar:
        raise HTTPException(status_code=400, detail="memberId, versionId, avatar, or headshot filename is required")
    if not resolved_version_id and not resolved_member_id and resolved_avatar:
        payload = _ai_companion_public_payload(resolved_brand, resolved_avatar, public_base_url=_companion_public_api_base_url(request=request))
        return {
            "ok": True,
            "version": None,
            **payload,
        }
    conn = _econnect_conn()
    try:
        _host_onboarding_ensure_schema(conn)
        row = None
        if resolved_version_id:
            row = conn.execute(
                f"SELECT * FROM {_HOST_ONBOARDING_VERSIONS_TABLE} WHERE version_id = ? LIMIT 1",
                (resolved_version_id,),
            ).fetchone()
        else:
            row = conn.execute(
                f"SELECT * FROM {_HOST_ONBOARDING_VERSIONS_TABLE} WHERE member_id = ? ORDER BY approved_epoch DESC, created_epoch DESC LIMIT 1",
                (resolved_member_id,),
            ).fetchone()
        if row is None:
            raise HTTPException(status_code=404, detail="No approved profile version found")
        profile = _host_onboarding_json_loads(row["profile_json"], {})
        if not isinstance(profile, dict):
            profile = {}
        payload = _host_onboarding_public_payload_from_profile(profile)
        return {
            "ok": True,
            "version": {
                "version_id": _host_onboarding_safe_str(row["version_id"]),
                "session_id": _host_onboarding_safe_str(row["session_id"]),
                "member_id": _host_onboarding_safe_str(row["member_id"]),
                "version_no": int(row["version_no"] or 0),
                "publish_scope": _host_onboarding_safe_str(row["publish_scope"]),
                "approved_epoch": float(row["approved_epoch"] or 0.0),
            },
            **payload,
        }
    finally:
        try:
            conn.close()
        except Exception:
            pass


@app.post("/host-onboarding/session/{session_id}/approve")
async def host_onboarding_approve(session_id: str, req: HostOnboardingApproveRequest):
    member_id = _host_onboarding_normalize_member_id(req.memberId or req.member_id)
    publish_scope = _host_onboarding_safe_str(req.publishScope or req.publish_scope).lower() or "limited"
    if publish_scope not in ("limited", "full"):
        publish_scope = "limited"
    if not member_id:
        raise HTTPException(status_code=400, detail="memberId is required")
    conn = _econnect_conn()
    try:
        _host_onboarding_ensure_schema(conn)
        conn.execute("BEGIN IMMEDIATE")
        session = _host_onboarding_get_session_by_id(conn, _host_onboarding_safe_str(session_id))
        if not session:
            raise HTTPException(status_code=404, detail="Host onboarding session not found")
        _host_onboarding_assert_member_access(session, member_id)
        readiness = _host_onboarding_compute_readiness(session)
        if publish_scope == "limited" and not bool(readiness.get("limited_publish_allowed") is True):
            missing = [str(x).strip() for x in list(readiness.get("limited_publish_missing_sections") or []) if str(x).strip()]
            blockers = [str(x).strip() for x in list(readiness.get("limited_publish_blockers") or []) if str(x).strip()]
            detail = "Limited publish requires basics, required photos, derived review, and a validated host voice capture."
            if missing:
                detail += " Missing requirements: " + ", ".join(missing) + "."
            if blockers:
                detail += " Voice capture blockers: " + " ".join(blockers)
            raise HTTPException(status_code=400, detail=detail)
        if publish_scope == "full" and not bool(readiness.get("full_publish_ready") is True):
            limited_missing = [str(x).strip() for x in list(readiness.get("limited_publish_missing_sections") or []) if str(x).strip()]
            full_missing = [str(x).strip() for x in list(readiness.get("full_publish_missing_sections") or []) if str(x).strip()]
            skipped = [str(x).strip() for x in list(readiness.get("full_publish_skipped_sections") or []) if str(x).strip()]
            missing: List[str] = []
            for item in limited_missing + full_missing:
                if item and item not in missing:
                    missing.append(item)
            detail = "Full publish requires completion of all MVP profile sections plus a validated host voice capture."
            if missing:
                detail += " Missing requirements: " + ", ".join(missing) + "."
            if skipped:
                detail += " Skipped sections must be completed for full publish: " + ", ".join(skipped) + "."
            raise HTTPException(status_code=400, detail=detail)
        version_no_row = conn.execute(
            f"SELECT COALESCE(MAX(version_no), 0) AS max_version FROM {_HOST_ONBOARDING_VERSIONS_TABLE} WHERE session_id = ?",
            (session_id,),
        ).fetchone()
        version_no = int(version_no_row["max_version"] if version_no_row is not None else 0) + 1
        version_id = uuid.uuid4().hex
        profile = _host_onboarding_compile_profile(session)
        profile = _host_onboarding_export_connect_profile(session, profile, version_id, db_conn=conn)
        approved_epoch = _host_onboarding_now()
        conn.execute(
            f"INSERT INTO {_HOST_ONBOARDING_VERSIONS_TABLE} (version_id, session_id, member_id, version_no, publish_scope, profile_json, created_epoch, approved_epoch) VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
            (version_id, session_id, member_id, version_no, publish_scope, _host_onboarding_json_dumps(profile), approved_epoch, approved_epoch),
        )
        workflow_state = "approved" if publish_scope == "full" else "approved_with_later_edits_pending"
        exported_session = dict(profile.get("session") or {})
        updated = _host_onboarding_upsert_session(
            conn,
            session_id=session["session_id"],
            member_id=member_id,
            brand=_host_onboarding_safe_str(exported_session.get("brand") or session.get("brand")),
            avatar=_host_onboarding_safe_str(exported_session.get("avatar") or session.get("avatar")),
            host_display_name=_host_onboarding_safe_str(session.get("host_display_name")),
            logged_in=bool(session.get("logged_in") is True),
            workflow_state=workflow_state,
            publish_status=publish_scope,
            approved_version_id=version_id,
            limited_publish_allowed=bool(readiness.get("limited_publish_allowed") is True),
            full_publish_ready=bool(readiness.get("full_publish_ready") is True),
        )
        _host_onboarding_audit(conn, session["session_id"], member_id, "profile_approved", {"version_id": version_id, "publish_scope": publish_scope})
        conn.commit()
        try:
            _load_companion_mappings_sync()
        except Exception:
            pass
        return {
            "ok": True,
            "session": updated,
            "version": {
                "version_id": version_id,
                "version_no": version_no,
                "publish_scope": publish_scope,
                "approved_epoch": approved_epoch,
            },
            "preview": profile,
            "readiness": _host_onboarding_compute_readiness(updated),
        }
    finally:
        try:
            conn.close()
        except Exception:
            pass
